	[AddComponentMenu("Cinemachine/Cinemachine Camera")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineCamera.html")]
	public sealed class CinemachineCamera : CinemachineVirtualCameraBase
	{
		[NoSaveDuringPlay]
		[Tooltip("Specifies the Tracking and LookAt targets for this camera.")]
		public CameraTarget Target;

		[Tooltip("Specifies the lens properties of this Virtual Camera.  This generally mirrors the Unity Camera's lens settings, and will be used to drive the Unity camera when the vcam is active.")]
		public LensSettings Lens = LensSettings.Default;

		[Tooltip("Hint for transitioning to and from this CinemachineCamera.  Hints can be combined, although not all combinations make sense.  In the case of conflicting hints, Cinemachine will make an arbitrary choice.")]
		public CinemachineCore.BlendHints BlendHint;

		private CameraState m_State = CameraState.Default;

		private CinemachineComponentBase[] m_Pipeline;

		public override CameraState State => m_State;

		public override Transform LookAt
		{
			get
			{
				return ResolveLookAt(Target.CustomLookAtTarget ? Target.LookAtTarget : Target.TrackingTarget);
			}
			set
			{
				Target.CustomLookAtTarget = true;
				Target.LookAtTarget = value;
			}
		}

		public override Transform Follow
		{
			get
			{
				return ResolveFollow(Target.TrackingTarget);
			}
			set
			{
				Target.TrackingTarget = value;
			}
		}

		internal bool PipelineCacheInvalidated => m_Pipeline == null;

		private void Reset()
		{
			Priority = default(PrioritySettings);
			OutputChannel = OutputChannels.Default;
			Target = default(CameraTarget);
			Lens = LensSettings.Default;
		}

		private void OnValidate()
		{
			Lens.Validate();
		}

		public override void OnTargetObjectWarped(Transform target, Vector3 positionDelta)
		{
			if (target == Follow)
			{
				base.transform.position += positionDelta;
				m_State.RawPosition += positionDelta;
			}
			UpdatePipelineCache();
			for (int i = 0; i < m_Pipeline.Length; i++)
			{
				if (m_Pipeline[i] != null)
				{
					m_Pipeline[i].OnTargetObjectWarped(target, positionDelta);
				}
			}
			base.OnTargetObjectWarped(target, positionDelta);
		}

		public override void ForceCameraPosition(Vector3 pos, Quaternion rot)
		{
			PreviousStateIsValid = false;
			UpdatePipelineCache();
			for (int i = 0; i < m_Pipeline.Length; i++)
			{
				if (m_Pipeline[i] != null)
				{
					m_Pipeline[i].ForceCameraPosition(pos, rot);
				}
			}
			m_State.RawPosition = pos;
			m_State.RawOrientation = rot;
			base.ForceCameraPosition(pos, rot);
		}

		public override float GetMaxDampTime()
		{
			float num = base.GetMaxDampTime();
			UpdatePipelineCache();
			for (int i = 0; i < m_Pipeline.Length; i++)
			{
				if (m_Pipeline[i] != null)
				{
					num = Mathf.Max(num, m_Pipeline[i].GetMaxDampTime());
				}
			}
			return num;
		}

		public override void OnTransitionFromCamera(ICinemachineCamera fromCam, Vector3 worldUp, float deltaTime)
		{
			base.OnTransitionFromCamera(fromCam, worldUp, deltaTime);
			InvokeOnTransitionInExtensions(fromCam, worldUp, deltaTime);
			bool flag = false;
			if ((State.BlendHint & CameraState.BlendHints.InheritPosition) != CameraState.BlendHints.Nothing && fromCam != null && !CinemachineCore.IsLiveInBlend(this))
			{
				CameraState state = fromCam.State;
				ForceCameraPosition(state.GetFinalPosition(), state.GetFinalOrientation());
			}
			UpdatePipelineCache();
			for (int i = 0; i < m_Pipeline.Length; i++)
			{
				if (m_Pipeline[i] != null && m_Pipeline[i].OnTransitionFromCamera(fromCam, worldUp, deltaTime))
				{
					flag = true;
				}
			}
			if (!flag)
			{
				UpdateCameraState(worldUp, deltaTime);
				return;
			}
			InternalUpdateCameraState(worldUp, deltaTime);
			InternalUpdateCameraState(worldUp, deltaTime);
		}

		public override void InternalUpdateCameraState(Vector3 worldUp, float deltaTime)
		{
			UpdateTargetCache();
			FollowTargetAttachment = 1f;
			LookAtTargetAttachment = 1f;
			if (deltaTime < 0f)
			{
				PreviousStateIsValid = false;
			}
			m_State = PullStateFromVirtualCamera(worldUp, ref Lens);
			Transform lookAt = LookAt;
			if (lookAt != null)
			{
				m_State.ReferenceLookAt = ((base.LookAtTargetAsVcam != null) ? base.LookAtTargetAsVcam.State.GetFinalPosition() : TargetPositionCache.GetTargetPosition(lookAt));
			}
			m_State.BlendHint = (CameraState.BlendHints)BlendHint;
			InvokeComponentPipeline(ref m_State, deltaTime);
			base.transform.ConservativeSetPositionAndRotation(m_State.RawPosition, m_State.RawOrientation);
			PreviousStateIsValid = true;
		}

		private CameraState InvokeComponentPipeline(ref CameraState state, float deltaTime)
		{
			InvokePrePipelineMutateCameraStateCallback(this, ref state, deltaTime);
			UpdatePipelineCache();
			for (int i = 0; i < m_Pipeline.Length; i++)
			{
				CinemachineComponentBase cinemachineComponentBase = m_Pipeline[i];
				if (cinemachineComponentBase != null && cinemachineComponentBase.IsValid)
				{
					cinemachineComponentBase.PrePipelineMutateCameraState(ref state, deltaTime);
				}
			}
			CinemachineComponentBase cinemachineComponentBase2 = null;
			for (int j = 0; j < m_Pipeline.Length; j++)
			{
				CinemachineCore.Stage stage = (CinemachineCore.Stage)j;
				CinemachineComponentBase cinemachineComponentBase3 = m_Pipeline[j];
				if (cinemachineComponentBase3 != null && cinemachineComponentBase3.IsValid)
				{
					if (stage == CinemachineCore.Stage.Body && cinemachineComponentBase3.BodyAppliesAfterAim)
					{
						cinemachineComponentBase2 = cinemachineComponentBase3;
						continue;
					}
					cinemachineComponentBase3.MutateCameraState(ref state, deltaTime);
				}
				InvokePostPipelineStageCallback(this, stage, ref state, deltaTime);
				if (stage == CinemachineCore.Stage.Aim && cinemachineComponentBase2 != null)
				{
					cinemachineComponentBase2.MutateCameraState(ref state, deltaTime);
					InvokePostPipelineStageCallback(this, CinemachineCore.Stage.Body, ref state, deltaTime);
				}
			}
			return state;
		}

		internal void InvalidatePipelineCache()
		{
			m_Pipeline = null;
		}

		internal Type PeekPipelineCacheType(CinemachineCore.Stage stage)
		{
			if (!(m_Pipeline[(int)stage] == null))
			{
				return m_Pipeline[(int)stage].GetType();
			}
			return null;
		}

		private void UpdatePipelineCache()
		{
			if (m_Pipeline != null && m_Pipeline.Length == 4)
			{
				return;
			}
			m_Pipeline = new CinemachineComponentBase[4];
			CinemachineComponentBase[] components = GetComponents<CinemachineComponentBase>();
			for (int i = 0; i < components.Length; i++)
			{
				if (m_Pipeline[(int)components[i].Stage] == null)
				{
					m_Pipeline[(int)components[i].Stage] = components[i];
				}
			}
		}

		public override CinemachineComponentBase GetCinemachineComponent(CinemachineCore.Stage stage)
		{
			UpdatePipelineCache();
			if (stage < CinemachineCore.Stage.Body || (int)stage >= m_Pipeline.Length)
			{
				return null;
			}
			return m_Pipeline[(int)stage];
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Camera Offset")]
	[ExecuteAlways]
	[SaveDuringPlay]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineCameraOffset.html")]
	public class CinemachineCameraOffset : CinemachineExtension
	{
		[Tooltip("Offset the camera's position by this much (camera space)")]
		[FormerlySerializedAs("m_Offset")]
		public Vector3 Offset = Vector3.zero;

		[Tooltip("When to apply the offset")]
		[FormerlySerializedAs("m_ApplyAfter")]
		public CinemachineCore.Stage ApplyAfter = CinemachineCore.Stage.Aim;

		[Tooltip("If applying offset after aim, re-adjust the aim to preserve the screen position of the LookAt target as much as possible")]
		[FormerlySerializedAs("m_PreserveComposition")]
		public bool PreserveComposition;

		private void Reset()
		{
			Offset = Vector3.zero;
			ApplyAfter = CinemachineCore.Stage.Aim;
			PreserveComposition = false;
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage == ApplyAfter)
			{
				bool num = PreserveComposition && state.HasLookAt() && stage > CinemachineCore.Stage.Body;
				Vector3 vector = Vector2.zero;
				if (num)
				{
					vector = state.RawOrientation.GetCameraRotationToTarget(state.ReferenceLookAt - state.GetCorrectedPosition(), state.ReferenceUp);
				}
				Vector3 vector2 = state.RawOrientation * Offset;
				state.PositionCorrection += vector2;
				if (!num)
				{
					state.ReferenceLookAt += vector2;
					return;
				}
				Quaternion orient = Quaternion.LookRotation(state.ReferenceLookAt - state.GetCorrectedPosition(), state.ReferenceUp);
				orient = orient.ApplyCameraRotation(-vector, state.ReferenceUp);
				state.RawOrientation = orient;
			}
		}
	}
	[DisallowMultipleComponent]
	[ExecuteAlways]
	[ExcludeFromPreset]
	[SaveDuringPlay]
	[AddComponentMenu("Cinemachine/Cinemachine ClearShot")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineClearShot.html")]
	public class CinemachineClearShot : CinemachineCameraManagerBase
	{
		private struct Pair
		{
			public int a;

			public float b;
		}

		[Tooltip("Wait this many seconds before activating a new child camera")]
		[FormerlySerializedAs("m_ActivateAfter")]
		public float ActivateAfter;

		[Tooltip("An active camera must be active for at least this many seconds")]
		[FormerlySerializedAs("m_MinDuration")]
		public float MinDuration;

		[Tooltip("If checked, camera choice will be randomized if multiple cameras are equally desirable.  Otherwise, child list order and child camera priority will be used.")]
		[FormerlySerializedAs("m_RandomizeChoice")]
		public bool RandomizeChoice;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_LookAt")]
		private Transform m_LegacyLookAt;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_Follow")]
		private Transform m_LegacyFollow;

		private float m_ActivationTime;

		private float m_PendingActivationTime;

		private CinemachineVirtualCameraBase m_PendingCamera;

		private bool m_RandomizeNow;

		private List<CinemachineVirtualCameraBase> m_RandomizedChildren;

		protected override void Reset()
		{
			base.Reset();
			ActivateAfter = 0f;
			MinDuration = 0f;
			RandomizeChoice = false;
			DefaultBlend = new CinemachineBlendDefinition(CinemachineBlendDefinition.Styles.EaseInOut, 0.5f);
			CustomBlends = null;
		}

		protected internal override void PerformLegacyUpgrade(int streamedVersion)
		{
			base.PerformLegacyUpgrade(streamedVersion);
			if (streamedVersion < 20220721 && (m_LegacyLookAt != null || m_LegacyFollow != null))
			{
				DefaultTarget = new DefaultTargetSettings
				{
					Enabled = true,
					Target = new CameraTarget
					{
						LookAtTarget = m_LegacyLookAt,
						TrackingTarget = m_LegacyFollow,
						CustomLookAtTarget = (m_LegacyLookAt != m_LegacyFollow)
					}
				};
				m_LegacyLookAt = (m_LegacyFollow = null);
			}
		}

		public override void OnTransitionFromCamera(ICinemachineCamera fromCam, Vector3 worldUp, float deltaTime)
		{
			if (RandomizeChoice && !base.IsBlending)
			{
				m_RandomizedChildren = null;
			}
			base.OnTransitionFromCamera(fromCam, worldUp, deltaTime);
		}

		public void ResetRandomization()
		{
			m_RandomizedChildren = null;
			m_RandomizeNow = true;
		}

		protected override CinemachineVirtualCameraBase ChooseCurrentCamera(Vector3 worldUp, float deltaTime)
		{
			if (!PreviousStateIsValid)
			{
				m_ActivationTime = 0f;
				m_PendingActivationTime = 0f;
				m_PendingCamera = null;
				m_RandomizedChildren = null;
			}
			CinemachineVirtualCameraBase cinemachineVirtualCameraBase = base.LiveChild as CinemachineVirtualCameraBase;
			if (base.ChildCameras == null || base.ChildCameras.Count == 0)
			{
				m_ActivationTime = 0f;
				return null;
			}
			List<CinemachineVirtualCameraBase> list = base.ChildCameras;
			if (!RandomizeChoice)
			{
				m_RandomizedChildren = null;
			}
			else if (list.Count > 1)
			{
				if (m_RandomizedChildren == null)
				{
					m_RandomizedChildren = Randomize(list);
				}
				list = m_RandomizedChildren;
			}
			if (cinemachineVirtualCameraBase != null && (!cinemachineVirtualCameraBase.IsValid || !cinemachineVirtualCameraBase.gameObject.activeSelf))
			{
				cinemachineVirtualCameraBase = null;
			}
			CinemachineVirtualCameraBase cinemachineVirtualCameraBase2 = cinemachineVirtualCameraBase;
			for (int i = 0; i < list.Count; i++)
			{
				CinemachineVirtualCameraBase cinemachineVirtualCameraBase3 = list[i];
				if (cinemachineVirtualCameraBase3 != null && cinemachineVirtualCameraBase3.gameObject.activeInHierarchy && (cinemachineVirtualCameraBase2 == null || cinemachineVirtualCameraBase3.State.ShotQuality > cinemachineVirtualCameraBase2.State.ShotQuality || (cinemachineVirtualCameraBase3.State.ShotQuality == cinemachineVirtualCameraBase2.State.ShotQuality && cinemachineVirtualCameraBase3.Priority.Value > cinemachineVirtualCameraBase2.Priority.Value) || (RandomizeChoice && m_RandomizeNow && cinemachineVirtualCameraBase3 != cinemachineVirtualCameraBase && cinemachineVirtualCameraBase3.State.ShotQuality == cinemachineVirtualCameraBase2.State.ShotQuality && cinemachineVirtualCameraBase3.Priority.Value == cinemachineVirtualCameraBase2.Priority.Value)))
				{
					cinemachineVirtualCameraBase2 = cinemachineVirtualCameraBase3;
				}
			}
			m_RandomizeNow = false;
			float currentTime = CinemachineCore.CurrentTime;
			if (m_ActivationTime != 0f)
			{
				if (cinemachineVirtualCameraBase == cinemachineVirtualCameraBase2)
				{
					m_PendingActivationTime = 0f;
					m_PendingCamera = null;
					return cinemachineVirtualCameraBase2;
				}
				if (PreviousStateIsValid && m_PendingActivationTime != 0f && m_PendingCamera == cinemachineVirtualCameraBase2)
				{
					if (currentTime - m_PendingActivationTime > ActivateAfter && currentTime - m_ActivationTime > MinDuration)
					{
						m_RandomizedChildren = null;
						m_ActivationTime = currentTime;
						m_PendingActivationTime = 0f;
						m_PendingCamera = null;
						return cinemachineVirtualCameraBase2;
					}
					return cinemachineVirtualCameraBase;
				}
			}
			m_PendingActivationTime = 0f;
			m_PendingCamera = null;
			if (PreviousStateIsValid && m_ActivationTime > 0f && (ActivateAfter > 0f || currentTime - m_ActivationTime < MinDuration))
			{
				m_PendingCamera = cinemachineVirtualCameraBase2;
				m_PendingActivationTime = currentTime;
				return cinemachineVirtualCameraBase;
			}
			m_RandomizedChildren = null;
			m_ActivationTime = currentTime;
			return cinemachineVirtualCameraBase2;
		}

		private static List<CinemachineVirtualCameraBase> Randomize(List<CinemachineVirtualCameraBase> src)
		{
			List<Pair> list = new List<Pair>();
			for (int i = 0; i < src.Count; i++)
			{
				Pair item = new Pair
				{
					a = i,
					b = UnityEngine.Random.Range(0f, 1000f)
				};
				list.Add(item);
			}
			list.Sort((Pair p1, Pair p2) => (int)p1.b - (int)p2.b);
			List<CinemachineVirtualCameraBase> list2 = new List<CinemachineVirtualCameraBase>(src.Count);
			for (int num = 0; num < src.Count; num++)
			{
				list2.Add(src[list[num].a]);
			}
			return list2;
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Confiner 2D")]
	[SaveDuringPlay]
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineConfiner2D.html")]
	public class CinemachineConfiner2D : CinemachineExtension
	{
		[Serializable]
		public struct OversizeWindowSettings
		{
			[Tooltip("Enable optimizing of computation and memory costs in the event that the window size is expected to be larger than will fit inside the confining shape.\nEnable only if needed, because it's costly")]
			public bool Enabled;

			[Tooltip("To optimize computation and memory costs, set this to the largest view size that the camera is expected to have.  The confiner will not compute a polygon cache for frustum sizes larger than this.  This refers to the size in world units of the frustum at the confiner plane (for orthographic cameras, this is just the orthographic size).  If set to 0, then this parameter is ignored and a polygon cache will be calculated for all potential window sizes.")]
			public float MaxWindowSize;

			[Tooltip("For large window sizes, the confiner will potentially generate polygons with zero area.  The padding may be used to add a small amount of area to these polygons, to prevent them from being a series of disconnected dots.")]
			[Range(0f, 100f)]
			public float Padding;
		}

		private class VcamExtraState : VcamExtraStateBase
		{
			public ConfinerOven.BakedSolution BakedSolution;

			public Vector3 PreviousDisplacement;

			public Vector3 DampedDisplacement;

			public Vector3 PreviousCameraPosition;

			public float FrustumHeight;
		}

		private struct ShapeCache
		{
			public ConfinerOven ConfinerOven;

			public List<List<Vector2>> OriginalPath;

			public Matrix4x4 DeltaWorldToBaked;

			public Matrix4x4 DeltaBakedToWorld;

			public float AspectRatio;

			private OversizeWindowSettings m_OversizeWindowSettings;

			internal float MaxComputationTimePerFrameInSeconds;

			private Matrix4x4 m_BakedToWorld;

			private Collider2D m_BoundingShape2D;

			public void Invalidate()
			{
				m_OversizeWindowSettings = default(OversizeWindowSettings);
				DeltaBakedToWorld = (DeltaWorldToBaked = Matrix4x4.identity);
				m_BoundingShape2D = null;
				OriginalPath = null;
				ConfinerOven = null;
			}

			public bool ValidateCache(Collider2D boundingShape2D, OversizeWindowSettings oversize, float aspectRatio, out bool confinerStateChanged)
			{
				confinerStateChanged = false;
				if (IsValid(in boundingShape2D, in oversize, aspectRatio))
				{
					if (ConfinerOven.State == ConfinerOven.BakingState.BAKING)
					{
						ConfinerOven.BakeConfiner(MaxComputationTimePerFrameInSeconds);
						confinerStateChanged = ConfinerOven.State != ConfinerOven.BakingState.BAKING;
					}
					CalculateDeltaTransformationMatrix();
					if (((Vector2)DeltaWorldToBaked.lossyScale).IsUniform())
					{
						return true;
					}
				}
				Invalidate();
				if (boundingShape2D == null)
				{
					return false;
				}
				confinerStateChanged = true;
				if (!(boundingShape2D is PolygonCollider2D polygonCollider2D))
				{
					if (!(boundingShape2D is BoxCollider2D boxCollider2D))
					{
						if (!(boundingShape2D is CompositeCollider2D compositeCollider2D))
						{
							return false;
						}
						OriginalPath = new List<List<Vector2>>();
						m_BakedToWorld = boundingShape2D.transform.localToWorldMatrix;
						Vector2[] array = new Vector2[compositeCollider2D.pointCount];
						for (int i = 0; i < compositeCollider2D.pathCount; i++)
						{
							int path = compositeCollider2D.GetPath(i, array);
							List<Vector2> list = new List<Vector2>();
							for (int j = 0; j < path; j++)
							{
								list.Add(m_BakedToWorld.MultiplyPoint3x4(array[j]));
							}
							OriginalPath.Add(list);
						}
					}
					else
					{
						m_BakedToWorld = boundingShape2D.transform.localToWorldMatrix;
						Vector2 size = boxCollider2D.size;
						float num = size.y / 2f;
						float num2 = size.x / 2f;
						Vector3 vector = m_BakedToWorld.MultiplyPoint3x4(new Vector3(0f - num2, num));
						Vector3 vector2 = m_BakedToWorld.MultiplyPoint3x4(new Vector3(num2, num));
						Vector3 vector3 = m_BakedToWorld.MultiplyPoint3x4(new Vector3(num2, 0f - num));
						Vector3 vector4 = m_BakedToWorld.MultiplyPoint3x4(new Vector3(0f - num2, 0f - num));
						OriginalPath = new List<List<Vector2>>
						{
							new List<Vector2> { vector, vector2, vector3, vector4 }
						};
					}
				}
				else
				{
					OriginalPath = new List<List<Vector2>>();
					m_BakedToWorld = boundingShape2D.transform.localToWorldMatrix;
					for (int k = 0; k < polygonCollider2D.pathCount; k++)
					{
						Vector2[] path2 = polygonCollider2D.GetPath(k);
						List<Vector2> list2 = new List<Vector2>();
						for (int l = 0; l < path2.Length; l++)
						{
							list2.Add(m_BakedToWorld.MultiplyPoint3x4(path2[l]));
						}
						OriginalPath.Add(list2);
					}
				}
				if (!HasAnyPoints(OriginalPath))
				{
					return false;
				}
				ConfinerOven = new ConfinerOven(in OriginalPath, in aspectRatio, oversize.Enabled ? oversize.MaxWindowSize : (-1f), oversize.Padding);
				m_BoundingShape2D = boundingShape2D;
				m_OversizeWindowSettings = oversize;
				AspectRatio = aspectRatio;
				CalculateDeltaTransformationMatrix();
				return true;
				static bool HasAnyPoints(List<List<Vector2>> originalPath)
				{
					for (int m = 0; m < originalPath.Count; m++)
					{
						if (originalPath[m].Count != 0)
						{
							return true;
						}
					}
					return false;
				}
			}

			private bool IsValid(in Collider2D boundingShape2D, in OversizeWindowSettings oversize, float aspectRatio)
			{
				if (boundingShape2D != null && m_BoundingShape2D != null && m_BoundingShape2D == boundingShape2D && OriginalPath != null && ConfinerOven != null && Math.Abs(AspectRatio - aspectRatio) < 0.0001f && m_OversizeWindowSettings.Enabled == oversize.Enabled && m_OversizeWindowSettings.Padding == oversize.Padding)
				{
					return Mathf.Abs(m_OversizeWindowSettings.MaxWindowSize - oversize.MaxWindowSize) < 0.0001f;
				}
				return false;
			}

			private void CalculateDeltaTransformationMatrix()
			{
				Matrix4x4 matrix4x = Matrix4x4.Translate(-m_BoundingShape2D.offset) * m_BoundingShape2D.transform.worldToLocalMatrix;
				DeltaWorldToBaked = m_BakedToWorld * matrix4x;
				DeltaBakedToWorld = DeltaWorldToBaked.inverse;
			}
		}

		[Tooltip("The 2D shape within which the camera is to be contained.  Can be polygon-, box-, or composite collider 2D.\n\nRemark: When assigning a GameObject here in the editor, this will be set to the first Collider2D found on the assigned GameObject!")]
		[FormerlySerializedAs("m_BoundingShape2D")]
		public Collider2D BoundingShape2D;

		[Tooltip("Damping applied around corners to avoid jumps.  Higher numbers are more gradual.")]
		[Range(0f, 5f)]
		[FormerlySerializedAs("m_Damping")]
		public float Damping;

		[Tooltip("Size of the slow-down zone at the edge of the bounding shape.")]
		public float SlowingDistance;

		[FoldoutWithEnabledButton("Enabled")]
		public OversizeWindowSettings OversizeWindow;

		private List<VcamExtraState> m_ExtraStateCache;

		private ShapeCache m_ShapeCache;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_MaxWindowSize")]
		private float m_LegacyMaxWindowSize = -2f;

		private const float k_CornerAngleThreshold = 10f;

		public bool BoundingShapeIsBaked
		{
			get
			{
				ConfinerOven confinerOven = m_ShapeCache.ConfinerOven;
				if (confinerOven == null)
				{
					return false;
				}
				return confinerOven.State == ConfinerOven.BakingState.BAKED;
			}
		}

		private void OnValidate()
		{
			Damping = Mathf.Max(0f, Damping);
			SlowingDistance = Mathf.Max(0f, SlowingDistance);
			m_ShapeCache.MaxComputationTimePerFrameInSeconds = 1f / 120f;
			OversizeWindow.MaxWindowSize = Mathf.Max(0f, OversizeWindow.MaxWindowSize);
			if (m_LegacyMaxWindowSize != -2f)
			{
				OversizeWindow = new OversizeWindowSettings
				{
					Enabled = (m_LegacyMaxWindowSize >= 0f),
					MaxWindowSize = Mathf.Max(0f, m_LegacyMaxWindowSize)
				};
				m_LegacyMaxWindowSize = -2f;
			}
		}

		private void Reset()
		{
			Damping = 0.5f;
			SlowingDistance = 5f;
			OversizeWindow = default(OversizeWindowSettings);
		}

		public override float GetMaxDampTime()
		{
			return Mathf.Max(Damping, SlowingDistance * 0.2f);
		}

		public override void OnTargetObjectWarped(CinemachineVirtualCameraBase vcam, Transform target, Vector3 positionDelta)
		{
			VcamExtraState extraState = GetExtraState<VcamExtraState>(vcam);
			if (extraState.Vcam.Follow == target)
			{
				extraState.PreviousCameraPosition += positionDelta;
			}
		}

		public void InvalidateLensCache()
		{
			if (m_ExtraStateCache == null)
			{
				m_ExtraStateCache = new List<VcamExtraState>();
			}
			GetAllExtraStates(m_ExtraStateCache);
			for (int i = 0; i < m_ExtraStateCache.Count; i++)
			{
				VcamExtraState vcamExtraState = m_ExtraStateCache[i];
				if (vcamExtraState.Vcam != null)
				{
					vcamExtraState.BakedSolution = null;
					vcamExtraState.FrustumHeight = 0f;
				}
			}
		}

		public void InvalidateBoundingShapeCache()
		{
			m_ShapeCache.Invalidate();
			InvalidateLensCache();
		}

		[Obsolete("Call InvalidateBoundingShapeCache() instead.", false)]
		public void InvalidateCache()
		{
			InvalidateBoundingShapeCache();
		}

		public bool BakeBoundingShape(CinemachineVirtualCameraBase vcam, float maxTimeInSeconds)
		{
			if (!m_ShapeCache.ValidateCache(BoundingShape2D, OversizeWindow, vcam.State.Lens.Aspect, out var _))
			{
				return false;
			}
			if (m_ShapeCache.ConfinerOven == null)
			{
				return false;
			}
			if (m_ShapeCache.ConfinerOven.State == ConfinerOven.BakingState.BAKING)
			{
				m_ShapeCache.ConfinerOven.BakeConfiner(maxTimeInSeconds);
			}
			return m_ShapeCache.ConfinerOven.State == ConfinerOven.BakingState.BAKED;
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage != CinemachineCore.Stage.Body)
			{
				return;
			}
			float aspect = state.Lens.Aspect;
			if (!m_ShapeCache.ValidateCache(BoundingShape2D, OversizeWindow, aspect, out var confinerStateChanged))
			{
				return;
			}
			VcamExtraState extraState = GetExtraState<VcamExtraState>(vcam);
			Vector3 correctedPosition = state.GetCorrectedPosition();
			if (confinerStateChanged || extraState.BakedSolution == null || !extraState.BakedSolution.IsValid())
			{
				Matrix4x4 deltaWorldToBaked = m_ShapeCache.DeltaWorldToBaked;
				m_ShapeCache.AspectRatio = aspect;
				ref LensSettings lens = ref state.Lens;
				Vector3 vector = deltaWorldToBaked.MultiplyPoint3x4(correctedPosition);
				extraState.FrustumHeight = CalculateHalfFrustumHeight(in lens, in vector.z) * deltaWorldToBaked.lossyScale.x;
				extraState.BakedSolution = m_ShapeCache.ConfinerOven.GetBakedSolution(extraState.FrustumHeight);
			}
			Vector3 fwd = state.GetCorrectedOrientation() * Vector3.forward;
			Vector3 vector2 = ConfinePoint(correctedPosition, extraState, fwd);
			if (SlowingDistance > 0.0001f && deltaTime >= 0f && vcam.PreviousStateIsValid)
			{
				Vector3 previousCameraPosition = extraState.PreviousCameraPosition;
				Vector3 vector3 = vector2 - previousCameraPosition;
				float magnitude = vector3.magnitude;
				if (magnitude > 0.0001f)
				{
					float num = GetDistanceFromEdge(previousCameraPosition, vector3 / magnitude, SlowingDistance, extraState, fwd) / SlowingDistance;
					vector2 = Vector3.Lerp(previousCameraPosition, vector2, num * num * num + 0.05f);
				}
			}
			Vector3 previousDisplacement = extraState.PreviousDisplacement;
			Vector3 vector4 = (extraState.PreviousDisplacement = vector2 - correctedPosition);
			if (!vcam.PreviousStateIsValid || deltaTime < 0f || Damping <= 0f)
			{
				extraState.DampedDisplacement = Vector3.zero;
			}
			else
			{
				if (previousDisplacement.sqrMagnitude > 0.01f && Vector2.Angle(previousDisplacement, vector4) > 10f)
				{
					extraState.DampedDisplacement += vector4 - previousDisplacement;
				}
				extraState.DampedDisplacement -= Damper.Damp(extraState.DampedDisplacement, Damping, deltaTime);
				vector4 -= extraState.DampedDisplacement;
			}
			state.PositionCorrection += vector4;
			extraState.PreviousCameraPosition = state.GetCorrectedPosition();
		}

		private Vector3 ConfinePoint(Vector3 pos, VcamExtraState extra, Vector3 fwd)
		{
			Vector3 vector = m_ShapeCache.DeltaWorldToBaked.MultiplyPoint3x4(pos);
			Vector3 vector2 = m_ShapeCache.DeltaBakedToWorld.MultiplyPoint3x4(extra.BakedSolution.ConfinePoint((Vector2)vector));
			return vector2 - fwd * Vector3.Dot(fwd, vector2 - pos);
		}

		private float GetDistanceFromEdge(Vector3 p, Vector3 dirUnit, float max, VcamExtraState extra, Vector3 fwd)
		{
			p += dirUnit * max;
			return Mathf.Max(0f, max - (ConfinePoint(p, extra, fwd) - p).magnitude);
		}

		public static float CalculateHalfFrustumHeight(in LensSettings lens, in float cameraPosLocalZ)
		{
			float f = ((!lens.Orthographic) ? (cameraPosLocalZ * Mathf.Tan(lens.FieldOfView * 0.5f * (MathF.PI / 180f))) : lens.OrthographicSize);
			return Mathf.Abs(f);
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Confiner 3D")]
	[SaveDuringPlay]
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineConfiner3D.html")]
	public class CinemachineConfiner3D : CinemachineExtension
	{
		private class VcamExtraState : VcamExtraStateBase
		{
			public Vector3 PreviousDisplacement;

			public Vector3 PreviousCameraPosition;
		}

		[Tooltip("The volume within which the camera is to be contained")]
		public Collider BoundingVolume;

		[Tooltip("Size of the slow-down zone at the edge of the bounding volume.")]
		public float SlowingDistance;

		public bool IsValid
		{
			get
			{
				if (BoundingVolume != null && BoundingVolume.enabled)
				{
					return BoundingVolume.gameObject.activeInHierarchy;
				}
				return false;
			}
		}

		public bool CameraWasDisplaced(CinemachineVirtualCameraBase vcam)
		{
			return GetCameraDisplacementDistance(vcam) > 0f;
		}

		public float GetCameraDisplacementDistance(CinemachineVirtualCameraBase vcam)
		{
			return GetExtraState<VcamExtraState>(vcam).PreviousDisplacement.magnitude;
		}

		private void Reset()
		{
			BoundingVolume = null;
			SlowingDistance = 0f;
		}

		private void OnValidate()
		{
			SlowingDistance = Mathf.Max(0f, SlowingDistance);
		}

		public override float GetMaxDampTime()
		{
			return SlowingDistance * 0.2f;
		}

		public override void OnTargetObjectWarped(CinemachineVirtualCameraBase vcam, Transform target, Vector3 positionDelta)
		{
			VcamExtraState extraState = GetExtraState<VcamExtraState>(vcam);
			if (extraState.Vcam.Follow == target)
			{
				extraState.PreviousCameraPosition += positionDelta;
			}
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage != CinemachineCore.Stage.Body || !IsValid)
			{
				return;
			}
			VcamExtraState extraState = GetExtraState<VcamExtraState>(vcam);
			Vector3 correctedPosition = state.GetCorrectedPosition();
			Vector3 vector = ConfinePoint(correctedPosition);
			if (SlowingDistance > 0.0001f && deltaTime >= 0f && vcam.PreviousStateIsValid)
			{
				Vector3 previousCameraPosition = extraState.PreviousCameraPosition;
				Vector3 vector2 = vector - previousCameraPosition;
				float magnitude = vector2.magnitude;
				if (magnitude > 0.0001f)
				{
					float num = GetDistanceFromEdge(previousCameraPosition, vector2 / magnitude, SlowingDistance) / SlowingDistance;
					vector = Vector3.Lerp(previousCameraPosition, vector, num * num * num + 0.05f);
				}
			}
			Vector3 vector3 = vector - correctedPosition;
			state.PositionCorrection += vector3;
			extraState.PreviousCameraPosition = state.GetCorrectedPosition();
			extraState.PreviousDisplacement = vector3;
		}

		private Vector3 ConfinePoint(Vector3 p)
		{
			MeshCollider meshCollider = BoundingVolume as MeshCollider;
			if (meshCollider != null && !meshCollider.convex)
			{
				return p;
			}
			return BoundingVolume.ClosestPoint(p);
		}

		private float GetDistanceFromEdge(Vector3 p, Vector3 dirUnit, float max)
		{
			p += dirUnit * max;
			return max - (ConfinePoint(p) - p).magnitude;
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Decollider")]
	[SaveDuringPlay]
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.Tracking)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineDecollider.html")]
	public class CinemachineDecollider : CinemachineExtension
	{
		[Serializable]
		public struct DecollisionSettings
		{
			[Serializable]
			public struct FollowTargetSettings
			{
				[Tooltip("Use the Follow target when resolving occlusions, instead of the LookAt target.")]
				public bool Enabled;

				[Tooltip("Vertical offset from the Follow target's root, in target local space")]
				public float YOffset;
			}

			[Tooltip("When enabled, will attempt to push the camera out of intersecting objects")]
			public bool Enabled;

			[Tooltip("Objects on these layers will be detected")]
			public LayerMask ObstacleLayers;

			[EnabledProperty("Enabled", "")]
			public FollowTargetSettings UseFollowTarget;

			[Range(0f, 10f)]
			[Tooltip("How gradually the camera returns to its normal position after having been corrected.  Higher numbers will move the camera more gradually back to normal.")]
			public float Damping;

			[Range(0f, 2f)]
			[Tooltip("Smoothing to apply to obstruction resolution.  Nearest camera point is held for at least this long")]
			public float SmoothingTime;
		}

		[Serializable]
		public struct TerrainSettings
		{
			[Tooltip("When enabled, will attempt to place the camera on top of terrain layers")]
			public bool Enabled;

			[Tooltip("Colliders on these layers will be detected")]
			public LayerMask TerrainLayers;

			[Tooltip("Specifies the maximum length of a raycast used to find terrain colliders")]
			public float MaximumRaycast;

			[Range(0f, 10f)]
			[Tooltip("How gradually the camera returns to its normal position after having been corrected.  Higher numbers will move the camera more gradually back to normal.")]
			public float Damping;
		}

		private class VcamExtraState : VcamExtraStateBase
		{
			public float PreviousTerrainDisplacement;

			public float PreviousDistanceFromTarget;

			public Vector3 PreviouDecollisionDisplacement;

			public Vector3 PreviousCorrectedCameraPosition;

			private float m_SmoothedDistance;

			private float m_SmoothingStartTime;

			public float UpdateDistanceSmoothing(float distance, float smoothingTime, bool haveDisplacement)
			{
				if (haveDisplacement && (m_SmoothedDistance == 0f || distance <= m_SmoothedDistance))
				{
					m_SmoothedDistance = distance;
					m_SmoothingStartTime = CinemachineCore.CurrentTime;
				}
				if (m_SmoothingStartTime != 0f && CinemachineCore.CurrentTime - m_SmoothingStartTime < smoothingTime)
				{
					distance = Mathf.Min(distance, m_SmoothedDistance);
				}
				if (!haveDisplacement && CinemachineCore.CurrentTime - m_SmoothingStartTime >= smoothingTime)
				{
					m_SmoothedDistance = (m_SmoothingStartTime = 0f);
				}
				return distance;
			}
		}

		[Tooltip("Camera will try to maintain this distance from any obstacle or terrain.  Increase it if necessary to keep the camera from clipping the near edge of obsacles.")]
		public float CameraRadius = 0.4f;

		[FoldoutWithEnabledButton("Enabled")]
		public DecollisionSettings Decollision;

		[FoldoutWithEnabledButton("Enabled")]
		public TerrainSettings TerrainResolution;

		private const int kColliderBufferSize = 10;

		private static Collider[] s_ColliderBuffer = new Collider[10];

		private static float[] s_ColliderDistanceBuffer = new float[10];

		private static int[] s_ColliderOrderBuffer = new int[10];

		private static readonly IComparer<int> s_ColliderBufferSorter = Comparer<int>.Create(delegate(int a, int b)
		{
			if (s_ColliderDistanceBuffer[a] == s_ColliderDistanceBuffer[b])
			{
				return 0;
			}
			return (!(s_ColliderDistanceBuffer[a] > s_ColliderDistanceBuffer[b])) ? 1 : (-1);
		});

		private void OnValidate()
		{
			CameraRadius = Mathf.Max(0.01f, CameraRadius);
		}

		private void Reset()
		{
			CameraRadius = 0.4f;
			TerrainResolution = new TerrainSettings
			{
				Enabled = true,
				TerrainLayers = 1,
				MaximumRaycast = 10f,
				Damping = 0.5f
			};
			Decollision = new DecollisionSettings
			{
				Enabled = false,
				ObstacleLayers = 1,
				Damping = 0.5f
			};
		}

		protected override void OnDestroy()
		{
			RuntimeUtility.DestroyScratchCollider();
			base.OnDestroy();
		}

		public override float GetMaxDampTime()
		{
			return Mathf.Max(Decollision.Enabled ? Decollision.Damping : 0f, TerrainResolution.Enabled ? TerrainResolution.Damping : 0f);
		}

		public override void ForceCameraPosition(CinemachineVirtualCameraBase vcam, Vector3 pos, Quaternion rot)
		{
			GetExtraState<VcamExtraState>(vcam).PreviousCorrectedCameraPosition = pos;
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage != CinemachineCore.Stage.Body)
			{
				return;
			}
			VcamExtraState extraState = GetExtraState<VcamExtraState>(vcam);
			Vector3 referenceUp = state.ReferenceUp;
			Vector3 correctedPosition = state.GetCorrectedPosition();
			bool num = state.HasLookAt();
			Vector3 vector = (num ? state.ReferenceLookAt : state.GetCorrectedPosition());
			Vector3 avoidanceResolutionTargetPoint = GetAvoidanceResolutionTargetPoint(vcam, ref state);
			Vector2 vector2 = (num ? state.RawOrientation.GetCameraRotationToTarget(vector - correctedPosition, state.ReferenceUp) : Vector2.zero);
			if (!vcam.PreviousStateIsValid)
			{
				deltaTime = -1f;
			}
			extraState.PreviousTerrainDisplacement = (TerrainResolution.Enabled ? ResolveTerrain(extraState, state.GetCorrectedPosition(), referenceUp, deltaTime) : 0f);
			state.PositionCorrection += extraState.PreviousTerrainDisplacement * referenceUp;
			if (Decollision.Enabled)
			{
				Vector3 correctedPosition2 = state.GetCorrectedPosition();
				Vector3 displacement = DecollideCamera(correctedPosition2, avoidanceResolutionTargetPoint);
				displacement = ApplySmoothingAndDamping(displacement, avoidanceResolutionTargetPoint, correctedPosition2, extraState, deltaTime);
				if (!displacement.AlmostZero())
				{
					state.PositionCorrection += displacement;
					float num2 = (TerrainResolution.Enabled ? ResolveTerrain(extraState, state.GetCorrectedPosition(), referenceUp, -1f) : 0f);
					if (Mathf.Abs(num2) > 0.0001f)
					{
						state.PositionCorrection += num2 * referenceUp;
						extraState.PreviousTerrainDisplacement = 0f;
					}
				}
			}
			Vector3 correctedPosition3 = state.GetCorrectedPosition();
			if (num && !(correctedPosition - correctedPosition3).AlmostZero())
			{
				Quaternion orient = Quaternion.LookRotation(vector - correctedPosition3, referenceUp);
				state.RawOrientation = orient.ApplyCameraRotation(-vector2, referenceUp);
				if (deltaTime >= 0f)
				{
					Vector3 v = extraState.PreviousCorrectedCameraPosition - vector;
					Vector3 v2 = correctedPosition3 - vector;
					if (v.sqrMagnitude > 0.0001f && v2.sqrMagnitude > 0.0001f)
					{
						state.RotationDampingBypass = UnityVectorExtensions.SafeFromToRotation(v, v2, referenceUp);
					}
				}
			}
			extraState.PreviousCorrectedCameraPosition = correctedPosition3;
		}

		private Vector3 GetAvoidanceResolutionTargetPoint(CinemachineVirtualCameraBase vcam, ref CameraState state)
		{
			Vector3 result = (state.HasLookAt() ? state.ReferenceLookAt : state.GetCorrectedPosition());
			if (Decollision.UseFollowTarget.Enabled)
			{
				Transform follow = vcam.Follow;
				if (follow != null)
				{
					result = TargetPositionCache.GetTargetPosition(follow) + TargetPositionCache.GetTargetRotation(follow) * Vector3.up * Decollision.UseFollowTarget.YOffset;
				}
			}
			return result;
		}

		private float ResolveTerrain(VcamExtraState extra, Vector3 camPos, Vector3 up, float deltaTime)
		{
			float num = 0f;
			if (RuntimeUtility.SphereCastIgnoreTag(new Ray(camPos + TerrainResolution.MaximumRaycast * up, -up), CameraRadius + 0.0001f, out var hitInfo, TerrainResolution.MaximumRaycast, TerrainResolution.TerrainLayers, in string.Empty))
			{
				num = TerrainResolution.MaximumRaycast - hitInfo.distance + 0.0001f;
			}
			if (deltaTime >= 0f && TerrainResolution.Damping > 0.0001f && num < extra.PreviousTerrainDisplacement)
			{
				num = extra.PreviousTerrainDisplacement + Damper.Damp(num - extra.PreviousTerrainDisplacement, TerrainResolution.Damping, deltaTime);
			}
			return num;
		}

		private Vector3 DecollideCamera(Vector3 cameraPos, Vector3 lookAtPoint)
		{
			LayerMask layerMask = Decollision.ObstacleLayers;
			if (TerrainResolution.Enabled)
			{
				layerMask = (int)layerMask & ~(int)TerrainResolution.TerrainLayers;
			}
			if ((int)layerMask == 0)
			{
				return Vector3.zero;
			}
			Vector3 vector = cameraPos - lookAtPoint;
			float magnitude = vector.magnitude;
			if (magnitude < 0.0001f)
			{
				return Vector3.zero;
			}
			int num = Physics.OverlapCapsuleNonAlloc(lookAtPoint, cameraPos, CameraRadius - 0.0001f, s_ColliderBuffer, layerMask, QueryTriggerInteraction.Ignore);
			if (num == 0)
			{
				return Vector3.zero;
			}
			vector /= magnitude;
			for (int i = 0; i < num; i++)
			{
				Collider obj = s_ColliderBuffer[i];
				s_ColliderOrderBuffer[i] = i;
				s_ColliderDistanceBuffer[i] = 0f;
				if (obj.Raycast(new Ray(lookAtPoint, vector), out var hitInfo, magnitude + CameraRadius))
				{
					float num2 = hitInfo.distance - CameraRadius;
					if (num2 < CameraRadius)
					{
						num2 = Mathf.Max(0.01f, num2 + (CameraRadius - num2) * 0.5f);
					}
					s_ColliderDistanceBuffer[i] = num2;
				}
			}
			Array.Sort(s_ColliderOrderBuffer, 0, num, s_ColliderBufferSorter);
			Vector3 vector2 = cameraPos;
			SphereCollider scratchCollider = RuntimeUtility.GetScratchCollider();
			scratchCollider.radius = CameraRadius - 0.0001f;
			for (int j = 0; j < num; j++)
			{
				int num3 = s_ColliderOrderBuffer[j];
				if (s_ColliderDistanceBuffer[num3] != 0f)
				{
					Collider collider = s_ColliderBuffer[num3];
					if (Physics.ComputePenetration(scratchCollider, vector2, Quaternion.identity, collider, collider.transform.position, collider.transform.rotation, out var _, out var _))
					{
						vector2 = lookAtPoint + vector * s_ColliderDistanceBuffer[num3];
					}
				}
			}
			return vector2 - cameraPos;
		}

		private Vector3 ApplySmoothingAndDamping(Vector3 displacement, Vector3 lookAtPoint, Vector3 oldCamPos, VcamExtraState extra, float deltaTime)
		{
			Vector3 vector = oldCamPos + displacement - lookAtPoint;
			float num = float.MaxValue;
			if (deltaTime >= 0f)
			{
				num = vector.magnitude;
				if (num > CameraRadius)
				{
					Vector3 vector2 = vector / num;
					if (Decollision.SmoothingTime > 0.0001f)
					{
						num = extra.UpdateDistanceSmoothing(num, Decollision.SmoothingTime, !displacement.AlmostZero());
						displacement = lookAtPoint + vector2 * num - oldCamPos;
					}
					if (Decollision.Damping > 0.0001f && num > extra.PreviousDistanceFromTarget)
					{
						float num2 = extra.PreviousDistanceFromTarget;
						float num3 = (oldCamPos - lookAtPoint).magnitude - extra.PreviouDecollisionDisplacement.magnitude;
						if (Mathf.Abs(num - num3) < Mathf.Abs(num - num2))
						{
							num2 = num3;
						}
						num = num2 + Damper.Damp(num - num2, Decollision.Damping, deltaTime);
						displacement = lookAtPoint + vector2 * num - oldCamPos;
					}
				}
			}
			extra.PreviousDistanceFromTarget = num;
			extra.PreviouDecollisionDisplacement = displacement;
			return displacement;
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Deoccluder")]
	[SaveDuringPlay]
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.Tracking)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineDeoccluder.html")]
	public class CinemachineDeoccluder : CinemachineExtension, IShotQualityEvaluator
	{
		[Serializable]
		public struct ObstacleAvoidance
		{
			[Serializable]
			public struct FollowTargetSettings
			{
				[Tooltip("Use the Follow target when resolving occlusions, instead of the LookAt target.")]
				public bool Enabled;

				[Tooltip("Vertical offset from the Follow target's root, in target local space")]
				public float YOffset;
			}

			public enum ResolutionStrategy
			{
				PullCameraForward,
				PreserveCameraHeight,
				PreserveCameraDistance
			}

			[Tooltip("When enabled, will attempt to resolve situations where the line of sight to the target is blocked by an obstacle")]
			public bool Enabled;

			[Tooltip("The maximum raycast distance when checking if the line of sight to this camera's target is clear.  If the setting is 0 or less, the current actual distance to target will be used.")]
			public float DistanceLimit;

			[Tooltip("Don't take action unless occlusion has lasted at least this long.")]
			public float MinimumOcclusionTime;

			[Tooltip("Camera will try to maintain this distance from any obstacle.  Try to keep this value small.  Increase it if you are seeing inside obstacles due to a large FOV on the camera.")]
			public float CameraRadius;

			[EnabledProperty("Enabled", "")]
			public FollowTargetSettings UseFollowTarget;

			[Tooltip("The way in which the Deoccluder will attempt to preserve sight of the target.")]
			public ResolutionStrategy Strategy;

			[Range(1f, 10f)]
			[Tooltip("Upper limit on how many obstacle hits to process.  Higher numbers may impact performance.  In most environments, 4 is enough.")]
			public int MaximumEffort;

			[Range(0f, 2f)]
			[Tooltip("Smoothing to apply to obstruction resolution.  Nearest camera point is held for at least this long")]
			public float SmoothingTime;

			[Range(0f, 10f)]
			[Tooltip("How gradually the camera returns to its normal position after having been corrected.  Higher numbers will move the camera more gradually back to normal.")]
			public float Damping;

			[Range(0f, 10f)]
			[Tooltip("How gradually the camera moves to resolve an occlusion.  Higher numbers will move the camera more gradually.")]
			public float DampingWhenOccluded;

			internal static ObstacleAvoidance Default => new ObstacleAvoidance
			{
				Enabled = true,
				DistanceLimit = 0f,
				MinimumOcclusionTime = 0f,
				CameraRadius = 0.4f,
				Strategy = ResolutionStrategy.PullCameraForward,
				MaximumEffort = 4,
				SmoothingTime = 0f,
				Damping = 0.4f,
				DampingWhenOccluded = 0.2f
			};
		}

		[Serializable]
		public struct QualityEvaluation
		{
			[Tooltip("If enabled, will evaluate shot quality based on target distance and occlusion")]
			public bool Enabled;

			[Tooltip("If greater than zero, maximum quality boost will occur when target is this far from the camera")]
			public float OptimalDistance;

			[Tooltip("Shots with targets closer to the camera than this will not get a quality boost")]
			public float NearLimit;

			[Tooltip("Shots with targets farther from the camera than this will not get a quality boost")]
			public float FarLimit;

			[Tooltip("High quality shots will be boosted by this fraction of their normal quality")]
			public float MaxQualityBoost;

			internal static QualityEvaluation Default => new QualityEvaluation
			{
				NearLimit = 5f,
				FarLimit = 30f,
				OptimalDistance = 10f,
				MaxQualityBoost = 0.2f
			};
		}

		private class VcamExtraState : VcamExtraStateBase
		{
			public Vector3 PreviousDisplacement;

			public bool TargetObscured;

			public float OcclusionStartTime;

			public List<Vector3> DebugResolutionPath;

			public List<Collider> OccludingObjects;

			public Vector3 PreviousCameraOffset;

			public Vector3 PreviousCameraPosition;

			public float PreviousDampTime;

			public bool StateIsValid;

			private float m_SmoothedDistance;

			private float m_SmoothedTime;

			public void AddPointToDebugPath(Vector3 p, Collider c)
			{
			}

			public float ApplyDistanceSmoothing(float distance, float smoothingTime)
			{
				if (m_SmoothedTime != 0f && smoothingTime > 0.0001f && CinemachineCore.CurrentTime - m_SmoothedTime < smoothingTime)
				{
					return Mathf.Min(distance, m_SmoothedDistance);
				}
				return distance;
			}

			public void UpdateDistanceSmoothing(float distance)
			{
				if (!StateIsValid || m_SmoothedDistance == 0f || distance < m_SmoothedDistance)
				{
					m_SmoothedDistance = distance;
					m_SmoothedTime = CinemachineCore.CurrentTime;
				}
			}

			public void ResetDistanceSmoothing(float smoothingTime)
			{
				if (CinemachineCore.CurrentTime - m_SmoothedTime >= smoothingTime)
				{
					m_SmoothedDistance = (m_SmoothedTime = 0f);
				}
			}
		}

		[Tooltip("Objects on these layers will be detected")]
		public LayerMask CollideAgainst = 1;

		[TagField]
		[Tooltip("Obstacles with this tag will be ignored.  It is a good idea to set this field to the target's tag")]
		public string IgnoreTag = string.Empty;

		[Tooltip("Objects on these layers will never obstruct view of the target")]
		public LayerMask TransparentLayers = 0;

		[Tooltip("Obstacles closer to the target than this will be ignored")]
		public float MinimumDistanceFromTarget = 0.3f;

		[FoldoutWithEnabledButton("Enabled")]
		public ObstacleAvoidance AvoidObstacles;

		[FoldoutWithEnabledButton("Enabled")]
		public QualityEvaluation ShotQualityEvaluation = QualityEvaluation.Default;

		private List<VcamExtraState> m_extraStateCache;

		private const float k_PrecisionSlush = 0.001f;

		private RaycastHit[] m_CornerBuffer = new RaycastHit[4];

		private const float k_AngleThreshold = 0.1f;

		private static Collider[] s_ColliderBuffer = new Collider[5];

		public bool IsTargetObscured(CinemachineVirtualCameraBase vcam)
		{
			return GetExtraState<VcamExtraState>(vcam).TargetObscured;
		}

		public bool CameraWasDisplaced(CinemachineVirtualCameraBase vcam)
		{
			return GetCameraDisplacementDistance(vcam) > 0f;
		}

		public float GetCameraDisplacementDistance(CinemachineVirtualCameraBase vcam)
		{
			return GetExtraState<VcamExtraState>(vcam).PreviousDisplacement.magnitude;
		}

		private void OnValidate()
		{
			AvoidObstacles.DistanceLimit = Mathf.Max(0f, AvoidObstacles.DistanceLimit);
			AvoidObstacles.MinimumOcclusionTime = Mathf.Max(0f, AvoidObstacles.MinimumOcclusionTime);
			AvoidObstacles.CameraRadius = Mathf.Max(0f, AvoidObstacles.CameraRadius);
			MinimumDistanceFromTarget = Mathf.Max(0.01f, MinimumDistanceFromTarget);
			ShotQualityEvaluation.NearLimit = Mathf.Max(0.1f, ShotQualityEvaluation.NearLimit);
			ShotQualityEvaluation.FarLimit = Mathf.Max(ShotQualityEvaluation.NearLimit, ShotQualityEvaluation.FarLimit);
			ShotQualityEvaluation.OptimalDistance = Mathf.Clamp(ShotQualityEvaluation.OptimalDistance, ShotQualityEvaluation.NearLimit, ShotQualityEvaluation.FarLimit);
		}

		private void Reset()
		{
			CollideAgainst = 1;
			IgnoreTag = string.Empty;
			TransparentLayers = 0;
			MinimumDistanceFromTarget = 0.3f;
			AvoidObstacles = ObstacleAvoidance.Default;
			ShotQualityEvaluation = QualityEvaluation.Default;
		}

		protected override void OnDestroy()
		{
			RuntimeUtility.DestroyScratchCollider();
			base.OnDestroy();
		}

		protected override void OnEnable()
		{
			base.OnEnable();
			List<VcamExtraState> list = new List<VcamExtraState>();
			GetAllExtraStates(list);
			for (int i = 0; i < list.Count; i++)
			{
				list[i].StateIsValid = false;
			}
		}

		public void DebugCollisionPaths(List<List<Vector3>> paths, List<List<Collider>> obstacles)
		{
			paths?.Clear();
			obstacles?.Clear();
			if (m_extraStateCache == null)
			{
				m_extraStateCache = new List<VcamExtraState>();
			}
			GetAllExtraStates(m_extraStateCache);
			for (int i = 0; i < m_extraStateCache.Count; i++)
			{
				VcamExtraState vcamExtraState = m_extraStateCache[i];
				if (vcamExtraState.DebugResolutionPath != null && vcamExtraState.DebugResolutionPath.Count > 0)
				{
					paths?.Add(vcamExtraState.DebugResolutionPath);
					obstacles?.Add(vcamExtraState.OccludingObjects);
				}
			}
		}

		public override float GetMaxDampTime()
		{
			if (!AvoidObstacles.Enabled)
			{
				return 0f;
			}
			return Mathf.Max(AvoidObstacles.Damping, Mathf.Max(AvoidObstacles.DampingWhenOccluded, AvoidObstacles.SmoothingTime));
		}

		public override void OnTargetObjectWarped(CinemachineVirtualCameraBase vcam, Transform target, Vector3 positionDelta)
		{
			GetExtraState<VcamExtraState>(vcam).PreviousCameraPosition += positionDelta;
		}

		public override void ForceCameraPosition(CinemachineVirtualCameraBase vcam, Vector3 pos, Quaternion rot)
		{
			GetExtraState<VcamExtraState>(vcam).PreviousCameraPosition = pos;
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage == CinemachineCore.Stage.Body)
			{
				VcamExtraState extra = GetExtraState<VcamExtraState>(vcam);
				extra.TargetObscured = false;
				extra.DebugResolutionPath?.Clear();
				extra.OccludingObjects?.Clear();
				if (!vcam.PreviousStateIsValid || deltaTime < 0f)
				{
					extra.StateIsValid = false;
				}
				if (!AvoidObstacles.Enabled)
				{
					extra.StateIsValid = false;
				}
				else
				{
					Vector3 correctedPosition = state.GetCorrectedPosition();
					Vector3 referenceUp = state.ReferenceUp;
					bool num = state.HasLookAt();
					Vector3 vector = (num ? state.ReferenceLookAt : state.GetCorrectedPosition());
					Vector3 resolutuionTargetPoint;
					bool avoidanceResolutionTargetPoint = GetAvoidanceResolutionTargetPoint(vcam, ref state, out resolutuionTargetPoint);
					Vector2 vector2 = (num ? state.RawOrientation.GetCameraRotationToTarget(vector - correctedPosition, referenceUp) : Vector2.zero);
					Quaternion rotationDampingBypass = state.RotationDampingBypass;
					if (extra.StateIsValid)
					{
						extra.PreviousDisplacement = rotationDampingBypass * extra.PreviousDisplacement;
					}
					Vector3 vector3 = (avoidanceResolutionTargetPoint ? PreserveLineOfSight(ref state, ref extra, resolutuionTargetPoint) : Vector3.zero);
					if (AvoidObstacles.MinimumOcclusionTime > 0.0001f)
					{
						float currentTime = CinemachineCore.CurrentTime;
						if (vector3.AlmostZero())
						{
							extra.OcclusionStartTime = 0f;
						}
						else
						{
							if (extra.OcclusionStartTime <= 0f)
							{
								extra.OcclusionStartTime = currentTime;
							}
							if (extra.StateIsValid && currentTime - extra.OcclusionStartTime < AvoidObstacles.MinimumOcclusionTime)
							{
								vector3 = extra.PreviousDisplacement;
							}
						}
					}
					if (avoidanceResolutionTargetPoint && AvoidObstacles.SmoothingTime > 0.0001f)
					{
						if (!extra.StateIsValid)
						{
							extra.ResetDistanceSmoothing(0f);
						}
						Vector3 vector4 = correctedPosition + vector3;
						Vector3 vector5 = vector4 - resolutuionTargetPoint;
						float magnitude = vector5.magnitude;
						if (magnitude > 0.0001f)
						{
							vector5 /= magnitude;
							if (!vector3.AlmostZero())
							{
								extra.UpdateDistanceSmoothing(magnitude);
							}
							magnitude = extra.ApplyDistanceSmoothing(magnitude, AvoidObstacles.SmoothingTime);
							vector3 += resolutuionTargetPoint + vector5 * magnitude - vector4;
						}
					}
					if (vector3.AlmostZero())
					{
						extra.ResetDistanceSmoothing(AvoidObstacles.SmoothingTime);
					}
					Vector3 cameraPos = correctedPosition + vector3;
					if (AvoidObstacles.Strategy != ObstacleAvoidance.ResolutionStrategy.PullCameraForward)
					{
						vector3 += RespectCameraRadius(cameraPos, resolutuionTargetPoint);
					}
					float num2 = AvoidObstacles.DampingWhenOccluded;
					if (avoidanceResolutionTargetPoint && extra.StateIsValid && AvoidObstacles.DampingWhenOccluded + AvoidObstacles.Damping > 0.0001f)
					{
						float sqrMagnitude = vector3.sqrMagnitude;
						float sqrMagnitude2 = extra.PreviousDisplacement.sqrMagnitude;
						if (Mathf.Abs(sqrMagnitude - sqrMagnitude2) > 9.999999E-09f)
						{
							num2 = ((sqrMagnitude > sqrMagnitude2) ? AvoidObstacles.DampingWhenOccluded : AvoidObstacles.Damping);
							if (sqrMagnitude < 0.0001f && num2 < extra.PreviousDampTime)
							{
								num2 = extra.PreviousDampTime + Damper.Damp(num2 - extra.PreviousDampTime, num2, deltaTime);
							}
							if (AvoidObstacles.Strategy == ObstacleAvoidance.ResolutionStrategy.PullCameraForward)
							{
								Vector3 vector6 = correctedPosition + vector3 - resolutuionTargetPoint;
								float magnitude2 = vector6.magnitude;
								Vector3 vector7 = vector6 / magnitude2;
								float num3 = extra.PreviousCameraOffset.magnitude;
								float num4 = (correctedPosition - resolutuionTargetPoint).magnitude - Mathf.Sqrt(sqrMagnitude2);
								if (Mathf.Abs(magnitude2 - num4) < Mathf.Abs(magnitude2 - num3))
								{
									num3 = num4;
								}
								magnitude2 = num3 + Damper.Damp(magnitude2 - num3, num2, deltaTime);
								cameraPos = resolutuionTargetPoint + vector7 * magnitude2;
								vector3 = cameraPos - correctedPosition;
							}
							else
							{
								Vector3 vector8 = resolutuionTargetPoint + rotationDampingBypass * extra.PreviousCameraOffset - correctedPosition;
								if (vector8.sqrMagnitude > sqrMagnitude2)
								{
									vector8 = extra.PreviousDisplacement;
								}
								vector3 = vector8 + Damper.Damp(vector3 - vector8, num2, deltaTime);
							}
						}
					}
					state.PositionCorrection += vector3;
					cameraPos = state.GetCorrectedPosition();
					if (num && vector3.sqrMagnitude > 0.0001f)
					{
						Quaternion orient = Quaternion.LookRotation(vector - cameraPos, referenceUp);
						state.RawOrientation = orient.ApplyCameraRotation(-vector2, referenceUp);
						if (extra.StateIsValid)
						{
							Vector3 v = extra.PreviousCameraPosition - vector;
							Vector3 v2 = cameraPos - vector;
							if (v.sqrMagnitude > 0.0001f && v2.sqrMagnitude > 0.0001f)
							{
								state.RotationDampingBypass = UnityVectorExtensions.SafeFromToRotation(v, v2, referenceUp);
							}
						}
					}
					extra.PreviousDisplacement = vector3;
					extra.PreviousCameraOffset = cameraPos - resolutuionTargetPoint;
					extra.PreviousCameraPosition = cameraPos;
					extra.PreviousDampTime = num2;
					extra.StateIsValid = true;
				}
			}
			if (stage != CinemachineCore.Stage.Finalize || !ShotQualityEvaluation.Enabled || !state.HasLookAt())
			{
				return;
			}
			VcamExtraState extraState = GetExtraState<VcamExtraState>(vcam);
			extraState.TargetObscured = state.IsTargetOffscreen() || IsTargetObscured(state);
			if (extraState.TargetObscured)
			{
				state.ShotQuality *= 0.2f;
			}
			if (extraState.StateIsValid && !extraState.PreviousDisplacement.AlmostZero())
			{
				state.ShotQuality *= 0.8f;
			}
			float num5 = 0f;
			if (!(ShotQualityEvaluation.OptimalDistance > 0f))
			{
				return;
			}
			float num6 = Vector3.Magnitude(state.ReferenceLookAt - state.GetFinalPosition());
			if (num6 <= ShotQualityEvaluation.OptimalDistance)
			{
				if (num6 >= ShotQualityEvaluation.NearLimit)
				{
					num5 = ShotQualityEvaluation.MaxQualityBoost * (num6 - ShotQualityEvaluation.NearLimit) / (ShotQualityEvaluation.OptimalDistance - ShotQualityEvaluation.NearLimit);
				}
			}
			else
			{
				num6 -= ShotQualityEvaluation.OptimalDistance;
				if (num6 < ShotQualityEvaluation.FarLimit)
				{
					num5 = ShotQualityEvaluation.MaxQualityBoost * (1f - num6 / ShotQualityEvaluation.FarLimit);
				}
			}
			state.ShotQuality *= 1f + num5;
		}

		private bool GetAvoidanceResolutionTargetPoint(CinemachineVirtualCameraBase vcam, ref CameraState state, out Vector3 resolutuionTargetPoint)
		{
			bool flag = state.HasLookAt();
			resolutuionTargetPoint = (flag ? state.ReferenceLookAt : state.GetCorrectedPosition());
			if (AvoidObstacles.UseFollowTarget.Enabled)
			{
				Transform follow = vcam.Follow;
				if (follow != null)
				{
					flag = true;
					resolutuionTargetPoint = TargetPositionCache.GetTargetPosition(follow) + TargetPositionCache.GetTargetRotation(follow) * Vector3.up * AvoidObstacles.UseFollowTarget.YOffset;
				}
			}
			return flag;
		}

		private Vector3 PreserveLineOfSight(ref CameraState state, ref VcamExtraState extra, Vector3 lookAtPoint)
		{
			if ((int)CollideAgainst != 0 && (int)CollideAgainst != (int)TransparentLayers)
			{
				Vector3 correctedPosition = state.GetCorrectedPosition();
				RaycastHit hitInfo = default(RaycastHit);
				Vector3 vector = PullCameraInFrontOfNearestObstacle(correctedPosition, lookAtPoint, (int)CollideAgainst & ~(int)TransparentLayers, ref hitInfo);
				if (hitInfo.collider != null)
				{
					extra.AddPointToDebugPath(vector, hitInfo.collider);
					if (AvoidObstacles.Strategy != ObstacleAvoidance.ResolutionStrategy.PullCameraForward)
					{
						Vector3 pushDir = correctedPosition - lookAtPoint;
						vector = PushCameraBack(vector, pushDir, hitInfo, lookAtPoint, new Plane(state.ReferenceUp, correctedPosition), pushDir.magnitude, AvoidObstacles.MaximumEffort, ref extra);
					}
				}
				return vector - correctedPosition;
			}
			return Vector3.zero;
		}

		private Vector3 PullCameraInFrontOfNearestObstacle(Vector3 cameraPos, Vector3 lookAtPos, int layerMask, ref RaycastHit hitInfo)
		{
			Vector3 vector = cameraPos;
			Vector3 vector2 = cameraPos - lookAtPos;
			float magnitude = vector2.magnitude;
			if (magnitude > 0.0001f)
			{
				vector2 /= magnitude;
				float num = MinimumDistanceFromTarget + AvoidObstacles.CameraRadius + 0.001f;
				if (magnitude > num)
				{
					float num2 = Mathf.Max(magnitude - num - AvoidObstacles.CameraRadius, 0.001f);
					if (AvoidObstacles.DistanceLimit > 0.0001f)
					{
						num2 = Mathf.Min(AvoidObstacles.DistanceLimit, num2);
					}
					if (RuntimeUtility.SphereCastIgnoreTag(new Ray(lookAtPos + vector2 * num, vector2), AvoidObstacles.CameraRadius, out hitInfo, num2, layerMask, in IgnoreTag))
					{
						vector = hitInfo.point + hitInfo.normal * (AvoidObstacles.CameraRadius + 0.001f);
					}
					if ((lookAtPos - vector).sqrMagnitude < num * num)
					{
						vector = lookAtPos + vector2 * num;
					}
				}
			}
			return vector;
		}

		private Vector3 PushCameraBack(Vector3 currentPos, Vector3 pushDir, RaycastHit obstacle, Vector3 lookAtPos, Plane startPlane, float targetDistance, int iterations, ref VcamExtraState extra)
		{
			Vector3 vector = currentPos;
			Vector3 outDir = Vector3.zero;
			if (obstacle.collider == null || !GetWalkingDirection(vector, pushDir, obstacle, ref outDir))
			{
				return vector;
			}
			Ray ray = new Ray(vector, outDir);
			float pushBackDistance = GetPushBackDistance(ray, startPlane, targetDistance, lookAtPos);
			if (pushBackDistance <= 0.0001f)
			{
				return vector;
			}
			float num = ClampRayToBounds(ray, pushBackDistance, obstacle.collider.bounds);
			pushBackDistance = Mathf.Min(pushBackDistance, num + 0.001f);
			if (RuntimeUtility.SphereCastIgnoreTag(ray, AvoidObstacles.CameraRadius, out var hitInfo, pushBackDistance, (int)CollideAgainst & ~(int)TransparentLayers, in IgnoreTag))
			{
				float distance = hitInfo.distance - 0.001f;
				vector = ray.GetPoint(distance);
				extra.AddPointToDebugPath(vector, hitInfo.collider);
				if (iterations > 1)
				{
					vector = PushCameraBack(vector, outDir, hitInfo, lookAtPos, startPlane, targetDistance, iterations - 1, ref extra);
				}
				return vector;
			}
			vector = ray.GetPoint(pushBackDistance);
			outDir = vector - lookAtPos;
			float magnitude = outDir.magnitude;
			if (magnitude < 0.0001f || RuntimeUtility.SphereCastIgnoreTag(new Ray(lookAtPos, outDir), AvoidObstacles.CameraRadius, out var _, magnitude - 0.001f, (int)CollideAgainst & ~(int)TransparentLayers, in IgnoreTag))
			{
				return currentPos;
			}
			ray = new Ray(vector, outDir);
			extra.AddPointToDebugPath(vector, null);
			pushBackDistance = GetPushBackDistance(ray, startPlane, targetDistance, lookAtPos);
			if (pushBackDistance > 0.0001f)
			{
				if (!RuntimeUtility.SphereCastIgnoreTag(ray, AvoidObstacles.CameraRadius, out hitInfo, pushBackDistance, (int)CollideAgainst & ~(int)TransparentLayers, in IgnoreTag))
				{
					vector = ray.GetPoint(pushBackDistance);
					extra.AddPointToDebugPath(vector, null);
				}
				else
				{
					float distance2 = hitInfo.distance - 0.001f;
					vector = ray.GetPoint(distance2);
					extra.AddPointToDebugPath(vector, hitInfo.collider);
					if (iterations > 1)
					{
						vector = PushCameraBack(vector, outDir, hitInfo, lookAtPos, startPlane, targetDistance, iterations - 1, ref extra);
					}
				}
			}
			return vector;
		}

		private bool GetWalkingDirection(Vector3 pos, Vector3 pushDir, RaycastHit obstacle, ref Vector3 outDir)
		{
			Vector3 normal = obstacle.normal;
			float num = 0.0050000004f;
			int num2 = Physics.SphereCastNonAlloc(pos, num, pushDir.normalized, m_CornerBuffer, 0f, (int)CollideAgainst & ~(int)TransparentLayers, QueryTriggerInteraction.Ignore);
			if (num2 > 1)
			{
				for (int i = 0; i < num2; i++)
				{
					if (m_CornerBuffer[i].collider == null || (IgnoreTag.Length > 0 && m_CornerBuffer[i].collider.CompareTag(IgnoreTag)))
					{
						continue;
					}
					Type type = m_CornerBuffer[i].collider.GetType();
					if (!(type == typeof(BoxCollider)) && !(type == typeof(SphereCollider)) && !(type == typeof(CapsuleCollider)))
					{
						continue;
					}
					Vector3 direction = m_CornerBuffer[i].collider.ClosestPoint(pos) - pos;
					if (direction.magnitude > 1E-05f && m_CornerBuffer[i].collider.Raycast(new Ray(pos, direction), out m_CornerBuffer[i], num))
					{
						if (!(m_CornerBuffer[i].normal - obstacle.normal).AlmostZero())
						{
							normal = m_CornerBuffer[i].normal;
						}
						break;
					}
				}
			}
			Vector3 vector = Vector3.Cross(obstacle.normal, normal);
			if (vector.AlmostZero())
			{
				vector = Vector3.ProjectOnPlane(pushDir, obstacle.normal);
			}
			else
			{
				float num3 = Vector3.Dot(vector, pushDir);
				if (Mathf.Abs(num3) < 0.0001f)
				{
					return false;
				}
				if (num3 < 0f)
				{
					vector = -vector;
				}
			}
			if (vector.AlmostZero())
			{
				return false;
			}
			outDir = vector.normalized;
			return true;
		}

		private float GetPushBackDistance(Ray ray, Plane startPlane, float targetDistance, Vector3 lookAtPos)
		{
			float num = targetDistance - (ray.origin - lookAtPos).magnitude;
			if (num < 0.0001f)
			{
				return 0f;
			}
			if (AvoidObstacles.Strategy == ObstacleAvoidance.ResolutionStrategy.PreserveCameraDistance)
			{
				return num;
			}
			if (!startPlane.Raycast(ray, out var enter))
			{
				enter = 0f;
			}
			enter = Mathf.Min(num, enter);
			if (enter < 0.0001f)
			{
				return 0f;
			}
			float num2 = Mathf.Abs(UnityVectorExtensions.Angle(startPlane.normal, ray.direction) - 90f);
			return Mathf.Lerp(0f, enter, num2 / 0.1f);
		}

		private static float ClampRayToBounds(Ray ray, float distance, Bounds bounds)
		{
			float enter;
			if (Vector3.Dot(ray.direction, Vector3.up) > 0f)
			{
				if (new Plane(Vector3.down, bounds.max).Raycast(ray, out enter) && enter > 0.0001f)
				{
					distance = Mathf.Min(distance, enter);
				}
			}
			else if (Vector3.Dot(ray.direction, Vector3.down) > 0f && new Plane(Vector3.up, bounds.min).Raycast(ray, out enter) && enter > 0.0001f)
			{
				distance = Mathf.Min(distance, enter);
			}
			if (Vector3.Dot(ray.direction, Vector3.right) > 0f)
			{
				if (new Plane(Vector3.left, bounds.max).Raycast(ray, out enter) && enter > 0.0001f)
				{
					distance = Mathf.Min(distance, enter);
				}
			}
			else if (Vector3.Dot(ray.direction, Vector3.left) > 0f && new Plane(Vector3.right, bounds.min).Raycast(ray, out enter) && enter > 0.0001f)
			{
				distance = Mathf.Min(distance, enter);
			}
			if (Vector3.Dot(ray.direction, Vector3.forward) > 0f)
			{
				if (new Plane(Vector3.back, bounds.max).Raycast(ray, out enter) && enter > 0.0001f)
				{
					distance = Mathf.Min(distance, enter);
				}
			}
			else if (Vector3.Dot(ray.direction, Vector3.back) > 0f && new Plane(Vector3.forward, bounds.min).Raycast(ray, out enter) && enter > 0.0001f)
			{
				distance = Mathf.Min(distance, enter);
			}
			return distance;
		}

		private Vector3 RespectCameraRadius(Vector3 cameraPos, Vector3 lookAtPos)
		{
			Vector3 vector = Vector3.zero;
			if (AvoidObstacles.CameraRadius < 0.0001f || (int)CollideAgainst == 0)
			{
				return vector;
			}
			Vector3 vector2 = cameraPos - lookAtPos;
			float magnitude = vector2.magnitude;
			if (magnitude > 0.0001f)
			{
				vector2 /= magnitude;
			}
			int num = Physics.OverlapSphereNonAlloc(cameraPos, AvoidObstacles.CameraRadius, s_ColliderBuffer, CollideAgainst, QueryTriggerInteraction.Ignore);
			RaycastHit hitInfo;
			if (num == 0 && (int)TransparentLayers != 0 && magnitude > MinimumDistanceFromTarget + 0.0001f)
			{
				float num2 = magnitude - MinimumDistanceFromTarget;
				if (RuntimeUtility.SphereCastIgnoreTag(new Ray(lookAtPos + vector2 * MinimumDistanceFromTarget, vector2), AvoidObstacles.CameraRadius, out hitInfo, num2, CollideAgainst, in IgnoreTag))
				{
					Collider collider = hitInfo.collider;
					if (!collider.Raycast(new Ray(cameraPos, -vector2), out hitInfo, num2))
					{
						s_ColliderBuffer[num++] = collider;
					}
				}
			}
			if ((num > 0 && magnitude == 0f) || magnitude > MinimumDistanceFromTarget)
			{
				SphereCollider scratchCollider = RuntimeUtility.GetScratchCollider();
				scratchCollider.radius = AvoidObstacles.CameraRadius;
				Vector3 vector3 = cameraPos;
				for (int i = 0; i < num; i++)
				{
					Collider collider2 = s_ColliderBuffer[i];
					if (IgnoreTag.Length > 0 && collider2.CompareTag(IgnoreTag))
					{
						continue;
					}
					if (magnitude > MinimumDistanceFromTarget)
					{
						vector2 = vector3 - lookAtPos;
						float magnitude2 = vector2.magnitude;
						if (magnitude2 > 0.0001f)
						{
							vector2 /= magnitude2;
							Ray ray = new Ray(lookAtPos, vector2);
							if (collider2.Raycast(ray, out hitInfo, magnitude2 + AvoidObstacles.CameraRadius))
							{
								vector3 = ray.GetPoint(hitInfo.distance) - vector2 * 0.001f;
							}
						}
					}
					if (Physics.ComputePenetration(scratchCollider, vector3, Quaternion.identity, collider2, collider2.transform.position, collider2.transform.rotation, out var direction, out var distance))
					{
						vector3 += direction * distance;
					}
				}
				vector = vector3 - cameraPos;
			}
			if (magnitude > 0.0001f && MinimumDistanceFromTarget > 0.0001f)
			{
				float num3 = Mathf.Max(MinimumDistanceFromTarget, AvoidObstacles.CameraRadius) + 0.001f;
				if ((cameraPos + vector - lookAtPos).magnitude < num3)
				{
					vector = lookAtPos - cameraPos + vector2 * num3;
				}
			}
			return vector;
		}

		private bool IsTargetObscured(CameraState state)
		{
			if (state.HasLookAt())
			{
				Vector3 referenceLookAt = state.ReferenceLookAt;
				Vector3 correctedPosition = state.GetCorrectedPosition();
				Vector3 vector = referenceLookAt - correctedPosition;
				float magnitude = vector.magnitude;
				if (magnitude < Mathf.Max(MinimumDistanceFromTarget, 0.0001f))
				{
					return true;
				}
				if (RuntimeUtility.SphereCastIgnoreTag(new Ray(correctedPosition, vector.normalized), AvoidObstacles.CameraRadius, out var _, magnitude - MinimumDistanceFromTarget, (int)CollideAgainst & ~(int)TransparentLayers, in IgnoreTag))
				{
					return true;
				}
			}
			return false;
		}
	}
	[RequireComponent(typeof(Camera))]
	[DisallowMultipleComponent]
	[AddComponentMenu("Cinemachine/Cinemachine External Camera")]
	[ExecuteAlways]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineExternalCamera.html")]
	public class CinemachineExternalCamera : CinemachineVirtualCameraBase
	{
		[Tooltip("Hint for transitioning to and from this CinemachineCamera.  Hints can be combined, although not all combinations make sense.  In the case of conflicting hints, Cinemachine will make an arbitrary choice.")]
		[FormerlySerializedAs("m_PositionBlending")]
		[FormerlySerializedAs("m_BlendHint")]
		public CinemachineCore.BlendHints BlendHint;

		[Tooltip("The object that the camera is looking at.  Setting this may improve the quality of the blends to and from this camera")]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_LookAt")]
		public Transform LookAtTarget;

		private Camera m_Camera;

		private CameraState m_State = CameraState.Default;

		public override CameraState State => m_State;

		public override Transform LookAt
		{
			get
			{
				return LookAtTarget;
			}
			set
			{
				LookAtTarget = value;
			}
		}

		[HideInInspector]
		public override Transform Follow { get; set; }

		public override void InternalUpdateCameraState(Vector3 worldUp, float deltaTime)
		{
			if (m_Camera == null)
			{
				TryGetComponent<Camera>(out m_Camera);
			}
			m_State = CameraState.Default;
			m_State.RawPosition = base.transform.position;
			m_State.RawOrientation = base.transform.rotation;
			m_State.ReferenceUp = m_State.RawOrientation * Vector3.up;
			if (m_Camera != null)
			{
				m_State.Lens = LensSettings.FromCamera(m_Camera);
			}
			if (LookAtTarget != null)
			{
				m_State.ReferenceLookAt = LookAtTarget.transform.position;
				Vector3 vector = m_State.ReferenceLookAt - State.RawPosition;
				if (!vector.AlmostZero())
				{
					m_State.ReferenceLookAt = m_State.RawPosition + Vector3.Project(vector, State.RawOrientation * Vector3.forward);
				}
			}
			m_State.BlendHint = (CameraState.BlendHints)BlendHint;
			InvokePostPipelineStageCallback(this, CinemachineCore.Stage.Finalize, ref m_State, deltaTime);
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Follow Zoom")]
	[SaveDuringPlay]
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.LookAt)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineFollowZoom.html")]
	public class CinemachineFollowZoom : CinemachineExtension
	{
		private class VcamExtraState : VcamExtraStateBase
		{
			public float m_PreviousFrameZoom;
		}

		[Tooltip("The shot width to maintain, in world units, at target distance.")]
		[FormerlySerializedAs("m_Width")]
		public float Width = 2f;

		[Range(0f, 20f)]
		[Tooltip("Increase this value to soften the aggressiveness of the follow-zoom.  Small numbers are more responsive, larger numbers give a more heavy slowly responding camera.")]
		[FormerlySerializedAs("m_Damping")]
		public float Damping = 1f;

		[MinMaxRangeSlider(1f, 179f)]
		[Tooltip("Range for the FOV that this behaviour will generate.")]
		public Vector2 FovRange = new Vector2(3f, 60f);

		private void Reset()
		{
			Width = 2f;
			Damping = 1f;
			FovRange = new Vector2(3f, 60f);
		}

		private void OnValidate()
		{
			Width = Mathf.Max(0f, Width);
			FovRange.y = Mathf.Clamp(FovRange.y, 1f, 179f);
			FovRange.x = Mathf.Clamp(FovRange.x, 1f, FovRange.y);
		}

		public override float GetMaxDampTime()
		{
			return Damping;
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			VcamExtraState extraState = GetExtraState<VcamExtraState>(vcam);
			if (deltaTime < 0f || !vcam.PreviousStateIsValid)
			{
				extraState.m_PreviousFrameZoom = state.Lens.FieldOfView;
			}
			if (stage != CinemachineCore.Stage.Body)
			{
				return;
			}
			float value = Mathf.Max(Width, 0f);
			float value2 = 179f;
			float num = Vector3.Distance(state.GetCorrectedPosition(), state.ReferenceLookAt);
			if (num > 0.0001f)
			{
				float min = num * 2f * Mathf.Tan(FovRange.x * (MathF.PI / 180f) / 2f);
				float max = num * 2f * Mathf.Tan(FovRange.y * (MathF.PI / 180f) / 2f);
				value = Mathf.Clamp(value, min, max);
				if (deltaTime >= 0f && Damping > 0f && vcam.PreviousStateIsValid)
				{
					float num2 = num * 2f * Mathf.Tan(extraState.m_PreviousFrameZoom * (MathF.PI / 180f) / 2f);
					float initial = value - num2;
					initial = vcam.DetachedLookAtTargetDamp(initial, Damping, deltaTime);
					value = num2 + initial;
				}
				value2 = 2f * Mathf.Atan(value / (2f * num)) * 57.29578f;
			}
			LensSettings lens = state.Lens;
			lens.FieldOfView = (extraState.m_PreviousFrameZoom = Mathf.Clamp(value2, FovRange.x, FovRange.y));
			state.Lens = lens;
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine FreeLook Modifier")]
	[SaveDuringPlay]
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineFreeLookModifier.html")]
	public class CinemachineFreeLookModifier : CinemachineExtension
	{
		public interface IModifierValueSource
		{
			float NormalizedModifierValue { get; }
		}

		public interface IModifiablePositionDamping
		{
			Vector3 PositionDamping { get; set; }
		}

		public interface IModifiableComposition
		{
			ScreenComposerSettings Composition { get; set; }
		}

		public interface IModifiableDistance
		{
			float Distance { get; set; }
		}

		public interface IModifiableNoise
		{
			(float, float) NoiseAmplitudeFrequency { get; set; }
		}

		[Serializable]
		public abstract class Modifier
		{
			public virtual Type CachedComponentType => null;

			public virtual bool HasRequiredComponent => true;

			public virtual void Validate(CinemachineVirtualCameraBase vcam)
			{
			}

			public virtual void Reset(CinemachineVirtualCameraBase vcam)
			{
			}

			public virtual void RefreshCache(CinemachineVirtualCameraBase vcam)
			{
			}

			public virtual void BeforePipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
			}

			public virtual void AfterPipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
			}
		}

		public abstract class ComponentModifier<T> : Modifier
		{
			protected T CachedComponent;

			public override bool HasRequiredComponent => CachedComponent != null;

			public override Type CachedComponentType => typeof(T);

			public override void RefreshCache(CinemachineVirtualCameraBase vcam)
			{
				TryGetVcamComponent<T>(vcam, out CachedComponent);
			}
		}

		public class TiltModifier : Modifier
		{
			[HideFoldout]
			public TopBottomRigs<float> Tilt;

			public override void Validate(CinemachineVirtualCameraBase vcam)
			{
				Tilt.Top = Mathf.Clamp(Tilt.Top, -30f, 30f);
				Tilt.Bottom = Mathf.Clamp(Tilt.Bottom, -30f, 30f);
			}

			public override void Reset(CinemachineVirtualCameraBase vcam)
			{
				Tilt = new TopBottomRigs<float>
				{
					Top = -5f,
					Bottom = 5f
				};
			}

			public override void AfterPipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
				float angle = ((modifierValue > 0f) ? Mathf.Lerp(0f, Tilt.Top, modifierValue) : Mathf.Lerp(Tilt.Bottom, 0f, modifierValue + 1f));
				Quaternion quaternion2 = state.RawOrientation * Quaternion.AngleAxis(angle, Vector3.right);
				state.OrientationCorrection = Quaternion.Inverse(state.GetCorrectedOrientation()) * quaternion2;
			}
		}

		public class LensModifier : Modifier
		{
			[Tooltip("Value to take at the top of the axis range")]
			[LensSettingsHideModeOverrideProperty]
			public LensSettings Top;

			[Tooltip("Value to take at the bottom of the axis range")]
			[LensSettingsHideModeOverrideProperty]
			public LensSettings Bottom;

			public override void Validate(CinemachineVirtualCameraBase vcam)
			{
				Top.Validate();
				Bottom.Validate();
			}

			public override void Reset(CinemachineVirtualCameraBase vcam)
			{
				if (vcam == null)
				{
					Top = (Bottom = LensSettings.Default);
					return;
				}
				CameraState state = vcam.State;
				Top = (Bottom = state.Lens);
				Top.CopyCameraMode(ref state.Lens);
				Bottom.CopyCameraMode(ref state.Lens);
			}

			public override void BeforePipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
				Top.CopyCameraMode(ref state.Lens);
				Bottom.CopyCameraMode(ref state.Lens);
				if (modifierValue >= 0f)
				{
					state.Lens.Lerp(in Top, modifierValue);
				}
				else
				{
					state.Lens.Lerp(in Bottom, 0f - modifierValue);
				}
			}
		}

		public class PositionDampingModifier : ComponentModifier<IModifiablePositionDamping>
		{
			[HideFoldout]
			public TopBottomRigs<Vector3> Damping;

			private Vector3 m_CenterDamping;

			public override void Validate(CinemachineVirtualCameraBase vcam)
			{
				Damping.Top = new Vector3(Mathf.Max(0f, Damping.Top.x), Mathf.Max(0f, Damping.Top.y), Mathf.Max(0f, Damping.Top.z));
				Damping.Bottom = new Vector3(Mathf.Max(0f, Damping.Bottom.x), Mathf.Max(0f, Damping.Bottom.y), Mathf.Max(0f, Damping.Bottom.z));
			}

			public override void Reset(CinemachineVirtualCameraBase vcam)
			{
				if (CachedComponent != null)
				{
					Damping.Top = (Damping.Bottom = CachedComponent.PositionDamping);
				}
			}

			public override void BeforePipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
				if (CachedComponent != null)
				{
					m_CenterDamping = CachedComponent.PositionDamping;
					CachedComponent.PositionDamping = ((modifierValue >= 0f) ? Vector3.Lerp(m_CenterDamping, Damping.Top, modifierValue) : Vector3.Lerp(Damping.Bottom, m_CenterDamping, modifierValue + 1f));
				}
			}

			public override void AfterPipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
				if (CachedComponent != null)
				{
					CachedComponent.PositionDamping = m_CenterDamping;
				}
			}
		}

		public class CompositionModifier : ComponentModifier<IModifiableComposition>
		{
			[HideFoldout]
			public TopBottomRigs<ScreenComposerSettings> Composition;

			private ScreenComposerSettings m_SavedComposition;

			public override void Validate(CinemachineVirtualCameraBase vcam)
			{
				Composition.Top.Validate();
				Composition.Bottom.Validate();
			}

			public override void Reset(CinemachineVirtualCameraBase vcam)
			{
				if (CachedComponent != null)
				{
					Composition.Top = (Composition.Bottom = CachedComponent.Composition);
				}
			}

			public override void BeforePipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
				if (CachedComponent != null)
				{
					m_SavedComposition = CachedComponent.Composition;
					CachedComponent.Composition = ((modifierValue >= 0f) ? ScreenComposerSettings.Lerp(in m_SavedComposition, in Composition.Top, modifierValue) : ScreenComposerSettings.Lerp(in Composition.Bottom, in m_SavedComposition, modifierValue + 1f));
				}
			}

			public override void AfterPipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
				if (CachedComponent != null)
				{
					CachedComponent.Composition = m_SavedComposition;
				}
			}
		}

		public class DistanceModifier : ComponentModifier<IModifiableDistance>
		{
			[HideFoldout]
			public TopBottomRigs<float> Distance;

			private float m_CenterDistance;

			public override void Validate(CinemachineVirtualCameraBase vcam)
			{
				Distance.Top = Mathf.Max(0f, Distance.Top);
				Distance.Bottom = Mathf.Max(0f, Distance.Bottom);
			}

			public override void Reset(CinemachineVirtualCameraBase vcam)
			{
				if (CachedComponent != null)
				{
					Distance.Top = (Distance.Bottom = CachedComponent.Distance);
				}
			}

			public override void BeforePipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
				if (CachedComponent != null)
				{
					m_CenterDistance = CachedComponent.Distance;
					CachedComponent.Distance = ((modifierValue >= 0f) ? Mathf.Lerp(m_CenterDistance, Distance.Top, modifierValue) : Mathf.Lerp(Distance.Bottom, m_CenterDistance, modifierValue + 1f));
				}
			}

			public override void AfterPipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
				if (CachedComponent != null)
				{
					CachedComponent.Distance = m_CenterDistance;
				}
			}
		}

		public class NoiseModifier : ComponentModifier<IModifiableNoise>
		{
			[Serializable]
			public struct NoiseSettings
			{
				[Tooltip("Multiplier for the noise amplitude")]
				public float Amplitude;

				[Tooltip("Multiplier for the noise frequency")]
				public float Frequency;
			}

			[HideFoldout]
			public TopBottomRigs<NoiseSettings> Noise;

			private (float, float) m_CenterNoise;

			public override void Reset(CinemachineVirtualCameraBase vcam)
			{
				if (CachedComponent != null)
				{
					(float, float) noiseAmplitudeFrequency = CachedComponent.NoiseAmplitudeFrequency;
					Noise.Top = (Noise.Bottom = new NoiseSettings
					{
						Amplitude = noiseAmplitudeFrequency.Item1,
						Frequency = noiseAmplitudeFrequency.Item2
					});
				}
			}

			public override void BeforePipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
				if (CachedComponent != null)
				{
					m_CenterNoise = CachedComponent.NoiseAmplitudeFrequency;
					if (modifierValue >= 0f)
					{
						CachedComponent.NoiseAmplitudeFrequency = (Mathf.Lerp(m_CenterNoise.Item1, Noise.Top.Amplitude, modifierValue), Mathf.Lerp(m_CenterNoise.Item2, Noise.Top.Frequency, modifierValue));
					}
					else
					{
						CachedComponent.NoiseAmplitudeFrequency = (Mathf.Lerp(Noise.Bottom.Amplitude, m_CenterNoise.Item1, modifierValue + 1f), Mathf.Lerp(Noise.Bottom.Frequency, m_CenterNoise.Item2, modifierValue + 1f));
					}
				}
			}

			public override void AfterPipeline(CinemachineVirtualCameraBase vcam, ref CameraState state, float deltaTime, float modifierValue)
			{
				if (CachedComponent != null)
				{
					CachedComponent.NoiseAmplitudeFrequency = m_CenterNoise;
				}
			}
		}

		[Serializable]
		public struct TopBottomRigs<T>
		{
			[Tooltip("Value to take at the top of the axis range")]
			public T Top;

			[Tooltip("Value to take at the bottom of the axis range")]
			public T Bottom;
		}

		[Tooltip("The amount of easing to apply towards the center value. Zero easing blends linearly through the center value, while an easing of 1 smooths the result as it passes over the center value.")]
		[Range(0f, 1f)]
		public float Easing;

		[Tooltip("These will modify settings as a function of the FreeLook's Vertical axis value")]
		[SerializeReference]
		public List<Modifier> Modifiers = new List<Modifier>();

		private IModifierValueSource m_ValueSource;

		private float m_CurrentValue;

		private AnimationCurve m_EasingCurve;

		private float m_CachedEasingValue;

		private void OnValidate()
		{
			CinemachineVirtualCameraBase componentOwner = base.ComponentOwner;
			for (int i = 0; i < Modifiers.Count; i++)
			{
				Modifiers[i]?.Validate(componentOwner);
			}
		}

		protected override void OnEnable()
		{
			base.OnEnable();
			RefreshComponentCache();
		}

		private static void TryGetVcamComponent<T>(CinemachineVirtualCameraBase vcam, out T component)
		{
			if (vcam == null || !vcam.TryGetComponent<T>(out component))
			{
				component = default(T);
			}
		}

		private void RefreshComponentCache()
		{
			CinemachineVirtualCameraBase componentOwner = base.ComponentOwner;
			TryGetVcamComponent<IModifierValueSource>(componentOwner, out m_ValueSource);
			for (int i = 0; i < Modifiers.Count; i++)
			{
				Modifiers[i]?.RefreshCache(componentOwner);
			}
		}

		internal bool HasValueSource()
		{
			RefreshComponentCache();
			return m_ValueSource != null;
		}

		public override void PrePipelineMutateCameraStateCallback(CinemachineVirtualCameraBase vcam, ref CameraState curState, float deltaTime)
		{
			if (m_ValueSource == null || !(vcam == base.ComponentOwner))
			{
				return;
			}
			if (m_EasingCurve == null || m_CachedEasingValue != Easing)
			{
				if (m_EasingCurve == null)
				{
					m_EasingCurve = AnimationCurve.Linear(0f, 0f, 1f, 1f);
				}
				Keyframe[] keys = m_EasingCurve.keys;
				keys[0].outTangent = 1f - Easing;
				keys[1].inTangent = 1f + 2f * Easing;
				m_EasingCurve.keys = keys;
				m_CachedEasingValue = Easing;
			}
			float normalizedModifierValue = m_ValueSource.NormalizedModifierValue;
			float num = Mathf.Sign(normalizedModifierValue);
			m_CurrentValue = num * m_EasingCurve.Evaluate(Mathf.Abs(normalizedModifierValue));
			for (int i = 0; i < Modifiers.Count; i++)
			{
				Modifiers[i]?.BeforePipeline(vcam, ref curState, deltaTime, m_CurrentValue);
			}
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (m_ValueSource != null && stage == CinemachineCore.Stage.Finalize && vcam == base.ComponentOwner)
			{
				for (int i = 0; i < Modifiers.Count; i++)
				{
					Modifiers[i]?.AfterPipeline(vcam, ref state, deltaTime, m_CurrentValue);
				}
			}
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Group Framing")]
	[ExecuteAlways]
	[SaveDuringPlay]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.GroupLookAt)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineGroupFraming.html")]
	public class CinemachineGroupFraming : CinemachineExtension
	{
		public enum FramingModes
		{
			Horizontal,
			Vertical,
			HorizontalAndVertical
		}

		public enum SizeAdjustmentModes
		{
			ZoomOnly,
			DollyOnly,
			DollyThenZoom
		}

		public enum LateralAdjustmentModes
		{
			ChangePosition,
			ChangeRotation
		}

		private class VcamExtraState : VcamExtraStateBase
		{
			public Vector3 PosAdjustment;

			public Vector2 RotAdjustment;

			public float FovAdjustment;

			public CinemachineCore.Stage Stage = CinemachineCore.Stage.Finalize;

			public CinemachineConfiner2D Confiner;

			public float PreviousOrthoSize;

			public void Reset()
			{
				PosAdjustment = Vector3.zero;
				RotAdjustment = Vector2.zero;
				FovAdjustment = 0f;
				Stage = CinemachineCore.Stage.Finalize;
			}
		}

		[Tooltip("What screen dimensions to consider when framing.  Can be Horizontal, Vertical, or both")]
		public FramingModes FramingMode = FramingModes.HorizontalAndVertical;

		[Tooltip("The bounding box of the targets should occupy this amount of the screen space.  1 means fill the whole screen.  0.5 means fill half the screen, etc.")]
		[Range(0f, 2f)]
		public float FramingSize = 0.8f;

		[Tooltip("A nonzero value will offset the group in the camera frame.")]
		public Vector2 CenterOffset = Vector2.zero;

		[Range(0f, 20f)]
		[Tooltip("How aggressively the camera tries to frame the group. Small numbers are more responsive, rapidly adjusting the camera to keep the group in the frame.  Larger numbers give a heavier more slowly responding camera.")]
		public float Damping = 2f;

		[Tooltip("How to adjust the camera to get the desired framing size.  You can zoom, dolly in/out, or do both.")]
		public SizeAdjustmentModes SizeAdjustment = SizeAdjustmentModes.DollyThenZoom;

		[Tooltip("How to adjust the camera to get the desired horizontal and vertical framing.")]
		public LateralAdjustmentModes LateralAdjustment;

		[Tooltip("Allowable FOV range, if adjusting FOV.")]
		[MinMaxRangeSlider(1f, 179f)]
		public Vector2 FovRange = new Vector2(1f, 100f);

		[Tooltip("Allowable range for the camera to move.  0 is the undollied position.  Negative values move the camera closer to the target.")]
		[Vector2AsRange]
		public Vector2 DollyRange = new Vector2(-100f, 100f);

		[Tooltip("Allowable orthographic size range, if adjusting orthographic size.")]
		[Vector2AsRange]
		public Vector2 OrthoSizeRange = new Vector2(1f, 1000f);

		private const float k_MinimumGroupSize = 0.01f;

		internal Bounds GroupBounds;

		internal Matrix4x4 GroupBoundsMatrix;

		private void OnValidate()
		{
			FramingSize = Mathf.Max(0.01f, FramingSize);
			Damping = Mathf.Max(0f, Damping);
			DollyRange.y = Mathf.Max(DollyRange.x, DollyRange.y);
			FovRange.y = Mathf.Clamp(FovRange.y, 1f, 179f);
			FovRange.x = Mathf.Clamp(FovRange.x, 1f, FovRange.y);
			OrthoSizeRange.x = Mathf.Max(0.01f, OrthoSizeRange.x);
			OrthoSizeRange.y = Mathf.Max(OrthoSizeRange.x, OrthoSizeRange.y);
		}

		private void Reset()
		{
			FramingMode = FramingModes.HorizontalAndVertical;
			SizeAdjustment = SizeAdjustmentModes.DollyThenZoom;
			LateralAdjustment = LateralAdjustmentModes.ChangePosition;
			FramingSize = 0.8f;
			CenterOffset = Vector2.zero;
			Damping = 2f;
			DollyRange = new Vector2(-100f, 100f);
			FovRange = new Vector2(1f, 100f);
			OrthoSizeRange = new Vector2(1f, 1000f);
		}

		public override float GetMaxDampTime()
		{
			return Damping;
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			VcamExtraState extraState = GetExtraState<VcamExtraState>(vcam);
			if (!vcam.PreviousStateIsValid)
			{
				extraState.Reset();
			}
			if (extraState.Stage == CinemachineCore.Stage.Finalize || !Application.isPlaying)
			{
				if (vcam.TryGetComponent<CinemachineConfiner2D>(out extraState.Confiner))
				{
					extraState.Stage = CinemachineCore.Stage.Body;
				}
				else
				{
					extraState.Stage = CinemachineCore.Stage.Aim;
					if (vcam is CinemachineCamera cinemachineCamera)
					{
						CinemachineComponentBase cinemachineComponent = cinemachineCamera.GetCinemachineComponent(CinemachineCore.Stage.Body);
						if (cinemachineComponent != null && cinemachineComponent.BodyAppliesAfterAim)
						{
							extraState.Stage = CinemachineCore.Stage.Body;
						}
					}
				}
			}
			if (stage != extraState.Stage)
			{
				return;
			}
			ICinemachineTargetGroup cinemachineTargetGroup = vcam.LookAtTargetAsGroup;
			if (cinemachineTargetGroup == null)
			{
				cinemachineTargetGroup = vcam.FollowTargetAsGroup;
			}
			if (cinemachineTargetGroup != null && cinemachineTargetGroup.IsValid)
			{
				if (state.Lens.Orthographic)
				{
					OrthoFraming(vcam, cinemachineTargetGroup, extraState, ref state, deltaTime);
				}
				else
				{
					PerspectiveFraming(vcam, cinemachineTargetGroup, extraState, ref state, deltaTime);
				}
				if (extraState.Confiner != null && Mathf.Abs(extraState.PreviousOrthoSize - state.Lens.OrthographicSize) > 0.0001f)
				{
					extraState.Confiner.InvalidateLensCache();
					extraState.PreviousOrthoSize = state.Lens.OrthographicSize;
				}
			}
		}

		private void OrthoFraming(CinemachineVirtualCameraBase vcam, ICinemachineTargetGroup group, VcamExtraState extra, ref CameraState state, float deltaTime)
		{
			float dampTime = ((vcam.PreviousStateIsValid && deltaTime >= 0f) ? Damping : 0f);
			Vector3 correctedPosition = state.GetCorrectedPosition();
			Quaternion correctedOrientation = state.GetCorrectedOrientation();
			GroupBoundsMatrix = Matrix4x4.TRS(correctedPosition, correctedOrientation, Vector3.one);
			GroupBounds = group.GetViewSpaceBoundingBox(GroupBoundsMatrix, includeBehind: true);
			Vector3 center = GroupBounds.center;
			center.z = Mathf.Min(0f, center.z - GroupBounds.extents.z);
			LensSettings lens = state.Lens;
			float num = Mathf.Clamp(GetFrameHeight(GroupBounds.size / FramingSize, lens.Aspect) * 0.5f, OrthoSizeRange.x, OrthoSizeRange.y) - lens.OrthographicSize;
			extra.FovAdjustment += vcam.DetachedFollowTargetDamp(num - extra.FovAdjustment, dampTime, deltaTime);
			lens.OrthographicSize += extra.FovAdjustment;
			center.x -= CenterOffset.x * lens.OrthographicSize / lens.Aspect;
			center.y -= CenterOffset.y * lens.OrthographicSize;
			extra.PosAdjustment += vcam.DetachedFollowTargetDamp(center - extra.PosAdjustment, dampTime, deltaTime);
			state.PositionCorrection += correctedOrientation * extra.PosAdjustment;
			state.Lens = lens;
		}

		private void PerspectiveFraming(CinemachineVirtualCameraBase vcam, ICinemachineTargetGroup group, VcamExtraState extra, ref CameraState state, float deltaTime)
		{
			float dampTime = ((vcam.PreviousStateIsValid && deltaTime >= 0f) ? Damping : 0f);
			Vector3 correctedPosition = state.GetCorrectedPosition();
			Quaternion correctedOrientation = state.GetCorrectedOrientation();
			Vector3 camPos = correctedPosition;
			Quaternion camRot = correctedOrientation;
			Vector3 vector = camRot * Vector3.up;
			float fov = state.Lens.FieldOfView;
			bool flag = SizeAdjustment != SizeAdjustmentModes.ZoomOnly;
			Vector2 vector2 = (flag ? DollyRange : Vector2.zero);
			Matrix4x4 observer = Matrix4x4.TRS(camPos, camRot, Vector3.one);
			Bounds viewSpaceBoundingBox = group.GetViewSpaceBoundingBox(observer, flag);
			bool flag2 = LateralAdjustment == LateralAdjustmentModes.ChangePosition;
			if (!flag2)
			{
				Vector3 vector3 = observer.MultiplyPoint3x4(viewSpaceBoundingBox.center) - camPos;
				if (!Vector3.Cross(vector3, vector).AlmostZero())
				{
					camRot = Quaternion.LookRotation(vector3, vector);
				}
			}
			float dollyAmount = Mathf.Clamp(Mathf.Min(0f, viewSpaceBoundingBox.center.z) - viewSpaceBoundingBox.extents.z - 5f, vector2.x, vector2.y);
			camPos += camRot * new Vector3(0f, 0f, dollyAmount);
			ComputeCameraViewGroupBounds(group, ref camPos, ref camRot, flag2);
			AdjustSize(group, state.Lens.Aspect, ref camPos, ref camRot, ref fov, ref dollyAmount);
			LensSettings lens = state.Lens;
			float num = fov - lens.FieldOfView;
			extra.FovAdjustment += vcam.DetachedFollowTargetDamp(num - extra.FovAdjustment, dampTime, deltaTime);
			lens.FieldOfView += extra.FovAdjustment;
			state.Lens = lens;
			Vector2 cameraRotationToTarget = correctedOrientation.GetCameraRotationToTarget(camRot * Vector3.forward, vector);
			extra.RotAdjustment.x += vcam.DetachedFollowTargetDamp(cameraRotationToTarget.x - extra.RotAdjustment.x, dampTime, deltaTime);
			extra.RotAdjustment.y += vcam.DetachedFollowTargetDamp(cameraRotationToTarget.y - extra.RotAdjustment.y, dampTime, deltaTime);
			state.OrientationCorrection *= Quaternion.identity.ApplyCameraRotation(extra.RotAdjustment, vector);
			correctedOrientation = state.GetCorrectedOrientation();
			Vector3 vector4 = Quaternion.Inverse(correctedOrientation) * (camPos - correctedPosition);
			extra.PosAdjustment += vcam.DetachedFollowTargetDamp(vector4 - extra.PosAdjustment, dampTime, deltaTime);
			state.PositionCorrection += correctedOrientation * extra.PosAdjustment;
			if (Mathf.Abs(CenterOffset.x) > 0.01f || Mathf.Abs(CenterOffset.y) > 0.01f)
			{
				float num2 = 0.5f * state.Lens.FieldOfView;
				if (flag2)
				{
					float num3 = GroupBounds.center.z - GroupBounds.extents.z;
					state.PositionCorrection -= correctedOrientation * new Vector3(CenterOffset.x * Mathf.Tan(num2 * (MathF.PI / 180f) * state.Lens.Aspect) * num3, CenterOffset.y * Mathf.Tan(num2 * (MathF.PI / 180f)) * num3, 0f);
				}
				else
				{
					Vector2 rot = new Vector2(CenterOffset.y * num2, CenterOffset.x * num2 / state.Lens.Aspect);
					state.OrientationCorrection *= Quaternion.identity.ApplyCameraRotation(rot, state.ReferenceUp);
				}
			}
		}

		private void AdjustSize(ICinemachineTargetGroup group, float aspect, ref Vector3 camPos, ref Quaternion camRot, ref float fov, ref float dollyAmount)
		{
			if (SizeAdjustment != SizeAdjustmentModes.ZoomOnly)
			{
				float frameHeight = GetFrameHeight(GroupBounds.size / FramingSize, aspect);
				float num = GroupBounds.center.z - GroupBounds.extents.z;
				float num2 = frameHeight / (2f * Mathf.Tan(fov * (MathF.PI / 180f) / 2f));
				float num3 = num - num2;
				num3 = Mathf.Clamp(num3 + dollyAmount, DollyRange.x, DollyRange.y) - dollyAmount;
				dollyAmount += num3;
				camPos += camRot * new Vector3(0f, 0f, num3);
				ComputeCameraViewGroupBounds(group, ref camPos, ref camRot, moveCamera: true);
			}
			if (SizeAdjustment != SizeAdjustmentModes.DollyOnly)
			{
				float frameHeight2 = GetFrameHeight(GroupBounds.size / FramingSize, aspect);
				float num4 = GroupBounds.center.z - GroupBounds.extents.z;
				if (num4 > 0.0001f)
				{
					fov = 2f * Mathf.Atan(frameHeight2 / (2f * num4)) * 57.29578f;
				}
				fov = Mathf.Clamp(fov, FovRange.x, FovRange.y);
			}
		}

		private void ComputeCameraViewGroupBounds(ICinemachineTargetGroup group, ref Vector3 camPos, ref Quaternion camRot, bool moveCamera)
		{
			GroupBoundsMatrix = Matrix4x4.TRS(camPos, camRot, Vector3.one);
			if (moveCamera)
			{
				GroupBounds = group.GetViewSpaceBoundingBox(GroupBoundsMatrix, includeBehind: false);
				Vector3 center = GroupBounds.center;
				center.z = 0f;
				camPos = GroupBoundsMatrix.MultiplyPoint3x4(center);
				GroupBoundsMatrix = Matrix4x4.TRS(camPos, camRot, Vector3.one);
			}
			group.GetViewSpaceAngularBounds(GroupBoundsMatrix, out var minAngles, out var maxAngles, out var zRange);
			Vector2 vector = (minAngles + maxAngles) / 2f;
			Quaternion quaternion2 = Quaternion.identity.ApplyCameraRotation(vector, Vector3.up);
			if (moveCamera)
			{
				Vector3 vector2 = quaternion2 * Vector3.forward;
				new Plane(Vector3.forward, new Vector3(0f, 0f, zRange.x)).Raycast(new Ray(Vector3.zero, vector2), out var enter);
				camPos = vector2 * enter;
				camPos.z = 0f;
				camPos = GroupBoundsMatrix.MultiplyPoint3x4(camPos);
				GroupBoundsMatrix.SetColumn(3, camPos);
				group.GetViewSpaceAngularBounds(GroupBoundsMatrix, out minAngles, out maxAngles, out zRange);
			}
			else
			{
				camRot *= quaternion2;
				GroupBoundsMatrix = Matrix4x4.TRS(camPos, camRot, Vector3.one);
				minAngles -= vector;
				maxAngles -= vector;
			}
			Vector2 vector3 = new Vector2(89.5f, 89.5f);
			if (zRange.x > 0f)
			{
				vector3 = Vector2.Max(maxAngles, minAngles.Abs());
				vector3 = Vector2.Min(vector3, new Vector2(89.5f, 89.5f));
			}
			float num = zRange.x * 2f;
			vector3 *= MathF.PI / 180f;
			GroupBounds = new Bounds(new Vector3(0f, 0f, (zRange.x + zRange.y) * 0.5f), new Vector3(Mathf.Tan(vector3.y) * num, Mathf.Tan(vector3.x) * num, zRange.y - zRange.x));
		}

		private float GetFrameHeight(Vector2 boundsSize, float aspect)
		{
			return Mathf.Max(FramingMode switch
			{
				FramingModes.Horizontal => Mathf.Max(0.0001f, boundsSize.x) / aspect, 
				FramingModes.Vertical => Mathf.Max(0.0001f, boundsSize.y), 
				_ => Mathf.Max(Mathf.Max(0.0001f, boundsSize.x) / aspect, Mathf.Max(0.0001f, boundsSize.y)), 
			}, 0.01f);
		}
	}
	[DisallowMultipleComponent]
	[ExecuteAlways]
	[ExcludeFromPreset]
	[AddComponentMenu("Cinemachine/Cinemachine Mixing Camera")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineMixingCamera.html")]
	public class CinemachineMixingCamera : CinemachineCameraManagerBase
	{
		public const int MaxCameras = 8;

		[Tooltip("The weight of the first tracked camera")]
		[FormerlySerializedAs("m_Weight0")]
		public float Weight0 = 0.5f;

		[Tooltip("The weight of the second tracked camera")]
		[FormerlySerializedAs("m_Weight1")]
		public float Weight1 = 0.5f;

		[Tooltip("The weight of the third tracked camera")]
		[FormerlySerializedAs("m_Weight2")]
		public float Weight2 = 0.5f;

		[Tooltip("The weight of the fourth tracked camera")]
		[FormerlySerializedAs("m_Weight3")]
		public float Weight3 = 0.5f;

		[Tooltip("The weight of the fifth tracked camera")]
		[FormerlySerializedAs("m_Weight4")]
		public float Weight4 = 0.5f;

		[Tooltip("The weight of the sixth tracked camera")]
		[FormerlySerializedAs("m_Weight5")]
		public float Weight5 = 0.5f;

		[Tooltip("The weight of the seventh tracked camera")]
		[FormerlySerializedAs("m_Weight6")]
		public float Weight6 = 0.5f;

		[Tooltip("The weight of the eighth tracked camera")]
		[FormerlySerializedAs("m_Weight7")]
		public float Weight7 = 0.5f;

		private CameraState m_CameraState = CameraState.Default;

		private Dictionary<CinemachineVirtualCameraBase, int> m_IndexMap;

		private float m_LiveChildPercent;

		public override CameraState State => m_CameraState;

		public override string Description
		{
			get
			{
				if (base.LiveChild == null)
				{
					return "[(none)]";
				}
				StringBuilder stringBuilder = CinemachineDebug.SBFromPool();
				stringBuilder.Append("[");
				stringBuilder.Append(base.LiveChild.Name);
				stringBuilder.Append(" ");
				stringBuilder.Append(Mathf.RoundToInt(m_LiveChildPercent));
				stringBuilder.Append("%]");
				string result = stringBuilder.ToString();
				CinemachineDebug.ReturnToPool(stringBuilder);
				return result;
			}
		}

		private void OnValidate()
		{
			for (int i = 0; i < 8; i++)
			{
				SetWeight(i, Mathf.Max(0f, GetWeight(i)));
			}
		}

		protected override void Reset()
		{
			base.Reset();
			for (int i = 0; i < 8; i++)
			{
				SetWeight(i, (i == 0) ? 1 : 0);
			}
		}

		public float GetWeight(int index)
		{
			switch (index)
			{
			case 0:
				return Weight0;
			case 1:
				return Weight1;
			case 2:
				return Weight2;
			case 3:
				return Weight3;
			case 4:
				return Weight4;
			case 5:
				return Weight5;
			case 6:
				return Weight6;
			case 7:
				return Weight7;
			default:
				UnityEngine.Debug.LogError("CinemachineMixingCamera: Invalid index: " + index);
				return 0f;
			}
		}

		public void SetWeight(int index, float w)
		{
			switch (index)
			{
			case 0:
				Weight0 = w;
				break;
			case 1:
				Weight1 = w;
				break;
			case 2:
				Weight2 = w;
				break;
			case 3:
				Weight3 = w;
				break;
			case 4:
				Weight4 = w;
				break;
			case 5:
				Weight5 = w;
				break;
			case 6:
				Weight6 = w;
				break;
			case 7:
				Weight7 = w;
				break;
			default:
				UnityEngine.Debug.LogError("CinemachineMixingCamera: Invalid index: " + index);
				break;
			}
		}

		public float GetWeight(CinemachineVirtualCameraBase vcam)
		{
			UpdateCameraCache();
			if (m_IndexMap.TryGetValue(vcam, out var value))
			{
				return GetWeight(value);
			}
			return 0f;
		}

		public void SetWeight(CinemachineVirtualCameraBase vcam, float w)
		{
			UpdateCameraCache();
			if (m_IndexMap.TryGetValue(vcam, out var value))
			{
				SetWeight(value, w);
			}
			else
			{
				UnityEngine.Debug.LogError("CinemachineMixingCamera: Invalid child: " + ((vcam != null) ? vcam.Name : "(null)"));
			}
		}

		public override bool IsLiveChild(ICinemachineCamera vcam, bool dominantChildOnly = false)
		{
			if (dominantChildOnly)
			{
				return base.LiveChild == vcam;
			}
			List<CinemachineVirtualCameraBase> childCameras = base.ChildCameras;
			for (int i = 0; i < 8 && i < childCameras.Count; i++)
			{
				if (childCameras[i] == vcam)
				{
					if (GetWeight(i) > 0.0001f)
					{
						return childCameras[i].isActiveAndEnabled;
					}
					return false;
				}
			}
			return false;
		}

		protected override bool UpdateCameraCache()
		{
			if (!base.UpdateCameraCache())
			{
				return false;
			}
			m_IndexMap = new Dictionary<CinemachineVirtualCameraBase, int>();
			for (int i = 0; i < base.ChildCameras.Count; i++)
			{
				m_IndexMap.Add(base.ChildCameras[i], i);
			}
			return true;
		}

		public override void OnTransitionFromCamera(ICinemachineCamera fromCam, Vector3 worldUp, float deltaTime)
		{
			for (int i = 0; i < 8 && i < base.ChildCameras.Count; i++)
			{
				base.ChildCameras[i].OnTransitionFromCamera(fromCam, worldUp, deltaTime);
			}
			base.OnTransitionFromCamera(fromCam, worldUp, deltaTime);
		}

		public override void InternalUpdateCameraState(Vector3 worldUp, float deltaTime)
		{
			UpdateCameraCache();
			CinemachineVirtualCameraBase activeCamera = null;
			List<CinemachineVirtualCameraBase> childCameras = base.ChildCameras;
			float num = 0f;
			float num2 = 0f;
			for (int i = 0; i < 8 && i < childCameras.Count; i++)
			{
				CinemachineVirtualCameraBase cinemachineVirtualCameraBase = childCameras[i];
				if (!cinemachineVirtualCameraBase.isActiveAndEnabled)
				{
					continue;
				}
				float num3 = Mathf.Max(0f, GetWeight(i));
				if (num3 > 0.0001f)
				{
					num2 += num3;
					if (num2 == num3)
					{
						m_CameraState = cinemachineVirtualCameraBase.State;
					}
					else
					{
						m_CameraState = CameraState.Lerp(in m_CameraState, cinemachineVirtualCameraBase.State, num3 / num2);
					}
					if (num3 > num)
					{
						num = num3;
						activeCamera = cinemachineVirtualCameraBase;
					}
				}
			}
			m_LiveChildPercent = ((num2 > 0.001f) ? (num * 100f / num2) : 0f);
			SetLiveChild(activeCamera, worldUp, deltaTime);
			InvokePostPipelineStageCallback(this, CinemachineCore.Stage.Finalize, ref m_CameraState, deltaTime);
			PreviousStateIsValid = true;
		}

		protected override CinemachineVirtualCameraBase ChooseCurrentCamera(Vector3 worldUp, float deltaTime)
		{
			return null;
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Pixel Perfect")]
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachinePixelPerfect.html")]
	public class CinemachinePixelPerfect : CinemachineExtension
	{
		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage != CinemachineCore.Stage.Body)
			{
				return;
			}
			CinemachineBrain cinemachineBrain = CinemachineCore.FindPotentialTargetBrain(vcam);
			if (!(cinemachineBrain == null) && cinemachineBrain.IsLiveChild(vcam))
			{
				cinemachineBrain.TryGetComponent<PixelPerfectCamera>(out var component);
				if (!(component == null) && component.isActiveAndEnabled)
				{
					LensSettings lens = state.Lens;
					lens.OrthographicSize = component.CorrectCinemachineOrthoSize(lens.OrthographicSize);
					state.Lens = lens;
				}
			}
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Recomposer")]
	[ExecuteAlways]
	[SaveDuringPlay]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineRecomposer.html")]
	public class CinemachineRecomposer : CinemachineExtension
	{
		[Tooltip("When to apply the adjustment")]
		[FormerlySerializedAs("m_ApplyAfter")]
		public CinemachineCore.Stage ApplyAfter;

		[Tooltip("Tilt the camera by this much")]
		[FormerlySerializedAs("m_Tilt")]
		public float Tilt;

		[Tooltip("Pan the camera by this much")]
		[FormerlySerializedAs("m_Pan")]
		public float Pan;

		[Tooltip("Roll the camera by this much")]
		[FormerlySerializedAs("m_Dutch")]
		public float Dutch;

		[Tooltip("Scale the zoom by this amount (normal = 1)")]
		[FormerlySerializedAs("m_ZoomScale")]
		public float ZoomScale;

		[Range(0f, 1f)]
		[Tooltip("Lowering this value relaxes the camera's attention to the Follow target (normal = 1)")]
		[FormerlySerializedAs("m_FollowAttachment")]
		public float FollowAttachment;

		[Range(0f, 1f)]
		[Tooltip("Lowering this value relaxes the camera's attention to the LookAt target (normal = 1)")]
		[FormerlySerializedAs("m_LookAtAttachment")]
		public float LookAtAttachment;

		private void Reset()
		{
			ApplyAfter = CinemachineCore.Stage.Finalize;
			Tilt = 0f;
			Pan = 0f;
			Dutch = 0f;
			ZoomScale = 1f;
			FollowAttachment = 1f;
			LookAtAttachment = 1f;
		}

		private void OnValidate()
		{
			ZoomScale = Mathf.Max(0.01f, ZoomScale);
			FollowAttachment = Mathf.Clamp01(FollowAttachment);
			LookAtAttachment = Mathf.Clamp01(LookAtAttachment);
		}

		public override void PrePipelineMutateCameraStateCallback(CinemachineVirtualCameraBase vcam, ref CameraState curState, float deltaTime)
		{
			vcam.FollowTargetAttachment = FollowAttachment;
			vcam.LookAtTargetAttachment = LookAtAttachment;
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage == ApplyAfter)
			{
				LensSettings lens = state.Lens;
				Quaternion quaternion2 = state.RawOrientation * Quaternion.AngleAxis(Tilt, Vector3.right);
				Quaternion quaternion3 = Quaternion.AngleAxis(Pan, state.ReferenceUp) * quaternion2;
				state.OrientationCorrection = Quaternion.Inverse(state.GetCorrectedOrientation()) * quaternion3;
				lens.Dutch += Dutch;
				if (ZoomScale != 1f)
				{
					lens.OrthographicSize *= ZoomScale;
					lens.FieldOfView *= ZoomScale;
				}
				state.Lens = lens;
			}
		}
	}
	[DisallowMultipleComponent]
	[ExecuteAlways]
	[ExcludeFromPreset]
	[SaveDuringPlay]
	[AddComponentMenu("Cinemachine/Cinemachine Sequencer Camera")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineSequencerCamera.html")]
	public class CinemachineSequencerCamera : CinemachineCameraManagerBase
	{
		[Serializable]
		public struct Instruction
		{
			[Tooltip("The camera to activate when this instruction becomes active")]
			[FormerlySerializedAs("m_VirtualCamera")]
			[ChildCameraProperty]
			public CinemachineVirtualCameraBase Camera;

			[Tooltip("How to blend to the next camera in the list (if any)")]
			[FormerlySerializedAs("m_Blend")]
			public CinemachineBlendDefinition Blend;

			[Tooltip("How long to wait (in seconds) before activating the next camera in the list (if any)")]
			[FormerlySerializedAs("m_Hold")]
			public float Hold;

			public void Validate()
			{
				Hold = Mathf.Max(Hold, 0f);
			}
		}

		[Tooltip("When enabled, the child vcams will cycle indefinitely instead of just stopping at the last one")]
		[FormerlySerializedAs("m_Loop")]
		public bool Loop;

		[Tooltip("The set of instructions for enabling child cameras.")]
		[FormerlySerializedAs("m_Instructions")]
		public List<Instruction> Instructions = new List<Instruction>();

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_LookAt")]
		private Transform m_LegacyLookAt;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_Follow")]
		private Transform m_LegacyFollow;

		private float m_ActivationTime = -1f;

		private int m_CurrentInstruction;

		protected override void Reset()
		{
			base.Reset();
			Loop = false;
			Instructions = null;
		}

		private void OnValidate()
		{
			if (Instructions != null)
			{
				for (int i = 0; i < Instructions.Count; i++)
				{
					Instruction value = Instructions[i];
					value.Validate();
					Instructions[i] = value;
				}
			}
		}

		protected internal override void PerformLegacyUpgrade(int streamedVersion)
		{
			base.PerformLegacyUpgrade(streamedVersion);
			if (streamedVersion < 20220721 && (m_LegacyLookAt != null || m_LegacyFollow != null))
			{
				DefaultTarget = new DefaultTargetSettings
				{
					Enabled = true,
					Target = new CameraTarget
					{
						LookAtTarget = m_LegacyLookAt,
						TrackingTarget = m_LegacyFollow,
						CustomLookAtTarget = (m_LegacyLookAt != m_LegacyFollow)
					}
				};
				m_LegacyLookAt = (m_LegacyFollow = null);
			}
		}

		public override void OnTransitionFromCamera(ICinemachineCamera fromCam, Vector3 worldUp, float deltaTime)
		{
			m_ActivationTime = CinemachineCore.CurrentTime;
			m_CurrentInstruction = 0;
		}

		protected override CinemachineVirtualCameraBase ChooseCurrentCamera(Vector3 worldUp, float deltaTime)
		{
			if (!PreviousStateIsValid)
			{
				m_CurrentInstruction = -1;
			}
			AdvanceCurrentInstruction(deltaTime);
			if (m_CurrentInstruction < 0 || m_CurrentInstruction >= Instructions.Count)
			{
				return null;
			}
			return Instructions[m_CurrentInstruction].Camera;
		}

		protected override CinemachineBlendDefinition LookupBlend(ICinemachineCamera outgoing, ICinemachineCamera incoming)
		{
			return Instructions[m_CurrentInstruction].Blend;
		}

		protected override bool UpdateCameraCache()
		{
			if (Instructions == null)
			{
				Instructions = new List<Instruction>();
			}
			return base.UpdateCameraCache();
		}

		private void AdvanceCurrentInstruction(float deltaTime)
		{
			if (base.ChildCameras == null || base.ChildCameras.Count == 0 || m_ActivationTime < 0f || Instructions.Count == 0)
			{
				m_ActivationTime = -1f;
				m_CurrentInstruction = -1;
				return;
			}
			float currentTime = CinemachineCore.CurrentTime;
			if (m_CurrentInstruction < 0 || deltaTime < 0f)
			{
				m_ActivationTime = currentTime;
				m_CurrentInstruction = 0;
			}
			if (m_CurrentInstruction > Instructions.Count - 1)
			{
				m_ActivationTime = currentTime;
				m_CurrentInstruction = Instructions.Count - 1;
			}
			float b = Instructions[m_CurrentInstruction].Hold + Instructions[m_CurrentInstruction].Blend.BlendTime;
			float a = ((m_CurrentInstruction < Instructions.Count - 1 || Loop) ? 0f : float.MaxValue);
			if (currentTime - m_ActivationTime > Mathf.Max(a, b))
			{
				m_ActivationTime = currentTime;
				m_CurrentInstruction++;
				if (Loop && m_CurrentInstruction == Instructions.Count)
				{
					m_CurrentInstruction = 0;
				}
			}
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Shot Quality Evaluator")]
	[SaveDuringPlay]
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.Tracking)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineShotQualityEvaluator.html")]
	public class CinemachineShotQualityEvaluator : CinemachineExtension, IShotQualityEvaluator
	{
		[Serializable]
		public struct DistanceEvaluationSettings
		{
			[Tooltip("If enabled, will evaluate shot quality based on target distance")]
			public bool Enabled;

			[Tooltip("If greater than zero, maximum quality boost will occur when target is this far from the camera")]
			public float OptimalDistance;

			[Tooltip("Shots with targets closer to the camera than this will not get a quality boost")]
			public float NearLimit;

			[Tooltip("Shots with targets farther from the camera than this will not get a quality boost")]
			public float FarLimit;

			[Tooltip("High quality shots will be boosted by this fraction of their normal quality")]
			public float MaxQualityBoost;

			internal static DistanceEvaluationSettings Default => new DistanceEvaluationSettings
			{
				NearLimit = 5f,
				FarLimit = 30f,
				OptimalDistance = 10f,
				MaxQualityBoost = 0.2f
			};
		}

		[Tooltip("Objects on these layers will be detected")]
		public LayerMask OcclusionLayers = 1;

		[TagField]
		[Tooltip("Obstacles with this tag will be ignored.  It is a good idea to set this field to the target's tag")]
		public string IgnoreTag = string.Empty;

		[Tooltip("Obstacles closer to the target than this will be ignored")]
		public float MinimumDistanceFromTarget = 0.2f;

		[Tooltip("Radius of the spherecast that will be done to check for occlusions.")]
		public float CameraRadius;

		[FoldoutWithEnabledButton("Enabled")]
		public DistanceEvaluationSettings DistanceEvaluation = DistanceEvaluationSettings.Default;

		private void OnValidate()
		{
			CameraRadius = Mathf.Max(0f, CameraRadius);
			MinimumDistanceFromTarget = Mathf.Max(0.01f, MinimumDistanceFromTarget);
			CameraRadius = Mathf.Max(0f, CameraRadius);
			DistanceEvaluation.NearLimit = Mathf.Max(0.1f, DistanceEvaluation.NearLimit);
			DistanceEvaluation.FarLimit = Mathf.Max(DistanceEvaluation.NearLimit, DistanceEvaluation.FarLimit);
			DistanceEvaluation.OptimalDistance = Mathf.Clamp(DistanceEvaluation.OptimalDistance, DistanceEvaluation.NearLimit, DistanceEvaluation.FarLimit);
		}

		private void Reset()
		{
			OcclusionLayers = 1;
			IgnoreTag = string.Empty;
			MinimumDistanceFromTarget = 0.2f;
			CameraRadius = 0f;
			DistanceEvaluation = DistanceEvaluationSettings.Default;
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage != CinemachineCore.Stage.Finalize || !state.HasLookAt())
			{
				return;
			}
			if (state.IsTargetOffscreen() || IsTargetObscured(state))
			{
				state.ShotQuality *= 0.2f;
			}
			if (!DistanceEvaluation.Enabled)
			{
				return;
			}
			float num = 0f;
			if (!(DistanceEvaluation.OptimalDistance > 0f))
			{
				return;
			}
			float num2 = Vector3.Magnitude(state.ReferenceLookAt - state.GetFinalPosition());
			if (num2 <= DistanceEvaluation.OptimalDistance)
			{
				if (num2 >= DistanceEvaluation.NearLimit)
				{
					num = DistanceEvaluation.MaxQualityBoost * (num2 - DistanceEvaluation.NearLimit) / (DistanceEvaluation.OptimalDistance - DistanceEvaluation.NearLimit);
				}
			}
			else
			{
				num2 -= DistanceEvaluation.OptimalDistance;
				if (num2 < DistanceEvaluation.FarLimit)
				{
					num = DistanceEvaluation.MaxQualityBoost * (1f - num2 / DistanceEvaluation.FarLimit);
				}
			}
			state.ShotQuality *= 1f + num;
		}

		private bool IsTargetObscured(CameraState state)
		{
			Vector3 referenceLookAt = state.ReferenceLookAt;
			Vector3 correctedPosition = state.GetCorrectedPosition();
			Vector3 vector = referenceLookAt - correctedPosition;
			float magnitude = vector.magnitude;
			if (magnitude < Mathf.Max(MinimumDistanceFromTarget, 0.0001f))
			{
				return true;
			}
			RaycastHit hitInfo;
			return RuntimeUtility.SphereCastIgnoreTag(new Ray(correctedPosition, vector.normalized), CameraRadius, out hitInfo, magnitude - MinimumDistanceFromTarget, OcclusionLayers, in IgnoreTag);
		}
	}
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Spline Cart")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineSplineCart.html")]
	public class CinemachineSplineCart : MonoBehaviour, ISplineReferencer
	{
		public enum UpdateMethods
		{
			Update,
			FixedUpdate,
			LateUpdate
		}

		[SerializeField]
		[FormerlySerializedAs("SplineSettings")]
		private SplineSettings m_SplineSettings = new SplineSettings
		{
			Units = PathIndexUnit.Normalized
		};

		[Tooltip("When to move the cart, if Speed is non-zero")]
		public UpdateMethods UpdateMethod;

		[FoldoutWithEnabledButton("Enabled")]
		[Tooltip("Controls how automatic dollying occurs.  A tracking target may be necessary to use this feature.")]
		public SplineAutoDolly AutomaticDolly;

		[Tooltip("Used only by Automatic Dolly settings that require it")]
		public Transform TrackingTarget;

		private CinemachineSplineRoll.RollCache m_RollCache;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("SplinePosition")]
		private float m_LegacyPosition = -1f;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("PositionUnits")]
		private PathIndexUnit m_LegacyUnits;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("Spline")]
		private SplineContainer m_LegacySpline;

		public ref SplineSettings SplineSettings => ref m_SplineSettings;

		public SplineContainer Spline
		{
			get
			{
				return m_SplineSettings.Spline;
			}
			set
			{
				m_SplineSettings.Spline = value;
			}
		}

		public float SplinePosition
		{
			get
			{
				return m_SplineSettings.Position;
			}
			set
			{
				m_SplineSettings.Position = value;
			}
		}

		public PathIndexUnit PositionUnits
		{
			get
			{
				return m_SplineSettings.Units;
			}
			set
			{
				m_SplineSettings.ChangeUnitPreservePosition(value);
			}
		}

		private void PerformLegacyUpgrade()
		{
			if (m_LegacyPosition != -1f)
			{
				m_SplineSettings.Position = m_LegacyPosition;
				m_SplineSettings.Units = m_LegacyUnits;
				m_LegacyPosition = -1f;
				m_LegacyUnits = PathIndexUnit.Distance;
			}
			if (m_LegacySpline != null)
			{
				m_SplineSettings.Spline = m_LegacySpline;
				m_LegacySpline = null;
			}
		}

		private void OnValidate()
		{
			PerformLegacyUpgrade();
			AutomaticDolly.Method?.Validate();
		}

		private void Reset()
		{
			m_SplineSettings = new SplineSettings
			{
				Units = PathIndexUnit.Normalized
			};
			UpdateMethod = UpdateMethods.Update;
			AutomaticDolly.Method = null;
			TrackingTarget = null;
		}

		private void OnEnable()
		{
			m_RollCache.Refresh(this);
			AutomaticDolly.Method?.Reset();
		}

		private void OnDisable()
		{
			SplineSettings.InvalidateCache();
		}

		private void FixedUpdate()
		{
			if (UpdateMethod == UpdateMethods.FixedUpdate)
			{
				UpdateCartPosition();
			}
		}

		private void Update()
		{
			if (!Application.isPlaying)
			{
				SetCartPosition(SplinePosition);
			}
			else if (UpdateMethod == UpdateMethods.Update)
			{
				UpdateCartPosition();
			}
		}

		private void LateUpdate()
		{
			if (!Application.isPlaying)
			{
				SetCartPosition(SplinePosition);
			}
			else if (UpdateMethod == UpdateMethods.LateUpdate)
			{
				UpdateCartPosition();
			}
		}

		private void UpdateCartPosition()
		{
			if (AutomaticDolly.Enabled && AutomaticDolly.Method != null)
			{
				SplinePosition = AutomaticDolly.Method.GetSplinePosition(this, TrackingTarget, Spline, SplinePosition, PositionUnits, Time.deltaTime);
			}
			SetCartPosition(SplinePosition);
		}

		private void SetCartPosition(float distanceAlongPath)
		{
			CachedScaledSpline cachedSpline = m_SplineSettings.GetCachedSpline();
			if (cachedSpline != null)
			{
				Spline spline = Spline.Splines[0];
				SplinePosition = cachedSpline.StandardizePosition(distanceAlongPath, PositionUnits, out var _);
				float tNormalized = spline.ConvertIndexUnit(SplinePosition, PositionUnits, PathIndexUnit.Normalized);
				cachedSpline.EvaluateSplineWithRoll(Spline.transform, tNormalized, m_RollCache.GetSplineRoll(this), out var position, out var rotation);
				base.transform.ConservativeSetPositionAndRotation(position, rotation);
			}
		}
	}
	[ExecuteInEditMode]
	[DisallowMultipleComponent]
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Spline Roll")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineSplineRoll.html")]
	[SaveDuringPlay]
	public class CinemachineSplineRoll : MonoBehaviour, ISerializationCallbackReceiver
	{
		[Serializable]
		public struct RollData
		{
			[Tooltip("Roll (in degrees) around the forward direction for specific location on the track.\n- When placed on a SplineContainer, this is going to be a global override that affects all vcams using the Spline.\n- When placed on a CinemachineCamera, this is going to be a local override that only affects that CinemachineCamera.")]
			public float Value;

			public static implicit operator float(RollData roll)
			{
				return roll.Value;
			}

			public static implicit operator RollData(float roll)
			{
				return new RollData
				{
					Value = roll
				};
			}
		}

		[StructLayout(LayoutKind.Sequential, Size = 1)]
		public struct LerpRollData : IInterpolator<RollData>
		{
			public RollData Interpolate(RollData a, RollData b, float t)
			{
				return new RollData
				{
					Value = Mathf.Lerp(a.Value, b.Value, t)
				};
			}
		}

		[StructLayout(LayoutKind.Sequential, Size = 1)]
		public struct LerpRollDataWithEasing : IInterpolator<RollData>
		{
			public RollData Interpolate(RollData a, RollData b, float t)
			{
				float num = t * t;
				float num2 = 1f - t;
				t = 3f * num2 * num + t * num;
				return new RollData
				{
					Value = Mathf.Lerp(a.Value, b.Value, t)
				};
			}
		}

		internal struct RollCache
		{
			private CinemachineSplineRoll m_RollCache;

			public void Refresh(MonoBehaviour owner)
			{
				m_RollCache = null;
				if (!owner.TryGetComponent<CinemachineSplineRoll>(out m_RollCache) && owner is ISplineReferencer splineReferencer)
				{
					SplineContainer spline = splineReferencer.SplineSettings.Spline;
					if (spline != null)
					{
						spline?.TryGetComponent<CinemachineSplineRoll>(out m_RollCache);
					}
				}
			}

			public CinemachineSplineRoll GetSplineRoll(MonoBehaviour owner)
			{
				return m_RollCache;
			}
		}

		[Tooltip("When enabled, roll eases into and out of the data point values.  Otherwise, interpolation is linear.")]
		public bool Easing = true;

		[HideFoldout]
		public SplineData<RollData> Roll;

		[HideInInspector]
		[SerializeField]
		[NoSaveDuringPlay]
		private int m_StreamingVersion;

		public IInterpolator<RollData> GetInterpolator()
		{
			if (!Easing)
			{
				return default(LerpRollData);
			}
			return default(LerpRollDataWithEasing);
		}

		private void PerformLegacyUpgrade(int streamedVersion)
		{
			if (streamedVersion < 20240101)
			{
				for (int i = 0; i < Roll.Count; i++)
				{
					DataPoint<RollData> value = Roll[i];
					value.Value = 0f - (float)value.Value;
					Roll[i] = value;
				}
			}
		}

		private void Reset()
		{
			Roll?.Clear();
			Easing = true;
		}

		private void OnEnable()
		{
		}

		public void OnBeforeSerialize()
		{
		}

		public void OnAfterDeserialize()
		{
			if (m_StreamingVersion < 20241001)
			{
				PerformLegacyUpgrade(m_StreamingVersion);
			}
			m_StreamingVersion = 20241001;
		}
	}
	[DisallowMultipleComponent]
	[ExecuteAlways]
	[ExcludeFromPreset]
