	[AddComponentMenu("Cinemachine/Cinemachine State Driven Camera")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineStateDrivenCamera.html")]
	public class CinemachineStateDrivenCamera : CinemachineCameraManagerBase
	{
		[Serializable]
		public struct Instruction
		{
			[Tooltip("The full hash of the animation state")]
			[FormerlySerializedAs("m_FullHash")]
			public int FullHash;

			[Tooltip("The virtual camera to activate when the animation state becomes active")]
			[FormerlySerializedAs("m_VirtualCamera")]
			[ChildCameraProperty]
			public CinemachineVirtualCameraBase Camera;

			[Tooltip("How long to wait (in seconds) before activating the camera. This filters out very short state durations")]
			[FormerlySerializedAs("m_ActivateAfter")]
			public float ActivateAfter;

			[Tooltip("The minimum length of time (in seconds) to keep a camera active")]
			[FormerlySerializedAs("m_MinDuration")]
			public float MinDuration;
		}

		[Serializable]
		internal struct ParentHash
		{
			public int Hash;

			public int HashOfParent;
		}

		private struct HashPair
		{
			public int parentHash;

			public int hash;
		}

		[Space]
		[Tooltip("The state machine whose state changes will drive this camera's choice of active child")]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_AnimatedTarget")]
		public Animator AnimatedTarget;

		[Tooltip("Which layer in the target state machine to observe")]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_LayerIndex")]
		public int LayerIndex;

		[Tooltip("The set of instructions associating cameras with states.  These instructions are used to choose the live child at any given moment")]
		[FormerlySerializedAs("m_Instructions")]
		public Instruction[] Instructions;

		[HideInInspector]
		[SerializeField]
		[NoSaveDuringPlay]
		private List<ParentHash> HashOfParent = new List<ParentHash>();

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_LookAt")]
		private Transform m_LegacyLookAt;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_Follow")]
		private Transform m_LegacyFollow;

		private float m_ActivationTime;

		private int m_ActiveInstructionIndex;

		private float m_PendingActivationTime;

		private int m_PendingInstructionIndex;

		private Dictionary<int, List<int>> m_InstructionDictionary;

		private Dictionary<int, int> m_StateParentLookup;

		private readonly List<AnimatorClipInfo> m_ClipInfoList = new List<AnimatorClipInfo>();

		private Dictionary<AnimationClip, List<HashPair>> m_HashCache;

		internal void SetParentHash(List<ParentHash> list)
		{
			HashOfParent.Clear();
			HashOfParent.AddRange(list);
		}

		protected override void Reset()
		{
			base.Reset();
			Instructions = null;
			AnimatedTarget = null;
			LayerIndex = 0;
			Instructions = null;
			DefaultBlend = new CinemachineBlendDefinition(CinemachineBlendDefinition.Styles.EaseInOut, 0.5f);
			CustomBlends = null;
		}

		protected internal override void PerformLegacyUpgrade(int streamedVersion)
		{
			base.PerformLegacyUpgrade(streamedVersion);
			if (streamedVersion < 20220721 && (m_LegacyLookAt != null || m_LegacyFollow != null))
			{
				DefaultTarget = new DefaultTargetSettings
				{
					Enabled = true,
					Target = new CameraTarget
					{
						LookAtTarget = m_LegacyLookAt,
						TrackingTarget = m_LegacyFollow,
						CustomLookAtTarget = (m_LegacyLookAt != m_LegacyFollow)
					}
				};
				m_LegacyLookAt = (m_LegacyFollow = null);
			}
		}

		internal static int CreateFakeHash(int parentHash, AnimationClip clip)
		{
			return Animator.StringToHash(parentHash + "_" + clip.name);
		}

		private int LookupFakeHash(int parentHash, AnimationClip clip)
		{
			if (m_HashCache == null)
			{
				m_HashCache = new Dictionary<AnimationClip, List<HashPair>>();
			}
			if (!m_HashCache.TryGetValue(clip, out var value))
			{
				value = new List<HashPair>();
				m_HashCache[clip] = value;
			}
			for (int i = 0; i < value.Count; i++)
			{
				if (value[i].parentHash == parentHash)
				{
					return value[i].hash;
				}
			}
			int num = CreateFakeHash(parentHash, clip);
			value.Add(new HashPair
			{
				parentHash = parentHash,
				hash = num
			});
			m_StateParentLookup[num] = parentHash;
			return num;
		}

		internal void ValidateInstructions()
		{
			if (Instructions == null)
			{
				Instructions = Array.Empty<Instruction>();
			}
			m_InstructionDictionary = new Dictionary<int, List<int>>();
			for (int i = 0; i < Instructions.Length; i++)
			{
				if (!m_InstructionDictionary.TryGetValue(Instructions[i].FullHash, out var value))
				{
					value = new List<int>();
					m_InstructionDictionary[Instructions[i].FullHash] = value;
				}
				value.Add(i);
			}
			m_StateParentLookup = new Dictionary<int, int>();
			int num = 0;
			while (HashOfParent != null && num < HashOfParent.Count)
			{
				m_StateParentLookup[HashOfParent[num].Hash] = HashOfParent[num].HashOfParent;
				num++;
			}
			m_HashCache = null;
			m_ActivationTime = (m_PendingActivationTime = 0f);
			ResetLiveChild();
		}

		protected override CinemachineVirtualCameraBase ChooseCurrentCamera(Vector3 worldUp, float deltaTime)
		{
			if (!PreviousStateIsValid)
			{
				ValidateInstructions();
			}
			List<CinemachineVirtualCameraBase> childCameras = base.ChildCameras;
			if (childCameras == null || childCameras.Count == 0)
			{
				m_ActivationTime = 0f;
				return null;
			}
			CinemachineVirtualCameraBase result = childCameras[0];
			if (AnimatedTarget == null || !AnimatedTarget.gameObject.activeSelf || AnimatedTarget.runtimeAnimatorController == null || LayerIndex < 0 || !AnimatedTarget.hasBoundPlayables || LayerIndex >= AnimatedTarget.layerCount)
			{
				m_ActivationTime = 0f;
				return result;
			}
			if (m_ActiveInstructionIndex < 0 || m_ActiveInstructionIndex >= Instructions.Length)
			{
				m_ActiveInstructionIndex = 0;
				m_ActivationTime = 0f;
			}
			if (!PreviousStateIsValid || m_PendingInstructionIndex < 0 || m_PendingInstructionIndex >= Instructions.Length)
			{
				m_PendingInstructionIndex = 0;
				m_PendingActivationTime = 0f;
			}
			int num;
			if (AnimatedTarget.IsInTransition(LayerIndex))
			{
				AnimatorStateInfo nextAnimatorStateInfo = AnimatedTarget.GetNextAnimatorStateInfo(LayerIndex);
				AnimatedTarget.GetNextAnimatorClipInfo(LayerIndex, m_ClipInfoList);
				num = GetClipHash(nextAnimatorStateInfo.fullPathHash, m_ClipInfoList);
			}
			else
			{
				AnimatorStateInfo currentAnimatorStateInfo = AnimatedTarget.GetCurrentAnimatorStateInfo(LayerIndex);
				AnimatedTarget.GetCurrentAnimatorClipInfo(LayerIndex, m_ClipInfoList);
				num = GetClipHash(currentAnimatorStateInfo.fullPathHash, m_ClipInfoList);
			}
			while (num != 0 && !m_InstructionDictionary.ContainsKey(num))
			{
				num = (m_StateParentLookup.ContainsKey(num) ? m_StateParentLookup[num] : 0);
			}
			int num2 = -1;
			if (m_InstructionDictionary.ContainsKey(num))
			{
				List<int> list = m_InstructionDictionary[num];
				int num3 = int.MinValue;
				for (int i = 0; i < list.Count; i++)
				{
					int num4 = list[i];
					CinemachineVirtualCameraBase cinemachineVirtualCameraBase = ((num4 < Instructions.Length) ? Instructions[num4].Camera : null);
					if (cinemachineVirtualCameraBase != null && cinemachineVirtualCameraBase.isActiveAndEnabled && cinemachineVirtualCameraBase.Priority.Value > num3)
					{
						num2 = num4;
						num3 = cinemachineVirtualCameraBase.Priority.Value;
					}
				}
			}
			float currentTime = CinemachineCore.CurrentTime;
			if (num2 >= 0)
			{
				if (m_ActivationTime == 0f)
				{
					m_ActiveInstructionIndex = num2;
					m_ActivationTime = currentTime;
					m_PendingActivationTime = 0f;
				}
				else if (m_ActiveInstructionIndex != num2 && (m_PendingActivationTime == 0f || m_PendingInstructionIndex != num2))
				{
					m_PendingInstructionIndex = num2;
					m_PendingActivationTime = currentTime;
				}
			}
			if (m_PendingActivationTime != 0f && currentTime - m_PendingActivationTime > Instructions[m_PendingInstructionIndex].ActivateAfter && currentTime - m_ActivationTime > Instructions[m_ActiveInstructionIndex].MinDuration)
			{
				m_ActiveInstructionIndex = m_PendingInstructionIndex;
				m_ActivationTime = currentTime;
				m_PendingActivationTime = 0f;
			}
			if (m_ActivationTime != 0f)
			{
				return Instructions[m_ActiveInstructionIndex].Camera;
			}
			return result;
		}

		private int GetClipHash(int hash, List<AnimatorClipInfo> clips)
		{
			int num = -1;
			for (int i = 0; i < clips.Count; i++)
			{
				if (num < 0 || clips[i].weight > clips[num].weight)
				{
					num = i;
				}
			}
			if (num >= 0 && clips[num].weight > 0f)
			{
				hash = LookupFakeHash(hash, clips[num].clip);
			}
			return hash;
		}

		public void CancelWait()
		{
			if (m_PendingActivationTime != 0f && m_PendingInstructionIndex >= 0 && m_PendingInstructionIndex < Instructions.Length)
			{
				m_ActiveInstructionIndex = m_PendingInstructionIndex;
				m_ActivationTime = CinemachineCore.CurrentTime;
				m_PendingActivationTime = 0f;
			}
		}
	}
	[SaveDuringPlay]
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Storyboard")]
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineStoryboard.html")]
	public class CinemachineStoryboard : CinemachineExtension
	{
		public enum FillStrategy
		{
			BestFit,
			CropImageToFit,
			StretchToFit
		}

		private class CanvasInfo
		{
			public GameObject Canvas;

			public Canvas CanvasComponent;

			public CinemachineBrain CanvasParent;

			public RectTransform Viewport;

			public RawImage RawImage;
		}

		public enum StoryboardRenderMode
		{
			ScreenSpaceOverlay,
			ScreenSpaceCamera
		}

		[Tooltip("If checked, all storyboards are globally muted")]
		public static bool s_StoryboardGlobalMute;

		[Tooltip("If checked, the specified image will be displayed as an overlay over the virtual camera's output")]
		[FormerlySerializedAs("m_ShowImage")]
		public bool ShowImage = true;

		[Tooltip("The image to display")]
		[FormerlySerializedAs("m_Image")]
		public Texture Image;

		[Tooltip("How to handle differences between image aspect and screen aspect")]
		[FormerlySerializedAs("m_Aspect")]
		public FillStrategy Aspect;

		[Tooltip("The opacity of the image.  0 is transparent, 1 is opaque")]
		[FormerlySerializedAs("m_Alpha")]
		[Range(0f, 1f)]
		public float Alpha = 1f;

		[Tooltip("The screen-space position at which to display the image.  Zero is center")]
		[FormerlySerializedAs("m_Center")]
		public Vector2 Center = Vector2.zero;

		[Tooltip("The screen-space rotation to apply to the image")]
		[FormerlySerializedAs("m_Rotation")]
		public Vector3 Rotation = Vector3.zero;

		[Tooltip("The screen-space scaling to apply to the image")]
		[FormerlySerializedAs("m_Scale")]
		public Vector2 Scale = Vector3.one;

		[Tooltip("If checked, X and Y scale are synchronized")]
		[FormerlySerializedAs("m_SyncScale")]
		public bool SyncScale = true;

		[Tooltip("If checked, Camera transform will not be controlled by this virtual camera")]
		[FormerlySerializedAs("m_MuteCamera")]
		public bool MuteCamera;

		[Range(-1f, 1f)]
		[Tooltip("Wipe the image on and off horizontally")]
		[FormerlySerializedAs("m_SplitView")]
		public float SplitView;

		[Tooltip("The render mode of the canvas on which the storyboard is drawn.")]
		[FormerlySerializedAs("m_RenderMode")]
		public StoryboardRenderMode RenderMode;

		[Tooltip("Allows ordering canvases to render on top or below other canvases.")]
		[FormerlySerializedAs("m_SortingOrder")]
		public int SortingOrder;

		[Tooltip("How far away from the camera is the Canvas generated.")]
		[FormerlySerializedAs("m_PlaneDistance")]
		public float PlaneDistance = 100f;

		private List<CanvasInfo> m_CanvasInfo = new List<CanvasInfo>();

		private string CanvasName => "_CM_canvas" + base.gameObject.GetInstanceID();

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (!(vcam != base.ComponentOwner) && stage == CinemachineCore.Stage.Finalize)
			{
				UpdateRenderCanvas();
				if (ShowImage)
				{
					state.AddCustomBlendable(new CameraState.CustomBlendableItems.Item
					{
						Custom = this,
						Weight = 1f
					});
				}
				if (MuteCamera)
				{
					state.BlendHint |= (CameraState.BlendHints)458752;
				}
			}
		}

		private void UpdateRenderCanvas()
		{
			for (int i = 0; i < m_CanvasInfo.Count; i++)
			{
				if (m_CanvasInfo[i] == null || m_CanvasInfo[i].CanvasComponent == null)
				{
					m_CanvasInfo.RemoveAt(i--);
					continue;
				}
				m_CanvasInfo[i].CanvasComponent.renderMode = (RenderMode)RenderMode;
				m_CanvasInfo[i].CanvasComponent.planeDistance = PlaneDistance;
				m_CanvasInfo[i].CanvasComponent.sortingOrder = SortingOrder;
			}
		}

		protected override void ConnectToVcam(bool connect)
		{
			base.ConnectToVcam(connect);
			CinemachineCore.CameraUpdatedEvent.RemoveListener(CameraUpdatedCallback);
			if (connect)
			{
				CinemachineCore.CameraUpdatedEvent.AddListener(CameraUpdatedCallback);
			}
			else
			{
				DestroyCanvas();
			}
		}

		private void CameraUpdatedCallback(CinemachineBrain brain)
		{
			CinemachineVirtualCameraBase componentOwner = base.ComponentOwner;
			if (!(componentOwner == null))
			{
				bool flag = base.enabled && ShowImage && CinemachineCore.IsLive(componentOwner);
				uint outputChannel = (uint)componentOwner.OutputChannel;
				if (s_StoryboardGlobalMute || ((uint)brain.ChannelMask & outputChannel) == 0)
				{
					flag = false;
				}
				CanvasInfo canvasInfo = LocateMyCanvas(brain, flag);
				if (canvasInfo != null && canvasInfo.Canvas != null)
				{
					canvasInfo.Canvas.SetActive(flag);
				}
			}
		}

		private CanvasInfo LocateMyCanvas(CinemachineBrain parent, bool createIfNotFound)
		{
			CanvasInfo canvasInfo = null;
			int num = 0;
			while (canvasInfo == null && num < m_CanvasInfo.Count)
			{
				if (m_CanvasInfo[num] != null && m_CanvasInfo[num].CanvasParent == parent)
				{
					canvasInfo = m_CanvasInfo[num];
				}
				num++;
			}
			if (createIfNotFound)
			{
				if (canvasInfo == null)
				{
					canvasInfo = new CanvasInfo
					{
						CanvasParent = parent
					};
					int childCount = parent.transform.childCount;
					int num2 = 0;
					while (canvasInfo.Canvas == null && num2 < childCount)
					{
						RectTransform rectTransform = parent.transform.GetChild(num2) as RectTransform;
						if (rectTransform != null && rectTransform.name == CanvasName)
						{
							canvasInfo.Canvas = rectTransform.gameObject;
							RectTransform[] componentsInChildren = canvasInfo.Canvas.GetComponentsInChildren<RectTransform>();
							canvasInfo.Viewport = ((componentsInChildren.Length > 1) ? componentsInChildren[1] : null);
							canvasInfo.RawImage = canvasInfo.Canvas.GetComponentInChildren<RawImage>();
							canvasInfo.CanvasComponent = canvasInfo.Canvas.GetComponent<Canvas>();
						}
						num2++;
					}
					m_CanvasInfo.Add(canvasInfo);
				}
				if (canvasInfo.Canvas == null || canvasInfo.Viewport == null || canvasInfo.RawImage == null || canvasInfo.CanvasComponent == null)
				{
					CreateCanvas(canvasInfo);
				}
			}
			return canvasInfo;
		}

		private void CreateCanvas(CanvasInfo ci)
		{
			ci.Canvas = new GameObject(CanvasName, typeof(RectTransform));
			ci.Canvas.layer = base.gameObject.layer;
			ci.Canvas.hideFlags = HideFlags.HideAndDontSave;
			ci.Canvas.transform.SetParent(ci.CanvasParent.transform);
			Canvas canvas = (ci.CanvasComponent = ci.Canvas.AddComponent<Canvas>());
			canvas.renderMode = (RenderMode)RenderMode;
			canvas.sortingOrder = SortingOrder;
			canvas.planeDistance = PlaneDistance;
			canvas.worldCamera = ci.CanvasParent.OutputCamera;
			GameObject gameObject = new GameObject("Viewport", typeof(RectTransform));
			gameObject.transform.SetParent(ci.Canvas.transform);
			ci.Viewport = (RectTransform)gameObject.transform;
			gameObject.AddComponent<RectMask2D>();
			gameObject = new GameObject("RawImage", typeof(RectTransform));
			gameObject.transform.SetParent(ci.Viewport.transform);
			ci.RawImage = gameObject.AddComponent<RawImage>();
		}

		private void DestroyCanvas()
		{
			int activeBrainCount = CinemachineBrain.ActiveBrainCount;
			for (int i = 0; i < activeBrainCount; i++)
			{
				CinemachineBrain activeBrain = CinemachineBrain.GetActiveBrain(i);
				for (int num = activeBrain.transform.childCount - 1; num >= 0; num--)
				{
					RectTransform rectTransform = activeBrain.transform.GetChild(num) as RectTransform;
					if (rectTransform != null && rectTransform.name == CanvasName)
					{
						RuntimeUtility.DestroyObject(rectTransform.gameObject);
					}
				}
			}
			m_CanvasInfo.Clear();
		}

		private void PlaceImage(CanvasInfo ci, float alpha)
		{
			if (!(ci.RawImage != null) || !(ci.Viewport != null))
			{
				return;
			}
			Rect rect = new Rect(0f, 0f, Screen.width, Screen.height);
			if (ci.CanvasParent.OutputCamera != null)
			{
				rect = ci.CanvasParent.OutputCamera.pixelRect;
			}
			rect.x -= (float)Screen.width / 2f;
			rect.y -= (float)Screen.height / 2f;
			float num = (0f - Mathf.Clamp(SplitView, -1f, 1f)) * rect.width;
			Vector2 center = rect.center;
			center.x -= num / 2f;
			ci.Viewport.localPosition = center;
			ci.Viewport.localRotation = Quaternion.identity;
			ci.Viewport.localScale = Vector3.one;
			ci.Viewport.ForceUpdateRectTransforms();
			ci.Viewport.sizeDelta = new Vector2(rect.width + 1f - Mathf.Abs(num), rect.height + 1f);
			Vector2 one = Vector2.one;
			if (Image != null && Image.width > 0 && Image.width > 0 && rect.width > 0f && rect.height > 0f)
			{
				float num2 = rect.height * (float)Image.width / (rect.width * (float)Image.height);
				switch (Aspect)
				{
				case FillStrategy.BestFit:
					if (num2 >= 1f)
					{
						one.y /= num2;
					}
					else
					{
						one.x *= num2;
					}
					break;
				case FillStrategy.CropImageToFit:
					if (num2 >= 1f)
					{
						one.x *= num2;
					}
					else
					{
						one.y /= num2;
					}
					break;
				}
			}
			one.x *= Scale.x;
			one.y *= (SyncScale ? Scale.x : Scale.y);
			ci.RawImage.texture = Image;
			Color white = Color.white;
			white.a = Alpha * alpha;
			ci.RawImage.color = white;
			center = new Vector2(rect.width * Center.x, rect.height * Center.y);
			center.x += num / 2f;
			ci.RawImage.rectTransform.localPosition = center;
			ci.RawImage.rectTransform.localRotation = Quaternion.Euler(Rotation);
			ci.RawImage.rectTransform.localScale = one;
			ci.RawImage.rectTransform.ForceUpdateRectTransforms();
			ci.RawImage.rectTransform.sizeDelta = rect.size;
		}

		private static void StaticBlendingHandler(CinemachineBrain brain)
		{
			CameraState state = brain.State;
			int numCustomBlendables = state.GetNumCustomBlendables();
			for (int i = 0; i < numCustomBlendables; i++)
			{
				CameraState.CustomBlendableItems.Item customBlendable = state.GetCustomBlendable(i);
				CinemachineStoryboard cinemachineStoryboard = customBlendable.Custom as CinemachineStoryboard;
				if (cinemachineStoryboard != null && cinemachineStoryboard.ComponentOwner != null)
				{
					bool createIfNotFound = true;
					uint outputChannel = (uint)cinemachineStoryboard.ComponentOwner.OutputChannel;
					if (s_StoryboardGlobalMute || ((uint)brain.ChannelMask & outputChannel) == 0)
					{
						createIfNotFound = false;
					}
					CanvasInfo canvasInfo = cinemachineStoryboard.LocateMyCanvas(brain, createIfNotFound);
					if (canvasInfo != null)
					{
						cinemachineStoryboard.PlaceImage(canvasInfo, customBlendable.Weight);
					}
				}
			}
		}

		[RuntimeInitializeOnLoadMethod]
		private static void InitializeModule()
		{
			CinemachineCore.CameraUpdatedEvent.RemoveListener(StaticBlendingHandler);
			CinemachineCore.CameraUpdatedEvent.AddListener(StaticBlendingHandler);
		}
	}
	public interface ICinemachineTargetGroup
	{
		bool IsValid { get; }

		Transform Transform { get; }

		Bounds BoundingBox { get; }

		BoundingSphere Sphere { get; }

		bool IsEmpty { get; }

		Bounds GetViewSpaceBoundingBox(Matrix4x4 observer, bool includeBehind);

		void GetViewSpaceAngularBounds(Matrix4x4 observer, out Vector2 minAngles, out Vector2 maxAngles, out Vector2 zRange);
	}
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Target Group")]
	[SaveDuringPlay]
	[ExecuteAlways]
	[DisallowMultipleComponent]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineTargetGroup.html")]
	public class CinemachineTargetGroup : MonoBehaviour, ICinemachineTargetGroup
	{
		[Serializable]
		public class Target
		{
			[Tooltip("The target object.  This object's position and rotation will contribute to the group's average position and rotation, in accordance with its weight")]
			[FormerlySerializedAs("target")]
			public Transform Object;

			[Tooltip("How much weight to give the target when averaging.  Cannot be negative")]
			[FormerlySerializedAs("weight")]
			public float Weight = 1f;

			[Tooltip("The radius of the target, used for calculating the bounding box.  Cannot be negative")]
			[FormerlySerializedAs("radius")]
			public float Radius = 0.5f;
		}

		public enum PositionModes
		{
			GroupCenter,
			GroupAverage
		}

		public enum RotationModes
		{
			Manual,
			GroupAverage
		}

		public enum UpdateMethods
		{
			Update,
			FixedUpdate,
			LateUpdate
		}

		[Tooltip("How the group's position is calculated.  Select GroupCenter for the center of the bounding box, and GroupAverage for a weighted average of the positions of the members.")]
		[FormerlySerializedAs("m_PositionMode")]
		public PositionModes PositionMode;

		[Tooltip("How the group's rotation is calculated.  Select Manual to use the value in the group's transform, and GroupAverage for a weighted average of the orientations of the members.")]
		[FormerlySerializedAs("m_RotationMode")]
		public RotationModes RotationMode;

		[Tooltip("When to update the group's transform based on the position of the group members")]
		[FormerlySerializedAs("m_UpdateMethod")]
		public UpdateMethods UpdateMethod = UpdateMethods.LateUpdate;

		[NoSaveDuringPlay]
		[Tooltip("The target objects, together with their weights and radii, that will contribute to the group's average position, orientation, and size.")]
		public List<Target> Targets = new List<Target>();

		private float m_MaxWeight;

		private float m_WeightSum;

		private Vector3 m_AveragePos;

		private Bounds m_BoundingBox;

		private BoundingSphere m_BoundingSphere;

		private int m_LastUpdateFrame = -1;

		private List<int> m_ValidMembers = new List<int>();

		private List<bool> m_MemberValidity = new List<bool>();

		[HideInInspector]
		[SerializeField]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("m_Targets")]
		private Target[] m_LegacyTargets;

		[Obsolete("m_Targets is obsolete.  Please use Targets instead")]
		public Target[] m_Targets
		{
			get
			{
				return Targets.ToArray();
			}
			set
			{
				Targets.Clear();
				Targets.AddRange(value);
			}
		}

		public Transform Transform => base.transform;

		public bool IsValid => this != null;

		public Bounds BoundingBox
		{
			get
			{
				if (m_LastUpdateFrame != CinemachineCore.CurrentUpdateFrame)
				{
					DoUpdate();
				}
				return m_BoundingBox;
			}
			private set
			{
				m_BoundingBox = value;
			}
		}

		public BoundingSphere Sphere
		{
			get
			{
				if (m_LastUpdateFrame != CinemachineCore.CurrentUpdateFrame)
				{
					DoUpdate();
				}
				return m_BoundingSphere;
			}
			private set
			{
				m_BoundingSphere = value;
			}
		}

		public bool IsEmpty
		{
			get
			{
				if (m_LastUpdateFrame != CinemachineCore.CurrentUpdateFrame)
				{
					DoUpdate();
				}
				return m_ValidMembers.Count == 0;
			}
		}

		private bool CachedCountIsValid => m_MemberValidity.Count == Targets.Count;

		private void OnValidate()
		{
			int count = Targets.Count;
			for (int i = 0; i < count; i++)
			{
				Targets[i].Weight = Mathf.Max(0f, Targets[i].Weight);
				Targets[i].Radius = Mathf.Max(0f, Targets[i].Radius);
			}
		}

		private void Reset()
		{
			PositionMode = PositionModes.GroupCenter;
			RotationMode = RotationModes.Manual;
			UpdateMethod = UpdateMethods.LateUpdate;
			Targets.Clear();
		}

		private void Awake()
		{
			if (m_LegacyTargets != null && m_LegacyTargets.Length != 0)
			{
				Targets.AddRange(m_LegacyTargets);
			}
			m_LegacyTargets = null;
		}

		public void AddMember(Transform t, float weight, float radius)
		{
			Targets.Add(new Target
			{
				Object = t,
				Weight = weight,
				Radius = radius
			});
		}

		public void RemoveMember(Transform t)
		{
			int num = FindMember(t);
			if (num >= 0)
			{
				Targets.RemoveAt(num);
			}
		}

		public int FindMember(Transform t)
		{
			int count = Targets.Count;
			for (int i = 0; i < count; i++)
			{
				if (Targets[i].Object == t)
				{
					return i;
				}
			}
			return -1;
		}

		public BoundingSphere GetWeightedBoundsForMember(int index)
		{
			if (m_LastUpdateFrame != CinemachineCore.CurrentUpdateFrame)
			{
				DoUpdate();
			}
			if (!IndexIsValid(index) || !m_MemberValidity[index])
			{
				return Sphere;
			}
			return WeightedMemberBoundsForValidMember(Targets[index], m_AveragePos, m_MaxWeight);
		}

		public Bounds GetViewSpaceBoundingBox(Matrix4x4 observer, bool includeBehind)
		{
			if (m_LastUpdateFrame != CinemachineCore.CurrentUpdateFrame)
			{
				DoUpdate();
			}
			Matrix4x4 result = observer;
			if (!Matrix4x4.Inverse3DAffine(observer, ref result))
			{
				result = observer.inverse;
			}
			Bounds result2 = new Bounds(result.MultiplyPoint3x4(m_AveragePos), Vector3.zero);
			if (CachedCountIsValid)
			{
				bool flag = false;
				Vector3 vector = 2f * Vector3.one;
				int count = m_ValidMembers.Count;
				for (int i = 0; i < count; i++)
				{
					BoundingSphere boundingSphere = WeightedMemberBoundsForValidMember(Targets[m_ValidMembers[i]], m_AveragePos, m_MaxWeight);
					boundingSphere.position = result.MultiplyPoint3x4(boundingSphere.position);
					if (boundingSphere.position.z > 0f || includeBehind)
					{
						if (flag)
						{
							result2.Encapsulate(new Bounds(boundingSphere.position, boundingSphere.radius * vector));
						}
						else
						{
							result2 = new Bounds(boundingSphere.position, boundingSphere.radius * vector);
						}
						flag = true;
					}
				}
			}
			return result2;
		}

		private bool IndexIsValid(int index)
		{
			if (index >= 0 && index < Targets.Count)
			{
				return CachedCountIsValid;
			}
			return false;
		}

		private static BoundingSphere WeightedMemberBoundsForValidMember(Target t, Vector3 avgPos, float maxWeight)
		{
			Vector3 b = ((t.Object == null) ? avgPos : TargetPositionCache.GetTargetPosition(t.Object));
			float num = Mathf.Max(0f, t.Weight);
			num = ((!(maxWeight > 0.0001f) || !(num < maxWeight)) ? 1f : (num / maxWeight));
			return new BoundingSphere(Vector3.Lerp(avgPos, b, num), t.Radius * num);
		}

		public void DoUpdate()
		{
			m_LastUpdateFrame = CinemachineCore.CurrentUpdateFrame;
			UpdateMemberValidity();
			m_AveragePos = CalculateAveragePosition();
			BoundingBox = CalculateBoundingBox();
			m_BoundingSphere = CalculateBoundingSphere();
			switch (PositionMode)
			{
			case PositionModes.GroupCenter:
				base.transform.position = Sphere.position;
				break;
			case PositionModes.GroupAverage:
				base.transform.position = m_AveragePos;
				break;
			}
			RotationModes rotationMode = RotationMode;
			if (rotationMode != RotationModes.Manual && rotationMode == RotationModes.GroupAverage)
			{
				base.transform.rotation = CalculateAverageOrientation();
			}
		}

		private void UpdateMemberValidity()
		{
			if (Targets == null)
			{
				Targets = new List<Target>();
			}
			int count = Targets.Count;
			m_ValidMembers.Clear();
			m_ValidMembers.Capacity = Mathf.Max(m_ValidMembers.Capacity, count);
			m_MemberValidity.Clear();
			m_MemberValidity.Capacity = Mathf.Max(m_MemberValidity.Capacity, count);
			m_WeightSum = (m_MaxWeight = 0f);
			for (int i = 0; i < count; i++)
			{
				m_MemberValidity.Add(Targets[i].Object != null && Targets[i].Weight > 0.0001f && Targets[i].Object.gameObject.activeInHierarchy);
				if (m_MemberValidity[i])
				{
					m_ValidMembers.Add(i);
					m_MaxWeight = Mathf.Max(m_MaxWeight, Targets[i].Weight);
					m_WeightSum += Targets[i].Weight;
				}
			}
		}

		private Vector3 CalculateAveragePosition()
		{
			if (m_WeightSum < 0.0001f)
			{
				return base.transform.position;
			}
			Vector3 zero = Vector3.zero;
			int count = m_ValidMembers.Count;
			for (int i = 0; i < count; i++)
			{
				int index = m_ValidMembers[i];
				float weight = Targets[index].Weight;
				zero += TargetPositionCache.GetTargetPosition(Targets[index].Object) * weight;
			}
			return zero / m_WeightSum;
		}

		private Bounds CalculateBoundingBox()
		{
			if (m_MaxWeight < 0.0001f)
			{
				return m_BoundingBox;
			}
			Bounds result = new Bounds(m_AveragePos, Vector3.zero);
			int count = m_ValidMembers.Count;
			for (int i = 0; i < count; i++)
			{
				BoundingSphere boundingSphere = WeightedMemberBoundsForValidMember(Targets[m_ValidMembers[i]], m_AveragePos, m_MaxWeight);
				result.Encapsulate(new Bounds(boundingSphere.position, boundingSphere.radius * 2f * Vector3.one));
			}
			return result;
		}

		private BoundingSphere CalculateBoundingSphere()
		{
			int count = m_ValidMembers.Count;
			if (count == 0 || m_MaxWeight < 0.0001f)
			{
				return m_BoundingSphere;
			}
			BoundingSphere result = WeightedMemberBoundsForValidMember(Targets[m_ValidMembers[0]], m_AveragePos, m_MaxWeight);
			for (int i = 1; i < count; i++)
			{
				BoundingSphere boundingSphere = WeightedMemberBoundsForValidMember(Targets[m_ValidMembers[i]], m_AveragePos, m_MaxWeight);
				float num = (boundingSphere.position - result.position).magnitude + boundingSphere.radius;
				if (num > result.radius)
				{
					result.radius = (result.radius + num) * 0.5f;
					result.position = (result.radius * result.position + (num - result.radius) * boundingSphere.position) / num;
				}
			}
			return result;
		}

		private Quaternion CalculateAverageOrientation()
		{
			if (m_WeightSum > 0.001f)
			{
				Vector3 zero = Vector3.zero;
				Vector3 zero2 = Vector3.zero;
				int count = m_ValidMembers.Count;
				for (int i = 0; i < count; i++)
				{
					int index = m_ValidMembers[i];
					float num = Targets[index].Weight / m_WeightSum;
					Quaternion targetRotation = TargetPositionCache.GetTargetRotation(Targets[index].Object);
					zero += targetRotation * Vector3.forward * num;
					zero2 += targetRotation * Vector3.up * num;
				}
				if (zero.sqrMagnitude > 0.0001f && zero2.sqrMagnitude > 0.0001f)
				{
					return Quaternion.LookRotation(zero, zero2);
				}
			}
			return base.transform.rotation;
		}

		private void FixedUpdate()
		{
			if (UpdateMethod == UpdateMethods.FixedUpdate)
			{
				DoUpdate();
			}
		}

		private void Update()
		{
			if (!Application.isPlaying || UpdateMethod == UpdateMethods.Update)
			{
				DoUpdate();
			}
		}

		private void LateUpdate()
		{
			if (UpdateMethod == UpdateMethods.LateUpdate)
			{
				DoUpdate();
			}
		}

		public void GetViewSpaceAngularBounds(Matrix4x4 observer, out Vector2 minAngles, out Vector2 maxAngles, out Vector2 zRange)
		{
			if (m_LastUpdateFrame != CinemachineCore.CurrentUpdateFrame)
			{
				DoUpdate();
			}
			Matrix4x4 result = observer;
			if (!Matrix4x4.Inverse3DAffine(observer, ref result))
			{
				result = observer.inverse;
			}
			float radius = m_BoundingSphere.radius;
			Bounds bounds = new Bounds
			{
				center = result.MultiplyPoint3x4(m_AveragePos),
				extents = new Vector3(radius, radius, radius)
			};
			zRange = new Vector2(bounds.center.z - radius, bounds.center.z + radius);
			if (CachedCountIsValid)
			{
				bool flag = false;
				int count = m_ValidMembers.Count;
				for (int i = 0; i < count; i++)
				{
					BoundingSphere boundingSphere = WeightedMemberBoundsForValidMember(Targets[m_ValidMembers[i]], m_AveragePos, m_MaxWeight);
					Vector3 vector = result.MultiplyPoint3x4(boundingSphere.position);
					if (!(vector.z < 0.0001f))
					{
						float num = boundingSphere.radius / vector.z;
						Vector3 vector2 = new Vector3(num, num, 0f);
						Vector3 vector3 = vector / vector.z;
						if (!flag)
						{
							bounds.center = vector3;
							bounds.extents = vector2;
							zRange = new Vector2(vector.z, vector.z);
							flag = true;
						}
						else
						{
							bounds.Encapsulate(vector3 + vector2);
							bounds.Encapsulate(vector3 - vector2);
							zRange.x = Mathf.Min(zRange.x, vector.z);
							zRange.y = Mathf.Max(zRange.y, vector.z);
						}
					}
				}
			}
			Vector3 min = bounds.min;
			Vector3 max = bounds.max;
			minAngles = new Vector2(Vector3.SignedAngle(Vector3.forward, new Vector3(0f, max.y, 1f), Vector3.right), Vector3.SignedAngle(Vector3.forward, new Vector3(min.x, 0f, 1f), Vector3.up));
			maxAngles = new Vector2(Vector3.SignedAngle(Vector3.forward, new Vector3(0f, min.y, 1f), Vector3.right), Vector3.SignedAngle(Vector3.forward, new Vector3(max.x, 0f, 1f), Vector3.up));
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Rotation Control/Cinemachine Third Person Aim")]
	[ExecuteAlways]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineThirdPersonAim.html")]
	public class CinemachineThirdPersonAim : CinemachineExtension
	{
		[Header("Aim Target Detection")]
		[Tooltip("Objects on these layers will be detected")]
		public LayerMask AimCollisionFilter;

		[TagField]
		[Tooltip("Objects with this tag will be ignored.  It is a good idea to set this field to the target's tag")]
		public string IgnoreTag = string.Empty;

		[Tooltip("How far to project the object detection ray")]
		public float AimDistance;

		[Tooltip("If set, camera noise will be adjusted to stabilize target on screen")]
		public bool NoiseCancellation = true;

		public Vector3 AimTarget { get; private set; }

		private void OnValidate()
		{
			AimDistance = Mathf.Max(1f, AimDistance);
		}

		private void Reset()
		{
			AimCollisionFilter = 1;
			IgnoreTag = string.Empty;
			AimDistance = 200f;
			NoiseCancellation = true;
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			switch (stage)
			{
			case CinemachineCore.Stage.Body:
				if (NoiseCancellation)
				{
					Transform follow2 = vcam.Follow;
					if (follow2 != null)
					{
						state.ReferenceLookAt = ComputeLookAtPoint(state.GetCorrectedPosition(), follow2, follow2.forward);
						AimTarget = ComputeAimTarget(state.ReferenceLookAt, follow2);
					}
				}
				break;
			case CinemachineCore.Stage.Finalize:
				if (NoiseCancellation)
				{
					Vector3 forward = state.ReferenceLookAt - state.GetFinalPosition();
					if (forward.sqrMagnitude > 0.01f)
					{
						state.RawOrientation = Quaternion.LookRotation(forward, state.ReferenceUp);
						state.OrientationCorrection = Quaternion.identity;
					}
				}
				else
				{
					Transform follow = vcam.Follow;
					if (follow != null)
					{
						state.ReferenceLookAt = ComputeLookAtPoint(state.GetCorrectedPosition(), follow, state.GetCorrectedOrientation() * Vector3.forward);
						AimTarget = ComputeAimTarget(state.ReferenceLookAt, follow);
					}
				}
				break;
			}
		}

		private Vector3 ComputeLookAtPoint(Vector3 camPos, Transform player, Vector3 fwd)
		{
			float num = AimDistance;
			Vector3 vector = Quaternion.Inverse(player.rotation) * (player.position - camPos);
			if (vector.z > 0f)
			{
				camPos += fwd * vector.z;
				num -= vector.z;
			}
			num = Mathf.Max(1f, num);
			if (!RuntimeUtility.RaycastIgnoreTag(new Ray(camPos, fwd), out var hitInfo, num, AimCollisionFilter, in IgnoreTag))
			{
				return camPos + fwd * num;
			}
			return hitInfo.point;
		}

		private Vector3 ComputeAimTarget(Vector3 cameraLookAt, Transform player)
		{
			Vector3 position = player.position;
			Vector3 direction = cameraLookAt - position;
			if (RuntimeUtility.RaycastIgnoreTag(new Ray(position, direction), out var hitInfo, direction.magnitude, AimCollisionFilter, in IgnoreTag))
			{
				return hitInfo.point;
			}
			return cameraLookAt;
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Noise/Cinemachine Basic Multi Channel Perlin")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Noise)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineBasicMultiChannelPerlin.html")]
	public class CinemachineBasicMultiChannelPerlin : CinemachineComponentBase, CinemachineFreeLookModifier.IModifiableNoise
	{
		[Tooltip("The asset containing the Noise Profile.  Define the frequencies and amplitudes there to make a characteristic noise profile.  Make your own or just use one of the many presets.")]
		[FormerlySerializedAs("m_Definition")]
		[FormerlySerializedAs("m_NoiseProfile")]
		public NoiseSettings NoiseProfile;

		[Tooltip("When rotating the camera, offset the camera's pivot position by this much (camera space)")]
		[FormerlySerializedAs("m_PivotOffset")]
		public Vector3 PivotOffset = Vector3.zero;

		[Tooltip("Gain to apply to the amplitudes defined in the NoiseSettings asset.  1 is normal.  Setting this to 0 completely mutes the noise.")]
		[FormerlySerializedAs("m_AmplitudeGain")]
		public float AmplitudeGain = 1f;

		[Tooltip("Scale factor to apply to the frequencies defined in the NoiseSettings asset.  1 is normal.  Larger magnitudes will make the noise shake more rapidly.")]
		[FormerlySerializedAs("m_FrequencyGain")]
		public float FrequencyGain = 1f;

		private bool m_Initialized;

		private float m_NoiseTime;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("mNoiseOffsets")]
		private Vector3 m_NoiseOffsets = Vector3.zero;

		(float, float) CinemachineFreeLookModifier.IModifiableNoise.NoiseAmplitudeFrequency
		{
			get
			{
				return (AmplitudeGain, FrequencyGain);
			}
			set
			{
				(AmplitudeGain, FrequencyGain) = value;
			}
		}

		public override bool IsValid
		{
			get
			{
				if (base.enabled)
				{
					return NoiseProfile != null;
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Noise;

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			if (!IsValid || deltaTime < 0f)
			{
				m_Initialized = false;
				return;
			}
			if (!m_Initialized)
			{
				Initialize();
			}
			if (TargetPositionCache.CacheMode == TargetPositionCache.Mode.Playback && TargetPositionCache.HasCurrentTime)
			{
				m_NoiseTime = TargetPositionCache.CurrentTime * FrequencyGain;
			}
			else
			{
				m_NoiseTime += deltaTime * FrequencyGain;
			}
			curState.PositionCorrection += curState.GetCorrectedOrientation() * NoiseSettings.GetCombinedFilterResults(NoiseProfile.PositionNoise, m_NoiseTime, m_NoiseOffsets) * AmplitudeGain;
			Quaternion quaternion2 = Quaternion.Euler(NoiseSettings.GetCombinedFilterResults(NoiseProfile.OrientationNoise, m_NoiseTime, m_NoiseOffsets) * AmplitudeGain);
			if (PivotOffset != Vector3.zero)
			{
				Matrix4x4 matrix4x = Matrix4x4.Translate(-PivotOffset);
				matrix4x = Matrix4x4.Rotate(quaternion2) * matrix4x;
				matrix4x = Matrix4x4.Translate(PivotOffset) * matrix4x;
				curState.PositionCorrection += curState.GetCorrectedOrientation() * matrix4x.MultiplyPoint(Vector3.zero);
			}
			curState.OrientationCorrection *= quaternion2;
		}

		public void ReSeed()
		{
			m_NoiseOffsets = new Vector3(UnityEngine.Random.Range(-1000f, 1000f), UnityEngine.Random.Range(-1000f, 1000f), UnityEngine.Random.Range(-1000f, 1000f));
		}

		private void Initialize()
		{
			m_Initialized = true;
			m_NoiseTime = CinemachineCore.CurrentTime * FrequencyGain;
			if (m_NoiseOffsets == Vector3.zero)
			{
				ReSeed();
			}
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Position Control/Cinemachine Follow")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Body)]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.Tracking)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineFollow.html")]
	public class CinemachineFollow : CinemachineComponentBase
	{
		public TrackerSettings TrackerSettings = TrackerSettings.Default;

		[Tooltip("The distance vector that the camera will attempt to maintain from the tracking target")]
		public Vector3 FollowOffset = Vector3.back * 10f;

		private Tracker m_TargetTracker;

		internal Vector3 EffectiveOffset
		{
			get
			{
				Vector3 followOffset = FollowOffset;
				if (TrackerSettings.BindingMode == BindingMode.LazyFollow)
				{
					followOffset.x = 0f;
					followOffset.z = 0f - Mathf.Abs(followOffset.z);
				}
				return followOffset;
			}
		}

		public override bool IsValid
		{
			get
			{
				if (base.enabled)
				{
					return base.FollowTarget != null;
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Body;

		private void OnValidate()
		{
			FollowOffset = EffectiveOffset;
			TrackerSettings.Validate();
		}

		private void Reset()
		{
			FollowOffset = Vector3.back * 10f;
			TrackerSettings = TrackerSettings.Default;
		}

		public override float GetMaxDampTime()
		{
			return TrackerSettings.GetMaxDampTime();
		}

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			m_TargetTracker.InitStateInfo(this, deltaTime, TrackerSettings.BindingMode, curState.ReferenceUp);
			if (IsValid)
			{
				Vector3 effectiveOffset = EffectiveOffset;
				m_TargetTracker.TrackTarget(this, deltaTime, curState.ReferenceUp, effectiveOffset, in TrackerSettings, ref curState, out var outTargetPosition, out var outTargetOrient);
				effectiveOffset = outTargetOrient * effectiveOffset;
				curState.ReferenceUp = outTargetOrient * Vector3.up;
				Vector3 followTargetPosition = base.FollowTargetPosition;
				outTargetPosition += m_TargetTracker.GetOffsetForMinimumTargetDistance(this, outTargetPosition, effectiveOffset, curState.RawOrientation * Vector3.forward, curState.ReferenceUp, followTargetPosition);
				curState.RawPosition = outTargetPosition + effectiveOffset;
			}
		}

		public override void OnTargetObjectWarped(Transform target, Vector3 positionDelta)
		{
			base.OnTargetObjectWarped(target, positionDelta);
			if (target == base.FollowTarget)
			{
				m_TargetTracker.OnTargetObjectWarped(positionDelta);
			}
		}

		public override void ForceCameraPosition(Vector3 pos, Quaternion rot)
		{
			base.ForceCameraPosition(pos, rot);
			CameraState newState = base.VcamState;
			newState.RawPosition = pos;
			newState.RawOrientation = rot;
			newState.PositionCorrection = Vector3.zero;
			newState.OrientationCorrection = Quaternion.identity;
			m_TargetTracker.OnForceCameraPosition(this, TrackerSettings.BindingMode, ref newState);
		}

		internal Quaternion GetReferenceOrientation(Vector3 up)
		{
			CameraState cameraState = base.VcamState;
			return m_TargetTracker.GetReferenceOrientation(this, TrackerSettings.BindingMode, up, ref cameraState);
		}

		internal Vector3 GetDesiredCameraPosition(Vector3 worldUp)
		{
			if (!IsValid)
			{
				return Vector3.zero;
			}
			CameraState cameraState = base.VcamState;
			return base.FollowTargetPosition + m_TargetTracker.GetReferenceOrientation(this, TrackerSettings.BindingMode, worldUp, ref cameraState) * EffectiveOffset;
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Position Control/Cinemachine Hard Lock to Target")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Body)]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.Tracking)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineHardLockToTarget.html")]
	public class CinemachineHardLockToTarget : CinemachineComponentBase
	{
		[Tooltip("How much time it takes for the position to catch up to the target's position")]
		[FormerlySerializedAs("m_Damping")]
		public float Damping;

		private Vector3 m_PreviousTargetPosition;

		public override bool IsValid
		{
			get
			{
				if (base.enabled)
				{
					return base.FollowTarget != null;
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Body;

		public override float GetMaxDampTime()
		{
			return Damping;
		}

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			if (IsValid)
			{
				Vector3 vector = base.FollowTargetPosition;
				if (base.VirtualCamera.PreviousStateIsValid && deltaTime >= 0f)
				{
					vector = m_PreviousTargetPosition + base.VirtualCamera.DetachedFollowTargetDamp(vector - m_PreviousTargetPosition, Damping, deltaTime);
				}
				m_PreviousTargetPosition = vector;
				curState.RawPosition = vector;
			}
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Rotation Control/Cinemachine Hard Look At")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Aim)]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.LookAt)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineHardLookAt.html")]
	public class CinemachineHardLookAt : CinemachineComponentBase
	{
		[Tooltip("Offset from the LookAt target's origin, in target's local space.  The camera will look at this point.")]
		public Vector3 LookAtOffset = Vector3.zero;

		public override bool IsValid
		{
			get
			{
				if (base.enabled)
				{
					return base.LookAtTarget != null;
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Aim;

		internal override bool CameraLooksAtTarget => true;

		private void Reset()
		{
			LookAtOffset = Vector3.zero;
		}

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			if (!IsValid || !curState.HasLookAt())
			{
				return;
			}
			Vector3 vector = base.LookAtTargetRotation * LookAtOffset;
			Vector3 vector2 = curState.ReferenceLookAt + vector - curState.GetCorrectedPosition();
			if (vector2.magnitude > 0.0001f)
			{
				if (Vector3.Cross(vector2.normalized, curState.ReferenceUp).magnitude < 0.0001f)
				{
					curState.RawOrientation = Quaternion.FromToRotation(Vector3.forward, vector2);
				}
				else
				{
					curState.RawOrientation = Quaternion.LookRotation(vector2, curState.ReferenceUp);
				}
			}
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Position Control/Cinemachine Orbital Follow")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Body)]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.Tracking)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineOrbitalFollow.html")]
	public class CinemachineOrbitalFollow : CinemachineComponentBase, IInputAxisOwner, IInputAxisResetSource, CinemachineFreeLookModifier.IModifierValueSource, CinemachineFreeLookModifier.IModifiablePositionDamping, CinemachineFreeLookModifier.IModifiableDistance
	{
		public enum OrbitStyles
		{
			Sphere,
			ThreeRing
		}

		public enum ReferenceFrames
		{
			AxisCenter,
			ParentObject,
			TrackingTarget,
			LookAtTarget
		}

		[Tooltip("Offset from the target object's center in target-local space. Use this to fine-tune the orbit when the desired focus of the orbit is not the tracked object's center.")]
		public Vector3 TargetOffset;

		public TrackerSettings TrackerSettings = TrackerSettings.Default;

		[Tooltip("Defines the manner in which the orbit surface is constructed.")]
		public OrbitStyles OrbitStyle;

		[Tooltip("The camera will be placed at this distance from the Follow target.")]
		public float Radius = 10f;

		[Tooltip("Defines a complex surface rig from 3 horizontal rings.")]
		[HideFoldout]
		public Cinemachine3OrbitRig.Settings Orbits = Cinemachine3OrbitRig.Settings.Default;

		[Tooltip("Defines the reference frame for horizontal recentering.  The axis center will be dynamically updated to be behind the selected object.")]
		public ReferenceFrames RecenteringTarget = ReferenceFrames.TrackingTarget;

		[Tooltip("Axis representing the current horizontal rotation.  Value is in degrees and represents a rotation about the up vector.")]
		public InputAxis HorizontalAxis = DefaultHorizontal;

		[Tooltip("Axis representing the current vertical rotation.  Value is in degrees and represents a rotation about the right vector.")]
		public InputAxis VerticalAxis = DefaultVertical;

		[Tooltip("Axis controlling the scale of the current distance.  Value is a scalar multiplier and is applied to the specified camera distance.")]
		public InputAxis RadialAxis = DefaultRadial;

		private Vector3 m_PreviousOffset;

		private Tracker m_TargetTracker;

		private Cinemachine3OrbitRig.OrbitSplineCache m_OrbitCache;

		private Action m_ResetHandler;

		internal Vector3 TrackedPoint { get; private set; }

		private static InputAxis DefaultHorizontal => new InputAxis
		{
			Value = 0f,
			Range = new Vector2(-180f, 180f),
			Wrap = true,
			Center = 0f,
			Recentering = InputAxis.RecenteringSettings.Default
		};

		private static InputAxis DefaultVertical => new InputAxis
		{
			Value = 17.5f,
			Range = new Vector2(-10f, 45f),
			Wrap = false,
			Center = 17.5f,
			Recentering = InputAxis.RecenteringSettings.Default
		};

		private static InputAxis DefaultRadial => new InputAxis
		{
			Value = 1f,
			Range = new Vector2(1f, 1f),
			Wrap = false,
			Center = 1f,
			Recentering = InputAxis.RecenteringSettings.Default
		};

		public override bool IsValid
		{
			get
			{
				if (base.enabled)
				{
					return base.FollowTarget != null;
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Body;

		bool IInputAxisResetSource.HasResetHandler => m_ResetHandler != null;

		float CinemachineFreeLookModifier.IModifierValueSource.NormalizedModifierValue => GetCameraPoint().w / Mathf.Max(0.0001f, RadialAxis.Value);

		Vector3 CinemachineFreeLookModifier.IModifiablePositionDamping.PositionDamping
		{
			get
			{
				return TrackerSettings.PositionDamping;
			}
			set
			{
				TrackerSettings.PositionDamping = value;
			}
		}

		float CinemachineFreeLookModifier.IModifiableDistance.Distance
		{
			get
			{
				return Radius;
			}
			set
			{
				Radius = value;
			}
		}

		private void OnValidate()
		{
			Radius = Mathf.Max(0f, Radius);
			TrackerSettings.Validate();
			HorizontalAxis.Validate();
			VerticalAxis.Validate();
			RadialAxis.Validate();
			RadialAxis.Range.x = Mathf.Max(RadialAxis.Range.x, 0.0001f);
			HorizontalAxis.Restrictions &= ~(InputAxis.RestrictionFlags.RangeIsDriven | InputAxis.RestrictionFlags.NoRecentering);
		}

		private void Reset()
		{
			TargetOffset = Vector3.zero;
			TrackerSettings = TrackerSettings.Default;
			OrbitStyle = OrbitStyles.Sphere;
			Radius = 10f;
			Orbits = Cinemachine3OrbitRig.Settings.Default;
			HorizontalAxis = DefaultHorizontal;
			VerticalAxis = DefaultVertical;
			RadialAxis = DefaultRadial;
		}

		public override float GetMaxDampTime()
		{
			return TrackerSettings.GetMaxDampTime();
		}

		void IInputAxisOwner.GetInputAxes(List<IInputAxisOwner.AxisDescriptor> axes)
		{
			axes.Add(new IInputAxisOwner.AxisDescriptor
			{
				DrivenAxis = () => ref HorizontalAxis,
				Name = "Look Orbit X",
				Hint = IInputAxisOwner.AxisDescriptor.Hints.X
			});
			axes.Add(new IInputAxisOwner.AxisDescriptor
			{
				DrivenAxis = () => ref VerticalAxis,
				Name = "Look Orbit Y",
				Hint = IInputAxisOwner.AxisDescriptor.Hints.Y
			});
			axes.Add(new IInputAxisOwner.AxisDescriptor
			{
				DrivenAxis = () => ref RadialAxis,
				Name = "Orbit Scale",
				Hint = IInputAxisOwner.AxisDescriptor.Hints.Y
			});
		}

		void IInputAxisResetSource.RegisterResetHandler(Action handler)
		{
			m_ResetHandler = (Action)Delegate.Combine(m_ResetHandler, handler);
		}

		void IInputAxisResetSource.UnregisterResetHandler(Action handler)
		{
			m_ResetHandler = (Action)Delegate.Remove(m_ResetHandler, handler);
		}

		internal Vector3 GetCameraOffsetForNormalizedAxisValue(float t)
		{
			return m_OrbitCache.SplineValue(Mathf.Clamp01((t + 1f) * 0.5f));
		}

		private Vector4 GetCameraPoint()
		{
			Vector3 vector2;
			float w;
			if (OrbitStyle == OrbitStyles.ThreeRing)
			{
				if (m_OrbitCache.SettingsChanged(in Orbits))
				{
					m_OrbitCache.UpdateOrbitCache(in Orbits);
				}
				Vector4 vector = m_OrbitCache.SplineValue(VerticalAxis.GetNormalizedValue());
				vector *= RadialAxis.Value;
				vector2 = Quaternion.AngleAxis(HorizontalAxis.Value, Vector3.up) * vector;
				w = vector.w;
			}
			else
			{
				vector2 = Quaternion.Euler(VerticalAxis.Value, HorizontalAxis.Value, 0f) * new Vector3(0f, 0f, (0f - Radius) * RadialAxis.Value);
				w = VerticalAxis.GetNormalizedValue() * 2f - 1f;
			}
			if (TrackerSettings.BindingMode == BindingMode.LazyFollow)
			{
				vector2.z = 0f - Mathf.Abs(vector2.z);
			}
			return new Vector4(vector2.x, vector2.y, vector2.z, w);
		}

		public override bool OnTransitionFromCamera(ICinemachineCamera fromCam, Vector3 worldUp, float deltaTime)
		{
			m_ResetHandler?.Invoke();
			if (fromCam != null && (base.VirtualCamera.State.BlendHint & CameraState.BlendHints.InheritPosition) != CameraState.BlendHints.Nothing && !CinemachineCore.IsLiveInBlend(base.VirtualCamera))
			{
				CameraState state = fromCam.State;
				ForceCameraPosition(state.GetFinalPosition(), state.GetFinalOrientation());
				return true;
			}
			return false;
		}

		public override void ForceCameraPosition(Vector3 pos, Quaternion rot)
		{
			m_ResetHandler?.Invoke();
			if (!(base.FollowTarget != null))
			{
				return;
			}
			CameraState state = base.VcamState;
			m_PreviousOffset = rot * Quaternion.Inverse(state.GetFinalOrientation()) * m_PreviousOffset;
			state.RawPosition = pos;
			state.RawOrientation = rot;
			state.PositionCorrection = Vector3.zero;
			state.OrientationCorrection = Quaternion.identity;
			Vector3 dir = pos - base.FollowTarget.TransformPoint(TargetOffset);
			float magnitude = dir.magnitude;
			if (magnitude > 0.001f)
			{
				dir /= magnitude;
				if (OrbitStyle == OrbitStyles.ThreeRing)
				{
					InferAxesFromPosition_ThreeRing(dir, magnitude, ref state);
				}
				else
				{
					InferAxesFromPosition_Sphere(dir, magnitude, ref state);
				}
			}
			m_TargetTracker.OnForceCameraPosition(this, TrackerSettings.BindingMode, ref state);
		}

		private void InferAxesFromPosition_Sphere(Vector3 dir, float distance, ref CameraState state)
		{
			Vector3 referenceUp = state.ReferenceUp;
			Vector3 v = Quaternion.Inverse(m_TargetTracker.GetReferenceOrientation(this, TrackerSettings.BindingMode, referenceUp, ref state)) * dir;
			Vector3 eulerAngles = UnityVectorExtensions.SafeFromToRotation(Vector3.back, v, referenceUp).eulerAngles;
			VerticalAxis.Value = VerticalAxis.ClampValue(UnityVectorExtensions.NormalizeAngle(eulerAngles.x));
			HorizontalAxis.Value = HorizontalAxis.ClampValue(UnityVectorExtensions.NormalizeAngle(eulerAngles.y));
			RadialAxis.Value = RadialAxis.ClampValue(distance / Radius);
		}

		private void InferAxesFromPosition_ThreeRing(Vector3 dir, float distance, ref CameraState state)
		{
			Vector3 up = state.ReferenceUp;
			Quaternion orient = m_TargetTracker.GetReferenceOrientation(this, TrackerSettings.BindingMode, up, ref state);
			HorizontalAxis.Value = GetHorizontalAxis();
			VerticalAxis.Value = GetVerticalAxisClosestValue(out var splinePoint);
			RadialAxis.Value = RadialAxis.ClampValue(distance / splinePoint.magnitude);
			float GetHorizontalAxis()
			{
				Vector3 vector = (orient * Vector3.back).ProjectOntoPlane(up);
				if (!vector.AlmostZero())
				{
					return UnityVectorExtensions.SignedAngle(vector, dir.ProjectOntoPlane(up), up);
				}
				return HorizontalAxis.Value;
			}
			float GetVerticalAxisClosestValue(out Vector3 reference)
			{
				Vector3 vector = UnityVectorExtensions.SafeFromToRotation(up, Vector3.up, up) * dir;
				Vector3 vector2 = vector;
				vector2.y = 0f;
				if (!vector2.AlmostZero())
				{
					vector = Quaternion.AngleAxis(UnityVectorExtensions.SignedAngle(vector2, Vector3.back, Vector3.up), Vector3.up) * vector;
				}
				vector.x = 0f;
				vector.Normalize();
				float num = SteepestDescent(vector * distance);
				reference = m_OrbitCache.SplineValue(num);
				if (!(num <= 0.5f))
				{
					return Mathf.Lerp(VerticalAxis.Center, VerticalAxis.Range.y, MapTo(num, 0.5f, 1f));
				}
				return Mathf.Lerp(VerticalAxis.Range.x, VerticalAxis.Center, MapTo(num, 0f, 0.5f));
			}
			static float MapTo(float valueToMap, float fMin, float fMax)
			{
				return (valueToMap - fMin) / (fMax - fMin);
			}
			float SteepestDescent(Vector3 cameraOffset)
			{
				float num = InitialGuess();
				for (int i = 0; i < 5; i++)
				{
					float num2 = AngleFunction(num);
					float num3 = SlopeOfAngleFunction(num);
					if (Mathf.Abs(num3) < 0.005f || Mathf.Abs(num2) < 0.005f)
					{
						break;
					}
					num = Mathf.Clamp01(num - num2 / num3);
				}
				return num;
				float AngleFunction(float input)
				{
					Vector4 vector = m_OrbitCache.SplineValue(input);
					return Mathf.Abs(UnityVectorExtensions.SignedAngle(cameraOffset, vector, Vector3.right));
				}
				float InitialGuess()
				{
					if (m_OrbitCache.SettingsChanged(in Orbits))
					{
						m_OrbitCache.UpdateOrbitCache(in Orbits);
					}
					float best = 0.5f;
					float bestAngle = AngleFunction(best);
					for (int j = 0; j <= 5; j++)
					{
						float num4 = (float)j * 0.1f;
						ChooseBestAngle(0.5f + num4);
						ChooseBestAngle(0.5f - num4);
					}
					return best;
					void ChooseBestAngle(float x)
					{
						float num5 = AngleFunction(x);
						if (num5 < bestAngle)
						{
							bestAngle = num5;
							best = x;
						}
					}
				}
				float SlopeOfAngleFunction(float input)
				{
					float num4 = AngleFunction(input - 0.005f);
					return (AngleFunction(input + 0.005f) - num4) / 0.01f;
				}
			}
		}

		public override void OnTargetObjectWarped(Transform target, Vector3 positionDelta)
		{
			base.OnTargetObjectWarped(target, positionDelta);
			if (target == base.FollowTarget)
			{
				m_TargetTracker.OnTargetObjectWarped(positionDelta);
			}
		}

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			m_TargetTracker.InitStateInfo(this, deltaTime, TrackerSettings.BindingMode, curState.ReferenceUp);
			if (IsValid)
			{
				if (deltaTime < 0f)
				{
					m_ResetHandler?.Invoke();
				}
				Vector3 vector = GetCameraPoint();
				bool flag = HorizontalAxis.TrackValueChange();
				bool flag2 = VerticalAxis.TrackValueChange();
				bool flag3 = RadialAxis.TrackValueChange();
				if (TrackerSettings.BindingMode == BindingMode.LazyFollow)
				{
					HorizontalAxis.SetValueAndLastValue(0f);
				}
				m_TargetTracker.TrackTarget(this, deltaTime, curState.ReferenceUp, vector, in TrackerSettings, ref curState, out var outTargetPosition, out var outTargetOrient);
				vector = outTargetOrient * vector;
				curState.ReferenceUp = outTargetOrient * Vector3.up;
				Vector3 followTargetPosition = base.FollowTargetPosition;
				outTargetPosition += m_TargetTracker.GetOffsetForMinimumTargetDistance(this, outTargetPosition, vector, curState.RawOrientation * Vector3.forward, curState.ReferenceUp, followTargetPosition);
				outTargetPosition += outTargetOrient * TargetOffset;
				TrackedPoint = outTargetPosition;
				curState.RawPosition = outTargetPosition + vector;
				if (curState.HasLookAt())
				{
					Vector3 vector2 = outTargetOrient * (curState.ReferenceLookAt - (base.FollowTargetPosition + base.FollowTargetRotation * TargetOffset));
					vector = curState.RawPosition - (outTargetPosition + vector2);
				}
				if (deltaTime >= 0f && base.VirtualCamera.PreviousStateIsValid && m_PreviousOffset.sqrMagnitude > 0.0001f && vector.sqrMagnitude > 0.0001f)
				{
					curState.RotationDampingBypass = UnityVectorExtensions.SafeFromToRotation(m_PreviousOffset, vector, curState.ReferenceUp);
				}
				m_PreviousOffset = vector;
				if (HorizontalAxis.Recentering.Enabled)
				{
					UpdateHorizontalCenter(outTargetOrient);
				}
				flag |= flag2 && HorizontalAxis.Recentering.Time == VerticalAxis.Recentering.Time;
				flag |= flag3 && HorizontalAxis.Recentering.Time == RadialAxis.Recentering.Time;
				flag2 |= flag && VerticalAxis.Recentering.Time == HorizontalAxis.Recentering.Time;
				flag2 |= flag3 && VerticalAxis.Recentering.Time == RadialAxis.Recentering.Time;
				flag3 |= flag && RadialAxis.Recentering.Time == HorizontalAxis.Recentering.Time;
				flag3 |= flag2 && RadialAxis.Recentering.Time == VerticalAxis.Recentering.Time;
				HorizontalAxis.UpdateRecentering(deltaTime, flag);
				VerticalAxis.UpdateRecentering(deltaTime, flag2);
				RadialAxis.UpdateRecentering(deltaTime, flag3);
			}
		}

		private void UpdateHorizontalCenter(Quaternion referenceOrientation)
		{
			Vector3 forward = Vector3.forward;
			switch (RecenteringTarget)
			{
			case ReferenceFrames.AxisCenter:
				if (TrackerSettings.BindingMode == BindingMode.LazyFollow)
				{
					HorizontalAxis.Center = 0f;
				}
				return;
			case ReferenceFrames.ParentObject:
				if (base.transform.parent != null)
				{
					forward = base.transform.parent.forward;
				}
				break;
			case ReferenceFrames.TrackingTarget:
				if (base.FollowTarget != null)
				{
					forward = base.FollowTarget.forward;
				}
				break;
			case ReferenceFrames.LookAtTarget:
				if (base.LookAtTarget != null)
				{
					forward = base.LookAtTarget.forward;
				}
				break;
			}
			Vector3 vector = referenceOrientation * Vector3.up;
			forward.ProjectOntoPlane(vector);
			HorizontalAxis.Center = 0f - Vector3.SignedAngle(forward, referenceOrientation * Vector3.forward, vector);
		}

		internal Quaternion GetReferenceOrientation()
		{
			return m_TargetTracker.PreviousReferenceOrientation.normalized;
		}
	}
	public static class Cinemachine3OrbitRig
	{
		[Serializable]
		public struct Orbit
		{
			[Tooltip("Horizontal radius of the orbit")]
			public float Radius;

			[Tooltip("Height of the horizontal orbit circle, relative to the target position")]
			public float Height;
		}

		[Serializable]
		public struct Settings
		{
			[Tooltip("Value to take at the top of the axis range")]
			public Orbit Top;

			[Tooltip("Value to take at the center of the axis range")]
			public Orbit Center;

			[Tooltip("Value to take at the bottom of the axis range")]
			public Orbit Bottom;

			[Tooltip("Controls how taut is the line that connects the rigs' orbits, which determines final placement on the Y axis")]
			[Range(0f, 1f)]
			public float SplineCurvature;

			public static Settings Default => new Settings
			{
				SplineCurvature = 0.5f,
				Top = new Orbit
				{
					Height = 5f,
					Radius = 2f
				},
				Center = new Orbit
				{
					Height = 2.25f,
					Radius = 4f
				},
				Bottom = new Orbit
				{
					Height = 0.1f,
					Radius = 2.5f
				}
			};
		}

		internal struct OrbitSplineCache
		{
			private Settings OrbitSettings;

			private Vector4[] CachedKnots;

			private Vector4[] CachedCtrl1;

			private Vector4[] CachedCtrl2;

			public bool SettingsChanged(in Settings other)
			{
				if (OrbitSettings.SplineCurvature == other.SplineCurvature && OrbitSettings.Top.Height == other.Top.Height && OrbitSettings.Top.Radius == other.Top.Radius && OrbitSettings.Center.Height == other.Center.Height && OrbitSettings.Center.Radius == other.Center.Radius && OrbitSettings.Bottom.Height == other.Bottom.Height)
				{
					return OrbitSettings.Bottom.Radius != other.Bottom.Radius;
				}
				return true;
			}

			public void UpdateOrbitCache(in Settings orbits)
			{
				OrbitSettings = orbits;
				float splineCurvature = orbits.SplineCurvature;
				CachedKnots = new Vector4[5];
				CachedCtrl1 = new Vector4[5];
				CachedCtrl2 = new Vector4[5];
				CachedKnots[1] = new Vector4(0f, orbits.Bottom.Height, 0f - orbits.Bottom.Radius, -1f);
				CachedKnots[2] = new Vector4(0f, orbits.Center.Height, 0f - orbits.Center.Radius, 0f);
				CachedKnots[3] = new Vector4(0f, orbits.Top.Height, 0f - orbits.Top.Radius, 1f);
				CachedKnots[0] = Vector4.Lerp(CachedKnots[1] + (CachedKnots[1] - CachedKnots[2]) * 0.5f, Vector4.zero, splineCurvature);
				CachedKnots[4] = Vector4.Lerp(CachedKnots[3] + (CachedKnots[3] - CachedKnots[2]) * 0.5f, Vector4.zero, splineCurvature);
				SplineHelpers.ComputeSmoothControlPoints(ref CachedKnots, ref CachedCtrl1, ref CachedCtrl2);
			}

			public Vector4 SplineValue(float t)
			{
				if (CachedKnots == null)
				{
					return Vector4.zero;
				}
				int num = 1;
				if (t > 0.5f)
				{
					t -= 0.5f;
					num = 2;
				}
				Vector4 result = SplineHelpers.Bezier3(t * 2f, CachedKnots[num], CachedCtrl1[num], CachedCtrl2[num], CachedKnots[num + 1]);
				result.w = SplineHelpers.Bezier1(t * 2f, CachedKnots[num].w, CachedCtrl1[num].w, CachedCtrl2[num].w, CachedKnots[num + 1].w);
				return result;
			}
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Rotation Control/Cinemachine Pan Tilt")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Aim)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachinePanTilt.html")]
	public class CinemachinePanTilt : CinemachineComponentBase, IInputAxisOwner, IInputAxisResetSource, CinemachineFreeLookModifier.IModifierValueSource
	{
		public enum ReferenceFrames
		{
			ParentObject,
			World,
			TrackingTarget,
			LookAtTarget
		}

		public enum RecenterTargetModes
		{
			AxisCenter,
			TrackingTargetForward,
			LookAtTargetForward
		}

		public ReferenceFrames ReferenceFrame;

		public RecenterTargetModes RecenterTarget;

		[Tooltip("Axis representing the current horizontal rotation.  Value is in degrees and represents a rotation about the Y axis.")]
		public InputAxis PanAxis = DefaultPan;

		[Tooltip("Axis representing the current vertical rotation.  Value is in degrees and represents a rotation about the X axis.")]
		public InputAxis TiltAxis = DefaultTilt;

		private Quaternion m_PreviousCameraRotation;

		private Action m_ResetHandler;

		private static InputAxis DefaultPan => new InputAxis
		{
			Value = 0f,
			Range = new Vector2(-180f, 180f),
			Wrap = true,
			Center = 0f,
			Recentering = InputAxis.RecenteringSettings.Default
		};

		private static InputAxis DefaultTilt => new InputAxis
		{
			Value = 0f,
			Range = new Vector2(-70f, 70f),
			Wrap = false,
			Center = 0f,
			Recentering = InputAxis.RecenteringSettings.Default
		};

		float CinemachineFreeLookModifier.IModifierValueSource.NormalizedModifierValue
		{
			get
			{
				float num = TiltAxis.Range.y - TiltAxis.Range.x;
				return (TiltAxis.Value - TiltAxis.Range.x) / ((num > 0.001f) ? num : 1f) * 2f - 1f;
			}
		}

		bool IInputAxisResetSource.HasResetHandler => m_ResetHandler != null;

		public override bool IsValid => base.enabled;

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Aim;

		private void OnValidate()
		{
			PanAxis.Validate();
			TiltAxis.Range.x = Mathf.Clamp(TiltAxis.Range.x, -90f, 90f);
			TiltAxis.Range.y = Mathf.Clamp(TiltAxis.Range.y, -90f, 90f);
			TiltAxis.Validate();
		}

		private void Reset()
		{
			PanAxis = DefaultPan;
			TiltAxis = DefaultTilt;
			ReferenceFrame = ReferenceFrames.ParentObject;
			RecenterTarget = RecenterTargetModes.AxisCenter;
		}

		void IInputAxisOwner.GetInputAxes(List<IInputAxisOwner.AxisDescriptor> axes)
		{
			axes.Add(new IInputAxisOwner.AxisDescriptor
			{
				DrivenAxis = () => ref PanAxis,
				Name = "Look X (Pan)",
				Hint = IInputAxisOwner.AxisDescriptor.Hints.X
			});
			axes.Add(new IInputAxisOwner.AxisDescriptor
			{
				DrivenAxis = () => ref TiltAxis,
				Name = "Look Y (Tilt)",
				Hint = IInputAxisOwner.AxisDescriptor.Hints.Y
			});
		}

		void IInputAxisResetSource.RegisterResetHandler(Action handler)
		{
			m_ResetHandler = (Action)Delegate.Combine(m_ResetHandler, handler);
		}

		void IInputAxisResetSource.UnregisterResetHandler(Action handler)
		{
			m_ResetHandler = (Action)Delegate.Remove(m_ResetHandler, handler);
		}

		public override void PrePipelineMutateCameraState(ref CameraState state, float deltaTime)
		{
		}

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			if (IsValid)
			{
				if (deltaTime < 0f || !base.VirtualCamera.PreviousStateIsValid || !CinemachineCore.IsLive(base.VirtualCamera))
				{
					m_ResetHandler?.Invoke();
				}
				Quaternion quaternion2 = (curState.RawOrientation = GetReferenceFrame(curState.ReferenceUp) * Quaternion.Euler(TiltAxis.Value, PanAxis.Value, 0f));
				if (base.VirtualCamera.PreviousStateIsValid)
				{
					curState.RotationDampingBypass *= UnityVectorExtensions.SafeFromToRotation(m_PreviousCameraRotation * Vector3.forward, quaternion2 * Vector3.forward, curState.ReferenceUp);
				}
				m_PreviousCameraRotation = quaternion2;
				bool flag = PanAxis.TrackValueChange();
				bool flag2 = TiltAxis.TrackValueChange();
				if (PanAxis.Recentering.Time == TiltAxis.Recentering.Time)
				{
					flag = flag || flag2;
					flag2 = flag2 || flag;
				}
				Vector2 recenterTarget = GetRecenterTarget();
				PanAxis.UpdateRecentering(deltaTime, flag, recenterTarget.x);
				TiltAxis.UpdateRecentering(deltaTime, flag2, recenterTarget.y);
			}
		}

		public override void ForceCameraPosition(Vector3 pos, Quaternion rot)
		{
			SetAxesForRotation(rot);
		}

		public override bool OnTransitionFromCamera(ICinemachineCamera fromCam, Vector3 worldUp, float deltaTime)
		{
			m_ResetHandler?.Invoke();
			if (fromCam != null && (base.VirtualCamera.State.BlendHint & CameraState.BlendHints.InheritPosition) != CameraState.BlendHints.Nothing && !CinemachineCore.IsLiveInBlend(base.VirtualCamera))
			{
				SetAxesForRotation(fromCam.State.RawOrientation);
				return true;
			}
			return false;
		}

		private void SetAxesForRotation(Quaternion targetRot)
		{
			m_ResetHandler?.Invoke();
			Vector3 referenceUp = base.VcamState.ReferenceUp;
			Vector3 vector = GetReferenceFrame(referenceUp) * Vector3.forward;
			PanAxis.Value = 0f;
			Vector3 vector2 = targetRot * Vector3.forward;
			Vector3 vector3 = vector.ProjectOntoPlane(referenceUp);
			Vector3 vector4 = vector2.ProjectOntoPlane(referenceUp);
			if (!vector3.AlmostZero() && !vector4.AlmostZero())
			{
				PanAxis.Value = Vector3.SignedAngle(vector3, vector4, referenceUp);
			}
			TiltAxis.Value = 0f;
			vector = Quaternion.AngleAxis(PanAxis.Value, referenceUp) * vector;
			Vector3 vector5 = Vector3.Cross(referenceUp, vector);
			if (!vector5.AlmostZero())
			{
				TiltAxis.Value = Vector3.SignedAngle(vector, vector2, vector5);
			}
		}

		private Quaternion GetReferenceFrame(Vector3 up)
		{
			Transform transform = null;
			switch (ReferenceFrame)
			{
			case ReferenceFrames.TrackingTarget:
				transform = base.FollowTarget;
				break;
			case ReferenceFrames.LookAtTarget:
				transform = base.LookAtTarget;
				break;
			case ReferenceFrames.ParentObject:
				transform = base.VirtualCamera.transform.parent;
				break;
			}
			if (!(transform != null))
			{
				return Quaternion.FromToRotation(Vector3.up, up);
			}
			return transform.rotation;
		}

		public Vector2 GetRecenterTarget()
		{
			Transform transform = null;
			switch (RecenterTarget)
			{
			case RecenterTargetModes.TrackingTargetForward:
				transform = base.VirtualCamera.Follow;
				break;
			case RecenterTargetModes.LookAtTargetForward:
				transform = base.VirtualCamera.LookAt;
				break;
			}
			if (transform != null)
			{
				Vector3 vector = transform.forward;
				Transform parent = base.VirtualCamera.transform.parent;
				if (parent != null)
				{
					vector = parent.rotation * vector;
				}
				Vector3 eulerAngles = Quaternion.FromToRotation(Vector3.forward, vector).eulerAngles;
				return new Vector2(NormalizeAngle(eulerAngles.y), NormalizeAngle(eulerAngles.x));
			}
			return new Vector2(PanAxis.Center, TiltAxis.Center);
			static float NormalizeAngle(float angle)
			{
				return (angle + 180f) % 360f - 180f;
			}
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Position Control/Cinemachine Position Composer")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Body)]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.Tracking)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachinePositionComposer.html")]
	public class CinemachinePositionComposer : CinemachineComponentBase, CinemachineFreeLookModifier.IModifiablePositionDamping, CinemachineFreeLookModifier.IModifiableDistance, CinemachineFreeLookModifier.IModifiableComposition
	{
		[Header("Camera Position")]
		[Tooltip("The distance along the camera axis that will be maintained from the target")]
		public float CameraDistance = 10f;

		[Tooltip("The camera will not move along its z-axis if the target is within this distance of the specified camera distance")]
		public float DeadZoneDepth;

		[Header("Composition")]
		[HideFoldout]
		public ScreenComposerSettings Composition = ScreenComposerSettings.Default;

		[Tooltip("Force target to center of screen when this camera activates.  If false, will clamp target to the edges of the dead zone")]
		public bool CenterOnActivate = true;

		[Header("Target Tracking")]
		[Tooltip("Offset from the target object (in target-local co-ordinates).  The camera will attempt to frame the point which is the target's position plus this offset.  Use it to correct for cases when the target's origin is not the point of interest for the camera.")]
		[FormerlySerializedAs("TrackedObjectOffset")]
		public Vector3 TargetOffset;

		[Tooltip("How aggressively the camera tries to follow the target in the screen space. Small numbers are more responsive, rapidly orienting the camera to keep the target in the dead zone. Larger numbers give a more heavy slowly responding camera. Using different vertical and horizontal settings can yield a wide range of camera behaviors.")]
		public Vector3 Damping;

		[FoldoutWithEnabledButton("Enabled")]
		public LookaheadSettings Lookahead;

		private const float kMinimumCameraDistance = 0.01f;

		internal PositionPredictor m_Predictor;

		private Vector3 m_PreviousCameraPosition = Vector3.zero;

		private Quaternion m_PreviousRotation;

		private ScreenComposerSettings m_PreviousComposition;

		private float m_PreviousDesiredDistance;

		private bool m_InheritingPosition;

		internal ScreenComposerSettings GetEffectiveComposition => m_PreviousComposition;

		ScreenComposerSettings CinemachineFreeLookModifier.IModifiableComposition.Composition
		{
			get
			{
				return Composition;
			}
			set
			{
				Composition = value;
			}
		}

		Vector3 CinemachineFreeLookModifier.IModifiablePositionDamping.PositionDamping
		{
			get
			{
				return Damping;
			}
			set
			{
				Damping = value;
			}
		}

		float CinemachineFreeLookModifier.IModifiableDistance.Distance
		{
			get
			{
				return CameraDistance;
			}
			set
			{
				CameraDistance = value;
			}
		}

		public override bool IsValid
		{
			get
			{
				if (base.enabled)
				{
					return base.FollowTarget != null;
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Body;

		public override bool BodyAppliesAfterAim => true;

		internal Vector3 TrackedPoint { get; private set; }

		private void Reset()
		{
			TargetOffset = Vector3.zero;
			Lookahead = default(LookaheadSettings);
			Damping = Vector3.one;
			CameraDistance = 10f;
			Composition = ScreenComposerSettings.Default;
			DeadZoneDepth = 0f;
			CenterOnActivate = true;
		}

		private void OnValidate()
		{
			Damping.x = Mathf.Max(0f, Damping.x);
			Damping.y = Mathf.Max(0f, Damping.y);
			Damping.z = Mathf.Max(0f, Damping.z);
			CameraDistance = Mathf.Max(0.01f, CameraDistance);
			DeadZoneDepth = Mathf.Max(0f, DeadZoneDepth);
			Composition.Validate();
		}

		public override void OnTargetObjectWarped(Transform target, Vector3 positionDelta)
		{
			base.OnTargetObjectWarped(target, positionDelta);
			if (target == base.FollowTarget)
			{
				m_PreviousCameraPosition += positionDelta;
				m_Predictor.ApplyTransformDelta(positionDelta);
			}
		}

		public override void ForceCameraPosition(Vector3 pos, Quaternion rot)
		{
			base.ForceCameraPosition(pos, rot);
			m_Predictor.ApplyRotationDelta(rot * Quaternion.Inverse(m_PreviousRotation));
			m_PreviousCameraPosition = pos;
			m_PreviousRotation = rot;
		}

		public override float GetMaxDampTime()
		{
			return Mathf.Max(Damping.x, Mathf.Max(Damping.y, Damping.z));
		}

		public override bool OnTransitionFromCamera(ICinemachineCamera fromCam, Vector3 worldUp, float deltaTime)
		{
			if (fromCam != null && (base.VirtualCamera.State.BlendHint & CameraState.BlendHints.InheritPosition) != CameraState.BlendHints.Nothing && !CinemachineCore.IsLiveInBlend(base.VirtualCamera))
			{
				m_PreviousCameraPosition = fromCam.State.RawPosition;
				m_PreviousRotation = fromCam.State.RawOrientation;
				m_InheritingPosition = true;
				return true;
			}
			return false;
		}

		private Rect ScreenToOrtho(Rect rScreen, float orthoSize, float aspect)
		{
			return new Rect
			{
				yMax = 2f * orthoSize * (1f - rScreen.yMin - 0.5f),
				yMin = 2f * orthoSize * (1f - rScreen.yMax - 0.5f),
				xMin = 2f * orthoSize * aspect * (rScreen.xMin - 0.5f),
				xMax = 2f * orthoSize * aspect * (rScreen.xMax - 0.5f)
			};
		}

		private Vector3 OrthoOffsetToScreenBounds(Vector3 targetPos2D, Rect screenRect)
		{
			Vector3 zero = Vector3.zero;
			if (targetPos2D.x < screenRect.xMin)
			{
				zero.x += targetPos2D.x - screenRect.xMin;
			}
			if (targetPos2D.x > screenRect.xMax)
			{
				zero.x += targetPos2D.x - screenRect.xMax;
			}
			if (targetPos2D.y < screenRect.yMin)
			{
				zero.y += targetPos2D.y - screenRect.yMin;
			}
			if (targetPos2D.y > screenRect.yMax)
			{
				zero.y += targetPos2D.y - screenRect.yMax;
			}
			return zero;
		}

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			LensSettings lens = curState.Lens;
			Vector3 vector = base.FollowTargetPosition + base.FollowTargetRotation * TargetOffset;
			bool flag = deltaTime >= 0f && base.VirtualCamera.PreviousStateIsValid;
			if (!flag || base.VirtualCamera.FollowTargetChanged)
			{
				m_Predictor.Reset();
			}
			if (!flag)
			{
				m_PreviousCameraPosition = curState.RawPosition;
				m_PreviousRotation = curState.RawOrientation;
				m_PreviousDesiredDistance = CameraDistance;
				m_PreviousComposition = Composition;
				if (!m_InheritingPosition && CenterOnActivate)
				{
					m_PreviousCameraPosition = base.FollowTargetPosition + curState.RawOrientation * Vector3.back * CameraDistance;
				}
			}
			if (!IsValid)
			{
				m_InheritingPosition = false;
				return;
			}
			float fieldOfView = lens.FieldOfView;
			TrackedPoint = vector;
			if (Lookahead.Enabled && Lookahead.Time > 0.0001f)
			{
				m_Predictor.Smoothing = Lookahead.Smoothing;
				m_Predictor.AddPosition(vector, deltaTime);
				Vector3 vector2 = m_Predictor.PredictPositionDelta(Lookahead.Time);
				if (Lookahead.IgnoreY)
				{
					vector2 = vector2.ProjectOntoPlane(curState.ReferenceUp);
				}
				TrackedPoint = vector + vector2;
			}
			if (!curState.HasLookAt() || curState.ReferenceLookAt == base.FollowTargetPosition)
			{
				curState.ReferenceLookAt = vector;
			}
			Quaternion rawOrientation = curState.RawOrientation;
			if (flag)
			{
				Vector3 vector3 = rawOrientation * Quaternion.Inverse(m_PreviousRotation) * (m_PreviousCameraPosition - TrackedPoint);
				m_PreviousCameraPosition = TrackedPoint + vector3;
				float num = CameraDistance - m_PreviousDesiredDistance;
				if (Mathf.Abs(num) > 0.0001f)
				{
					m_PreviousCameraPosition += vector3.normalized * num;
				}
			}
			m_PreviousRotation = rawOrientation;
			Vector3 previousCameraPosition = m_PreviousCameraPosition;
			Quaternion quaternion2 = Quaternion.Inverse(rawOrientation);
			Vector3 vector4 = quaternion2 * previousCameraPosition;
			Vector3 vector5 = quaternion2 * TrackedPoint - vector4;
			Vector3 vector6 = vector5;
			Vector3 vector7 = Vector3.zero;
			float num2 = Mathf.Max(0.01f, CameraDistance - DeadZoneDepth / 2f);
			float num3 = Mathf.Max(num2, CameraDistance + DeadZoneDepth / 2f);
			float num4 = Mathf.Min(vector5.z, vector6.z);
			if (num4 < num2)
			{
				vector7.z = num4 - num2;
			}
			if (num4 > num3)
			{
				vector7.z = num4 - num3;
			}
			float num5 = (lens.Orthographic ? lens.OrthographicSize : (Mathf.Tan(0.5f * fieldOfView * (MathF.PI / 180f)) * (num4 - vector7.z)));
			Rect rect = ScreenToOrtho(Composition.DeadZoneRect, num5, lens.Aspect);
			if (!flag)
			{
				Rect screenRect = rect;
				if (CenterOnActivate && !m_InheritingPosition)
				{
					screenRect = new Rect(screenRect.center, Vector2.zero);
				}
				vector7 += OrthoOffsetToScreenBounds(vector5, screenRect);
			}
			else
			{
				if (Composition.ScreenPosition != m_PreviousComposition.ScreenPosition)
				{
					Vector2 vector8 = Composition.ScreenPosition - m_PreviousComposition.ScreenPosition;
					Vector3 vector9 = new Vector3((0f - vector8.x) * num5 * lens.Aspect * 2f, vector8.y * num5 * 2f, 0f);
					vector5 += vector9;
					previousCameraPosition += rawOrientation * vector9;
				}
				vector7 += OrthoOffsetToScreenBounds(vector5, rect);
				vector7 = base.VirtualCamera.DetachedFollowTargetDamp(vector7, Damping, deltaTime);
				if (Composition.HardLimits.Enabled && (deltaTime < 0f || base.VirtualCamera.FollowTargetAttachment > 0.9999f))
				{
					Rect screenRect2 = ScreenToOrtho(Composition.HardLimitsRect, num5, lens.Aspect);
					Vector3 vector10 = quaternion2 * vector - vector4;
					vector7 += OrthoOffsetToScreenBounds(vector10 - vector7, screenRect2);
				}
			}
			curState.RawPosition = previousCameraPosition + rawOrientation * vector7;
			m_PreviousCameraPosition = curState.RawPosition;
			m_PreviousComposition = Composition;
			m_PreviousDesiredDistance = CameraDistance;
			m_InheritingPosition = false;
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Rotation Control/Cinemachine Rotate With Follow Target")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Aim)]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.Tracking)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineRotateWithFollowTarget.html")]
	public class CinemachineRotateWithFollowTarget : CinemachineComponentBase
	{
		[Tooltip("How much time it takes for the aim to catch up to the target's rotation")]
		public float Damping;

		private Quaternion m_PreviousReferenceOrientation = Quaternion.identity;

		public override bool IsValid
		{
			get
			{
				if (base.enabled)
				{
					return base.FollowTarget != null;
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Aim;

		public override float GetMaxDampTime()
		{
			return Damping;
		}

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			if (IsValid)
			{
				Quaternion quaternion2 = base.FollowTargetRotation;
				if (deltaTime >= 0f)
				{
					float t = base.VirtualCamera.DetachedFollowTargetDamp(1f, Damping, deltaTime);
					quaternion2 = Quaternion.Slerp(m_PreviousReferenceOrientation, base.FollowTargetRotation, t);
				}
				m_PreviousReferenceOrientation = quaternion2;
				curState.RawOrientation = quaternion2;
				curState.ReferenceUp = quaternion2 * Vector3.up;
			}
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Rotation Control/Cinemachine Rotation Composer")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Aim)]
	[RequiredTarget(RequiredTargetAttribute.RequiredTargets.LookAt)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineRotationComposer.html")]
	public class CinemachineRotationComposer : CinemachineComponentBase, CinemachineFreeLookModifier.IModifiableComposition
	{
		private struct FovCache
		{
			public Rect FovSoftGuideRect;

			public Rect FovHardGuideRect;

			public Vector2 Fov;

			private float m_OrthoSizeOverDistance;

			private float m_Aspect;

			private Rect m_DeadZoneRect;

			private Rect m_HardLimitRect;

			private Vector2 m_ScreenBounds;

			private Vector2 m_HalfFovRad;

			public void UpdateCache(ref LensSettings lens, Rect softGuide, Rect hardGuide, float targetDistance)
			{
				bool flag = m_Aspect != lens.Aspect || softGuide != m_DeadZoneRect || hardGuide != m_HardLimitRect || m_ScreenBounds == Vector2.zero;
				if (lens.Orthographic)
				{
					float num = Mathf.Abs(lens.OrthographicSize / targetDistance);
					if (m_OrthoSizeOverDistance == 0f || Mathf.Abs(num - m_OrthoSizeOverDistance) / m_OrthoSizeOverDistance > m_OrthoSizeOverDistance * 0.01f)
					{
						flag = true;
					}
					if (flag)
					{
						m_HalfFovRad = new Vector2(Mathf.Atan(lens.Aspect * num), Mathf.Atan(num));
						Fov = new Vector2(114.59156f * m_HalfFovRad.x, 114.59156f * m_HalfFovRad.y);
						m_OrthoSizeOverDistance = num;
					}
				}
				else
				{
					float fieldOfView = lens.FieldOfView;
					if (Fov.y != fieldOfView)
					{
						flag = true;
					}
					if (flag)
					{
						float num2 = fieldOfView * (MathF.PI / 180f) * 0.5f;
						m_HalfFovRad = new Vector2((float)Math.Atan(Math.Tan(num2) * (double)lens.Aspect), num2);
						Fov = new Vector2(57.29578f * m_HalfFovRad.x * 2f, fieldOfView);
						m_OrthoSizeOverDistance = 0f;
					}
				}
				if (flag)
				{
					m_Aspect = lens.Aspect;
					m_ScreenBounds = new Vector2(Mathf.Tan(m_HalfFovRad.x), Mathf.Tan(m_HalfFovRad.y));
					m_DeadZoneRect = softGuide;
					m_HardLimitRect = hardGuide;
					FovSoftGuideRect = new Rect
					{
						min = ScreenToAngle(softGuide.min),
						max = ScreenToAngle(softGuide.max)
					};
					FovHardGuideRect = new Rect
					{
						min = ScreenToAngle(hardGuide.min),
						max = ScreenToAngle(hardGuide.max)
					};
				}
			}

			private readonly Vector2 ScreenToAngle(Vector2 p)
			{
				return new Vector2((m_HalfFovRad.x + Mathf.Atan(2f * (p.x - 0.5f) * m_ScreenBounds.x)) / (2f * m_HalfFovRad.x), (m_HalfFovRad.y + Mathf.Atan(2f * (p.y - 0.5f) * m_ScreenBounds.y)) / (2f * m_HalfFovRad.y));
			}

			public readonly Vector3 DirectionFromScreen(Vector2 p)
			{
				return new Vector3(2f * (p.x - 0.5f) * m_ScreenBounds.x, -2f * (p.y - 0.5f) * m_ScreenBounds.y, 1f);
			}
		}

		[Header("Composition")]
		[HideFoldout]
		public ScreenComposerSettings Composition = ScreenComposerSettings.Default;

		[Tooltip("Force target to center of screen when this camera activates.  If false, will clamp target to the edges of the dead zone")]
		public bool CenterOnActivate = true;

		[Header("Target Tracking")]
		[Tooltip("Target offset from the target object's center in target-local space. Use this to fine-tune the tracking target position when the desired area is not the tracked object's center.")]
		[FormerlySerializedAs("TrackedObjectOffset")]
		public Vector3 TargetOffset;

		[Tooltip("How aggressively the camera tries to follow the target in the screen space. Small numbers are more responsive, rapidly orienting the camera to keep the target in the dead zone. Larger numbers give a more heavy slowly responding camera. Using different vertical and horizontal settings can yield a wide range of camera behaviors.")]
		public Vector2 Damping;

		[FoldoutWithEnabledButton("Enabled")]
		public LookaheadSettings Lookahead;

		private Vector3 m_CameraPosPrevFrame = Vector3.zero;

		private Vector3 m_LookAtPrevFrame = Vector3.zero;

		private Vector2 m_ScreenOffsetPrevFrame = Vector2.zero;

		private Quaternion m_CameraOrientationPrevFrame = Quaternion.identity;

		internal PositionPredictor m_Predictor;

		private ScreenComposerSettings m_CompositionLastFrame;

		private FovCache m_Cache;

		public override bool IsValid
		{
			get
			{
				if (base.enabled)
				{
					return base.LookAtTarget != null;
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Aim;

		internal override bool CameraLooksAtTarget => true;

		internal Vector3 TrackedPoint { get; private set; }

		internal ScreenComposerSettings GetEffectiveComposition => m_CompositionLastFrame;

		ScreenComposerSettings CinemachineFreeLookModifier.IModifiableComposition.Composition
		{
			get
			{
				return Composition;
			}
			set
			{
				Composition = value;
			}
		}

		private void Reset()
		{
			TargetOffset = Vector3.zero;
			Lookahead = default(LookaheadSettings);
			Damping = new Vector2(0.5f, 0.5f);
			Composition = ScreenComposerSettings.Default;
			CenterOnActivate = true;
		}

		private void OnValidate()
		{
			Damping.x = Mathf.Max(0f, Damping.x);
			Damping.y = Mathf.Max(0f, Damping.y);
			Composition.Validate();
		}

		private Vector3 GetLookAtPointAndSetTrackedPoint(Vector3 lookAt, Vector3 up, float deltaTime)
		{
			Vector3 vector = lookAt;
			if (base.LookAtTarget != null)
			{
				vector += base.LookAtTargetRotation * TargetOffset;
			}
			if (!Lookahead.Enabled || Lookahead.Time < 0.0001f)
			{
				TrackedPoint = vector;
			}
			else
			{
				bool flag = base.VirtualCamera.LookAtTargetChanged || !base.VirtualCamera.PreviousStateIsValid;
				m_Predictor.Smoothing = Lookahead.Smoothing;
				m_Predictor.AddPosition(vector, flag ? (-1f) : deltaTime);
				Vector3 vector2 = m_Predictor.PredictPositionDelta(Lookahead.Time);
				if (Lookahead.IgnoreY)
				{
					vector2 = vector2.ProjectOntoPlane(up);
				}
				TrackedPoint = vector + vector2;
			}
			return TrackedPoint;
		}

		public override void OnTargetObjectWarped(Transform target, Vector3 positionDelta)
		{
			base.OnTargetObjectWarped(target, positionDelta);
			if (target == base.LookAtTarget)
			{
				m_CameraPosPrevFrame += positionDelta;
				m_LookAtPrevFrame += positionDelta;
				m_Predictor.ApplyTransformDelta(positionDelta);
			}
		}

		public override void ForceCameraPosition(Vector3 pos, Quaternion rot)
		{
			base.ForceCameraPosition(pos, rot);
			m_Predictor.ApplyRotationDelta(rot * Quaternion.Inverse(m_CameraOrientationPrevFrame));
			m_CameraPosPrevFrame = pos;
			m_CameraOrientationPrevFrame = rot;
		}

		public override float GetMaxDampTime()
		{
			return Mathf.Max(Damping.x, Damping.y);
		}

		public override void PrePipelineMutateCameraState(ref CameraState curState, float deltaTime)
		{
			if (IsValid && curState.HasLookAt())
			{
				curState.ReferenceLookAt = GetLookAtPointAndSetTrackedPoint(curState.ReferenceLookAt, curState.ReferenceUp, deltaTime);
			}
		}

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			if (!IsValid || !curState.HasLookAt())
			{
				return;
			}
			if (!(TrackedPoint - curState.ReferenceLookAt).AlmostZero())
			{
				Vector3 vector = Vector3.Lerp(curState.GetCorrectedPosition(), curState.ReferenceLookAt, 0.5f);
				Vector3 lhs = curState.ReferenceLookAt - vector;
				Vector3 rhs = TrackedPoint - vector;
				if (Vector3.Dot(lhs, rhs) < 0f)
				{
					float t = Vector3.Distance(curState.ReferenceLookAt, vector) / Vector3.Distance(curState.ReferenceLookAt, TrackedPoint);
					TrackedPoint = Vector3.Lerp(curState.ReferenceLookAt, TrackedPoint, t);
				}
			}
			float magnitude = (TrackedPoint - curState.GetCorrectedPosition()).magnitude;
			if (magnitude < 0.0001f)
			{
				if (deltaTime >= 0f && base.VirtualCamera.PreviousStateIsValid)
				{
					curState.RawOrientation = m_CameraOrientationPrevFrame;
				}
				return;
			}
			m_Cache.UpdateCache(ref curState.Lens, Composition.DeadZoneRect, Composition.HardLimitsRect, magnitude);
			Quaternion rawOrientation = curState.RawOrientation;
			if (deltaTime < 0f || !base.VirtualCamera.PreviousStateIsValid)
			{
				rawOrientation = Quaternion.LookRotation(rawOrientation * Vector3.forward, curState.ReferenceUp);
				Rect screenRect = m_Cache.FovSoftGuideRect;
				if (CenterOnActivate)
				{
					screenRect = new Rect(screenRect.center, Vector2.zero);
				}
				RotateToScreenBounds(ref curState, screenRect, curState.ReferenceLookAt, ref rawOrientation, m_Cache.Fov, -1f);
			}
			else
			{
				Vector3 vector2 = m_LookAtPrevFrame - m_CameraPosPrevFrame;
				if (vector2.AlmostZero())
				{
					rawOrientation = Quaternion.LookRotation(m_CameraOrientationPrevFrame * Vector3.forward, curState.ReferenceUp);
				}
				else
				{
					vector2 = curState.RotationDampingBypass * vector2;
					if (Composition.ScreenPosition != m_CompositionLastFrame.ScreenPosition)
					{
						Vector3 v = m_Cache.DirectionFromScreen(m_CompositionLastFrame.ScreenPosition);
						Vector3 v2 = m_Cache.DirectionFromScreen(Composition.ScreenPosition);
						Quaternion quaternion2 = Quaternion.identity.ApplyCameraRotation(m_ScreenOffsetPrevFrame, Vector3.up);
						quaternion2 *= UnityVectorExtensions.SafeFromToRotation(v, v2, Vector3.up);
						m_ScreenOffsetPrevFrame = Quaternion.identity.GetCameraRotationToTarget(quaternion2 * Vector3.forward, Vector3.up);
					}
					rawOrientation = Quaternion.LookRotation(vector2, curState.ReferenceUp);
					rawOrientation = rawOrientation.ApplyCameraRotation(-m_ScreenOffsetPrevFrame, curState.ReferenceUp);
				}
				RotateToScreenBounds(ref curState, m_Cache.FovSoftGuideRect, TrackedPoint, ref rawOrientation, m_Cache.Fov, deltaTime);
				if (Composition.HardLimits.Enabled && (deltaTime < 0f || base.VirtualCamera.LookAtTargetAttachment > 0.9999f))
				{
					RotateToScreenBounds(ref curState, m_Cache.FovHardGuideRect, curState.ReferenceLookAt, ref rawOrientation, m_Cache.Fov, -1f);
				}
			}
			m_CameraPosPrevFrame = curState.GetCorrectedPosition();
			m_LookAtPrevFrame = TrackedPoint;
			m_CameraOrientationPrevFrame = rawOrientation.normalized;
			m_ScreenOffsetPrevFrame = m_CameraOrientationPrevFrame.GetCameraRotationToTarget(m_LookAtPrevFrame - m_CameraPosPrevFrame, curState.ReferenceUp);
			m_CompositionLastFrame = Composition;
			curState.RawOrientation = m_CameraOrientationPrevFrame;
		}

		private void RotateToScreenBounds(ref CameraState state, Rect screenRect, Vector3 trackedPoint, ref Quaternion rigOrientation, Vector2 fov, float deltaTime)
		{
			Vector3 vector = trackedPoint - state.GetCorrectedPosition();
			Vector2 cameraRotationToTarget = rigOrientation.GetCameraRotationToTarget(vector, state.ReferenceUp);
			ClampVerticalBounds(ref screenRect, vector, state.ReferenceUp, fov.y);
			float num = (screenRect.yMin - 0.5f) * fov.y;
			float num2 = (screenRect.yMax - 0.5f) * fov.y;
			if (cameraRotationToTarget.x < num)
			{
				cameraRotationToTarget.x -= num;
			}
			else if (cameraRotationToTarget.x > num2)
			{
				cameraRotationToTarget.x -= num2;
			}
			else
			{
				cameraRotationToTarget.x = 0f;
			}
			num = (screenRect.xMin - 0.5f) * fov.x;
			num2 = (screenRect.xMax - 0.5f) * fov.x;
			if (cameraRotationToTarget.y < num)
			{
				cameraRotationToTarget.y -= num;
			}
			else if (cameraRotationToTarget.y > num2)
			{
				cameraRotationToTarget.y -= num2;
			}
			else
			{
				cameraRotationToTarget.y = 0f;
			}
			if (deltaTime >= 0f && base.VirtualCamera.PreviousStateIsValid)
			{
				cameraRotationToTarget.x = base.VirtualCamera.DetachedLookAtTargetDamp(cameraRotationToTarget.x, Damping.y, deltaTime);
				cameraRotationToTarget.y = base.VirtualCamera.DetachedLookAtTargetDamp(cameraRotationToTarget.y, Damping.x, deltaTime);
			}
			rigOrientation = rigOrientation.ApplyCameraRotation(cameraRotationToTarget, state.ReferenceUp);
		}

		private static bool ClampVerticalBounds(ref Rect r, Vector3 dir, Vector3 up, float fov)
		{
			float num = UnityVectorExtensions.Angle(dir, up);
			float num2 = fov / 2f + 1f;
			if (num < num2)
			{
				float num3 = 1f - (num2 - num) / fov;
				if (r.yMax > num3)
				{
					r.yMin = Mathf.Min(r.yMin, num3);
					r.yMax = Mathf.Min(r.yMax, num3);
					return true;
				}
			}
			if (num > 180f - num2)
			{
				float num4 = (num - (180f - num2)) / fov;
				if (num4 > r.yMin)
				{
					r.yMin = Mathf.Max(r.yMin, num4);
					r.yMax = Mathf.Max(r.yMax, num4);
					return true;
				}
			}
			return false;
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Position Control/Cinemachine Spline Dolly")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Body)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineSplineDolly.html")]
	public class CinemachineSplineDolly : CinemachineComponentBase, ISplineReferencer
	{
		public enum RotationMode
		{
			Default,
			Spline,
			SplineNoRoll,
			FollowTarget,
			FollowTargetNoRoll
		}

		[Serializable]
		public struct DampingSettings
		{
			[Tooltip("Enables damping, which causes the camera to move gradually towards the desired spline position")]
			public bool Enabled;

			[Tooltip("How aggressively the camera tries to maintain the offset along the x, y, or z directions in spline local space. \n- x represents the axis that is perpendicular to the spline. Use this to smooth out imperfections in the path. This may move the camera off the spline.\n- y represents the axis that is defined by the spline-local up direction. Use this to smooth out imperfections in the path. This may move the camera off the spline.\n- z represents the axis that is parallel to the spline. This won't move the camera off the spline.\n\nSmaller numbers are more responsive, larger numbers give a heavier more slowly responding camera. Using different settings per axis can yield a wide range of camera behaviors.")]
			public Vector3 Position;

			[Range(0f, 20f)]
			[Tooltip("How aggressively the camera tries to maintain the desired rotation.  This is only used if Camera Rotation is not Default.")]
			public float Angular;
		}

		[SerializeField]
		[FormerlySerializedAs("SplineSettings")]
		private SplineSettings m_SplineSettings = new SplineSettings
		{
			Units = PathIndexUnit.Normalized
		};

		[Tooltip("Where to put the camera relative to the spline position.  X is perpendicular to the spline, Y is up, and Z is parallel to the spline.")]
		public Vector3 SplineOffset = Vector3.zero;

		[Tooltip("How to set the camera's rotation and Up.  This will affect the screen composition, because the camera Aim behaviours will always try to respect the Up direction.")]
		[FormerlySerializedAs("CameraUp")]
		public RotationMode CameraRotation;

		[FoldoutWithEnabledButton("Enabled")]
		[Tooltip("Settings for controlling damping, which causes the camera to move gradually towards the desired spline position")]
		public DampingSettings Damping;

		[NoSaveDuringPlay]
		[FoldoutWithEnabledButton("Enabled")]
		[Tooltip("Controls how automatic dolly occurs.  A tracking target may be necessary to use this feature.")]
		public SplineAutoDolly AutomaticDolly;

		private float m_PreviousSplinePosition;

		private Quaternion m_PreviousRotation;

		private Vector3 m_PreviousPosition;

		private CinemachineSplineRoll.RollCache m_RollCache;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("CameraPosition")]
		private float m_LegacyPosition = -1f;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("PositionUnits")]
		private PathIndexUnit m_LegacyUnits;

		[SerializeField]
		[HideInInspector]
		[NoSaveDuringPlay]
		[FormerlySerializedAs("Spline")]
		private SplineContainer m_LegacySpline;

		public ref SplineSettings SplineSettings => ref m_SplineSettings;

		public SplineContainer Spline
		{
			get
			{
				return m_SplineSettings.Spline;
			}
			set
			{
				m_SplineSettings.Spline = value;
			}
		}

		public float CameraPosition
		{
			get
			{
				return m_SplineSettings.Position;
			}
			set
			{
				m_SplineSettings.Position = value;
			}
		}

		public PathIndexUnit PositionUnits
		{
			get
			{
				return m_SplineSettings.Units;
			}
			set
			{
				m_SplineSettings.ChangeUnitPreservePosition(value);
			}
		}

		public override bool IsValid
		{
			get
			{
				if (base.enabled)
				{
					return Spline != null;
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Body;

		private void PerformLegacyUpgrade()
		{
			if (m_LegacyPosition != -1f)
			{
				m_SplineSettings.Position = m_LegacyPosition;
				m_SplineSettings.Units = m_LegacyUnits;
				m_LegacyPosition = -1f;
				m_LegacyUnits = PathIndexUnit.Distance;
			}
			if (m_LegacySpline != null)
			{
				m_SplineSettings.Spline = m_LegacySpline;
				m_LegacySpline = null;
			}
		}

		private void OnValidate()
		{
			PerformLegacyUpgrade();
			Damping.Position.x = Mathf.Clamp(Damping.Position.x, 0f, 20f);
			Damping.Position.y = Mathf.Clamp(Damping.Position.y, 0f, 20f);
			Damping.Position.z = Mathf.Clamp(Damping.Position.z, 0f, 20f);
			Damping.Angular = Mathf.Clamp(Damping.Angular, 0f, 20f);
			AutomaticDolly.Method?.Validate();
		}

		private void Reset()
		{
			m_SplineSettings = new SplineSettings
			{
				Units = PathIndexUnit.Normalized
			};
			SplineOffset = Vector3.zero;
			CameraRotation = RotationMode.Default;
			Damping = default(DampingSettings);
			AutomaticDolly.Method = null;
		}

		protected override void OnEnable()
		{
			base.OnEnable();
			m_RollCache.Refresh(this);
			AutomaticDolly.Method?.Reset();
		}

		protected override void OnDisable()
		{
			m_SplineSettings.InvalidateCache();
			base.OnDisable();
		}

		public override float GetMaxDampTime()
		{
			if (Damping.Enabled)
			{
				return Mathf.Max(Mathf.Max(Damping.Position.x, Mathf.Max(Damping.Position.y, Damping.Position.z)), Damping.Angular);
			}
			return 0f;
		}

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			if (!IsValid)
			{
				return;
			}
			CachedScaledSpline cachedSpline = m_SplineSettings.GetCachedSpline();
			if (cachedSpline == null)
			{
				return;
			}
			float maxPos;
			float num = cachedSpline.StandardizePosition(CameraPosition, PositionUnits, out maxPos);
			if (deltaTime < 0f || !base.VirtualCamera.PreviousStateIsValid)
			{
				m_PreviousSplinePosition = num;
				m_PreviousPosition = curState.RawPosition;
				m_PreviousRotation = curState.RawOrientation;
				m_RollCache.Refresh(this);
			}
			if (AutomaticDolly.Enabled && AutomaticDolly.Method != null)
			{
				num = AutomaticDolly.Method.GetSplinePosition(this, base.FollowTarget, Spline, num, PositionUnits, deltaTime);
			}
			if (Damping.Enabled && deltaTime >= 0f && base.VirtualCamera.PreviousStateIsValid)
			{
				float num2 = m_PreviousSplinePosition;
				if (cachedSpline.Closed && Mathf.Abs(num - num2) > maxPos * 0.5f)
				{
					num2 += ((num > num2) ? maxPos : (0f - maxPos));
				}
				num = num2 + Damper.Damp(num - num2, Damping.Position.z, deltaTime);
			}
			float previousSplinePosition = (CameraPosition = num);
			m_PreviousSplinePosition = previousSplinePosition;
			cachedSpline.EvaluateSplineWithRoll(Spline.transform, cachedSpline.ConvertIndexUnit(num, PositionUnits, PathIndexUnit.Normalized), m_RollCache.GetSplineRoll(this), out var position, out var rotation);
			Vector3 vector = rotation * Vector3.right;
			Vector3 vector2 = rotation * Vector3.up;
			Vector3 vector3 = rotation * Vector3.forward;
			position += SplineOffset.x * vector;
			position += SplineOffset.y * vector2;
			position += SplineOffset.z * vector3;
			if (Damping.Enabled && deltaTime >= 0f && base.VirtualCamera.PreviousStateIsValid)
			{
				Vector3 previousPosition = m_PreviousPosition;
				Vector3 vector4 = previousPosition - position;
				Vector3 vector5 = Vector3.Dot(vector4, vector2) * vector2;
				Vector3 initial = vector4 - vector5;
				initial = Damper.Damp(initial, Damping.Position.x, deltaTime);
				vector5 = Damper.Damp(vector5, Damping.Position.y, deltaTime);
				position = previousPosition - (initial + vector5);
			}
			curState.RawPosition = (m_PreviousPosition = position);
			bool isDefault;
			Quaternion quaternion2 = GetCameraRotationAtSplinePoint(rotation, curState.ReferenceUp, out isDefault);
			if (Damping.Enabled && deltaTime >= 0f && base.VirtualCamera.PreviousStateIsValid)
			{
				float t = base.VirtualCamera.DetachedFollowTargetDamp(1f, Damping.Angular, deltaTime);
				quaternion2 = Quaternion.Slerp(m_PreviousRotation, quaternion2, t);
			}
			m_PreviousRotation = quaternion2;
			curState.RawOrientation = quaternion2;
			if (!isDefault)
			{
				curState.ReferenceUp = curState.RawOrientation * Vector3.up;
			}
		}

		private Quaternion GetCameraRotationAtSplinePoint(Quaternion splineOrientation, Vector3 up, out bool isDefault)
		{
			isDefault = false;
			switch (CameraRotation)
			{
			case RotationMode.Spline:
				return splineOrientation;
			case RotationMode.SplineNoRoll:
				return Quaternion.LookRotation(splineOrientation * Vector3.forward, up);
			case RotationMode.FollowTarget:
				if (base.FollowTarget != null)
				{
					return base.FollowTargetRotation;
				}
				break;
			case RotationMode.FollowTargetNoRoll:
				if (base.FollowTarget != null)
				{
					return Quaternion.LookRotation(base.FollowTargetRotation * Vector3.forward, up);
				}
				break;
			}
			isDefault = true;
			return Quaternion.LookRotation(base.VirtualCamera.transform.rotation * Vector3.forward, up);
		}
	}
	[ExecuteAlways]
	[SaveDuringPlay]
	[CameraPipeline(CinemachineCore.Stage.Aim)]
	[AddComponentMenu("Cinemachine/Procedural/Rotation Control/Cinemachine Spline Dolly LookAt Targets")]
	[DisallowMultipleComponent]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineSplineDollyLookAtTargets.html")]
	public class CinemachineSplineDollyLookAtTargets : CinemachineComponentBase
	{
		[Serializable]
		public struct Item
		{
			[Tooltip("The target object to look at.  It may be None, in which case the Offset will specify a point in world space.")]
			public Transform LookAt;

			[Tooltip("The offset (in local coords) from the LookAt target's origin.  If LookAt target is None, this will specify a world-space point.")]
			public Vector3 Offset;

			[Tooltip("Controls how to ease in and out of this data point.  A value of 0 will linearly interpolate between LookAt points, while a value of 1 will slow down and briefly pause the rotation to look at the target.")]
			[Range(0f, 1f)]
			public float Easing;

			public Vector3 WorldLookAt
			{
				readonly get
				{
					if (!(LookAt == null))
					{
						return LookAt.TransformPoint(Offset);
					}
					return Offset;
				}
				set
				{
					Offset = ((LookAt == null) ? value : LookAt.InverseTransformPoint(value));
				}
			}
		}

		[StructLayout(LayoutKind.Sequential, Size = 1)]
		internal struct LerpItem : IInterpolator<Item>
		{
			public Item Interpolate(Item a, Item b, float t)
			{
				float num = t * t;
				float num2 = 1f - t;
				t = 3f * num2 * num2 * t * Mathf.Lerp(0.3333f, 0f, a.Easing) + 3f * num2 * num * Mathf.Lerp(0.6666f, 1f, b.Easing) + t * num;
				return new Item
				{
					Offset = Vector3.Lerp(a.WorldLookAt, b.WorldLookAt, t)
				};
			}
		}

		[Tooltip("LookAt targets for the camera at specific positions on the Spline")]
		public SplineData<Item> Targets = new SplineData<Item>
		{
			DefaultValue = new Item
			{
				Easing = 1f
			}
		};

		public override bool IsValid
		{
			get
			{
				SplineContainer spline;
				CinemachineSplineDolly dolly;
				if (base.enabled && Targets != null)
				{
					return GetGetSplineAndDolly(out spline, out dolly);
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Aim;

		private void Reset()
		{
			Targets = new SplineData<Item>
			{
				DefaultValue = new Item
				{
					Easing = 1f
				}
			};
		}

		public override void MutateCameraState(ref CameraState state, float deltaTime)
		{
			if (!GetGetSplineAndDolly(out var _, out var dolly))
			{
				return;
			}
			CachedScaledSpline cachedSpline = dolly.SplineSettings.GetCachedSpline();
			Item item = Targets.Evaluate(cachedSpline, dolly.CameraPosition, dolly.PositionUnits, default(LerpItem));
			Vector3 vector = item.WorldLookAt - state.RawPosition;
			if (vector.sqrMagnitude > 0.0001f)
			{
				Vector3 vector2 = state.ReferenceUp;
				if (Vector3.Cross(vector, vector2).sqrMagnitude < 0.0001f)
				{
					vector2 = state.RawOrientation * Vector3.back;
					if (Vector3.Cross(vector, vector2).sqrMagnitude < 0.0001f)
					{
						vector2 = state.RawOrientation * Vector3.left;
					}
				}
				state.RawOrientation = Quaternion.LookRotation(vector, vector2);
			}
			state.ReferenceLookAt = item.Offset;
		}

		internal bool GetGetSplineAndDolly(out SplineContainer spline, out CinemachineSplineDolly dolly)
		{
			dolly = null;
			if (this != null && TryGetComponent<CinemachineSplineDolly>(out dolly))
			{
				spline = dolly.Spline;
				if (spline != null)
				{
					return spline.Spline != null;
				}
				return false;
			}
			spline = null;
			return false;
		}
	}
	[AddComponentMenu("Cinemachine/Procedural/Position Control/Cinemachine Third Person Follow")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[CameraPipeline(CinemachineCore.Stage.Body)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineThirdPersonFollow.html")]
	public class CinemachineThirdPersonFollow : CinemachineComponentBase, CinemachineFreeLookModifier.IModifierValueSource, CinemachineFreeLookModifier.IModifiablePositionDamping, CinemachineFreeLookModifier.IModifiableDistance
	{
		[Serializable]
		public struct ObstacleSettings
		{
			[Tooltip("If enabled, camera will be pulled in front of occluding obstacles")]
			public bool Enabled;

			[Tooltip("Camera will avoid obstacles on these layers")]
			public LayerMask CollisionFilter;

			[TagField]
			[Tooltip("Obstacles with this tag will be ignored.  It is a good idea to set this field to the target's tag")]
			public string IgnoreTag;

			[Tooltip("Specifies how close the camera can get to obstacles")]
			[Range(0f, 1f)]
			public float CameraRadius;

			[Range(0f, 10f)]
			[Tooltip("How gradually the camera moves to correct for occlusions.  Higher numbers will move the camera more gradually.")]
			public float DampingIntoCollision;

			[Range(0f, 10f)]
			[Tooltip("How gradually the camera returns to its normal position after having been corrected by the built-in collision resolution system.  Higher numbers will move the camera more gradually back to normal.")]
			public float DampingFromCollision;

			internal static ObstacleSettings Default => new ObstacleSettings
			{
				Enabled = false,
				CollisionFilter = 1,
				IgnoreTag = string.Empty,
				CameraRadius = 0.2f,
				DampingIntoCollision = 0f,
				DampingFromCollision = 0.5f
			};
		}

		[Tooltip("How responsively the camera tracks the target.  Each axis (camera-local) can have its own setting.  Value is the approximate time it takes the camera to catch up to the target's new position.  Smaller values give a more rigid effect, larger values give a squishier one")]
		public Vector3 Damping;

		[Header("Rig")]
		[Tooltip("Position of the shoulder pivot relative to the Follow target origin.  This offset is in target-local space")]
		public Vector3 ShoulderOffset;

		[Tooltip("Vertical offset of the hand in relation to the shoulder.  Arm length will affect the follow target's screen position when the camera rotates vertically")]
		public float VerticalArmLength;

		[Tooltip("Specifies which shoulder (left, right, or in-between) the camera is on")]
		[Range(0f, 1f)]
		public float CameraSide;

		[Tooltip("How far behind the hand the camera will be placed")]
		public float CameraDistance;

		[FoldoutWithEnabledButton("Enabled")]
		public ObstacleSettings AvoidObstacles = ObstacleSettings.Default;

		private Vector3 m_PreviousFollowTargetPosition;

		private Vector3 m_DampingCorrection;

		private float m_CamPosCollisionCorrection;

		public Collider CurrentObstacle { get; set; }

		float CinemachineFreeLookModifier.IModifierValueSource.NormalizedModifierValue
		{
			get
			{
				Vector3 referenceUp = base.VirtualCamera.State.ReferenceUp;
				Quaternion followTargetRotation = base.FollowTargetRotation;
				return Mathf.Clamp(Vector3.SignedAngle(followTargetRotation * Vector3.up, referenceUp, followTargetRotation * Vector3.right), -90f, 90f) / -90f;
			}
		}

		Vector3 CinemachineFreeLookModifier.IModifiablePositionDamping.PositionDamping
		{
			get
			{
				return Damping;
			}
			set
			{
				Damping = value;
			}
		}

		float CinemachineFreeLookModifier.IModifiableDistance.Distance
		{
			get
			{
				return CameraDistance;
			}
			set
			{
				CameraDistance = value;
			}
		}

		public override bool IsValid
		{
			get
			{
				if (base.enabled)
				{
					return base.FollowTarget != null;
				}
				return false;
			}
		}

		public override CinemachineCore.Stage Stage => CinemachineCore.Stage.Body;

		private void OnValidate()
		{
			CameraSide = Mathf.Clamp(CameraSide, -1f, 1f);
			Damping.x = Mathf.Max(0f, Damping.x);
			Damping.y = Mathf.Max(0f, Damping.y);
			Damping.z = Mathf.Max(0f, Damping.z);
			AvoidObstacles.CameraRadius = Mathf.Max(0.001f, AvoidObstacles.CameraRadius);
			AvoidObstacles.DampingIntoCollision = Mathf.Max(0f, AvoidObstacles.DampingIntoCollision);
			AvoidObstacles.DampingFromCollision = Mathf.Max(0f, AvoidObstacles.DampingFromCollision);
		}

		private void Reset()
		{
			ShoulderOffset = new Vector3(0.5f, -0.4f, 0f);
			VerticalArmLength = 0.4f;
			CameraSide = 1f;
			CameraDistance = 2f;
			Damping = new Vector3(0.1f, 0.5f, 0.3f);
			AvoidObstacles = ObstacleSettings.Default;
		}

		public override float GetMaxDampTime()
		{
			return Mathf.Max(AvoidObstacles.Enabled ? Mathf.Max(AvoidObstacles.DampingIntoCollision, AvoidObstacles.DampingFromCollision) : 0f, Mathf.Max(Damping.x, Mathf.Max(Damping.y, Damping.z)));
		}

		public override void MutateCameraState(ref CameraState curState, float deltaTime)
		{
			if (IsValid)
			{
				if (!base.VirtualCamera.PreviousStateIsValid)
				{
					deltaTime = -1f;
				}
				PositionCamera(ref curState, deltaTime);
			}
		}

		public override void OnTargetObjectWarped(Transform target, Vector3 positionDelta)
		{
			base.OnTargetObjectWarped(target, positionDelta);
			if (target == base.FollowTarget)
			{
				m_PreviousFollowTargetPosition += positionDelta;
			}
		}

		private void PositionCamera(ref CameraState curState, float deltaTime)
		{
			Vector3 referenceUp = curState.ReferenceUp;
			Vector3 followTargetPosition = base.FollowTargetPosition;
			Quaternion followTargetRotation = base.FollowTargetRotation;
			Vector3 vector = followTargetRotation * Vector3.forward;
			Quaternion heading = GetHeading(followTargetRotation, referenceUp);
			if (deltaTime < 0f)
			{
				m_DampingCorrection = Vector3.zero;
				m_CamPosCollisionCorrection = 0f;
			}
			else
			{
				m_DampingCorrection += Quaternion.Inverse(heading) * (m_PreviousFollowTargetPosition - followTargetPosition);
				m_DampingCorrection -= base.VirtualCamera.DetachedFollowTargetDamp(m_DampingCorrection, Damping, deltaTime);
			}
			m_PreviousFollowTargetPosition = followTargetPosition;
			Vector3 root = followTargetPosition;
			GetRawRigPositions(root, followTargetRotation, heading, out var _, out var hand);
			Vector3 vector2 = hand - vector * (CameraDistance - m_DampingCorrection.z);
			CurrentObstacle = null;
			if (AvoidObstacles.Enabled)
			{
				float collisionCorrection = 0f;
				Vector3 root2 = ResolveCollisions(root, hand, -1f, AvoidObstacles.CameraRadius * 1.05f, ref collisionCorrection);
				vector2 = ResolveCollisions(root2, vector2, deltaTime, AvoidObstacles.CameraRadius, ref m_CamPosCollisionCorrection);
			}
			curState.RawPosition = vector2;
			curState.RawOrientation = followTargetRotation;
			if (!curState.HasLookAt() || curState.ReferenceLookAt.Equals(followTargetPosition))
			{
				curState.ReferenceLookAt = followTargetPosition + vector * 0.01f;
			}
		}

		public void GetRigPositions(out Vector3 root, out Vector3 shoulder, out Vector3 hand)
		{
			Vector3 referenceUp = base.VirtualCamera.State.ReferenceUp;
			Quaternion followTargetRotation = base.FollowTargetRotation;
			Quaternion heading = GetHeading(followTargetRotation, referenceUp);
			root = m_PreviousFollowTargetPosition;
			GetRawRigPositions(root, followTargetRotation, heading, out shoulder, out hand);
			if (AvoidObstacles.Enabled)
			{
				float collisionCorrection = 0f;
				hand = ResolveCollisions(root, hand, -1f, AvoidObstacles.CameraRadius * 1.05f, ref collisionCorrection);
			}
		}

		internal static Quaternion GetHeading(Quaternion targetRot, Vector3 up)
		{
			Vector3 vector = targetRot * Vector3.forward;
			Vector3 vector2 = Vector3.Cross(up, Vector3.Cross(vector.ProjectOntoPlane(up), up));
			if (vector2.AlmostZero())
			{
				vector2 = Vector3.Cross(targetRot * Vector3.right, up);
			}
			return Quaternion.LookRotation(vector2, up);
		}

		private void GetRawRigPositions(Vector3 root, Quaternion targetRot, Quaternion heading, out Vector3 shoulder, out Vector3 hand)
		{
			Vector3 shoulderOffset = ShoulderOffset;
			shoulderOffset.x = Mathf.Lerp(0f - shoulderOffset.x, shoulderOffset.x, CameraSide);
			shoulderOffset.x += m_DampingCorrection.x;
			shoulderOffset.y += m_DampingCorrection.y;
			shoulder = root + heading * shoulderOffset;
			hand = shoulder + targetRot * new Vector3(0f, VerticalArmLength, 0f);
		}

		private Vector3 ResolveCollisions(Vector3 root, Vector3 tip, float deltaTime, float cameraRadius, ref float collisionCorrection)
		{
			if (AvoidObstacles.CollisionFilter.value == 0)
			{
				return tip;
			}
			Vector3 vector = tip - root;
			float magnitude = vector.magnitude;
			if (magnitude < 0.0001f)
			{
				return tip;
			}
			vector /= magnitude;
			Vector3 result = tip;
			float num = 0f;
			if (RuntimeUtility.SphereCastIgnoreTag(new Ray(root, vector), cameraRadius, out var hitInfo, magnitude, AvoidObstacles.CollisionFilter, in AvoidObstacles.IgnoreTag))
			{
				CurrentObstacle = hitInfo.collider;
				num = (hitInfo.point + hitInfo.normal * cameraRadius - tip).magnitude;
			}
			collisionCorrection += ((deltaTime < 0f) ? (num - collisionCorrection) : Damper.Damp(num - collisionCorrection, (num > collisionCorrection) ? AvoidObstacles.DampingIntoCollision : AvoidObstacles.DampingFromCollision, deltaTime));
			if (collisionCorrection > 0.0001f)
			{
				result -= vector * collisionCorrection;
			}
			return result;
		}
	}
	internal class BlendManager : CameraBlendStack
	{
		private CinemachineBlend m_CurrentLiveCameras = new CinemachineBlend();

		private HashSet<ICinemachineCamera> m_PreviousLiveCameras = new HashSet<ICinemachineCamera>();

		private ICinemachineCamera m_PreviousActiveCamera;

		private bool m_WasBlending;

		public ICinemachineCamera ActiveVirtualCamera => DeepCamBFromBlend(m_CurrentLiveCameras);

		public CinemachineBlend ActiveBlend
		{
			get
			{
				if (m_CurrentLiveCameras.CamA == null || m_CurrentLiveCameras.IsComplete)
				{
					return null;
				}
				return m_CurrentLiveCameras;
			}
			set
			{
				SetRootBlend(value);
			}
		}

		public bool IsBlending => ActiveBlend != null;

		public string Description
		{
			get
			{
				if (ActiveVirtualCamera == null)
				{
					return "[(none)]";
				}
				StringBuilder stringBuilder = CinemachineDebug.SBFromPool();
				stringBuilder.Append("[");
				stringBuilder.Append(IsBlending ? ActiveBlend.Description : ActiveVirtualCamera.Name);
				stringBuilder.Append("]");
				string result = stringBuilder.ToString();
				CinemachineDebug.ReturnToPool(stringBuilder);
				return result;
			}
		}

		public CameraState CameraState => m_CurrentLiveCameras.State;

		public override void OnEnable()
		{
			base.OnEnable();
			m_PreviousLiveCameras.Clear();
			m_PreviousActiveCamera = null;
			m_WasBlending = false;
		}

		private static ICinemachineCamera DeepCamBFromBlend(CinemachineBlend blend)
		{
			ICinemachineCamera cinemachineCamera;
			for (cinemachineCamera = blend?.CamB; cinemachineCamera is NestedBlendSource nestedBlendSource; cinemachineCamera = nestedBlendSource.Blend.CamB)
			{
			}
			if (cinemachineCamera != null && cinemachineCamera.IsValid)
			{
				return cinemachineCamera;
			}
			return null;
		}

		public bool IsLiveInBlend(ICinemachineCamera cam)
		{
			if (cam != null)
			{
				if (cam == m_CurrentLiveCameras.CamA)
				{
					return true;
				}
				if (m_CurrentLiveCameras.CamA is NestedBlendSource nestedBlendSource && nestedBlendSource.Blend.Uses(cam))
				{
					return true;
				}
			}
			return false;
		}

		public bool IsLive(ICinemachineCamera cam)
		{
			return m_CurrentLiveCameras.Uses(cam);
		}

		public void ComputeCurrentBlend()
		{
			ProcessOverrideFrames(ref m_CurrentLiveCameras, 0);
		}

		public void RefreshCurrentCameraState(Vector3 up, float deltaTime)
		{
			m_CurrentLiveCameras.UpdateCameraState(up, deltaTime);
		}

		public ICinemachineCamera ProcessActiveCamera(ICinemachineMixer mixer, Vector3 up, float deltaTime)
		{
			foreach (ICinemachineCamera previousLiveCamera in m_PreviousLiveCameras)
			{
				if (!IsLive(previousLiveCamera))
				{
					CinemachineCore.CameraDeactivatedEvent.Invoke(mixer, previousLiveCamera);
				}
			}
			ICinemachineCamera activeVirtualCamera = ActiveVirtualCamera;
			if (activeVirtualCamera != null && activeVirtualCamera.IsValid)
			{
				ICinemachineCamera cinemachineCamera = m_PreviousActiveCamera;
				if (cinemachineCamera != null && !cinemachineCamera.IsValid)
				{
					cinemachineCamera = null;
				}
				if (activeVirtualCamera == cinemachineCamera)
				{
					if (m_WasBlending && m_CurrentLiveCameras.CamA == null)
					{
						CinemachineCore.BlendFinishedEvent.Invoke(mixer, activeVirtualCamera);
					}
				}
				else
				{
					ICinemachineCamera cinemachineCamera2 = cinemachineCamera;
					if (IsBlending)
					{
						cinemachineCamera2 = new NestedBlendSource(ActiveBlend);
						cinemachineCamera2.UpdateCameraState(up, deltaTime);
					}
					ICinemachineCamera.ActivationEventParams activationEventParams = new ICinemachineCamera.ActivationEventParams
					{
						Origin = mixer,
						OutgoingCamera = cinemachineCamera2,
						IncomingCamera = activeVirtualCamera,
						IsCut = !IsBlending,
						WorldUp = up,
						DeltaTime = deltaTime
					};
					activeVirtualCamera.OnCameraActivated(activationEventParams);
					mixer.OnCameraActivated(activationEventParams);
					CinemachineCore.CameraActivatedEvent.Invoke(activationEventParams);
					activeVirtualCamera.UpdateCameraState(up, deltaTime);
				}
			}
			m_PreviousLiveCameras.Clear();
			CollectLiveCameras(m_CurrentLiveCameras, ref m_PreviousLiveCameras);
			m_PreviousActiveCamera = DeepCamBFromBlend(m_CurrentLiveCameras);
			m_WasBlending = m_CurrentLiveCameras.CamA != null;
			return activeVirtualCamera;
			static void CollectLiveCameras(CinemachineBlend blend, ref HashSet<ICinemachineCamera> cams)
			{
				if (blend.CamA is NestedBlendSource { Blend: not null } nestedBlendSource)
				{
					CollectLiveCameras(nestedBlendSource.Blend, ref cams);
				}
				else if (blend.CamA != null)
				{
					cams.Add(blend.CamA);
				}
				if (blend.CamB is NestedBlendSource { Blend: not null } nestedBlendSource2)
				{
					CollectLiveCameras(nestedBlendSource2.Blend, ref cams);
				}
				else if (blend.CamB != null)
				{
					cams.Add(blend.CamB);
				}
			}
		}
	}
	public interface ICameraOverrideStack
	{
		Vector3 DefaultWorldUp { get; }

		int SetCameraOverride(int overrideId, int priority, ICinemachineCamera camA, ICinemachineCamera camB, float weightB, float deltaTime);

		void ReleaseCameraOverride(int overrideId);
	}
	internal class CameraBlendStack : ICameraOverrideStack
	{
		private class StackFrame : NestedBlendSource
		{
			public int Id;

			public int Priority;

			public readonly CinemachineBlend Source = new CinemachineBlend();

			public float DeltaTimeOverride;

			private readonly SnapshotBlendSource m_Snapshot = new SnapshotBlendSource();

			private ICinemachineCamera m_SnapshotSource;

			private float m_SnapshotBlendWeight;

			public bool Active => Source.IsValid;

			public StackFrame()
				: base(new CinemachineBlend())
			{
			}

			public ICinemachineCamera GetSnapshotIfAppropriate(ICinemachineCamera cam, float weight)
			{
				if (cam == null || (cam.State.BlendHint & CameraState.BlendHints.FreezeWhenBlendingOut) == 0)
				{
					m_Snapshot.TakeSnapshot(null);
					m_SnapshotSource = null;
					m_SnapshotBlendWeight = 0f;
					return cam;
				}
				if (m_SnapshotSource != cam || m_SnapshotBlendWeight > weight)
				{
					m_Snapshot.TakeSnapshot(cam);
					m_SnapshotSource = cam;
					m_SnapshotBlendWeight = weight;
				}
				return m_Snapshot;
			}
		}

		private class SnapshotBlendSource : ICinemachineCamera
		{
			private CameraState m_State;

			private string m_Name;

			public float RemainingTimeInBlend { get; set; }

			public string Name => m_Name;

			public string Description => Name;

			public CameraState State => m_State;

			public bool IsValid => true;

			public ICinemachineMixer ParentCamera => null;

			public SnapshotBlendSource(ICinemachineCamera source = null, float remainingTimeInBlend = 0f)
			{
				TakeSnapshot(source);
				RemainingTimeInBlend = remainingTimeInBlend;
			}

			public void UpdateCameraState(Vector3 worldUp, float deltaTime)
			{
			}

			public void OnCameraActivated(ICinemachineCamera.ActivationEventParams evt)
			{
			}

			public void TakeSnapshot(ICinemachineCamera source)
			{
				m_State = source?.State ?? CameraState.Default;
				m_State.BlendHint &= (CameraState.BlendHints)(-33);
				if (m_Name == null)
				{
					m_Name = ((source == null) ? "(null)" : ("*" + source.Name));
				}
			}
		}

		private const float kEpsilon = 0.0001f;

		private readonly List<StackFrame> m_FrameStack = new List<StackFrame>();

		private int m_NextFrameId;

		private static readonly AnimationCurve s_DefaultLinearAnimationCurve = AnimationCurve.Linear(0f, 0f, 1f, 1f);

		public Vector3 DefaultWorldUp => Vector3.up;

		public bool IsInitialized => m_FrameStack.Count > 0;

		public CinemachineBlendDefinition.LookupBlendDelegate LookupBlendDelegate { get; set; }

		public int SetCameraOverride(int overrideId, int priority, ICinemachineCamera camA, ICinemachineCamera camB, float weightB, float deltaTime)
		{
			if (overrideId < 0)
			{
				overrideId = ++m_NextFrameId;
			}
			if (m_FrameStack.Count == 0)
			{
				m_FrameStack.Add(new StackFrame());
			}
			StackFrame stackFrame = m_FrameStack[FindFrame(overrideId, priority)];
			stackFrame.DeltaTimeOverride = deltaTime;
			stackFrame.Source.TimeInBlend = weightB;
			if (stackFrame.Source.CamA != camA || stackFrame.Source.CamB != camB)
			{
				stackFrame.Source.CustomBlender = CinemachineCore.GetCustomBlender?.Invoke(camA, camB);
				stackFrame.Source.CamA = camA;
				stackFrame.Source.CamB = camB;
				if (camA is CinemachineVirtualCameraBase cinemachineVirtualCameraBase)
				{
					cinemachineVirtualCameraBase.EnsureStarted();
				}
				if (camB is CinemachineVirtualCameraBase cinemachineVirtualCameraBase2)
				{
					cinemachineVirtualCameraBase2.EnsureStarted();
				}
			}
			return overrideId;
			int FindFrame(int withId, int num2)
			{
				int count = m_FrameStack.Count;
				int num;
				for (num = count - 1; num > 0; num--)
				{
					if (m_FrameStack[num].Id == withId)
					{
						return num;
					}
				}
				for (num = 1; num < count && m_FrameStack[num].Priority <= num2; num++)
				{
				}
				StackFrame stackFrame2 = new StackFrame
				{
					Id = withId,
					Priority = num2
				};
				stackFrame2.Source.Duration = 1f;
				stackFrame2.Source.BlendCurve = s_DefaultLinearAnimationCurve;
				m_FrameStack.Insert(num, stackFrame2);
				return num;
			}
		}

		public void ReleaseCameraOverride(int overrideId)
		{
			for (int num = m_FrameStack.Count - 1; num > 0; num--)
			{
				if (m_FrameStack[num].Id == overrideId)
				{
					m_FrameStack.RemoveAt(num);
					break;
				}
			}
		}

		public virtual void OnEnable()
		{
			m_FrameStack.Clear();
			m_FrameStack.Add(new StackFrame());
		}

		public virtual void OnDisable()
		{
			m_FrameStack.Clear();
			m_NextFrameId = 0;
		}

		public void ResetRootFrame()
		{
			if (m_FrameStack.Count == 0)
			{
				m_FrameStack.Add(new StackFrame());
				return;
			}
			StackFrame stackFrame = m_FrameStack[0];
			stackFrame.Blend.ClearBlend();
			stackFrame.Blend.CamB = null;
			stackFrame.Source.ClearBlend();
			stackFrame.Source.CamB = null;
		}

		public void UpdateRootFrame(ICinemachineMixer context, ICinemachineCamera activeCamera, Vector3 up, float deltaTime)
		{
			if (m_FrameStack.Count == 0)
			{
				m_FrameStack.Add(new StackFrame());
			}
			StackFrame stackFrame = m_FrameStack[0];
			ICinemachineCamera camB = stackFrame.Source.CamB;
			if (activeCamera != camB)
			{
				bool flag = false;
				float num = 0f;
				float num2 = 0f;
