		protected internal virtual void PerformLegacyUpgrade(int streamedVersion)
		{
			if (streamedVersion < 20220601 && m_LegacyPriority != 0)
			{
				Priority.Value = m_LegacyPriority;
				m_LegacyPriority = 0;
			}
