	[Serializable]
	public struct SplineAutoDolly
	{
		public interface ISplineAutoDolly
		{
			bool RequiresTrackingTarget { get; }

			void Validate();

			void Reset();

			float GetSplinePosition(MonoBehaviour sender, Transform target, SplineContainer spline, float currentPosition, PathIndexUnit positionUnits, float deltaTime);
		}

		[Serializable]
		public class FixedSpeed : ISplineAutoDolly
		{
			[Tooltip("Speed of travel, in current position units per second.")]
			public float Speed;

			bool ISplineAutoDolly.RequiresTrackingTarget => false;

			void ISplineAutoDolly.Validate()
			{
			}

			void ISplineAutoDolly.Reset()
			{
			}

			float ISplineAutoDolly.GetSplinePosition(MonoBehaviour sender, Transform target, SplineContainer spline, float currentPosition, PathIndexUnit positionUnits, float deltaTime)
			{
				if (Application.isPlaying && spline.IsValid() && deltaTime > 0f)
				{
					return currentPosition + Speed * deltaTime;
				}
				return currentPosition;
			}
		}

		[Serializable]
		public class NearestPointToTarget : ISplineAutoDolly
		{
			[Tooltip("Offset, in current position units, from the closest point on the spline to the follow target")]
			public float PositionOffset;

			[Tooltip("Affects how many segments to split a spline into when calculating the nearest point.  Higher values mean smaller and more segments, which increases accuracy at the cost of processing time.  In most cases, the default value (4) is appropriate. Use with SearchIteration to fine-tune point accuracy.")]
			public int SearchResolution = 4;

			[Tooltip("The nearest point is calculated by finding the nearest point on the entire length of the spline using SearchResolution to divide into equally spaced line segments. Successive iterations will then subdivide further the nearest segment, producing more accurate results. In most cases, the default value (2) is sufficient.")]
			public int SearchIteration = 2;

			bool ISplineAutoDolly.RequiresTrackingTarget => true;

			void ISplineAutoDolly.Validate()
			{
				SearchResolution = Mathf.Max(SearchResolution, 1);
				SearchIteration = Mathf.Max(SearchIteration, 1);
			}

			void ISplineAutoDolly.Reset()
			{
			}

			float ISplineAutoDolly.GetSplinePosition(MonoBehaviour sender, Transform target, SplineContainer spline, float currentPosition, PathIndexUnit positionUnits, float deltaTime)
			{
				if (target == null || !spline.IsValid())
				{
					return currentPosition;
				}
				SplineUtility.GetNearestPoint(spline.Spline, spline.transform.InverseTransformPoint(target.position), out var _, out var t, SearchResolution, SearchIteration);
				t = Mathf.Clamp01(t);
				return spline.Spline.ConvertIndexUnit(t, PathIndexUnit.Normalized, positionUnits) + PositionOffset;
			}
		}

		[Tooltip("If set, will enable the selected automatic dolly along the spline")]
		public bool Enabled;

		[SerializeReference]
		public ISplineAutoDolly Method;
	}
	internal static class SplineContainerExtensions
	{
		public static bool IsValid(this ISplineContainer spline)
		{
			if (spline != null && spline.Splines != null)
			{
				return spline.Splines.Count > 0;
			}
			return false;
		}

		public static bool LocalEvaluateSplineWithRoll(this ISpline spline, float tNormalized, CinemachineSplineRoll roll, out Vector3 position, out Quaternion rotation)
		{
			if (spline == null || !spline.Evaluate(tNormalized, out var position2, out var tangent, out var upVector))
			{
				position = Vector3.zero;
				rotation = Quaternion.identity;
				return false;
			}
			Vector3 v = Vector3.Cross(tangent, upVector);
			if (v.AlmostZero() || v.IsNaN())
			{
				tangent = Vector3.forward;
				upVector = Vector3.up;
			}
			if (roll == null || !roll.enabled)
			{
				rotation = Quaternion.LookRotation(tangent, upVector);
			}
			else
			{
				float angle = roll.Roll.Evaluate(spline, tNormalized, PathIndexUnit.Normalized, roll.GetInterpolator());
				rotation = Quaternion.LookRotation(tangent, upVector) * RollAroundForward(angle);
			}
			position = position2;
			return true;
			static Quaternion RollAroundForward(float num)
			{
				float f = num * 0.5f * (MathF.PI / 180f);
				return new Quaternion(0f, 0f, Mathf.Sin(f), Mathf.Cos(f));
			}
		}

		public static bool EvaluateSplineWithRoll(this ISpline spline, Transform transform, float tNormalized, CinemachineSplineRoll roll, out Vector3 position, out Quaternion rotation)
		{
			bool result = spline.LocalEvaluateSplineWithRoll(tNormalized, roll, out position, out rotation);
			position = Matrix4x4.TRS(transform.position, transform.rotation, Vector3.one).MultiplyPoint3x4(position);
			rotation = transform.rotation * rotation;
			return result;
		}

		public static Vector3 EvaluateSplinePosition(this ISpline spline, Transform transform, float tNormalized)
		{
			float3 float5 = spline?.EvaluatePosition(tNormalized) ?? default(float3);
			if (!(transform == null))
			{
				return Matrix4x4.TRS(transform.position, transform.rotation, Vector3.one).MultiplyPoint3x4(float5);
			}
			return float5;
		}

		public static float GetMaxPosition(this ISpline spline, PathIndexUnit unit)
		{
			switch (unit)
			{
			case PathIndexUnit.Distance:
				return spline.GetLength();
			case PathIndexUnit.Knot:
			{
				int count = spline.Count;
				return (!spline.Closed || count < 2) ? Mathf.Max(0, count - 1) : count;
			}
			default:
				return 1f;
			}
		}

		public static float StandardizePosition(this ISpline spline, float t, PathIndexUnit unit, out float maxPos)
		{
			maxPos = spline.GetMaxPosition(unit);
			if (float.IsNaN(t))
			{
				return 0f;
			}
			if (!spline.Closed)
			{
				return Mathf.Clamp(t, 0f, maxPos);
			}
			t %= maxPos;
			if (t < 0f)
			{
				t += maxPos;
			}
			return t;
		}
	}
	internal static class SplineHelpers
	{
		public static Vector3 Bezier3(float t, Vector3 p0, Vector3 p1, Vector3 p2, Vector3 p3)
		{
			t = Mathf.Clamp01(t);
			float num = 1f - t;
			return num * num * num * p0 + 3f * num * num * t * p1 + 3f * num * t * t * p2 + t * t * t * p3;
		}

		public static Vector3 BezierTangent3(float t, Vector3 p0, Vector3 p1, Vector3 p2, Vector3 p3)
		{
			t = Mathf.Clamp01(t);
			return (-3f * p0 + 9f * p1 - 9f * p2 + 3f * p3) * (t * t) + (6f * p0 - 12f * p1 + 6f * p2) * t - 3f * p0 + 3f * p1;
		}

		public static void BezierTangentWeights3(Vector3 p0, Vector3 p1, Vector3 p2, Vector3 p3, out Vector3 w0, out Vector3 w1, out Vector3 w2)
		{
			w0 = -3f * p0 + 9f * p1 - 9f * p2 + 3f * p3;
			w1 = 6f * p0 - 12f * p1 + 6f * p2;
			w2 = -3f * p0 + 3f * p1;
		}

		public static float Bezier1(float t, float p0, float p1, float p2, float p3)
		{
			t = Mathf.Clamp01(t);
			float num = 1f - t;
			return num * num * num * p0 + 3f * num * num * t * p1 + 3f * num * t * t * p2 + t * t * t * p3;
		}

		public static float BezierTangent1(float t, float p0, float p1, float p2, float p3)
		{
			t = Mathf.Clamp01(t);
			return (-3f * p0 + 9f * p1 - 9f * p2 + 3f * p3) * t * t + (6f * p0 - 12f * p1 + 6f * p2) * t - 3f * p0 + 3f * p1;
		}

		public static void ComputeSmoothControlPoints(ref Vector4[] knot, ref Vector4[] ctrl1, ref Vector4[] ctrl2)
		{
			int num = knot.Length;
			if (num <= 2)
			{
				switch (num)
				{
				case 2:
					ctrl1[0] = Vector4.Lerp(knot[0], knot[1], 0.33333f);
					ctrl2[0] = Vector4.Lerp(knot[0], knot[1], 0.66666f);
					break;
				case 1:
					ctrl1[0] = (ctrl2[0] = knot[0]);
					break;
				}
				return;
			}
			float[] array = new float[num];
			float[] array2 = new float[num];
			float[] array3 = new float[num];
			float[] array4 = new float[num];
			for (int i = 0; i < 4; i++)
			{
				int num2 = num - 1;
				array[0] = 0f;
				array2[0] = 2f;
				array3[0] = 1f;
				array4[0] = knot[0][i] + 2f * knot[1][i];
				for (int j = 1; j < num2 - 1; j++)
				{
					array[j] = 1f;
					array2[j] = 4f;
					array3[j] = 1f;
					array4[j] = 4f * knot[j][i] + 2f * knot[j + 1][i];
				}
				array[num2 - 1] = 2f;
				array2[num2 - 1] = 7f;
				array3[num2 - 1] = 0f;
				array4[num2 - 1] = 8f * knot[num2 - 1][i] + knot[num2][i];
				for (int k = 1; k < num2; k++)
				{
					float num3 = array[k] / array2[k - 1];
					array2[k] -= num3 * array3[k - 1];
					array4[k] -= num3 * array4[k - 1];
				}
				ctrl1[num2 - 1][i] = array4[num2 - 1] / array2[num2 - 1];
				for (int num4 = num2 - 2; num4 >= 0; num4--)
				{
					ctrl1[num4][i] = (array4[num4] - array3[num4] * ctrl1[num4 + 1][i]) / array2[num4];
				}
				for (int l = 0; l < num2; l++)
				{
					ctrl2[l][i] = 2f * knot[l + 1][i] - ctrl1[l + 1][i];
				}
				ctrl2[num2 - 1][i] = 0.5f * (knot[num2][i] + ctrl1[num2 - 1][i]);
			}
		}

		public static void ComputeSmoothControlPointsLooped(ref Vector4[] knot, ref Vector4[] ctrl1, ref Vector4[] ctrl2)
		{
			int num = knot.Length;
			if (num < 2)
			{
				if (num == 1)
				{
					ctrl1[0] = (ctrl2[0] = knot[0]);
				}
				return;
			}
			int num2 = Mathf.Min(4, num - 1);
			Vector4[] knot2 = new Vector4[num + 2 * num2];
			Vector4[] ctrl3 = new Vector4[num + 2 * num2];
			Vector4[] ctrl4 = new Vector4[num + 2 * num2];
			for (int i = 0; i < num2; i++)
			{
				knot2[i] = knot[num - (num2 - i)];
				knot2[num + num2 + i] = knot[i];
			}
			for (int j = 0; j < num; j++)
			{
				knot2[j + num2] = knot[j];
			}
			ComputeSmoothControlPoints(ref knot2, ref ctrl3, ref ctrl4);
			for (int k = 0; k < num; k++)
			{
				ctrl1[k] = ctrl3[k + num2];
				ctrl2[k] = ctrl4[k + num2];
			}
		}

		public static void ComputeSmoothControlPoints(ref float3[] knot, ref float3[] ctrl1, ref float3[] ctrl2)
		{
			int num = knot.Length;
			if (num <= 2)
