			}
			float[] array = new float[num];
			float[] array2 = new float[num];
			float[] array3 = new float[num];
			float[] array4 = new float[num];
			for (int i = 0; i < 3; i++)
			{
				int num2 = num - 1;
				array[0] = 0f;
				array2[0] = 2f;
				array3[0] = 1f;
				array4[0] = knot[0][i] + 2f * knot[1][i];
				for (int j = 1; j < num2 - 1; j++)
				{
					array[j] = 1f;
					array2[j] = 4f;
