	[Serializable]
	[Obsolete("LegacyLensSettings is deprecated. Use LensSettings instead.")]
	public struct LegacyLensSettings
	{
		public float FieldOfView;

		public float OrthographicSize;

		public float NearClipPlane;

		public float FarClipPlane;

		public float Dutch;

		public LensSettings.OverrideModes ModeOverride;

		public Camera.GateFitMode GateFit;

		[HideInInspector]
		public Vector2 m_SensorSize;

		public Vector2 LensShift;

		public float FocusDistance;

		public int Iso;

		public float ShutterSpeed;

		public float Aperture;

		public int BladeCount;

		public Vector2 Curvature;

		public float BarrelClipping;

		public float Anamorphism;

		public static LegacyLensSettings Default => new LegacyLensSettings
		{
			FieldOfView = 40f,
			OrthographicSize = 10f,
			NearClipPlane = 0.1f,
			FarClipPlane = 5000f,
			Dutch = 0f,
			ModeOverride = LensSettings.OverrideModes.None,
			m_SensorSize = new Vector2(21.946f, 16.002f),
			GateFit = Camera.GateFitMode.Horizontal,
			FocusDistance = 10f,
			LensShift = Vector2.zero,
			Iso = 200,
			ShutterSpeed = 0.005f,
			Aperture = 16f,
			BladeCount = 5,
			Curvature = new Vector2(2f, 11f),
			BarrelClipping = 0.25f,
			Anamorphism = 0f
		};

		public LensSettings ToLensSettings()
		{
			LensSettings result = new LensSettings
			{
				FieldOfView = FieldOfView,
				OrthographicSize = OrthographicSize,
				NearClipPlane = NearClipPlane,
				FarClipPlane = FarClipPlane,
				Dutch = Dutch,
				ModeOverride = ModeOverride,
				PhysicalProperties = LensSettings.Default.PhysicalProperties
			};
			result.PhysicalProperties.GateFit = GateFit;
			result.PhysicalProperties.SensorSize = m_SensorSize;
			result.PhysicalProperties.LensShift = LensShift;
			result.PhysicalProperties.FocusDistance = FocusDistance;
			result.PhysicalProperties.Iso = Iso;
			result.PhysicalProperties.ShutterSpeed = ShutterSpeed;
			result.PhysicalProperties.Aperture = Aperture;
			result.PhysicalProperties.BladeCount = BladeCount;
			result.PhysicalProperties.Curvature = Curvature;
			result.PhysicalProperties.BarrelClipping = BarrelClipping;
			result.PhysicalProperties.Anamorphism = Anamorphism;
			return result;
		}

		public void SetFromLensSettings(LensSettings src)
		{
			FieldOfView = src.FieldOfView;
			OrthographicSize = src.OrthographicSize;
			NearClipPlane = src.NearClipPlane;
			FarClipPlane = src.FarClipPlane;
			Dutch = src.Dutch;
			ModeOverride = src.ModeOverride;
			GateFit = src.PhysicalProperties.GateFit;
			m_SensorSize = src.PhysicalProperties.SensorSize;
			LensShift = src.PhysicalProperties.LensShift;
			FocusDistance = src.PhysicalProperties.FocusDistance;
			Iso = src.PhysicalProperties.Iso;
			ShutterSpeed = src.PhysicalProperties.ShutterSpeed;
			Aperture = src.PhysicalProperties.Aperture;
			BladeCount = src.PhysicalProperties.BladeCount;
			Curvature = src.PhysicalProperties.Curvature;
			BarrelClipping = src.PhysicalProperties.BarrelClipping;
			Anamorphism = src.PhysicalProperties.Anamorphism;
		}

		public void Validate()
		{
			FarClipPlane = Mathf.Max(FarClipPlane, NearClipPlane + 0.001f);
			FieldOfView = Mathf.Clamp(FieldOfView, 0.01f, 179f);
			FocusDistance = Mathf.Max(FocusDistance, 0.01f);
			ShutterSpeed = Mathf.Max(0f, ShutterSpeed);
			Aperture = Mathf.Clamp(Aperture, 0.7f, 32f);
			BladeCount = Mathf.Clamp(BladeCount, 3, 11);
			BarrelClipping = Mathf.Clamp01(BarrelClipping);
			Curvature.x = Mathf.Clamp(Curvature.x, 0.7f, 32f);
			Curvature.y = Mathf.Clamp(Curvature.y, Curvature.x, 32f);
			Anamorphism = Mathf.Clamp(Anamorphism, -1f, 1f);
		}
	}
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Brain Events")]
	[SaveDuringPlay]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineBrainEvents.html")]
	public class CinemachineBrainEvents : CinemachineMixerEventsBase
	{
		[Tooltip("This is the CinemachineBrain emitting the events.  If null and the current GameObject has a CinemachineBrain component, that component will be used.")]
		public CinemachineBrain Brain;

		[Tooltip("This event will fire after the brain updates its Camera.")]
		public CinemachineCore.BrainEvent BrainUpdatedEvent = new CinemachineCore.BrainEvent();

		protected override ICinemachineMixer GetMixer()
		{
			return Brain;
		}

		private void OnEnable()
		{
			if (Brain == null)
			{
				TryGetComponent<CinemachineBrain>(out Brain);
			}
			if (Brain != null)
			{
				InstallHandlers(Brain);
				CinemachineCore.CameraUpdatedEvent.AddListener(OnCameraUpdated);
			}
		}

		private void OnDisable()
		{
			UninstallHandlers();
			CinemachineCore.CameraUpdatedEvent.RemoveListener(OnCameraUpdated);
		}

		private void OnCameraUpdated(CinemachineBrain brain)
		{
			if (brain == Brain)
			{
				BrainUpdatedEvent.Invoke(brain);
			}
		}
	}
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Camera Events")]
	[SaveDuringPlay]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineCameraEvents.html")]
	public class CinemachineCameraEvents : MonoBehaviour
	{
		[Tooltip("This is the object whose events are being monitored.  If null and the current GameObject has a CinemachineVirtualCameraBase component, that component will be used.")]
		public CinemachineVirtualCameraBase EventTarget;

		[Space]
		[Tooltip("This event will fire whenever a virtual camera becomes active in the context of a mixer.  If a blend is involved, then the event will fire on the first frame of the blend.")]
		public CinemachineCore.CameraEvent CameraActivatedEvent = new CinemachineCore.CameraEvent();

		[Tooltip("This event will fire whenever a virtual stops being live.  If a blend is involved, then the event will fire after the last frame of the blend.")]
		public CinemachineCore.CameraEvent CameraDeactivatedEvent = new CinemachineCore.CameraEvent();

		[Tooltip("This event will fire whenever a blend is created that involves this camera.  The handler can modify any settings in the blend, except the cameras themselves.")]
		public CinemachineCore.BlendEvent BlendCreatedEvent = new CinemachineCore.BlendEvent();

		[Tooltip("This event will fire whenever a virtual camera finishes blending in.  It will not fire if the blend length is zero.")]
		public CinemachineCore.CameraEvent BlendFinishedEvent = new CinemachineCore.CameraEvent();

		private void OnEnable()
		{
			if (EventTarget == null)
			{
				TryGetComponent<CinemachineVirtualCameraBase>(out EventTarget);
			}
			if (EventTarget != null)
			{
				CinemachineCore.CameraActivatedEvent.AddListener(OnCameraActivated);
				CinemachineCore.CameraDeactivatedEvent.AddListener(OnCameraDeactivated);
				CinemachineCore.BlendCreatedEvent.AddListener(OnBlendCreated);
				CinemachineCore.BlendFinishedEvent.AddListener(OnBlendFinished);
			}
		}

		private void OnDisable()
		{
			CinemachineCore.CameraActivatedEvent.RemoveListener(OnCameraActivated);
			CinemachineCore.CameraDeactivatedEvent.RemoveListener(OnCameraDeactivated);
			CinemachineCore.BlendCreatedEvent.RemoveListener(OnBlendCreated);
			CinemachineCore.BlendFinishedEvent.RemoveListener(OnBlendFinished);
		}

		private void OnCameraActivated(ICinemachineCamera.ActivationEventParams evt)
		{
			if (evt.IncomingCamera == EventTarget)
