	[SaveDuringPlay]
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Input Axis Controller")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineInputAxisController.html")]
	public class CinemachineInputAxisController : InputAxisControllerBase<CinemachineInputAxisController.Reader>
	{
		internal delegate void SetControlDefaultsForAxis(in IInputAxisOwner.AxisDescriptor axis, ref Controller controller);

		[Serializable]
		public sealed class Reader : IInputAxisReader
		{
			public delegate float ControlValueReader(InputAction action, IInputAxisOwner.AxisDescriptor.Hints hint, UnityEngine.Object context, ControlValueReader defaultReader);

			[Tooltip("Action for the Input package (if used).")]
			public InputActionReference InputAction;

			[Tooltip("The input value is multiplied by this amount prior to processing.  Controls the input power.  Set it to a negative value to invert the input")]
			public float Gain = 1f;

			internal InputAction m_CachedAction;

			[Tooltip("Enable this if the input value is inherently dependent on frame time.  For example, mouse deltas will naturally be bigger for longer frames, so in this case the default deltaTime scaling should be canceled.")]
			public bool CancelDeltaTime;

			public float GetValue(UnityEngine.Object context, IInputAxisOwner.AxisDescriptor.Hints hint)
			{
				float num = 0f;
				if (InputAction != null && context is CinemachineInputAxisController context2)
				{
					num = ResolveAndReadInputAction(context2, hint) * Gain;
				}
				if (!(Time.deltaTime > 0f) || !CancelDeltaTime)
				{
					return num;
				}
				return num / Time.deltaTime;
			}

			private float ResolveAndReadInputAction(CinemachineInputAxisController context, IInputAxisOwner.AxisDescriptor.Hints hint)
			{
				if (m_CachedAction != null && InputAction.action.id != m_CachedAction.id)
				{
					m_CachedAction = null;
				}
				if (m_CachedAction == null)
				{
					m_CachedAction = InputAction.action;
					if (context.PlayerIndex != -1)
					{
						m_CachedAction = GetFirstMatch(InputUser.all[context.PlayerIndex], InputAction);
					}
					if (context.AutoEnableInputs && m_CachedAction != null)
					{
						m_CachedAction.Enable();
					}
				}
				if (m_CachedAction != null && m_CachedAction.enabled != InputAction.action.enabled)
				{
					if (InputAction.action.enabled)
					{
						m_CachedAction.Enable();
					}
					else
					{
						m_CachedAction.Disable();
					}
				}
				if (m_CachedAction != null)
				{
					if (context.ReadControlValueOverride != null)
					{
						return context.ReadControlValueOverride(m_CachedAction, hint, context, ReadInput);
					}
					return ReadInput(m_CachedAction, hint, context, null);
				}
				return 0f;
				static InputAction GetFirstMatch(in InputUser user, InputActionReference aRef)
				{
					IEnumerator<InputAction> enumerator = user.actions.GetEnumerator();
					while (enumerator.MoveNext())
					{
						if (enumerator.Current.id == aRef.action.id)
						{
							return enumerator.Current;
						}
					}
					return null;
				}
			}

			private float ReadInput(InputAction action, IInputAxisOwner.AxisDescriptor.Hints hint, UnityEngine.Object context, ControlValueReader defaultReader)
			{
				InputControl activeControl = action.activeControl;
				if (activeControl != null)
				{
					try
					{
						if (activeControl.valueType == typeof(Vector2) || action.expectedControlType == "Vector2")
						{
							Vector2 vector = action.ReadValue<Vector2>();
							return (hint == IInputAxisOwner.AxisDescriptor.Hints.Y) ? vector.y : vector.x;
						}
						return action.ReadValue<float>();
					}
					catch (InvalidOperationException)
					{
						UnityEngine.Debug.LogError("An action in " + context.name + " is mapped to a " + activeControl.valueType.Name + " control.  CinemachineInputAxisController.Reader can only handle float or Vector2 types.  To handle other types you can install a custom handler for CinemachineInputAxisController.ReadControlValueOverride.");
					}
				}
				return 0f;
			}
		}

		[Tooltip("Leave this at -1 for single-player games.  For multi-player games, set this to be the player index, and the actions will be read from that player's controls")]
		public int PlayerIndex = -1;

		[Tooltip("If set, Input Actions will be auto-enabled at start")]
		public bool AutoEnableInputs = true;

		internal static SetControlDefaultsForAxis SetControlDefaults;

		public Reader.ControlValueReader ReadControlValueOverride;

		protected override void Reset()
		{
			base.Reset();
			PlayerIndex = -1;
			AutoEnableInputs = true;
		}

		protected override void InitializeControllerDefaultsForAxis(in IInputAxisOwner.AxisDescriptor axis, Controller controller)
		{
			SetControlDefaults?.Invoke(in axis, ref controller);
		}

		private void Update()
		{
			if (Application.isPlaying)
			{
				UpdateControllers();
			}
		}
	}
	[SaveDuringPlay]
	public abstract class CinemachineMixerEventsBase : MonoBehaviour
	{
		[Space]
		[Tooltip("This event will fire whenever a virtual camera goes live.  If a blend is involved, then the event will fire on the first frame of the blend.")]
		public CinemachineCore.CameraEvent CameraActivatedEvent = new CinemachineCore.CameraEvent();

		[Tooltip("This event will fire whenever a virtual stops being live.  If a blend is involved, then the event will fire after the last frame of the blend.")]
		public CinemachineCore.CameraEvent CameraDeactivatedEvent = new CinemachineCore.CameraEvent();

		[Tooltip("This event will fire whenever a blend is created in the root frame of this Brain.  The handler can modify any settings in the blend, except the cameras themselves.  Note: timeline tracks will not generate these events.")]
		public CinemachineCore.BlendEvent BlendCreatedEvent = new CinemachineCore.BlendEvent();

		[Tooltip("This event will fire whenever a virtual camera finishes blending in.  It will not fire if the blend length is zero.")]
		public CinemachineCore.CameraEvent BlendFinishedEvent = new CinemachineCore.CameraEvent();

		[Tooltip("This event is fired when there is a camera cut.  A camera cut is a camera activation with a zero-length blend.")]
		public CinemachineCore.CameraEvent CameraCutEvent = new CinemachineCore.CameraEvent();

		protected abstract ICinemachineMixer GetMixer();

		protected void InstallHandlers(ICinemachineMixer mixer)
		{
			if (mixer != null)
			{
				CinemachineCore.CameraActivatedEvent.AddListener(OnCameraActivated);
				CinemachineCore.CameraDeactivatedEvent.AddListener(OnCameraDeactivated);
				CinemachineCore.BlendCreatedEvent.AddListener(OnBlendCreated);
				CinemachineCore.BlendFinishedEvent.AddListener(OnBlendFinished);
			}
		}

		protected void UninstallHandlers()
		{
			CinemachineCore.CameraActivatedEvent.RemoveListener(OnCameraActivated);
			CinemachineCore.CameraDeactivatedEvent.RemoveListener(OnCameraDeactivated);
			CinemachineCore.BlendCreatedEvent.RemoveListener(OnBlendCreated);
			CinemachineCore.BlendFinishedEvent.RemoveListener(OnBlendFinished);
		}

		private void OnCameraActivated(ICinemachineCamera.ActivationEventParams evt)
		{
			ICinemachineMixer mixer = GetMixer();
			if (evt.Origin == mixer)
			{
				CameraActivatedEvent.Invoke(mixer, evt.IncomingCamera);
				if (evt.IsCut)
				{
					CameraCutEvent.Invoke(mixer, evt.IncomingCamera);
				}
			}
		}

		private void OnCameraDeactivated(ICinemachineMixer mixer, ICinemachineCamera cam)
		{
			if (mixer == GetMixer())
			{
				CameraDeactivatedEvent.Invoke(mixer, cam);
			}
		}

		private void OnBlendCreated(CinemachineCore.BlendEventParams evt)
		{
			if (evt.Origin == GetMixer())
			{
				BlendCreatedEvent.Invoke(evt);
			}
		}

		private void OnBlendFinished(ICinemachineMixer mixer, ICinemachineCamera cam)
		{
			if (mixer == GetMixer())
			{
				BlendFinishedEvent.Invoke(mixer, cam);
			}
		}
	}
	[ExecuteAlways]
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Spline Smoother")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineSplineSmoother.html")]
	[RequireComponent(typeof(SplineContainer))]
	public class CinemachineSplineSmoother : MonoBehaviour
	{
		[Tooltip("If checked, the spline will be automatically smoothed whenever it is modified (editor only).")]
		public bool AutoSmooth = true;

		public void SmoothSplineNow()
		{
			if (!TryGetComponent<SplineContainer>(out var component) || component.Spline == null)
			{
				return;
			}
			Spline spline = component.Spline;
			int count = spline.Count;
			if (count >= 3)
			{
				float3[] ctrl = new float3[count];
				float3[] ctrl2 = new float3[count];
				float3[] knot = new float3[count];
				for (int i = 0; i < count; i++)
				{
					knot[i] = spline[i].Position;
				}
				if (spline.Closed)
				{
					SplineHelpers.ComputeSmoothControlPointsLooped(ref knot, ref ctrl, ref ctrl2);
				}
				else
				{
					SplineHelpers.ComputeSmoothControlPoints(ref knot, ref ctrl, ref ctrl2);
				}
				for (int j = 0; j < count; j++)
				{
					spline.SetTangentMode(j, TangentMode.Mirrored);
					BezierKnot value = spline[j];
					float3 up = math.mul(value.Rotation, new float3(0f, 1f, 0f));
					float3 float5 = ctrl[j] - knot[j];
					float num = (math.length(ctrl2[(j > 0) ? (j - 1) : (count - 1)] - knot[j]) + math.length(float5)) * 0.5f;
					value.Rotation = quaternion.LookRotationSafe(float5, up);
					value.TangentIn = ((j == 0 && !spline.Closed) ? default(float3) : new float3(0f, 0f, 0f - num));
					value.TangentOut = ((j == count - 1 && !spline.Closed) ? default(float3) : new float3(0f, 0f, num));
					spline[j] = value;
				}
			}
		}
	}
	[SaveDuringPlay]
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Trigger Action")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineTriggerAction.html")]
	public class CinemachineTriggerAction : MonoBehaviour
	{
		[Serializable]
		public struct ActionSettings(ActionSettings.ActionModes action)
		{
			public enum ActionModes
			{
				EventOnly,
				PriorityBoost,
				Activate,
				Deactivate,
				Enable,
				Disable,
				Play,
				Stop
			}

			[Serializable]
			public class TriggerEvent : UnityEvent
			{
			}

			public enum TimeModes
			{
				FromStart,
				FromEnd,
				BeforeNow,
				AfterNow
			}

			[Tooltip("What action to take")]
			[FormerlySerializedAs("m_Action")]
			public ActionModes Action = action;

			[Tooltip("The target object on which to operate.  If null, then the current behaviour/GameObject will be used")]
			[FormerlySerializedAs("m_Target")]
			public UnityEngine.Object Target = null;

			[Tooltip("If PriorityBoost, this amount will be added to the virtual camera's priority")]
			[FormerlySerializedAs("m_BoostAmount")]
			public int BoostAmount = 0;

			[Tooltip("If playing a timeline, start at this time")]
			[FormerlySerializedAs("m_StartTime")]
			public float StartTime = 0f;

			[Tooltip("How to interpret the start time")]
			[FormerlySerializedAs("m_Mode")]
			public TimeModes Mode = TimeModes.FromStart;

			[Tooltip("This event will be invoked")]
			[FormerlySerializedAs("m_Event")]
			public TriggerEvent Event = new TriggerEvent();

			public void Invoke()
			{
				UnityEngine.Object target = Target;
				if (target != null)
				{
					GameObject gameObject = target as GameObject;
					Behaviour behaviour = target as Behaviour;
					if (behaviour != null)
					{
						gameObject = behaviour.gameObject;
					}
					switch (Action)
					{
					case ActionModes.PriorityBoost:
					{
						if (gameObject.TryGetComponent<CinemachineVirtualCameraBase>(out var component5))
						{
							component5.Priority.Value += BoostAmount;
							component5.Prioritize();
						}
						break;
					}
					case ActionModes.Activate:
						if (gameObject != null)
						{
							gameObject.SetActive(value: true);
							if (gameObject.TryGetComponent<CinemachineVirtualCameraBase>(out var component6))
							{
								component6.Prioritize();
							}
						}
						break;
					case ActionModes.Deactivate:
						if (gameObject != null)
						{
							gameObject.SetActive(value: false);
						}
						break;
					case ActionModes.Enable:
						if (behaviour != null)
						{
							behaviour.enabled = true;
						}
						break;
					case ActionModes.Disable:
						if (behaviour != null)
						{
							behaviour.enabled = false;
						}
						break;
					case ActionModes.Play:
					{
						Animation component4;
						if (gameObject.TryGetComponent<PlayableDirector>(out var component3))
						{
							double num = 0.0;
							double duration = component3.duration;
							double time = component3.time;
							num = Mode switch
							{
								TimeModes.FromEnd => duration - (double)StartTime, 
								TimeModes.BeforeNow => time - (double)StartTime, 
								TimeModes.AfterNow => time + (double)StartTime, 
								_ => num + (double)StartTime, 
							};
							component3.time = num;
							component3.Play();
						}
						else if (gameObject.TryGetComponent<Animation>(out component4))
						{
							component4.Play();
						}
						break;
					}
					case ActionModes.Stop:
					{
						Animation component2;
						if (gameObject.TryGetComponent<PlayableDirector>(out var component))
						{
							component.Stop();
						}
						else if (gameObject.TryGetComponent<Animation>(out component2))
						{
							component2.Stop();
						}
						break;
					}
					}
				}
				Event.Invoke();
			}
		}

		[Header("Trigger Object Filter")]
		[Tooltip("Only triggers generated by objects on these layers will be considered")]
		[FormerlySerializedAs("m_LayerMask")]
		public LayerMask LayerMask = 1;

		[TagField]
		[Tooltip("If set, only triggers generated by objects with this tag will be considered")]
		[FormerlySerializedAs("m_WithTag")]
		public string WithTag = string.Empty;

		[TagField]
		[Tooltip("Triggers generated by objects with this tag will be ignored")]
		[FormerlySerializedAs("m_WithoutTag")]
		public string WithoutTag = string.Empty;

		[NoSaveDuringPlay]
		[Tooltip("Skip this many trigger entries before taking action")]
		[FormerlySerializedAs("m_SkipFirst")]
		public int SkipFirst;

		[Tooltip("Repeat the action for all subsequent trigger entries")]
		[FormerlySerializedAs("m_Repeating")]
		public bool Repeating = true;

		[Tooltip("What action to take when an eligible object enters the collider or trigger zone")]
		[FormerlySerializedAs("m_OnObjectEnter")]
		public ActionSettings OnObjectEnter = new ActionSettings(ActionSettings.ActionModes.EventOnly);

		[Tooltip("What action to take when an eligible object exits the collider or trigger zone")]
		[FormerlySerializedAs("m_OnObjectExit")]
		public ActionSettings OnObjectExit = new ActionSettings(ActionSettings.ActionModes.EventOnly);

		private HashSet<GameObject> m_ActiveTriggerObjects = new HashSet<GameObject>();

		private bool Filter(GameObject other)
		{
			if (!base.enabled)
			{
				return false;
			}
			if (((1 << other.layer) & (int)LayerMask) == 0)
			{
				return false;
			}
			if (WithTag.Length != 0 && !other.CompareTag(WithTag))
			{
				return false;
			}
			if (WithoutTag.Length != 0 && other.CompareTag(WithoutTag))
			{
				return false;
			}
			return true;
		}

		private void InternalDoTriggerEnter(GameObject other)
		{
			if (Filter(other))
			{
				SkipFirst--;
				if (SkipFirst <= -1 && (Repeating || SkipFirst == -1))
				{
					m_ActiveTriggerObjects.Add(other);
					OnObjectEnter.Invoke();
				}
			}
		}

		private void InternalDoTriggerExit(GameObject other)
		{
			if (m_ActiveTriggerObjects.Contains(other))
			{
				m_ActiveTriggerObjects.Remove(other);
				if (base.enabled)
				{
					OnObjectExit.Invoke();
				}
			}
		}

		private void OnTriggerEnter(Collider other)
		{
			InternalDoTriggerEnter(other.gameObject);
		}

		private void OnTriggerExit(Collider other)
		{
			InternalDoTriggerExit(other.gameObject);
		}

		private void OnCollisionEnter(Collision other)
		{
			InternalDoTriggerEnter(other.gameObject);
		}

		private void OnCollisionExit(Collision other)
		{
			InternalDoTriggerExit(other.gameObject);
		}

		private void OnTriggerEnter2D(Collider2D other)
		{
			InternalDoTriggerEnter(other.gameObject);
		}

		private void OnTriggerExit2D(Collider2D other)
		{
			InternalDoTriggerExit(other.gameObject);
		}

		private void OnCollisionEnter2D(Collision2D other)
		{
			InternalDoTriggerEnter(other.gameObject);
		}

		private void OnCollisionExit2D(Collision2D other)
		{
			InternalDoTriggerExit(other.gameObject);
		}

		private void OnEnable()
		{
		}
	}
	[RequireComponent(typeof(CinemachineTargetGroup))]
	[ExecuteAlways]
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Group Weight Manipulator")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/GroupWeightManipulator.html")]
	public class GroupWeightManipulator : MonoBehaviour
	{
		[Tooltip("The weight of the group member at index 0")]
		[FormerlySerializedAs("m_Weight0")]
		public float Weight0 = 1f;

		[Tooltip("The weight of the group member at index 1")]
		[FormerlySerializedAs("m_Weight1")]
		public float Weight1 = 1f;

		[Tooltip("The weight of the group member at index 2")]
		[FormerlySerializedAs("m_Weight2")]
		public float Weight2 = 1f;

		[Tooltip("The weight of the group member at index 3")]
		[FormerlySerializedAs("m_Weight3")]
		public float Weight3 = 1f;

		[Tooltip("The weight of the group member at index 4")]
		[FormerlySerializedAs("m_Weight4")]
		public float Weight4 = 1f;

		[Tooltip("The weight of the group member at index 5")]
		[FormerlySerializedAs("m_Weight5")]
		public float Weight5 = 1f;

		[Tooltip("The weight of the group member at index 6")]
		[FormerlySerializedAs("m_Weight6")]
		public float Weight6 = 1f;

		[Tooltip("The weight of the group member at index 7")]
		[FormerlySerializedAs("m_Weight7")]
		public float Weight7 = 1f;

		private CinemachineTargetGroup m_Group;

		private void Start()
		{
			TryGetComponent<CinemachineTargetGroup>(out m_Group);
		}

		private void OnValidate()
		{
			Weight0 = Mathf.Max(0f, Weight0);
			Weight1 = Mathf.Max(0f, Weight1);
			Weight2 = Mathf.Max(0f, Weight2);
			Weight3 = Mathf.Max(0f, Weight3);
			Weight4 = Mathf.Max(0f, Weight4);
			Weight5 = Mathf.Max(0f, Weight5);
			Weight6 = Mathf.Max(0f, Weight6);
			Weight7 = Mathf.Max(0f, Weight7);
		}

		private void Update()
		{
			if (m_Group != null)
			{
				UpdateWeights();
			}
		}

		private void UpdateWeights()
		{
			List<CinemachineTargetGroup.Target> targets = m_Group.Targets;
			int num = targets.Count - 1;
			if (num < 0)
			{
				return;
			}
			targets[0].Weight = Weight0;
			if (num < 1)
			{
				return;
			}
			targets[1].Weight = Weight1;
			if (num < 2)
			{
				return;
			}
			targets[2].Weight = Weight2;
			if (num < 3)
			{
				return;
			}
			targets[3].Weight = Weight3;
			if (num < 4)
			{
				return;
			}
			targets[4].Weight = Weight4;
			if (num < 5)
			{
				return;
			}
			targets[5].Weight = Weight5;
			if (num >= 6)
			{
				targets[6].Weight = Weight6;
				if (num >= 7)
				{
					targets[7].Weight = Weight7;
				}
			}
		}
	}
	[SaveDuringPlay]
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Collision Impulse Source")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineCollisionImpulseSource.html")]
	public class CinemachineCollisionImpulseSource : CinemachineImpulseSource
	{
		[Header("Trigger Object Filter")]
		[Tooltip("Only collisions with objects on these layers will generate Impulse events")]
		[FormerlySerializedAs("m_LayerMask")]
		public LayerMask LayerMask = 1;

		[TagField]
		[Tooltip("No Impulse events will be generated for collisions with objects having these tags")]
		[FormerlySerializedAs("m_IgnoreTag")]
		public string IgnoreTag = string.Empty;

		[Header("How To Generate The Impulse")]
		[Tooltip("If checked, signal direction will be affected by the direction of impact")]
		[FormerlySerializedAs("m_UseImpactDirection")]
		public bool UseImpactDirection;

		[Tooltip("If checked, signal amplitude will be multiplied by the mass of the impacting object")]
		[FormerlySerializedAs("m_ScaleImpactWithMass")]
		public bool ScaleImpactWithMass;

		[Tooltip("If checked, signal amplitude will be multiplied by the speed of the impacting object")]
		[FormerlySerializedAs("m_ScaleImpactWithSpeed")]
		public bool ScaleImpactWithSpeed;

		private Rigidbody m_RigidBody;

		private Rigidbody2D m_RigidBody2D;

		private void Reset()
		{
			LayerMask = 1;
			IgnoreTag = string.Empty;
			UseImpactDirection = false;
			ScaleImpactWithMass = false;
			ScaleImpactWithSpeed = false;
		}

		private void Start()
		{
			TryGetComponent<Rigidbody>(out m_RigidBody);
			TryGetComponent<Rigidbody2D>(out m_RigidBody2D);
		}

		private void OnEnable()
		{
		}

		private void OnCollisionEnter(Collision c)
		{
			GenerateImpactEvent(c.collider, c.relativeVelocity);
		}

		private void OnTriggerEnter(Collider c)
		{
			GenerateImpactEvent(c, Vector3.zero);
		}

		private float GetMassAndVelocity(Collider other, ref Vector3 vel)
		{
			bool flag = vel == Vector3.zero;
			float num = 1f;
			if (ScaleImpactWithMass || ScaleImpactWithSpeed || UseImpactDirection)
			{
				if (m_RigidBody != null)
				{
					if (ScaleImpactWithMass)
					{
						num *= m_RigidBody.mass;
					}
					if (flag)
					{
						vel = -m_RigidBody.linearVelocity;
					}
				}
				Rigidbody rigidbody = ((other != null) ? other.attachedRigidbody : null);
				if (rigidbody != null)
				{
					if (ScaleImpactWithMass)
					{
						num *= rigidbody.mass;
					}
					if (flag)
					{
						vel += rigidbody.linearVelocity;
					}
				}
			}
			return num;
		}

		private void GenerateImpactEvent(Collider other, Vector3 vel)
		{
			if (!base.enabled)
			{
				return;
			}
			if (other != null)
			{
				int layer = other.gameObject.layer;
				if (((1 << layer) & (int)LayerMask) == 0 || (IgnoreTag.Length != 0 && other.CompareTag(IgnoreTag)))
				{
					return;
				}
			}
			float num = GetMassAndVelocity(other, ref vel);
			if (ScaleImpactWithSpeed)
			{
				num *= Mathf.Sqrt(vel.magnitude);
			}
			Vector3 vector = DefaultVelocity;
			if (UseImpactDirection && !vel.AlmostZero())
			{
				vector = -vel.normalized * vector.magnitude;
			}
			GenerateImpulseWithVelocity(vector * num);
		}

		private void OnCollisionEnter2D(Collision2D c)
		{
			GenerateImpactEvent2D(c.collider, c.relativeVelocity);
		}

		private void OnTriggerEnter2D(Collider2D c)
		{
			GenerateImpactEvent2D(c, Vector3.zero);
		}

		private float GetMassAndVelocity2D(Collider2D other2d, ref Vector3 vel)
		{
			bool flag = vel == Vector3.zero;
			float num = 1f;
			if (ScaleImpactWithMass || ScaleImpactWithSpeed || UseImpactDirection)
			{
				if (m_RigidBody2D != null)
				{
					if (ScaleImpactWithMass)
					{
						num *= m_RigidBody2D.mass;
					}
					if (flag)
					{
						vel = -m_RigidBody2D.linearVelocity;
					}
				}
				Rigidbody2D rigidbody2D = ((other2d != null) ? other2d.attachedRigidbody : null);
				if (rigidbody2D != null)
				{
					if (ScaleImpactWithMass)
					{
						num *= rigidbody2D.mass;
					}
					if (flag)
					{
						Vector3 vector = rigidbody2D.linearVelocity;
						vel += vector;
					}
				}
			}
			return num;
		}

		private void GenerateImpactEvent2D(Collider2D other2d, Vector3 vel)
		{
			if (!base.enabled)
			{
				return;
			}
			if (other2d != null)
			{
				int layer = other2d.gameObject.layer;
				if (((1 << layer) & (int)LayerMask) == 0 || (IgnoreTag.Length != 0 && other2d.CompareTag(IgnoreTag)))
				{
					return;
				}
			}
			float num = GetMassAndVelocity2D(other2d, ref vel);
			if (ScaleImpactWithSpeed)
			{
				num *= Mathf.Sqrt(vel.magnitude);
			}
			Vector3 vector = DefaultVelocity;
			if (UseImpactDirection && !vel.AlmostZero())
			{
				vector = -vel.normalized * vector.magnitude;
			}
			GenerateImpulseWithVelocity(vector * num);
		}
	}
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineImpulseFixedSignals.html")]
	public class CinemachineFixedSignal : SignalSourceAsset
	{
		[Tooltip("The raw signal shape along the X axis")]
		[FormerlySerializedAs("m_XCurve")]
		public AnimationCurve XCurve;

		[Tooltip("The raw signal shape along the Y axis")]
		[FormerlySerializedAs("m_YCurve")]
		public AnimationCurve YCurve;

		[Tooltip("The raw signal shape along the Z axis")]
		[FormerlySerializedAs("m_ZCurve")]
		public AnimationCurve ZCurve;

		public override float SignalDuration => Mathf.Max(AxisDuration(XCurve), Mathf.Max(AxisDuration(YCurve), AxisDuration(ZCurve)));

		private float AxisDuration(AnimationCurve axis)
		{
			float result = 0f;
			if (axis != null && axis.length > 1)
			{
				float time = axis[0].time;
				result = axis[axis.length - 1].time - time;
			}
			return result;
		}

		public override void GetSignal(float timeSinceSignalStart, out Vector3 pos, out Quaternion rot)
		{
			rot = Quaternion.identity;
			pos = new Vector3(AxisValue(XCurve, timeSinceSignalStart), AxisValue(YCurve, timeSinceSignalStart), AxisValue(ZCurve, timeSinceSignalStart));
		}

		private float AxisValue(AnimationCurve axis, float time)
		{
			if (axis == null || axis.length == 0)
			{
				return 0f;
			}
			return axis.Evaluate(time);
		}
	}
	[Serializable]
	public class CinemachineImpulseDefinition
	{
		public enum ImpulseShapes
		{
			Custom,
			Recoil,
			Bump,
			Explosion,
			Rumble
		}

		public enum ImpulseTypes
		{
			Uniform,
			Dissipating,
			Propagating,
			Legacy
		}

		public enum RepeatModes
		{
			Stretch,
			Loop
		}

		private class SignalSource : ISignalSource6D
		{
			private CinemachineImpulseDefinition m_Def;

			private Vector3 m_Velocity;

			public float SignalDuration => m_Def.ImpulseDuration;

			public SignalSource(CinemachineImpulseDefinition def, Vector3 velocity)
			{
				m_Def = def;
				m_Velocity = velocity;
			}

			public void GetSignal(float timeSinceSignalStart, out Vector3 pos, out Quaternion rot)
			{
				pos = m_Velocity * m_Def.ImpulseCurve.Evaluate(timeSinceSignalStart / SignalDuration);
				rot = Quaternion.identity;
			}
		}

		private class LegacySignalSource : ISignalSource6D
		{
			private CinemachineImpulseDefinition m_Def;

			private Vector3 m_Velocity;

			private float m_StartTimeOffset;

			public float SignalDuration => m_Def.RawSignal.SignalDuration;

			public LegacySignalSource(CinemachineImpulseDefinition def, Vector3 velocity)
			{
				m_Def = def;
				m_Velocity = velocity;
				if (m_Def.Randomize && m_Def.RawSignal.SignalDuration <= 0f)
				{
					m_StartTimeOffset = UnityEngine.Random.Range(-1000f, 1000f);
				}
			}

			public void GetSignal(float timeSinceSignalStart, out Vector3 pos, out Quaternion rot)
			{
				float num = m_StartTimeOffset + timeSinceSignalStart * m_Def.FrequencyGain;
				float signalDuration = SignalDuration;
				if (signalDuration > 0f)
				{
					if (m_Def.RepeatMode == RepeatModes.Loop)
					{
						num %= signalDuration;
					}
					else if (m_Def.TimeEnvelope.Duration > 0.0001f)
					{
						num *= m_Def.TimeEnvelope.Duration / signalDuration;
					}
				}
				m_Def.RawSignal.GetSignal(num, out pos, out rot);
				float magnitude = m_Velocity.magnitude;
				magnitude *= m_Def.AmplitudeGain;
				pos *= magnitude;
				pos = Quaternion.FromToRotation(Vector3.down, m_Velocity) * pos;
				rot = Quaternion.SlerpUnclamped(Quaternion.identity, rot, magnitude);
			}
		}

		[CinemachineImpulseChannelProperty]
		[Tooltip("Impulse events generated here will appear on the channels included in the mask.")]
		[FormerlySerializedAs("m_ImpulseChannel")]
		public int ImpulseChannel = 1;

		[Tooltip("Shape of the impact signal")]
		[FormerlySerializedAs("m_ImpulseShape")]
		public ImpulseShapes ImpulseShape;

		[Tooltip("Defines the custom shape of the impact signal that will be generated.")]
		[FormerlySerializedAs("m_CustomImpulseShape")]
		public AnimationCurve CustomImpulseShape = new AnimationCurve();

		[Tooltip("The time during which the impact signal will occur.  The signal shape will be stretched to fill that time.")]
		[FormerlySerializedAs("m_ImpulseDuration")]
		public float ImpulseDuration = 0.2f;

		[Tooltip("How the impulse travels through space and time.")]
		[FormerlySerializedAs("m_ImpulseType")]
		public ImpulseTypes ImpulseType = ImpulseTypes.Legacy;

		[Tooltip("This defines how the widely signal will spread within the effect radius before dissipating with distance from the impact point")]
		[Range(0f, 1f)]
		[FormerlySerializedAs("m_DissipationRate")]
		public float DissipationRate;

		[Header("Signal Shape")]
		[Tooltip("Legacy mode only: Defines the signal that will be generated.")]
		[CinemachineEmbeddedAssetProperty(true)]
		[FormerlySerializedAs("m_RawSignal")]
		public SignalSourceAsset RawSignal;

		[Tooltip("Legacy mode only: Gain to apply to the amplitudes defined in the signal source.  1 is normal.  Setting this to 0 completely mutes the signal.")]
		[FormerlySerializedAs("m_AmplitudeGain")]
		public float AmplitudeGain = 1f;

		[Tooltip("Legacy mode only: Scale factor to apply to the time axis.  1 is normal.  Larger magnitudes will make the signal progress more rapidly.")]
		[FormerlySerializedAs("m_FrequencyGain")]
		public float FrequencyGain = 1f;

		[Tooltip("Legacy mode only: How to fit the signal into the envelope time")]
		[FormerlySerializedAs("m_RepeatMode")]
		public RepeatModes RepeatMode;

		[Tooltip("Legacy mode only: Randomize the signal start time")]
		[FormerlySerializedAs("m_Randomize")]
		public bool Randomize = true;

		[Tooltip("Legacy mode only: This defines the time-envelope of the signal.  The raw signal will be time-scaled to fit in the envelope.")]
		[FormerlySerializedAs("m_TimeEnvelope")]
		public CinemachineImpulseManager.EnvelopeDefinition TimeEnvelope = CinemachineImpulseManager.EnvelopeDefinition.Default;

		[Header("Spatial Range")]
		[Tooltip("Legacy mode only: The signal will have full amplitude in this radius surrounding the impact point.  Beyond that it will dissipate with distance.")]
		[FormerlySerializedAs("m_ImpactRadius")]
		public float ImpactRadius = 100f;

		[Tooltip("Legacy mode only: How the signal direction behaves as the listener moves away from the origin.")]
		[FormerlySerializedAs("m_DirectionMode")]
		public CinemachineImpulseManager.ImpulseEvent.DirectionModes DirectionMode;

		[Tooltip("Legacy mode only: This defines how the signal will dissipate with distance beyond the impact radius.")]
		[FormerlySerializedAs("m_DissipationMode")]
		public CinemachineImpulseManager.ImpulseEvent.DissipationModes DissipationMode = CinemachineImpulseManager.ImpulseEvent.DissipationModes.ExponentialDecay;

		[Tooltip("The signal will have no effect outside this radius surrounding the impact point.")]
		[FormerlySerializedAs("m_DissipationDistance")]
		public float DissipationDistance = 100f;

		[Tooltip("The speed (m/s) at which the impulse propagates through space.  High speeds allow listeners to react instantaneously, while slower speeds allow listeners in the scene to react as if to a wave spreading from the source.")]
		[FormerlySerializedAs("m_PropagationSpeed")]
		public float PropagationSpeed = 343f;

		private static AnimationCurve[] s_StandardShapes;

		internal AnimationCurve ImpulseCurve
		{
			get
			{
				if (ImpulseShape == ImpulseShapes.Custom)
				{
					if (CustomImpulseShape == null)
					{
						CustomImpulseShape = AnimationCurve.EaseInOut(0f, 0f, 1f, 1f);
					}
					return CustomImpulseShape;
				}
				return GetStandardCurve(ImpulseShape);
			}
		}

		public void OnValidate()
		{
			RuntimeUtility.NormalizeCurve(CustomImpulseShape, normalizeX: true, normalizeY: false);
			ImpulseDuration = Mathf.Max(0.0001f, ImpulseDuration);
			DissipationDistance = Mathf.Max(0.0001f, DissipationDistance);
			DissipationRate = Mathf.Clamp01(DissipationRate);
			PropagationSpeed = Mathf.Max(1f, PropagationSpeed);
			ImpactRadius = Mathf.Max(0f, ImpactRadius);
			TimeEnvelope.Validate();
			PropagationSpeed = Mathf.Max(1f, PropagationSpeed);
		}

		private static void CreateStandardShapes()
		{
			int num = 0;
			IEnumerator enumerator = Enum.GetValues(typeof(ImpulseShapes)).GetEnumerator();
			while (enumerator.MoveNext())
			{
				num = Mathf.Max(num, (int)enumerator.Current);
			}
			s_StandardShapes = new AnimationCurve[num + 1];
			s_StandardShapes[1] = new AnimationCurve(new Keyframe(0f, 1f, -3.2f, -3.2f), new Keyframe(1f, 0f, 0f, 0f));
			s_StandardShapes[2] = new AnimationCurve(new Keyframe(0f, 0f, -4.9f, -4.9f), new Keyframe(0.2f, 0f, 8.25f, 8.25f), new Keyframe(1f, 0f, -0.25f, -0.25f));
			s_StandardShapes[3] = new AnimationCurve(new Keyframe(0f, -1.4f, -7.9f, -7.9f), new Keyframe(0.27f, 0.78f, 23.4f, 23.4f), new Keyframe(0.54f, -0.12f, 22.6f, 22.6f), new Keyframe(0.75f, 0.042f, 9.23f, 9.23f), new Keyframe(0.9f, -0.02f, 5.8f, 5.8f), new Keyframe(0.95f, -0.006f, -3f, -3f), new Keyframe(1f, 0f, 0f, 0f));
			s_StandardShapes[4] = new AnimationCurve(new Keyframe(0f, 0f, 0f, 0f), new Keyframe(0.1f, 0.25f, 0f, 0f), new Keyframe(0.2f, 0f, 0f, 0f), new Keyframe(0.3f, 0.75f, 0f, 0f), new Keyframe(0.4f, 0f, 0f, 0f), new Keyframe(0.5f, 1f, 0f, 0f), new Keyframe(0.6f, 0f, 0f, 0f), new Keyframe(0.7f, 0.75f, 0f, 0f), new Keyframe(0.8f, 0f, 0f, 0f), new Keyframe(0.9f, 0.25f, 0f, 0f), new Keyframe(1f, 0f, 0f, 0f));
		}

		internal static AnimationCurve GetStandardCurve(ImpulseShapes shape)
		{
			if (s_StandardShapes == null)
			{
				CreateStandardShapes();
			}
			return s_StandardShapes[(int)shape];
		}

		public void CreateEvent(Vector3 position, Vector3 velocity)
		{
			CreateAndReturnEvent(position, velocity);
		}

		public CinemachineImpulseManager.ImpulseEvent CreateAndReturnEvent(Vector3 position, Vector3 velocity)
		{
			if (ImpulseType == ImpulseTypes.Legacy)
			{
				return LegacyCreateAndReturnEvent(position, velocity);
			}
			if ((ImpulseShape == ImpulseShapes.Custom && CustomImpulseShape == null) || Mathf.Abs(DissipationDistance) < 0.0001f || Mathf.Abs(ImpulseDuration) < 0.0001f)
			{
				return null;
			}
			CinemachineImpulseManager.ImpulseEvent impulseEvent = CinemachineImpulseManager.Instance.NewImpulseEvent();
			impulseEvent.Envelope = new CinemachineImpulseManager.EnvelopeDefinition
			{
				SustainTime = ImpulseDuration
			};
			impulseEvent.SignalSource = new SignalSource(this, velocity);
			impulseEvent.Position = position;
			impulseEvent.Radius = ((ImpulseType == ImpulseTypes.Uniform) ? 9999999f : 0f);
			impulseEvent.Channel = ImpulseChannel;
			impulseEvent.DirectionMode = CinemachineImpulseManager.ImpulseEvent.DirectionModes.Fixed;
			impulseEvent.DissipationDistance = ((ImpulseType == ImpulseTypes.Uniform) ? 0f : DissipationDistance);
			impulseEvent.PropagationSpeed = ((ImpulseType == ImpulseTypes.Propagating) ? PropagationSpeed : 9999999f);
			impulseEvent.CustomDissipation = DissipationRate;
			CinemachineImpulseManager.Instance.AddImpulseEvent(impulseEvent);
			return impulseEvent;
		}

		private CinemachineImpulseManager.ImpulseEvent LegacyCreateAndReturnEvent(Vector3 position, Vector3 velocity)
		{
			if (RawSignal == null || Mathf.Abs(TimeEnvelope.Duration) < 0.0001f)
			{
				return null;
			}
			CinemachineImpulseManager.ImpulseEvent impulseEvent = CinemachineImpulseManager.Instance.NewImpulseEvent();
			impulseEvent.Envelope = TimeEnvelope;
			impulseEvent.Envelope = TimeEnvelope;
			if (TimeEnvelope.ScaleWithImpact)
			{
				impulseEvent.Envelope.DecayTime *= Mathf.Sqrt(velocity.magnitude);
			}
			impulseEvent.SignalSource = new LegacySignalSource(this, velocity);
			impulseEvent.Position = position;
			impulseEvent.Radius = ImpactRadius;
			impulseEvent.Channel = ImpulseChannel;
			impulseEvent.DirectionMode = DirectionMode;
			impulseEvent.DissipationMode = DissipationMode;
			impulseEvent.DissipationDistance = DissipationDistance;
			impulseEvent.PropagationSpeed = PropagationSpeed;
			CinemachineImpulseManager.Instance.AddImpulseEvent(impulseEvent);
			return impulseEvent;
		}
	}
	[SaveDuringPlay]
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Impulse Listener")]
	[ExecuteAlways]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineImpulseListener.html")]
	public class CinemachineImpulseListener : CinemachineExtension
	{
		public enum SignalCombinationModes
		{
			Additive,
			UseLargest
		}

		[Serializable]
		public struct ImpulseReaction
		{
			[Tooltip("Secondary shake that will be triggered by the primary impulse.")]
			public NoiseSettings m_SecondaryNoise;

			[Tooltip("Gain to apply to the amplitudes defined in the signal source.  1 is normal.  Setting this to 0 completely mutes the signal.")]
			[FormerlySerializedAs("m_AmplitudeGain")]
			public float AmplitudeGain;

			[Tooltip("Scale factor to apply to the time axis.  1 is normal.  Larger magnitudes will make the signal progress more rapidly.")]
			[FormerlySerializedAs("m_FrequencyGain")]
			public float FrequencyGain;

			[Tooltip("How long the secondary reaction lasts.")]
			[FormerlySerializedAs("m_Duration")]
			public float Duration;

			private float m_CurrentAmount;

			private float m_CurrentTime;

			private float m_CurrentDamping;

			private bool m_Initialized;

			[SerializeField]
			[HideInInspector]
			[NoSaveDuringPlay]
			private Vector3 m_NoiseOffsets;

			public void ReSeed()
			{
				m_NoiseOffsets = new Vector3(UnityEngine.Random.Range(-1000f, 1000f), UnityEngine.Random.Range(-1000f, 1000f), UnityEngine.Random.Range(-1000f, 1000f));
			}

			public bool GetReaction(float deltaTime, Vector3 impulsePos, out Vector3 pos, out Quaternion rot)
			{
				if (!m_Initialized)
				{
					m_Initialized = true;
					m_CurrentAmount = 0f;
					m_CurrentDamping = 0f;
					m_CurrentTime = CinemachineCore.CurrentTime * FrequencyGain;
					if (m_NoiseOffsets == Vector3.zero)
					{
						ReSeed();
					}
				}
				pos = Vector3.zero;
				rot = Quaternion.identity;
				float sqrMagnitude = impulsePos.sqrMagnitude;
				if (m_SecondaryNoise == null || (sqrMagnitude < 0.001f && m_CurrentAmount < 0.0001f))
				{
					return false;
				}
				if (TargetPositionCache.CacheMode == TargetPositionCache.Mode.Playback && TargetPositionCache.HasCurrentTime)
				{
					m_CurrentTime = TargetPositionCache.CurrentTime * FrequencyGain;
				}
				else
				{
					m_CurrentTime += deltaTime * FrequencyGain;
				}
				m_CurrentAmount = Mathf.Max(m_CurrentAmount, Mathf.Sqrt(sqrMagnitude));
				m_CurrentDamping = Mathf.Max(m_CurrentDamping, Mathf.Max(1f, Mathf.Sqrt(m_CurrentAmount)) * Duration);
				float num = m_CurrentAmount * AmplitudeGain;
				pos = NoiseSettings.GetCombinedFilterResults(m_SecondaryNoise.PositionNoise, m_CurrentTime, m_NoiseOffsets) * num;
				rot = Quaternion.Euler(NoiseSettings.GetCombinedFilterResults(m_SecondaryNoise.OrientationNoise, m_CurrentTime, m_NoiseOffsets) * num);
				m_CurrentAmount -= Damper.Damp(m_CurrentAmount, m_CurrentDamping, deltaTime);
				m_CurrentDamping -= Damper.Damp(m_CurrentDamping, m_CurrentDamping, deltaTime);
				return true;
			}
		}

		[Tooltip("When to apply the impulse reaction.  Default is after the Noise stage.  Modify this if necessary to influence the ordering of extension effects")]
		[FormerlySerializedAs("m_ApplyAfter")]
		public CinemachineCore.Stage ApplyAfter = CinemachineCore.Stage.Aim;

		[Tooltip("Impulse events on channels not included in the mask will be ignored.")]
		[CinemachineImpulseChannelProperty]
		[FormerlySerializedAs("m_ChannelMask")]
		public int ChannelMask;

		[Tooltip("Gain to apply to the Impulse signal.  1 is normal strength.  Setting this to 0 completely mutes the signal.")]
		[FormerlySerializedAs("m_Gain")]
		public float Gain;

		[Tooltip("Enable this to perform distance calculation in 2D (ignore Z)")]
		[FormerlySerializedAs("m_Use2DDistance")]
		public bool Use2DDistance;

		[Tooltip("Enable this to process all impulse signals in camera space")]
		[FormerlySerializedAs("m_UseCameraSpace")]
		public bool UseCameraSpace;

		[Tooltip("Controls how the Impulse Listener combines multiple impulses active at the current point in space.\n\n<b>Additive</b>: Combines all the active signals together, like sound waves.  This is the default.\n\n<b>Use Largest</b>: Considers only the signal with the largest amplitude; ignores any others.")]
		public SignalCombinationModes SignalCombinationMode;

		[Tooltip("This controls the secondary reaction of the listener to the incoming impulse.  The impulse might be for example a sharp shock, and the secondary reaction could be a vibration whose amplitude and duration is controlled by the size of the original impulse.  This allows different listeners to respond in different ways to the same impulse signal.")]
		[FormerlySerializedAs("m_ReactionSettings")]
		public ImpulseReaction ReactionSettings;

		private void Reset()
		{
			ApplyAfter = CinemachineCore.Stage.Noise;
			ChannelMask = 1;
			Gain = 1f;
			Use2DDistance = false;
			UseCameraSpace = true;
			SignalCombinationMode = SignalCombinationModes.Additive;
			ReactionSettings = new ImpulseReaction
			{
				AmplitudeGain = 1f,
				FrequencyGain = 1f,
				Duration = 1f
			};
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage != ApplyAfter || !(deltaTime >= 0f))
			{
				return;
			}
			bool flag = false;
			Vector3 pos = Vector3.zero;
			Quaternion rot = Quaternion.identity;
			flag = ((SignalCombinationMode != SignalCombinationModes.Additive) ? CinemachineImpulseManager.Instance.GetStrongestImpulseAt(state.GetFinalPosition(), Use2DDistance, ChannelMask, out pos, out rot) : CinemachineImpulseManager.Instance.GetImpulseAt(state.GetFinalPosition(), Use2DDistance, ChannelMask, out pos, out rot));
			Vector3 pos2;
			Quaternion rot2;
			bool reaction = ReactionSettings.GetReaction(deltaTime, pos, out pos2, out rot2);
			if (flag)
			{
				rot = Quaternion.SlerpUnclamped(Quaternion.identity, rot, Gain);
				pos *= Gain;
			}
			if (reaction)
			{
				pos += pos2;
				rot *= rot2;
			}
			if (flag || reaction)
			{
				if (UseCameraSpace)
				{
					pos = state.RawOrientation * pos;
				}
				state.PositionCorrection += pos;
				state.OrientationCorrection *= rot;
			}
		}
	}
	public sealed class CinemachineImpulseChannelPropertyAttribute : PropertyAttribute
	{
	}
	public class CinemachineImpulseManager
	{
		[Serializable]
		public struct EnvelopeDefinition
		{
			[Tooltip("Normalized curve defining the shape of the start of the envelope.  If blank a default curve will be used")]
			[FormerlySerializedAs("m_AttackShape")]
			public AnimationCurve AttackShape;

			[Tooltip("Normalized curve defining the shape of the end of the envelope.  If blank a default curve will be used")]
			[FormerlySerializedAs("m_DecayShape")]
			public AnimationCurve DecayShape;

			[Tooltip("Duration in seconds of the attack.  Attack curve will be scaled to fit.  Must be >= 0.")]
			[FormerlySerializedAs("m_AttackTime")]
			public float AttackTime;

			[Tooltip("Duration in seconds of the central fully-scaled part of the envelope.  Must be >= 0.")]
			[FormerlySerializedAs("m_SustainTime")]
			public float SustainTime;

			[Tooltip("Duration in seconds of the decay.  Decay curve will be scaled to fit.  Must be >= 0.")]
			[FormerlySerializedAs("m_DecayTime")]
			public float DecayTime;

			[Tooltip("If checked, signal amplitude scaling will also be applied to the time envelope of the signal.  Stronger signals will last longer.")]
			[FormerlySerializedAs("m_ScaleWithImpact")]
			public bool ScaleWithImpact;

			[Tooltip("If true, then duration is infinite.")]
			[FormerlySerializedAs("m_HoldForever")]
			public bool HoldForever;

			public static EnvelopeDefinition Default => new EnvelopeDefinition
			{
				DecayTime = 0.7f,
				SustainTime = 0.2f,
				ScaleWithImpact = true
			};

			public readonly float Duration
			{
				get
				{
					if (!HoldForever)
					{
						return AttackTime + SustainTime + DecayTime;
					}
					return -1f;
				}
			}

			public readonly float GetValueAt(float offset)
			{
				if (offset >= 0f)
				{
					if (offset < AttackTime && AttackTime > 0.0001f)
					{
						if (AttackShape == null || AttackShape.length < 2)
						{
							return Damper.Damp(1f, AttackTime, offset);
						}
						return AttackShape.Evaluate(offset / AttackTime);
					}
					offset -= AttackTime;
					if (HoldForever || offset < SustainTime)
					{
						return 1f;
					}
					offset -= SustainTime;
					if (offset < DecayTime && DecayTime > 0.0001f)
					{
						if (DecayShape == null || DecayShape.length < 2)
						{
							return 1f - Damper.Damp(1f, DecayTime, offset);
						}
						return DecayShape.Evaluate(offset / DecayTime);
					}
				}
				return 0f;
			}

			public void ChangeStopTime(float offset, bool forceNoDecay)
			{
				if (offset < 0f)
				{
					offset = 0f;
				}
				if (offset < AttackTime)
				{
					AttackTime = 0f;
				}
				SustainTime = offset - AttackTime;
				if (forceNoDecay)
				{
					DecayTime = 0f;
				}
			}

			public void Clear()
			{
				AttackShape = (DecayShape = null);
				AttackTime = (SustainTime = (DecayTime = 0f));
			}

			public void Validate()
			{
				AttackTime = Mathf.Max(0f, AttackTime);
				DecayTime = Mathf.Max(0f, DecayTime);
				SustainTime = Mathf.Max(0f, SustainTime);
			}
		}

		public class ImpulseEvent
		{
			public enum DirectionModes
			{
				Fixed,
				RotateTowardSource
			}

			public enum DissipationModes
			{
				LinearDecay,
				SoftDecay,
				ExponentialDecay
			}

			public float StartTime;

			public EnvelopeDefinition Envelope;

			public ISignalSource6D SignalSource;

			public Vector3 Position;

			public float Radius;

			public DirectionModes DirectionMode;

			public int Channel;

			public DissipationModes DissipationMode;

			public float DissipationDistance;

			public float CustomDissipation;

			public float PropagationSpeed;

			public bool Expired
			{
				get
				{
					float duration = Envelope.Duration;
					float num = Radius + DissipationDistance;
					float num2 = Instance.CurrentTime - num / Mathf.Max(1f, PropagationSpeed);
					if (duration > 0f)
					{
						return StartTime + duration <= num2;
					}
					return false;
				}
			}

			public void Cancel(float time, bool forceNoDecay)
			{
				Envelope.HoldForever = false;
				Envelope.ChangeStopTime(time - StartTime, forceNoDecay);
			}

			public float DistanceDecay(float distance)
			{
				float num = Mathf.Max(Radius, 0f);
				if (distance < num)
				{
					return 1f;
				}
				distance -= num;
				if (distance >= DissipationDistance)
				{
					return 0f;
				}
				if (CustomDissipation >= 0f)
				{
					return EvaluateDissipationScale(CustomDissipation, distance / DissipationDistance);
				}
				return DissipationMode switch
				{
					DissipationModes.SoftDecay => 0.5f * (1f + Mathf.Cos(MathF.PI * (distance / DissipationDistance))), 
					DissipationModes.ExponentialDecay => 1f - Damper.Damp(1f, DissipationDistance, distance), 
					_ => Mathf.Lerp(1f, 0f, distance / DissipationDistance), 
				};
			}

			public bool GetDecayedSignal(Vector3 listenerPosition, bool use2D, out Vector3 pos, out Quaternion rot)
			{
				if (SignalSource != null)
				{
					float num = (use2D ? Vector2.Distance(listenerPosition, Position) : Vector3.Distance(listenerPosition, Position));
					float num2 = Instance.CurrentTime - StartTime - num / Mathf.Max(1f, PropagationSpeed);
					float num3 = Envelope.GetValueAt(num2) * DistanceDecay(num);
					if (num3 != 0f)
					{
						SignalSource.GetSignal(num2, out pos, out rot);
						pos *= num3;
						rot = Quaternion.SlerpUnclamped(Quaternion.identity, rot, num3);
						if (DirectionMode == DirectionModes.RotateTowardSource && num > 0.0001f)
						{
							Quaternion quaternion2 = Quaternion.FromToRotation(Vector3.up, listenerPosition - Position);
							if (Radius > 0.0001f)
							{
								float num4 = Mathf.Clamp01(num / Radius);
								quaternion2 = Quaternion.Slerp(quaternion2, Quaternion.identity, Mathf.Cos(MathF.PI * num4 / 2f));
							}
							pos = quaternion2 * pos;
						}
						return true;
					}
				}
				pos = Vector3.zero;
				rot = Quaternion.identity;
				return false;
			}

			public void Clear()
			{
				Envelope.Clear();
				StartTime = 0f;
				SignalSource = null;
				Position = Vector3.zero;
				Channel = 0;
				Radius = 0f;
				DissipationDistance = 100f;
				DissipationMode = DissipationModes.ExponentialDecay;
				CustomDissipation = -1f;
			}

			internal ImpulseEvent()
			{
			}
		}

		private static CinemachineImpulseManager s_Instance;

		private const float Epsilon = 0.0001f;

		private List<ImpulseEvent> m_ExpiredEvents;

		private List<ImpulseEvent> m_ActiveEvents;

		public bool IgnoreTimeScale;

		public static CinemachineImpulseManager Instance
		{
			get
			{
				if (s_Instance == null)
				{
					s_Instance = new CinemachineImpulseManager();
				}
				return s_Instance;
			}
		}

		public float CurrentTime
		{
			get
			{
				if (!IgnoreTimeScale)
				{
					return CinemachineCore.CurrentTime;
				}
				return Time.realtimeSinceStartup;
			}
		}

		private CinemachineImpulseManager()
		{
		}

		[RuntimeInitializeOnLoadMethod]
		private static void InitializeModule()
		{
			if (s_Instance != null)
			{
				s_Instance.Clear();
			}
		}

		internal static float EvaluateDissipationScale(float spread, float normalizedDistance)
		{
			float num = -0.8f + 1.6f * (1f - spread);
			num = (1f - num) * 0.5f;
			float t = Mathf.Clamp01(normalizedDistance) / ((1f / Mathf.Clamp01(num) - 2f) * (1f - normalizedDistance) + 1f);
			return 1f - SplineHelpers.Bezier1(t, 0f, 0f, 1f, 1f);
		}

		public bool GetImpulseAt(Vector3 listenerLocation, bool distance2D, int channelMask, out Vector3 pos, out Quaternion rot)
		{
			bool result = false;
			pos = Vector3.zero;
			rot = Quaternion.identity;
			if (m_ActiveEvents != null)
			{
				for (int num = m_ActiveEvents.Count - 1; num >= 0; num--)
				{
					ImpulseEvent impulseEvent = m_ActiveEvents[num];
					Vector3 pos2;
					Quaternion rot2;
					if (impulseEvent == null || impulseEvent.Expired)
					{
						m_ActiveEvents.RemoveAt(num);
						if (impulseEvent != null)
						{
							if (m_ExpiredEvents == null)
							{
								m_ExpiredEvents = new List<ImpulseEvent>();
							}
							impulseEvent.Clear();
							m_ExpiredEvents.Add(impulseEvent);
						}
					}
					else if ((impulseEvent.Channel & channelMask) != 0 && impulseEvent.GetDecayedSignal(listenerLocation, distance2D, out pos2, out rot2))
					{
						result = true;
						pos += pos2;
						rot *= rot2;
					}
				}
			}
			return result;
		}

		public bool GetStrongestImpulseAt(Vector3 listenerLocation, bool distance2D, int channelMask, out Vector3 pos, out Quaternion rot)
		{
			bool result = false;
			Vector3 vector = Vector3.zero;
			Quaternion quaternion2 = Quaternion.identity;
			if (m_ActiveEvents != null)
			{
				float num = 0f;
				for (int num2 = m_ActiveEvents.Count - 1; num2 >= 0; num2--)
				{
					ImpulseEvent impulseEvent = m_ActiveEvents[num2];
					Vector3 pos2;
					Quaternion rot2;
					if (impulseEvent == null || impulseEvent.Expired)
					{
						m_ActiveEvents.RemoveAt(num2);
						if (impulseEvent != null)
						{
							if (m_ExpiredEvents == null)
							{
								m_ExpiredEvents = new List<ImpulseEvent>();
							}
							impulseEvent.Clear();
							m_ExpiredEvents.Add(impulseEvent);
						}
					}
					else if ((impulseEvent.Channel & channelMask) != 0 && impulseEvent.GetDecayedSignal(listenerLocation, distance2D, out pos2, out rot2))
					{
						result = true;
						float sqrMagnitude = pos2.sqrMagnitude;
						if (sqrMagnitude > num)
						{
							num = sqrMagnitude;
							vector = pos2;
							quaternion2 = rot2;
						}
					}
				}
			}
			pos = vector;
			rot = quaternion2;
			return result;
		}

		public ImpulseEvent NewImpulseEvent()
		{
			if (m_ExpiredEvents == null || m_ExpiredEvents.Count == 0)
			{
				return new ImpulseEvent
				{
					CustomDissipation = -1f
				};
			}
			ImpulseEvent result = m_ExpiredEvents[m_ExpiredEvents.Count - 1];
			m_ExpiredEvents.RemoveAt(m_ExpiredEvents.Count - 1);
			return result;
		}

		public void AddImpulseEvent(ImpulseEvent e)
		{
			if (m_ActiveEvents == null)
			{
				m_ActiveEvents = new List<ImpulseEvent>();
			}
			if (e != null)
			{
				e.StartTime = CurrentTime;
				m_ActiveEvents.Add(e);
			}
		}

		public void Clear()
		{
			if (m_ActiveEvents != null)
			{
				for (int i = 0; i < m_ActiveEvents.Count; i++)
				{
					m_ActiveEvents[i].Clear();
				}
				m_ActiveEvents.Clear();
			}
		}
	}
	[SaveDuringPlay]
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine Impulse Source")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineImpulseSource.html")]
	public class CinemachineImpulseSource : MonoBehaviour
	{
		[FormerlySerializedAs("m_ImpulseDefinition")]
		public CinemachineImpulseDefinition ImpulseDefinition = new CinemachineImpulseDefinition();

		[Header("Default Invocation")]
		[Tooltip("The default direction and force of the Impulse Signal in the absense of any specified overrides.  Overrides can be specified by calling the appropriate GenerateImpulse method in the API.")]
		[FormerlySerializedAs("m_DefaultVelocity")]
		public Vector3 DefaultVelocity = Vector3.down;

		private void OnValidate()
		{
			ImpulseDefinition.OnValidate();
		}

		private void Reset()
		{
			ImpulseDefinition = new CinemachineImpulseDefinition
			{
				ImpulseChannel = 1,
				ImpulseShape = CinemachineImpulseDefinition.ImpulseShapes.Bump,
				CustomImpulseShape = new AnimationCurve(),
				ImpulseDuration = 0.2f,
				ImpulseType = CinemachineImpulseDefinition.ImpulseTypes.Uniform,
				DissipationDistance = 100f,
				DissipationRate = 0.25f,
				PropagationSpeed = 343f
			};
			DefaultVelocity = Vector3.down;
		}

		public void GenerateImpulseAtPositionWithVelocity(Vector3 position, Vector3 velocity)
		{
			if (ImpulseDefinition != null)
			{
				ImpulseDefinition.CreateEvent(position, velocity);
			}
		}

		public void GenerateImpulseWithVelocity(Vector3 velocity)
		{
			GenerateImpulseAtPositionWithVelocity(base.transform.position, velocity);
		}

		public void GenerateImpulseWithForce(float force)
		{
			GenerateImpulseAtPositionWithVelocity(base.transform.position, DefaultVelocity * force);
		}

		public void GenerateImpulse()
		{
			GenerateImpulseWithVelocity(DefaultVelocity);
		}

		public void GenerateImpulseAt(Vector3 position, Vector3 velocity)
		{
			GenerateImpulseAtPositionWithVelocity(position, velocity);
		}

		public void GenerateImpulse(Vector3 velocity)
		{
			GenerateImpulseWithVelocity(velocity);
		}

		public void GenerateImpulse(float force)
		{
			GenerateImpulseWithForce(force);
		}
	}
	[SaveDuringPlay]
	[AddComponentMenu("Cinemachine/Helpers/Cinemachine External Impulse Listener")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineExternalImpulseListener.html")]
	public class CinemachineExternalImpulseListener : MonoBehaviour
	{
		private Vector3 m_ImpulsePosLastFrame;

		private Quaternion m_ImpulseRotLastFrame;

		[Tooltip("Impulse events on channels not included in the mask will be ignored.")]
		[CinemachineImpulseChannelProperty]
		[FormerlySerializedAs("m_ChannelMask")]
		public int ChannelMask;

		[Tooltip("Gain to apply to the Impulse signal.  1 is normal strength.  Setting this to 0 completely mutes the signal.")]
		[FormerlySerializedAs("m_Gain")]
		public float Gain;

		[Tooltip("Enable this to perform distance calculation in 2D (ignore Z)")]
		[FormerlySerializedAs("m_Use2DDistance")]
		public bool Use2DDistance;

		[Tooltip("Enable this to process all impulse signals in camera space")]
		[FormerlySerializedAs("m_UseLocalSpace")]
		public bool UseLocalSpace;

		[Tooltip("This controls the secondary reaction of the listener to the incoming impulse.  The impulse might be for example a sharp shock, and the secondary reaction could be a vibration whose amplitude and duration is controlled by the size of the original impulse.  This allows different listeners to respond in different ways to the same impulse signal.")]
		[FormerlySerializedAs("m_ReactionSettings")]
		public CinemachineImpulseListener.ImpulseReaction ReactionSettings;

		private void Reset()
		{
			ChannelMask = 1;
			Gain = 1f;
			Use2DDistance = false;
			UseLocalSpace = true;
			ReactionSettings = new CinemachineImpulseListener.ImpulseReaction
			{
				AmplitudeGain = 1f,
				FrequencyGain = 1f,
				Duration = 1f
			};
		}

		private void OnEnable()
		{
			m_ImpulsePosLastFrame = Vector3.zero;
			m_ImpulseRotLastFrame = Quaternion.identity;
		}

		private void Update()
		{
			base.transform.position -= m_ImpulsePosLastFrame;
			base.transform.rotation = base.transform.rotation * Quaternion.Inverse(m_ImpulseRotLastFrame);
		}

		private void LateUpdate()
		{
			bool impulseAt = CinemachineImpulseManager.Instance.GetImpulseAt(base.transform.position, Use2DDistance, ChannelMask, out m_ImpulsePosLastFrame, out m_ImpulseRotLastFrame);
			Vector3 pos;
			Quaternion rot;
			bool reaction = ReactionSettings.GetReaction(Time.deltaTime, m_ImpulsePosLastFrame, out pos, out rot);
			if (impulseAt)
			{
				m_ImpulseRotLastFrame = Quaternion.SlerpUnclamped(Quaternion.identity, m_ImpulseRotLastFrame, Gain);
				m_ImpulsePosLastFrame *= Gain;
			}
			if (reaction)
			{
				m_ImpulsePosLastFrame += pos;
				m_ImpulseRotLastFrame *= rot;
			}
			if (impulseAt || reaction)
			{
				if (UseLocalSpace)
				{
					m_ImpulsePosLastFrame = base.transform.rotation * m_ImpulsePosLastFrame;
				}
				base.transform.position += m_ImpulsePosLastFrame;
				base.transform.rotation = base.transform.rotation * m_ImpulseRotLastFrame;
			}
		}
	}
	[ExecuteAlways]
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Auto Focus")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineAutoFocus.html")]
	public class CinemachineAutoFocus : CinemachineExtension
	{
		public enum FocusTrackingMode
		{
			None,
			LookAtTarget,
			FollowTarget,
			CustomTarget,
			Camera,
			ScreenCenter
		}

		private class VcamExtraState : VcamExtraStateBase
		{
			public float CurrentFocusDistance;
		}

		[Tooltip("The camera's focus distance will be set to the distance from the camera to the selected target.  The Focus Offset field will then modify that distance.")]
		public FocusTrackingMode FocusTarget;

		[Tooltip("The target to use if Focus Target is set to Custom Target")]
		public Transform CustomTarget;

		[Tooltip("Offsets the sharpest point away in depth from the focus target location.")]
		public float FocusDepthOffset;

		[Tooltip("The value corresponds approximately to the time the focus will take to adjust to the new value.")]
		public float Damping;

		private void Reset()
		{
			Damping = 0.2f;
			FocusTarget = FocusTrackingMode.None;
			CustomTarget = null;
			FocusDepthOffset = 0f;
		}

		private void OnValidate()
		{
			Damping = Mathf.Max(0f, Damping);
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage != CinemachineCore.Stage.Finalize || FocusTarget == FocusTrackingMode.None)
			{
				return;
			}
			VcamExtraState extraState = GetExtraState<VcamExtraState>(vcam);
			float num = 0f;
			Transform transform = null;
			switch (FocusTarget)
			{
			case FocusTrackingMode.LookAtTarget:
				if (state.HasLookAt())
				{
					num = (state.GetFinalPosition() - state.ReferenceLookAt).magnitude;
				}
				else
				{
					transform = vcam.LookAt;
				}
				break;
			case FocusTrackingMode.FollowTarget:
				transform = vcam.Follow;
				break;
			case FocusTrackingMode.CustomTarget:
				transform = CustomTarget;
				break;
			}
			if (transform != null)
			{
				num += (state.GetFinalPosition() - transform.position).magnitude;
			}
			num = Mathf.Max(0.1f, num + FocusDepthOffset);
			if (deltaTime >= 0f && vcam.PreviousStateIsValid)
			{
				num = extraState.CurrentFocusDistance + Damper.Damp(num - extraState.CurrentFocusDistance, Damping, deltaTime);
			}
			extraState.CurrentFocusDistance = num;
			state.Lens.PhysicalProperties.FocusDistance = num;
		}
	}
	[ExecuteAlways]
	[AddComponentMenu("Cinemachine/Procedural/Extensions/Cinemachine Volume Settings")]
	[SaveDuringPlay]
	[DisallowMultipleComponent]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.cinemachine@3.1/manual/CinemachineVolumeSettings.html")]
	public class CinemachineVolumeSettings : CinemachineExtension
	{
		public enum FocusTrackingMode
		{
			None,
			LookAtTarget,
			FollowTarget,
			CustomTarget,
			Camera
		}

		private class VcamExtraState : VcamExtraStateBase
		{
			public VolumeProfile ProfileCopy;

			public void CreateProfileCopy(VolumeProfile source)
			{
				DestroyProfileCopy();
				VolumeProfile volumeProfile = ScriptableObject.CreateInstance<VolumeProfile>();
				int num = 0;
				while (source != null && num < source.components.Count)
				{
					VolumeComponent item = UnityEngine.Object.Instantiate(source.components[num]);
					volumeProfile.components.Add(item);
					volumeProfile.isDirty = true;
					num++;
				}
				ProfileCopy = volumeProfile;
			}

			public void DestroyProfileCopy()
			{
				if (ProfileCopy != null)
				{
					RuntimeUtility.DestroyObject(ProfileCopy);
				}
				ProfileCopy = null;
			}
		}

		public static float s_VolumePriority = 1000f;

		public float Weight = 1f;

		[Tooltip("If the profile has the appropriate overrides, will set the base focus distance to be the distance from the selected target to the camera.The Focus Offset field will then modify that distance.")]
		[FormerlySerializedAs("m_FocusTracking")]
		public FocusTrackingMode FocusTracking;

		[Tooltip("The target to use if Focus Tracks Target is set to Custom Target")]
		[FormerlySerializedAs("m_FocusTarget")]
		public Transform FocusTarget;

		[Tooltip("Offset from target distance, to be used with Focus Tracks Target.  Offsets the sharpest point away from the focus target.")]
		[FormerlySerializedAs("m_FocusOffset")]
		public float FocusOffset;

		[Tooltip("This profile will be applied whenever this virtual camera is live")]
		[FormerlySerializedAs("m_Profile")]
		public VolumeProfile Profile;

		private List<VcamExtraState> m_extraStateCache;

		private const string sVolumeOwnerName = "__CMVolumes";

		private static List<Volume> sVolumes = new List<Volume>();

		public float CalculatedFocusDistance { get; private set; }

		public bool IsValid
		{
			get
			{
				if (Profile != null)
				{
					return Profile.components.Count > 0;
				}
				return false;
			}
		}

		public void InvalidateCachedProfile()
		{
			if (m_extraStateCache == null)
			{
				m_extraStateCache = new List<VcamExtraState>();
			}
			GetAllExtraStates(m_extraStateCache);
			for (int i = 0; i < m_extraStateCache.Count; i++)
			{
				m_extraStateCache[i].DestroyProfileCopy();
			}
		}

		private void OnValidate()
		{
			Weight = Mathf.Max(0f, Weight);
		}

		private void Reset()
		{
			Weight = 1f;
			FocusTracking = FocusTrackingMode.None;
			FocusTarget = null;
			FocusOffset = 0f;
			Profile = null;
		}

		protected override void OnEnable()
		{
			InvalidateCachedProfile();
		}

		protected override void OnDestroy()
		{
			InvalidateCachedProfile();
			base.OnDestroy();
		}

		protected override void PostPipelineStageCallback(CinemachineVirtualCameraBase vcam, CinemachineCore.Stage stage, ref CameraState state, float deltaTime)
		{
			if (stage != CinemachineCore.Stage.Finalize)
			{
				return;
			}
			VcamExtraState extraState = GetExtraState<VcamExtraState>(vcam);
			if (!IsValid)
			{
				extraState.DestroyProfileCopy();
				return;
			}
			VolumeProfile volumeProfile = Profile;
			if (FocusTracking == FocusTrackingMode.None)
			{
				extraState.DestroyProfileCopy();
			}
			else
			{
				if (extraState.ProfileCopy == null)
				{
					extraState.CreateProfileCopy(Profile);
				}
				volumeProfile = extraState.ProfileCopy;
				if (volumeProfile.TryGet<DepthOfField>(out var component))
				{
					float num = FocusOffset;
					if (FocusTracking == FocusTrackingMode.LookAtTarget)
					{
						num += (state.GetFinalPosition() - state.ReferenceLookAt).magnitude;
					}
					else
					{
						Transform transform = null;
						switch (FocusTracking)
						{
						case FocusTrackingMode.FollowTarget:
							transform = vcam.Follow;
							break;
						case FocusTrackingMode.CustomTarget:
							transform = FocusTarget;
							break;
						}
						if (transform != null)
						{
							num += (state.GetFinalPosition() - transform.position).magnitude;
						}
					}
					num = (CalculatedFocusDistance = Mathf.Max(0f, num));
					component.focusDistance.value = num;
					state.Lens.PhysicalProperties.FocusDistance = num;
					volumeProfile.isDirty = true;
				}
			}
			state.AddCustomBlendable(new CameraState.CustomBlendableItems.Item
			{
				Custom = volumeProfile,
				Weight = Weight
			});
		}

		private static void OnCameraCut(ICinemachineCamera.ActivationEventParams evt)
		{
			if (evt.IsCut)
			{
				CinemachineBrain cinemachineBrain = evt.Origin as CinemachineBrain;
				Camera camera = ((cinemachineBrain == null) ? null : cinemachineBrain.OutputCamera);
				if (camera != null && camera.TryGetComponent<UniversalAdditionalCameraData>(out var component))
				{
					component.resetHistory = true;
				}
			}
		}

		private static void ApplyPostFX(CinemachineBrain brain)
		{
			CameraState state = brain.State;
			int numCustomBlendables = state.GetNumCustomBlendables();
			List<Volume> dynamicBrainVolumes = GetDynamicBrainVolumes(brain, numCustomBlendables);
			for (int i = 0; i < dynamicBrainVolumes.Count; i++)
			{
				dynamicBrainVolumes[i].weight = 0f;
				dynamicBrainVolumes[i].sharedProfile = null;
				dynamicBrainVolumes[i].profile = null;
			}
			Volume volume = null;
			int num = 0;
			for (int j = 0; j < numCustomBlendables; j++)
			{
				CameraState.CustomBlendableItems.Item customBlendable = state.GetCustomBlendable(j);
				VolumeProfile volumeProfile = customBlendable.Custom as VolumeProfile;
				if (!(volumeProfile == null))
				{
					Volume volume2 = dynamicBrainVolumes[j];
					if (volume == null)
					{
						volume = volume2;
					}
					volume2.sharedProfile = volumeProfile;
					volume2.isGlobal = true;
					volume2.priority = s_VolumePriority - (float)(numCustomBlendables - j) - 1f;
					volume2.weight = customBlendable.Weight;
					num++;
				}
				if (num > 1)
				{
					volume.weight = 1f;
				}
			}
		}

		private static List<Volume> GetDynamicBrainVolumes(CinemachineBrain brain, int minVolumes)
		{
			GameObject gameObject = null;
			Transform transform = brain.transform;
			int childCount = transform.childCount;
			sVolumes.Clear();
			int num = 0;
			while (gameObject == null && num < childCount)
			{
				GameObject gameObject2 = transform.GetChild(num).gameObject;
				if (gameObject2.hideFlags == HideFlags.HideAndDontSave)
				{
					gameObject2.GetComponents(sVolumes);
					if (sVolumes.Count > 0)
					{
						gameObject = gameObject2;
					}
				}
				num++;
			}
			if (minVolumes > 0)
			{
				if (gameObject == null)
				{
					gameObject = new GameObject("__CMVolumes");
					gameObject.hideFlags = HideFlags.HideAndDontSave;
					gameObject.transform.parent = transform;
				}
				brain.gameObject.TryGetComponent<UniversalAdditionalCameraData>(out var component);
				if (component != null)
				{
					int num2 = component.volumeLayerMask;
					for (int i = 0; i < 32; i++)
					{
						if ((num2 & (1 << i)) != 0)
						{
							gameObject.layer = i;
							break;
						}
					}
				}
				while (sVolumes.Count < minVolumes)
				{
					sVolumes.Add(gameObject.gameObject.AddComponent<Volume>());
				}
			}
			return sVolumes;
		}

		[RuntimeInitializeOnLoadMethod]
		private static void InitializeModule()
		{
			CinemachineCore.CameraUpdatedEvent.RemoveListener(ApplyPostFX);
			CinemachineCore.CameraUpdatedEvent.AddListener(ApplyPostFX);
			CinemachineCore.CameraActivatedEvent.RemoveListener(OnCameraCut);
			CinemachineCore.CameraActivatedEvent.AddListener(OnCameraCut);
		}
	}
