	internal class Minkowski
	{
		private static List<List<Point64>> MinkowskiInternal(List<Point64> pattern, List<Point64> path, bool isSum, bool isClosed)
		{
			int num = ((!isClosed) ? 1 : 0);
			int count = pattern.Count;
			int count2 = path.Count;
			List<List<Point64>> list = new List<List<Point64>>(count2);
			foreach (Point64 item in path)
			{
				List<Point64> list2 = new List<Point64>(count);
				if (isSum)
				{
					foreach (Point64 item2 in pattern)
					{
						list2.Add(item + item2);
					}
				}
				else
				{
					foreach (Point64 item3 in pattern)
					{
						list2.Add(item - item3);
					}
				}
				list.Add(list2);
			}
			List<List<Point64>> list3 = new List<List<Point64>>((count2 - num) * count);
			int index = (isClosed ? (count2 - 1) : 0);
			int index2 = count - 1;
			for (int i = num; i < count2; i++)
			{
				for (int j = 0; j < count; j++)
				{
					List<Point64> list4 = new List<Point64>(4)
					{
						list[index][index2],
						list[i][index2],
						list[i][j],
						list[index][j]
					};
					if (!Clipper.IsPositive(list4))
					{
						list3.Add(Clipper.ReversePath(list4));
					}
					else
					{
						list3.Add(list4);
					}
					index2 = j;
				}
				index = i;
			}
			return list3;
		}

		public static List<List<Point64>> Sum(List<Point64> pattern, List<Point64> path, bool isClosed)
		{
			return Clipper.Union(MinkowskiInternal(pattern, path, isSum: true, isClosed), FillRule.NonZero);
		}

		public static List<List<PointD>> Sum(List<PointD> pattern, List<PointD> path, bool isClosed, int decimalPlaces = 2)
		{
			double num = Math.Pow(10.0, decimalPlaces);
			return Clipper.ScalePathsD(Clipper.Union(MinkowskiInternal(Clipper.ScalePath64(pattern, num), Clipper.ScalePath64(path, num), isSum: true, isClosed), FillRule.NonZero), 1.0 / num);
		}

		public static List<List<Point64>> Diff(List<Point64> pattern, List<Point64> path, bool isClosed)
		{
			return Clipper.Union(MinkowskiInternal(pattern, path, isSum: false, isClosed), FillRule.NonZero);
		}

		public static List<List<PointD>> Diff(List<PointD> pattern, List<PointD> path, bool isClosed, int decimalPlaces = 2)
		{
			double num = Math.Pow(10.0, decimalPlaces);
			return Clipper.ScalePathsD(Clipper.Union(MinkowskiInternal(Clipper.ScalePath64(pattern, num), Clipper.ScalePath64(path, num), isSum: false, isClosed), FillRule.NonZero), 1.0 / num);
		}
	}
	internal enum JoinType
	{
		Square,
		Round,
		Miter
	}
	internal enum EndType
	{
		Polygon,
		Joined,
		Butt,
		Square,
		Round
	}
	internal class PathGroup
	{
		internal List<List<Point64>> _inPaths;

		internal List<Point64> _outPath;

		internal List<List<Point64>> _outPaths;

		internal JoinType _joinType;

		internal EndType _endType;

		internal bool _pathsReversed;

		public PathGroup(List<List<Point64>> paths, JoinType joinType, EndType endType = EndType.Polygon)
		{
			_inPaths = new List<List<Point64>>(paths);
			_joinType = joinType;
			_endType = endType;
			_outPath = new List<Point64>();
			_outPaths = new List<List<Point64>>();
			_pathsReversed = false;
		}
	}
	internal class ClipperOffset
	{
		private readonly List<PathGroup> _pathGroups = new List<PathGroup>();

		private readonly List<PointD> _normals = new List<PointD>();

		private readonly List<List<Point64>> solution = new List<List<Point64>>();

		private double _delta;

		private double _tmpLimit;

		private double _stepsPerRad;

		private JoinType _joinType;

		private const double TwoPi = Math.PI * 2.0;

		public double ArcTolerance { get; set; }

		public bool MergeGroups { get; set; }

		public double MiterLimit { get; set; }

		public bool PreserveCollinear { get; set; }

		public bool ReverseSolution { get; set; }

		public ClipperOffset(double miterLimit = 2.0, double arcTolerance = 0.0, bool preserveCollinear = false, bool reverseSolution = false)
		{
			MiterLimit = miterLimit;
			ArcTolerance = arcTolerance;
			MergeGroups = true;
			PreserveCollinear = preserveCollinear;
			ReverseSolution = reverseSolution;
		}

		public void Clear()
		{
			_pathGroups.Clear();
		}

		public void AddPath(List<Point64> path, JoinType joinType, EndType endType)
		{
			if (path.Count != 0)
			{
				List<List<Point64>> paths = new List<List<Point64>>(1) { path };
				AddPaths(paths, joinType, endType);
			}
		}

		public void AddPaths(List<List<Point64>> paths, JoinType joinType, EndType endType)
		{
			if (paths.Count != 0)
			{
				_pathGroups.Add(new PathGroup(paths, joinType, endType));
			}
		}

		public void AddPath(List<PointD> path, JoinType joinType, EndType endType)
		{
			if (path.Count != 0)
			{
				List<List<PointD>> paths = new List<List<PointD>>(1) { path };
				AddPaths(paths, joinType, endType);
			}
		}

		public void AddPaths(List<List<PointD>> paths, JoinType joinType, EndType endType)
		{
			if (paths.Count != 0)
			{
				_pathGroups.Add(new PathGroup(Clipper.Paths64(paths), joinType, endType));
			}
		}

		public List<List<Point64>> Execute(double delta)
		{
			solution.Clear();
			if (Math.Abs(delta) < 0.5)
			{
				foreach (PathGroup pathGroup in _pathGroups)
				{
					foreach (List<Point64> inPath in pathGroup._inPaths)
					{
						solution.Add(inPath);
					}
				}
				return solution;
			}
			_tmpLimit = ((MiterLimit <= 1.0) ? 2.0 : (2.0 / Clipper.Sqr(MiterLimit)));
			foreach (PathGroup pathGroup2 in _pathGroups)
			{
				DoGroupOffset(pathGroup2, delta);
			}
			if (MergeGroups && _pathGroups.Count > 0)
			{
				Clipper64 clipper = new Clipper64
				{
					PreserveCollinear = PreserveCollinear,
					ReverseSolution = (ReverseSolution != _pathGroups[0]._pathsReversed)
				};
				clipper.AddSubject(solution);
				if (_pathGroups[0]._pathsReversed)
				{
					clipper.Execute(ClipType.Union, FillRule.Negative, solution);
				}
				else
				{
					clipper.Execute(ClipType.Union, FillRule.Positive, solution);
				}
			}
			return solution;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		internal static PointD GetUnitNormal(Point64 pt1, Point64 pt2)
		{
			double num = pt2.X - pt1.X;
			double num2 = pt2.Y - pt1.Y;
			if (num == 0.0 && num2 == 0.0)
			{
				return default(PointD);
			}
			double num3 = 1.0 / Math.Sqrt(num * num + num2 * num2);
			num *= num3;
			num2 *= num3;
			return new PointD(num2, 0.0 - num);
		}

		private int GetLowestPolygonIdx(List<List<Point64>> paths)
		{
			Point64 point = new Point64(0L, long.MinValue);
			int result = -1;
			for (int i = 0; i < paths.Count; i++)
			{
				List<Point64> list = paths[i];
				for (int j = 0; j < list.Count; j++)
				{
					if (list[j].Y >= point.Y && (list[j].Y > point.Y || list[j].X < point.X))
					{
						result = i;
						point = list[j];
					}
				}
			}
			return result;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private PointD TranslatePoint(PointD pt, double dx, double dy)
		{
			return new PointD(pt.x + dx, pt.y + dy);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private PointD ReflectPoint(PointD pt, PointD pivot)
		{
			return new PointD(pivot.x + (pivot.x - pt.x), pivot.y + (pivot.y - pt.y));
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private bool AlmostZero(double value, double epsilon = 0.001)
		{
			return Math.Abs(value) < epsilon;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private double Hypotenuse(double x, double y)
		{
			return Math.Sqrt(Math.Pow(x, 2.0) + Math.Pow(y, 2.0));
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private PointD NormalizeVector(PointD vec)
		{
			double num = Hypotenuse(vec.x, vec.y);
			if (AlmostZero(num))
			{
				return new PointD(0L, 0L);
			}
			double num2 = 1.0 / num;
			return new PointD(vec.x * num2, vec.y * num2);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private PointD GetAvgUnitVector(PointD vec1, PointD vec2)
		{
			return NormalizeVector(new PointD(vec1.x + vec2.x, vec1.y + vec2.y));
		}

		private PointD IntersectPoint(PointD pt1a, PointD pt1b, PointD pt2a, PointD pt2b)
		{
			if (pt1a.x == pt1b.x)
			{
				if (pt2a.x == pt2b.x)
				{
					return new PointD(0L, 0L);
				}
				double num = (pt2b.y - pt2a.y) / (pt2b.x - pt2a.x);
				double num2 = pt2a.y - num * pt2a.x;
				return new PointD(pt1a.x, num * pt1a.x + num2);
			}
			if (pt2a.x == pt2b.x)
			{
				double num3 = (pt1b.y - pt1a.y) / (pt1b.x - pt1a.x);
				double num4 = pt1a.y - num3 * pt1a.x;
				return new PointD(pt2a.x, num3 * pt2a.x + num4);
			}
			double num5 = (pt1b.y - pt1a.y) / (pt1b.x - pt1a.x);
			double num6 = pt1a.y - num5 * pt1a.x;
			double num7 = (pt2b.y - pt2a.y) / (pt2b.x - pt2a.x);
			double num8 = pt2a.y - num7 * pt2a.x;
			if (num5 == num7)
			{
				return new PointD(0L, 0L);
			}
			double num9 = (num8 - num6) / (num5 - num7);
			return new PointD(num9, num5 * num9 + num6);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private void DoSquare(PathGroup group, List<Point64> path, int j, int k)
		{
			PointD avgUnitVector = GetAvgUnitVector(new PointD(0.0 - _normals[k].y, _normals[k].x), new PointD(_normals[j].y, 0.0 - _normals[j].x));
			PointD pt = new PointD(path[j]);
			pt = TranslatePoint(pt, _delta * avgUnitVector.x, _delta * avgUnitVector.y);
			PointD pt1a = TranslatePoint(pt, _delta * avgUnitVector.y, _delta * (0.0 - avgUnitVector.x));
			PointD pt1b = TranslatePoint(pt, _delta * (0.0 - avgUnitVector.y), _delta * avgUnitVector.x);
			PointD pt2a = new PointD((double)path[k].X + _normals[k].x * _delta, (double)path[k].Y + _normals[k].y * _delta);
			PointD pt2b = new PointD((double)path[j].X + _normals[k].x * _delta, (double)path[j].Y + _normals[k].y * _delta);
			PointD pt2 = IntersectPoint(pt1a, pt1b, pt2a, pt2b);
			group._outPath.Add(new Point64(pt2));
			group._outPath.Add(new Point64(ReflectPoint(pt2, pt)));
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private void DoMiter(PathGroup group, List<Point64> path, int j, int k, double cosA)
		{
			double num = _delta / (cosA + 1.0);
			group._outPath.Add(new Point64((double)path[j].X + (_normals[k].x + _normals[j].x) * num, (double)path[j].Y + (_normals[k].y + _normals[j].y) * num));
		}

		private void DoRound(PathGroup group, Point64 pt, PointD normal1, PointD normal2, double angle)
		{
			PointD pointD = new PointD(normal2.x * _delta, normal2.y * _delta);
			int num = (int)Math.Round(_stepsPerRad * Math.Abs(angle) + 0.501);
			group._outPath.Add(new Point64((double)pt.X + pointD.x, (double)pt.Y + pointD.y));
			double num2 = Math.Sin(angle / (double)num);
			double num3 = Math.Cos(angle / (double)num);
			for (int i = 0; i < num; i++)
			{
				pointD = new PointD(pointD.x * num3 - num2 * pointD.y, pointD.x * num2 + pointD.y * num3);
				group._outPath.Add(new Point64((double)pt.X + pointD.x, (double)pt.Y + pointD.y));
			}
			group._outPath.Add(new Point64((double)pt.X + normal1.x * _delta, (double)pt.Y + normal1.y * _delta));
		}

		private void BuildNormals(List<Point64> path)
		{
			int count = path.Count;
			_normals.Clear();
			_normals.Capacity = count;
			for (int i = 0; i < count - 1; i++)
			{
				_normals.Add(GetUnitNormal(path[i], path[i + 1]));
			}
			_normals.Add(GetUnitNormal(path[count - 1], path[0]));
		}

		private void OffsetPoint(PathGroup group, List<Point64> path, int j, ref int k)
		{
			double num = _normals[k].x * _normals[j].y - _normals[j].x * _normals[k].y;
			if (num > 1.0)
			{
				num = 1.0;
			}
			else if (num < -1.0)
			{
				num = -1.0;
			}
			if (num * _delta < 0.0)
			{
				Point64 point = new Point64((double)path[j].X + _normals[k].x * _delta, (double)path[j].Y + _normals[k].y * _delta);
				Point64 point2 = new Point64((double)path[j].X + _normals[j].x * _delta, (double)path[j].Y + _normals[j].y * _delta);
				group._outPath.Add(point);
				if (point != point2)
				{
					group._outPath.Add(path[j]);
					group._outPath.Add(point2);
				}
			}
			else
			{
				double num2 = InternalClipper.DotProduct(_normals[j], _normals[k]);
				switch (_joinType)
				{
				case JoinType.Miter:
					if (1.0 + num2 < _tmpLimit)
					{
						DoSquare(group, path, j, k);
					}
					else
					{
						DoMiter(group, path, j, k, num2);
					}
					break;
				case JoinType.Square:
					if (num2 >= 0.0)
					{
						DoMiter(group, path, j, k, num2);
					}
					else
					{
						DoSquare(group, path, j, k);
					}
					break;
				default:
					DoRound(group, path[j], _normals[j], _normals[k], Math.Atan2(num, num2));
					break;
				}
			}
			k = j;
		}

		private void OffsetPolygon(PathGroup group, List<Point64> path)
		{
			group._outPath = new List<Point64>();
			int count = path.Count;
			int k = count - 1;
			for (int i = 0; i < count; i++)
			{
				OffsetPoint(group, path, i, ref k);
			}
			group._outPaths.Add(group._outPath);
		}

		private void OffsetOpenJoined(PathGroup group, List<Point64> path)
		{
			OffsetPolygon(group, path);
			path = Clipper.ReversePath(path);
			BuildNormals(path);
			OffsetPolygon(group, path);
		}

		private void OffsetOpenPath(PathGroup group, List<Point64> path, EndType endType)
		{
			group._outPath = new List<Point64>();
			int num = path.Count - 1;
			int k = 0;
			for (int i = 1; i < num; i++)
			{
				OffsetPoint(group, path, i, ref k);
			}
			num++;
			_normals[num - 1] = new PointD(0.0 - _normals[num - 2].x, 0.0 - _normals[num - 2].y);
			switch (endType)
			{
			case EndType.Butt:
				group._outPath.Add(new Point64((double)path[num - 1].X + _normals[num - 2].x * _delta, (double)path[num - 1].Y + _normals[num - 2].y * _delta));
				group._outPath.Add(new Point64((double)path[num - 1].X - _normals[num - 2].x * _delta, (double)path[num - 1].Y - _normals[num - 2].y * _delta));
				break;
			case EndType.Round:
				DoRound(group, path[num - 1], _normals[num - 1], _normals[num - 2], Math.PI);
				break;
			default:
				DoSquare(group, path, num - 1, num - 2);
				break;
			}
			for (int num2 = num - 2; num2 > 0; num2--)
			{
				_normals[num2] = new PointD(0.0 - _normals[num2 - 1].x, 0.0 - _normals[num2 - 1].y);
			}
			_normals[0] = new PointD(0.0 - _normals[1].x, 0.0 - _normals[1].y);
			k = num - 1;
			for (int num3 = num - 2; num3 > 0; num3--)
			{
				OffsetPoint(group, path, num3, ref k);
			}
			switch (endType)
			{
			case EndType.Butt:
				group._outPath.Add(new Point64((double)path[0].X + _normals[1].x * _delta, (double)path[0].Y + _normals[1].y * _delta));
				group._outPath.Add(new Point64((double)path[0].X - _normals[1].x * _delta, (double)path[0].Y - _normals[1].y * _delta));
				break;
			case EndType.Round:
				DoRound(group, path[0], _normals[0], _normals[1], Math.PI);
				break;
			default:
				DoSquare(group, path, 0, 1);
				break;
			}
			group._outPaths.Add(group._outPath);
		}

		private bool IsFullyOpenEndType(EndType et)
		{
			if (et != EndType.Polygon)
			{
				return et != EndType.Joined;
			}
			return false;
		}

		private void DoGroupOffset(PathGroup group, double delta)
		{
			if (group._endType != EndType.Polygon)
			{
				delta = Math.Abs(delta) / 2.0;
			}
			bool flag = !IsFullyOpenEndType(group._endType);
			if (flag)
			{
				int lowestPolygonIdx = GetLowestPolygonIdx(group._inPaths);
				if (lowestPolygonIdx < 0)
				{
					return;
				}
				double num = Clipper.Area(group._inPaths[lowestPolygonIdx]);
				if (num == 0.0)
				{
					return;
				}
				group._pathsReversed = num < 0.0;
				if (group._pathsReversed)
				{
					delta = 0.0 - delta;
				}
			}
			else
			{
				group._pathsReversed = false;
			}
			_delta = delta;
			double num2 = Math.Abs(_delta);
			_joinType = group._joinType;
			if (group._joinType == JoinType.Round || group._endType == EndType.Round)
			{
				double num3 = ((ArcTolerance > 0.01) ? ArcTolerance : (Math.Log10(2.0 + num2) * 0.25));
				_stepsPerRad = Math.PI / Math.Acos(1.0 - num3 / num2) / (Math.PI * 2.0);
			}
			foreach (List<Point64> inPath in group._inPaths)
			{
				List<Point64> list = Clipper.StripDuplicates(inPath, flag);
				int count = list.Count;
				if (count == 0 || (count < 3 && !IsFullyOpenEndType(group._endType)))
				{
					continue;
				}
				if (count == 1)
				{
					group._outPath = new List<Point64>();
					if (group._endType == EndType.Round)
					{
						DoRound(group, list[0], new PointD(1.0, 0.0), new PointD(-1.0, 0.0), Math.PI * 2.0);
					}
					else
					{
						group._outPath.Capacity = 4;
						group._outPath.Add(new Point64((double)list[0].X - _delta, (double)list[0].Y - _delta));
						group._outPath.Add(new Point64((double)list[0].X + _delta, (double)list[0].Y - _delta));
						group._outPath.Add(new Point64((double)list[0].X + _delta, (double)list[0].Y + _delta));
						group._outPath.Add(new Point64((double)list[0].X - _delta, (double)list[0].Y + _delta));
					}
					group._outPaths.Add(group._outPath);
				}
				else
				{
					BuildNormals(list);
					if (group._endType == EndType.Polygon)
					{
						OffsetPolygon(group, list);
					}
					else if (group._endType == EndType.Joined)
					{
						OffsetOpenJoined(group, list);
					}
					else
					{
						OffsetOpenPath(group, list, group._endType);
					}
				}
			}
			if (!MergeGroups)
			{
				Clipper64 clipper = new Clipper64
				{
					PreserveCollinear = PreserveCollinear,
					ReverseSolution = (ReverseSolution != group._pathsReversed)
				};
				clipper.AddSubject(group._outPaths);
				if (group._pathsReversed)
				{
					clipper.Execute(ClipType.Union, FillRule.Negative, group._outPaths);
				}
				else
				{
					clipper.Execute(ClipType.Union, FillRule.Positive, group._outPaths);
				}
			}
			solution.AddRange(group._outPaths);
			group._outPaths.Clear();
		}
	}
	internal sealed class CinemachinePlayableMixer : PlayableBehaviour
	{
		public delegate PlayableDirector MasterDirectorDelegate();

		public int Priority;

		public static MasterDirectorDelegate GetMasterPlayableDirector;

		private ICameraOverrideStack m_BrainOverrideStack;

		private int m_BrainOverrideId = -1;

		private bool m_PreviewPlay;

		public override void OnPlayableDestroy(Playable playable)
		{
			if (m_BrainOverrideStack != null)
			{
				m_BrainOverrideStack.ReleaseCameraOverride(m_BrainOverrideId);
			}
			m_BrainOverrideId = -1;
		}

		public override void PrepareFrame(Playable playable, FrameData info)
		{
			m_PreviewPlay = false;
		}

		public override void ProcessFrame(Playable playable, FrameData info, object playerData)
		{
			base.ProcessFrame(playable, info, playerData);
			m_BrainOverrideStack = playerData as ICameraOverrideStack;
			if (m_BrainOverrideStack == null)
			{
				return;
			}
			int num = 0;
			int num2 = -1;
			int num3 = -1;
			bool flag = false;
			float num4 = 1f;
			for (int i = 0; i < playable.GetInputCount(); i++)
			{
				float inputWeight = playable.GetInputWeight(i);
				ScriptPlayable<CinemachineShotPlayable> playable2 = (ScriptPlayable<CinemachineShotPlayable>)playable.GetInput(i);
				CinemachineShotPlayable behaviour = playable2.GetBehaviour();
				if (behaviour == null || !behaviour.IsValid || playable.GetPlayState() != PlayState.Playing || !(inputWeight > 0f))
				{
					continue;
				}
				num2 = num3;
				num3 = i;
				num4 = inputWeight;
				if (++num == 2)
				{
					Playable input = playable.GetInput(num2);
					flag = playable2.GetTime() >= input.GetTime();
					if (playable2.GetTime() == input.GetTime())
					{
						flag = playable2.GetDuration() < input.GetDuration();
					}
					break;
				}
			}
			if (num == 1 && num4 < 1f && playable.GetInput(num3).GetTime() > playable.GetInput(num3).GetDuration() / 2.0)
			{
				flag = true;
			}
			if (flag)
			{
				int num5 = num3;
				int num6 = num2;
				num2 = num5;
				num3 = num6;
				num4 = 1f - num4;
			}
			ICinemachineCamera camA = null;
			if (num2 >= 0)
			{
				camA = ((ScriptPlayable<CinemachineShotPlayable>)playable.GetInput(num2)).GetBehaviour().VirtualCamera;
			}
			ICinemachineCamera camB = null;
			if (num3 >= 0)
			{
				camB = ((ScriptPlayable<CinemachineShotPlayable>)playable.GetInput(num3)).GetBehaviour().VirtualCamera;
			}
			m_BrainOverrideId = m_BrainOverrideStack.SetCameraOverride(m_BrainOverrideId, Priority, camA, camB, num4, GetDeltaTime(info.deltaTime));
		}

		private float GetDeltaTime(float deltaTime)
		{
			if (m_PreviewPlay || Application.isPlaying)
			{
				return deltaTime;
			}
			if (TargetPositionCache.CacheMode == TargetPositionCache.Mode.Playback && TargetPositionCache.HasCurrentTime)
			{
				return 0f;
			}
			return -1f;
		}
	}
	public sealed class CinemachineShot : PlayableAsset, IPropertyPreview
	{
		[Tooltip("The name to display on the track.  If empty, the CmCamera's name will be used.")]
		public string DisplayName;

		[Tooltip("The Cinemachine camera to use for this shot")]
		public ExposedReference<CinemachineVirtualCameraBase> VirtualCamera;

		public override Playable CreatePlayable(PlayableGraph graph, GameObject owner)
		{
			ScriptPlayable<CinemachineShotPlayable> scriptPlayable = ScriptPlayable<CinemachineShotPlayable>.Create(graph);
			scriptPlayable.GetBehaviour().VirtualCamera = VirtualCamera.Resolve(graph.GetResolver());
			return scriptPlayable;
		}

		public void GatherProperties(PlayableDirector director, IPropertyCollector driver)
		{
			driver.AddFromName<Transform>("m_LocalPosition.x");
			driver.AddFromName<Transform>("m_LocalPosition.y");
			driver.AddFromName<Transform>("m_LocalPosition.z");
			driver.AddFromName<Transform>("m_LocalRotation.x");
			driver.AddFromName<Transform>("m_LocalRotation.y");
			driver.AddFromName<Transform>("m_LocalRotation.z");
			driver.AddFromName<Transform>("m_LocalRotation.w");
			driver.AddFromName<Camera>("field of view");
			driver.AddFromName<Camera>("near clip plane");
			driver.AddFromName<Camera>("far clip plane");
		}
	}
	internal sealed class CinemachineShotPlayable : PlayableBehaviour
	{
		public CinemachineVirtualCameraBase VirtualCamera;

		public bool IsValid => VirtualCamera != null;
	}
	[Serializable]
	[TrackClipType(typeof(CinemachineShot))]
	[TrackBindingType(typeof(CinemachineBrain), TrackBindingFlags.None)]
	[TrackColor(0.53f, 0f, 0.08f)]
	public class CinemachineTrack : TrackAsset
	{
		[Tooltip("The priority controls the precedence that this track takes over other CinemachineTracks.  Tracks with higher priority will override tracks with lower priority.  If two simultaneous tracks have the same priority, then the more-recently instanced track will take precedence.  Track priority is unrelated to Cinemachine Camera priority.")]
		public int TrackPriority;

		public override Playable CreateTrackMixer(PlayableGraph graph, GameObject go, int inputCount)
		{
			ScriptPlayable<CinemachinePlayableMixer> scriptPlayable = ScriptPlayable<CinemachinePlayableMixer>.Create(graph);
			scriptPlayable.SetInputCount(inputCount);
			scriptPlayable.GetBehaviour().Priority = TrackPriority;
			return scriptPlayable;
		}
	}
}
namespace Unity.Cinemachine.TargetTracking
{
	public enum BindingMode
	{
		LockToTargetOnAssign,
		LockToTargetWithWorldUp,
		LockToTargetNoRoll,
		LockToTarget,
		WorldSpace,
		LazyFollow
	}
	public enum AngularDampingMode
	{
		Euler,
		Quaternion
	}
	[Serializable]
	public struct TrackerSettings
	{
		[Tooltip("The coordinate space to use when interpreting the offset from the target.  This is also used to set the camera's Up vector, which will be maintained when aiming the camera.")]
		public BindingMode BindingMode;

		[Tooltip("How aggressively the camera tries to maintain the offset, per axis.  Small numbers are more responsive, rapidly translating the camera to keep the target's offset.  Larger numbers give a more heavy slowly responding camera. Using different settings per axis can yield a wide range of camera behaviors.")]
		public Vector3 PositionDamping;

		public AngularDampingMode AngularDampingMode;

		[Tooltip("How aggressively the camera tries to track the target's rotation, per axis.  Small numbers are more responsive.  Larger numbers give a more heavy slowly responding camera.")]
		public Vector3 RotationDamping;

		[Range(0f, 20f)]
		[Tooltip("How aggressively the camera tries to track the target's rotation.  Small numbers are more responsive.  Larger numbers give a more heavy slowly responding camera.")]
		public float QuaternionDamping;

		public static TrackerSettings Default => new TrackerSettings
		{
			BindingMode = BindingMode.WorldSpace,
			PositionDamping = Vector3.one,
			AngularDampingMode = AngularDampingMode.Euler,
			RotationDamping = Vector3.one,
			QuaternionDamping = 1f
		};

		public void Validate()
		{
			PositionDamping.x = Mathf.Max(0f, PositionDamping.x);
			PositionDamping.y = Mathf.Max(0f, PositionDamping.y);
			PositionDamping.z = Mathf.Max(0f, PositionDamping.z);
			RotationDamping.x = Mathf.Max(0f, RotationDamping.x);
			RotationDamping.y = Mathf.Max(0f, RotationDamping.y);
			RotationDamping.z = Mathf.Max(0f, RotationDamping.z);
			QuaternionDamping = Mathf.Max(0f, QuaternionDamping);
		}
	}
	public static class TrackerSettingsExtensions
	{
		public static float GetMaxDampTime(this TrackerSettings s)
		{
			Vector3 effectivePositionDamping = s.GetEffectivePositionDamping();
			Vector3 vector = ((s.AngularDampingMode == AngularDampingMode.Euler) ? s.GetEffectiveRotationDamping() : new Vector3(s.QuaternionDamping, 0f, 0f));
			float a = Mathf.Max(effectivePositionDamping.x, Mathf.Max(effectivePositionDamping.y, effectivePositionDamping.z));
			float b = Mathf.Max(vector.x, Mathf.Max(vector.y, vector.z));
			return Mathf.Max(a, b);
		}

		internal static Vector3 GetEffectivePositionDamping(this TrackerSettings s)
		{
			if (s.BindingMode != BindingMode.LazyFollow)
			{
				return s.PositionDamping;
			}
			return new Vector3(0f, s.PositionDamping.y, s.PositionDamping.z);
		}

		internal static Vector3 GetEffectiveRotationDamping(this TrackerSettings s)
		{
			switch (s.BindingMode)
			{
			case BindingMode.LockToTargetNoRoll:
				return new Vector3(s.RotationDamping.x, s.RotationDamping.y, 0f);
			case BindingMode.LockToTargetWithWorldUp:
				return new Vector3(0f, s.RotationDamping.y, 0f);
			case BindingMode.WorldSpace:
			case BindingMode.LazyFollow:
				return Vector3.zero;
			default:
				return s.RotationDamping;
			}
		}
	}
	internal struct Tracker
	{
		private Quaternion m_TargetOrientationOnAssign;

		private Vector3 m_PreviousOffset;

		private Transform m_PreviousTarget;

		public Vector3 PreviousTargetPosition { get; private set; }

		public Quaternion PreviousReferenceOrientation { get; private set; }

		public void InitStateInfo(CinemachineComponentBase component, float deltaTime, BindingMode bindingMode, Vector3 up)
		{
			bool flag = deltaTime >= 0f && component.VirtualCamera.PreviousStateIsValid;
			if (m_PreviousTarget != component.FollowTarget || !flag)
			{
				m_PreviousTarget = component.FollowTarget;
				m_TargetOrientationOnAssign = component.FollowTargetRotation;
			}
			if (!flag)
			{
				PreviousTargetPosition = component.FollowTargetPosition;
				CameraState cameraState = component.VcamState;
				PreviousReferenceOrientation = GetReferenceOrientation(component, bindingMode, up, ref cameraState);
			}
		}

		public Quaternion GetReferenceOrientation(CinemachineComponentBase component, BindingMode bindingMode, Vector3 worldUp, ref CameraState cameraState)
		{
			if (bindingMode == BindingMode.WorldSpace)
			{
				return Quaternion.identity;
			}
			if (component.FollowTarget != null)
			{
				Quaternion followTargetRotation = component.FollowTargetRotation;
				switch (bindingMode)
				{
				case BindingMode.LockToTargetOnAssign:
					return m_TargetOrientationOnAssign;
				case BindingMode.LockToTargetWithWorldUp:
				{
					Vector3 vector2 = (followTargetRotation * Vector3.forward).ProjectOntoPlane(worldUp);
					if (!vector2.AlmostZero())
					{
						return Quaternion.LookRotation(vector2, worldUp);
					}
					break;
				}
				case BindingMode.LockToTargetNoRoll:
					return Quaternion.LookRotation(followTargetRotation * Vector3.forward, worldUp);
				case BindingMode.LockToTarget:
					return followTargetRotation;
				case BindingMode.LazyFollow:
				{
					Vector3 vector = (component.FollowTargetPosition - cameraState.RawPosition).ProjectOntoPlane(worldUp);
					if (!vector.AlmostZero())
					{
						return Quaternion.LookRotation(vector, worldUp);
					}
					break;
				}
				}
			}
			if (PreviousReferenceOrientation == new Quaternion(0f, 0f, 0f, 0f))
			{
				return Quaternion.identity;
			}
			return PreviousReferenceOrientation.normalized;
		}

		public void TrackTarget(CinemachineComponentBase component, float deltaTime, Vector3 up, Vector3 desiredCameraOffset, in TrackerSettings settings, ref CameraState cameraState, out Vector3 outTargetPosition, out Quaternion outTargetOrient)
		{
			Quaternion referenceOrientation = GetReferenceOrientation(component, settings.BindingMode, up, ref cameraState);
			Quaternion quaternion2 = referenceOrientation;
			bool flag = deltaTime >= 0f && component.VirtualCamera.PreviousStateIsValid;
			if (flag)
			{
				if (settings.AngularDampingMode == AngularDampingMode.Quaternion && settings.BindingMode == BindingMode.LockToTarget)
				{
					float t = component.VirtualCamera.DetachedFollowTargetDamp(1f, settings.QuaternionDamping, deltaTime);
					quaternion2 = Quaternion.Slerp(PreviousReferenceOrientation, referenceOrientation, t);
				}
				else if (settings.BindingMode != BindingMode.LazyFollow)
				{
					Vector3 eulerAngles = (Quaternion.Inverse(PreviousReferenceOrientation) * referenceOrientation).eulerAngles;
					for (int i = 0; i < 3; i++)
					{
						if (eulerAngles[i] > 180f)
						{
							eulerAngles[i] -= 360f;
						}
						if (Mathf.Abs(eulerAngles[i]) < 0.01f)
						{
							eulerAngles[i] = 0f;
						}
					}
					eulerAngles = component.VirtualCamera.DetachedFollowTargetDamp(eulerAngles, settings.GetEffectiveRotationDamping(), deltaTime);
					quaternion2 = PreviousReferenceOrientation * Quaternion.Euler(eulerAngles);
				}
			}
			PreviousReferenceOrientation = quaternion2;
			Vector3 followTargetPosition = component.FollowTargetPosition;
			Vector3 vector = PreviousTargetPosition;
			Vector3 vector2 = (flag ? m_PreviousOffset : desiredCameraOffset);
			if ((desiredCameraOffset - vector2).sqrMagnitude > 0.01f)
			{
				Quaternion quaternion3 = UnityVectorExtensions.SafeFromToRotation(m_PreviousOffset, desiredCameraOffset, up);
				vector = followTargetPosition + quaternion3 * (PreviousTargetPosition - followTargetPosition);
			}
			m_PreviousOffset = desiredCameraOffset;
			Vector3 vector3 = followTargetPosition - vector;
			if (flag)
			{
				Quaternion obj = (desiredCameraOffset.AlmostZero() ? component.VcamState.RawOrientation : Quaternion.LookRotation(quaternion2 * desiredCameraOffset, up));
				Vector3 initial = Quaternion.Inverse(obj) * vector3;
				initial = component.VirtualCamera.DetachedFollowTargetDamp(initial, settings.GetEffectivePositionDamping(), deltaTime);
				vector3 = obj * initial;
			}
			vector += vector3;
			Vector3 vector4 = (PreviousTargetPosition = vector);
			outTargetPosition = vector4;
			outTargetOrient = quaternion2;
		}

		public Vector3 GetOffsetForMinimumTargetDistance(CinemachineComponentBase component, Vector3 dampedTargetPos, Vector3 cameraOffset, Vector3 cameraFwd, Vector3 up, Vector3 actualTargetPos)
		{
			Vector3 vector = Vector3.zero;
			if (component.VirtualCamera.FollowTargetAttachment > 0.9999f)
			{
				cameraOffset = cameraOffset.ProjectOntoPlane(up);
				float num = cameraOffset.magnitude * 0.2f;
				if (num > 0f)
				{
					actualTargetPos = actualTargetPos.ProjectOntoPlane(up);
					dampedTargetPos = dampedTargetPos.ProjectOntoPlane(up);
					Vector3 vector2 = dampedTargetPos + cameraOffset;
					float num2 = Vector3.Dot(actualTargetPos - vector2, (dampedTargetPos - vector2).normalized);
					if (num2 < num)
					{
						Vector3 vector3 = actualTargetPos - dampedTargetPos;
						float magnitude = vector3.magnitude;
						if (magnitude < 0.01f)
						{
							vector3 = -cameraFwd.ProjectOntoPlane(up);
						}
						else
						{
							vector3 /= magnitude;
						}
						vector = vector3 * (num - num2);
					}
					PreviousTargetPosition += vector;
				}
			}
			return vector;
		}

		public void OnTargetObjectWarped(Vector3 positionDelta)
		{
			PreviousTargetPosition += positionDelta;
		}

		public void OnForceCameraPosition(CinemachineComponentBase component, BindingMode bindingMode, ref CameraState newState)
		{
			CameraState vcamState = component.VcamState;
			Vector3 vector = Quaternion.Inverse(vcamState.GetFinalOrientation()) * (PreviousTargetPosition - vcamState.GetFinalPosition());
			vector = newState.GetFinalOrientation() * vector;
			PreviousTargetPosition = newState.GetFinalPosition() + vector;
			PreviousReferenceOrientation = GetReferenceOrientation(component, bindingMode, newState.ReferenceUp, ref newState);
			m_PreviousOffset = -vector;
		}
	}
}
